INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 6,14-29', 'Marco', 'Il re Erode sentì parlare di Gesù, perché il suo nome era diventato famoso. Si diceva: «Giovanni il Battista è risorto dai morti e per questo ha il potere di fare prodigi». Altri invece dicevano: «È Elìa». Altri ancora dicevano: «È un profeta, come uno dei profeti». Ma Erode, al sentirne parlare, diceva: «Quel Giovanni che io ho fatto decapitare, è risorto!». Proprio Erode, infatti, aveva mandato ad arrestare Giovanni e lo aveva messo in prigione a causa di Erodìade, moglie di suo fratello Filippo, perché l''aveva sposata. Giovanni infatti diceva a Erode: «Non ti è lecito tenere con te la moglie di tuo fratello». Per questo Erodìade lo odiava e voleva farlo uccidere, ma non poteva, perché Erode temeva Giovanni, sapendolo uomo giusto e santo, e vigilava su di lui; nell''ascoltarlo restava molto perplesso, tuttavia lo ascoltava volentieri. Venne però il giorno propizio, quando Erode, per il suo compleanno, fece un banchetto per i più alti funzionari della sua corte, gli ufficiali dell''esercito e i notabili della Galilea. Entrata la figlia della stessa Erodìade, danzò e piacque a Erode e ai commensali. Allora il re disse alla fanciulla: «Chiedimi quello che vuoi e io te lo darò». E le giurò più volte: «Qualsiasi cosa mi chiederai, te la darò, fosse anche la metà del mio regno». Ella uscì e disse alla madre: «Che cosa devo chiedere?». Quella rispose: «La testa di Giovanni il Battista». E subito, entrata di corsa dal re, fece la richiesta, dicendo: «Voglio che tu mi dia adesso, su un vassoio, la testa di Giovanni il Battista». Il re, fattosi molto triste, a motivo del giuramento e dei commensali non volle opporle un rifiuto. E subito il re mandò una guardia e ordinò che gli fosse portata la testa di Giovanni. La guardia andò, lo decapitò in prigione e ne portò la testa su un vassoio, la diede alla fanciulla e la fanciulla la diede a sua madre. I discepoli di Giovanni, saputo il fatto, vennero, ne presero il cadavere e lo posero in un sepolcro');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 6,30-34', 'Marco', 'Gli apostoli si riunirono attorno a Gesù e gli riferirono tutto quello che avevano fatto e quello che avevano insegnato. Ed egli disse loro: «Venite in disparte, voi soli, in un luogo deserto, e riposatevi un po''». Erano infatti molti quelli che andavano e venivano e non avevano neanche il tempo di mangiare. Allora andarono con la barca verso un luogo deserto, in disparte. Molti però li videro partire e capirono, e da tutte le città accorsero là a piedi e li precedettero. Sceso dalla barca, egli vide una grande folla, ebbe compassione di loro, perché erano come pecore che non hanno pastore, e si mise a insegnare loro molte cose');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 6,7-13', 'Marco', '[In quel tempo, Gesù] chiamò a sé i Dodici e prese a mandarli a due a due e dava loro potere sugli spiriti impuri. E ordinò loro di non prendere per il viaggio nient''altro che un bastone: né pane, né sacca, né denaro nella cintura; ma di calzare sandali e di non portare due tuniche. E diceva loro: «Dovunque entriate in una casa, rimanetevi finché non sarete partiti di lì. Se in qualche luogo non vi accogliessero e non vi ascoltassero, andatevene e scuotete la polvere sotto i vostri piedi come testimonianza per loro». Ed essi, partiti, proclamarono che la gente si convertisse, scacciavano molti demòni, ungevano con olio molti infermi e li guarivano');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 6,1-6', 'Marco', '[In quel tempo, Gesù] venne nella sua patria e i suoi discepoli lo seguirono. Giunto il sabato, si mise a insegnare nella sinagoga. E molti, ascoltando, rimanevano stupiti e dicevano: «Da dove gli vengono queste cose? E che sapienza è quella che gli è stata data? E i prodigi come quelli compiuti dalle sue mani? Non è costui il falegname, il figlio di Maria, il fratello di Giacomo, di Ioses, di Giuda e di Simone? E le sue sorelle, non stanno qui da noi?». Ed era per loro motivo di scandalo. Ma Gesù disse loro: «Un profeta non è disprezzato se non nella sua patria, tra i suoi parenti e in casa sua». E lì non poteva compiere nessun prodigio, ma solo impose le mani a pochi malati e li guarì. E si meravigliava della loro incredulità. Gesù percorreva i villaggi d’intorno, insegnando');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 5,21-43', 'Marco', 'Essendo Gesù passato di nuovo in barca all''altra riva, gli si radunò attorno molta folla ed egli stava lungo il mare. E venne uno dei capi della sinagoga, di nome Giàiro, il quale, come lo vide, gli si gettò ai piedi e lo supplicò con insistenza: «La mia figlioletta sta morendo: vieni a imporle le mani, perché sia salvata e viva». Andò con lui. Molta folla lo seguiva e gli si stringeva intorno. Ora una donna, che aveva perdite di sangue da dodici anni e aveva molto sofferto per opera di molti medici, spendendo tutti i suoi averi senza alcun vantaggio, anzi piuttosto peggiorando, udito parlare di Gesù, venne tra la folla e da dietro toccò il suo mantello. Diceva infatti: «Se riuscirò anche solo a toccare le sue vesti, sarò salvata». E subito le si fermò il flusso di sangue e sentì nel suo corpo che era guarita dal male. E subito Gesù, essendosi reso conto della forza che era uscita da lui, si voltò alla folla dicendo: «Chi ha toccato le mie vesti?». I suoi discepoli gli dissero: «Tu vedi la folla che si stringe intorno a te e dici: "Chi mi ha toccato?"». Egli guardava attorno, per vedere colei che aveva fatto questo. E la donna, impaurita e tremante, sapendo ciò che le era accaduto, venne, gli si gettò davanti e gli disse tutta la verità. Ed egli le disse: «Figlia, la tua fede ti ha salvata. Va'' in pace e sii guarita dal tuo male». Stava ancora parlando, quando dalla casa del capo della sinagoga vennero a dire: «Tua figlia è morta. Perché disturbi ancora il Maestro?». Ma Gesù, udito quanto dicevano, disse al capo della sinagoga: «Non temere, soltanto abbi fede!». E non permise a nessuno di seguirlo, fuorché a Pietro, Giacomo e Giovanni, fratello di Giacomo. Giunsero alla casa del capo della sinagoga ed egli vide trambusto e gente che piangeva e urlava forte. Entrato, disse loro: «Perché vi agitate e piangete? La bambina non è morta, ma dorme». E lo deridevano. Ma egli, cacciati tutti fuori, prese con sé il padre e la madre della bambina e quelli che erano con lui ed entrò dove era la bambina. Prese la mano della bambina e le disse: «Talità kum», che significa: «Fanciulla, io ti dico: àlzati!». E subito la fanciulla si alzò e camminava; aveva infatti dodici anni. Essi furono presi da grande stupore. E raccomandò loro con insistenza che nessuno venisse a saperlo e disse di darle da mangiare');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 5,1-20', 'Marco', '[In quel tempo, Gesù e i suoi discepoli] giunsero all''altra riva del mare, nel paese dei Gerasèni. Sceso dalla barca, subito dai sepolcri gli venne incontro un uomo posseduto da uno spirito impuro. Costui aveva la sua dimora fra le tombe e nessuno riusciva a tenerlo legato, neanche con catene, perché più volte era stato legato con ceppi e catene, ma aveva spezzato le catene e spaccato i ceppi, e nessuno riusciva più a domarlo. Continuamente, notte e giorno, fra le tombe e sui monti, gridava e si percuoteva con pietre. Visto Gesù da lontano, accorse, gli si gettò ai piedi e, urlando a gran voce, disse: «Che vuoi da me, Gesù, Figlio del Dio altissimo? Ti scongiuro, in nome di Dio, non tormentarmi!». Gli diceva infatti: «Esci, spirito impuro, da quest''uomo!». E gli domandò: «Qual è il tuo nome?». «Il mio nome è Legione - gli rispose - perché siamo in molti». E lo scongiurava con insistenza perché non li cacciasse fuori dal paese. C''era là, sul monte, una numerosa mandria di porci al pascolo. E lo scongiurarono: «Mandaci da quei porci, perché entriamo in essi». Glielo permise. E gli spiriti impuri, dopo essere usciti, entrarono nei porci e la mandria si precipitò giù dalla rupe nel mare; erano circa duemila e affogarono nel mare. I loro mandriani allora fuggirono, portarono la notizia nella città e nelle campagne e la gente venne a vedere che cosa fosse accaduto. Giunsero da Gesù, videro l''indemoniato seduto, vestito e sano di mente, lui che era stato posseduto dalla Legione, ed ebbero paura. Quelli che avevano visto, spiegarono loro che cosa era accaduto all''indemoniato e il fatto dei porci. Ed essi si misero a pregarlo di andarsene dal loro territorio. Mentre risaliva nella barca, colui che era stato indemoniato lo supplicava di poter restare con lui. Non glielo permise, ma gli disse: «Va'' nella tua casa, dai tuoi, annuncia loro ciò che il Signore ti ha fatto e la misericordia che ha avuto per te». Egli se ne andò e si mise a proclamare per la Decàpoli quello che Gesù aveva fatto per lui e tutti erano meravigliati');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 4,21-30', 'Luca', '[In quel tempo, Gesù] cominciò a dire nella sinagoga: «Oggi si è compiuta questa Scrittura che voi avete ascoltato». Tutti gli davano testimonianza ed erano meravigliati delle parole di grazia che uscivano dalla sua bocca e dicevano: «Non è costui il figlio di Giuseppe?». Ma egli rispose loro: «Certamente voi mi citerete questo proverbio: "Medico, cura te stesso. Quanto abbiamo udito che accadde a Cafàrnao, fallo anche qui, nella tua patria!"». Poi aggiunse: «In verità io vi dico: nessun profeta è bene accetto nella sua patria. Anzi, in verità io vi dico: c''erano molte vedove in Israele al tempo di Elìa, quando il cielo fu chiuso per tre anni e sei mesi e ci fu una grande carestia in tutto il paese; ma a nessuna di esse fu mandato Elìa, se non a una vedova a Sarèpta di Sidòne. C''erano molti lebbrosi in Israele al tempo del profeta Eliseo; ma nessuno di loro fu purificato, se non Naamàn, il Siro». All''udire queste cose, tutti nella sinagoga si riempirono di sdegno. Si alzarono e lo cacciarono fuori della città e lo condussero fin sul ciglio del monte, sul quale era costruita la loro città, per gettarlo giù. Ma egli, passando in mezzo a loro, si mise in cammino');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 5,1-11', 'Luca', 'Mentre la folla gli faceva ressa attorno per ascoltare la parola di Dio, Gesù, stando presso il lago di Gennèsaret, vide due barche accostate alla sponda. I pescatori erano scesi e lavavano le reti. Salì in una barca, che era di Simone, e lo pregò di scostarsi un poco da terra. Sedette e insegnava alle folle dalla barca. Quando ebbe finito di parlare, disse a Simone: «Prendi il largo e gettate le vostre reti per la pesca». Simone rispose: «Maestro, abbiamo faticato tutta la notte e non abbiamo preso nulla; ma sulla tua parola getterò le reti». Fecero così e presero una quantità enorme di pesci e le loro reti quasi si rompevano. Allora fecero cenno ai compagni dell''altra barca, che venissero ad aiutarli. Essi vennero e riempirono tutte e due le barche fino a farle quasi affondare. Al vedere questo, Simon Pietro si gettò alle ginocchia di Gesù, dicendo: «Signore, allontànati da me, perché sono un peccatore». Lo stupore infatti aveva invaso lui e tutti quelli che erano con lui, per la pesca che avevano fatto; così pure Giacomo e Giovanni, figli di Zebedèo, che erano soci di Simone. Gesù disse a Simone: «Non temere; d''ora in poi sarai pescatore di uomini». E, tirate le barche a terra, lasciarono tutto e lo seguirono');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 6,53-56', 'Marco', '[In quel tempo, Gesù e i suoi discepoli], compiuta la traversata fino a terra, giunsero a Gennèsaret e approdarono. Scesi dalla barca, la gente subito lo riconobbe e, accorrendo da tutta quella regione, cominciarono a portargli sulle barelle i malati, dovunque udivano che egli si trovasse. E là dove giungeva, in villaggi o città o campagne, deponevano i malati nelle piazze e lo supplicavano di poter toccare almeno il lembo del suo mantello; e quanti lo toccavano venivano salvati');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 7,1-13', 'Marco', 'In quel tempo, si riunirono attorno a Gesù i farisei e alcuni degli scribi, venuti da Gerusalemme. Avendo visto che alcuni dei suoi discepoli prendevano cibo con mani impure, cioè non lavate - i farisei infatti e tutti i Giudei non mangiano se non si sono lavati accuratamente le mani, attenendosi alla tradizione degli antichi e, tornando dal mercato, non mangiano senza aver fatto le abluzioni, e osservano molte altre cose per tradizione, come lavature di bicchieri, di stoviglie, di oggetti di rame e di letti –, quei farisei e scribi lo interrogarono: «Perché i tuoi discepoli non si comportano secondo la tradizione degli antichi, ma prendono cibo con mani impure?». Ed egli rispose loro: «Bene ha profetato Isaia di voi, ipocriti, come sta scritto: "Questo popolo mi onora con le labbra, ma il suo cuore è lontano da me. Invano mi rendono culto, insegnando dottrine che sono precetti di uomini". Trascurando il comandamento di Dio, voi osservate la tradizione degli uomini». E diceva loro: «Siete veramente abili nel rifiutare il comandamento di Dio per osservare la vostra tradizione. Mosè infatti disse: "Onora tuo padre e tua madre", e: "Chi maledice il padre o la madre sia messo a morte". Voi invece dite: "Se uno dichiara al padre o alla madre: Ciò con cui dovrei aiutarti è korbàn, cioè offerta a Dio", non gli consentite di fare più nulla per il padre o la madre. Così annullate la parola di Dio con la tradizione che avete tramandato voi. E di cose simili ne fate molte»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 7,14-23', 'Marco', '[In quel tempo, Gesù], chiamata di nuovo la folla, diceva loro: «Ascoltatemi tutti e comprendete bene! Non c''è nulla fuori dell''uomo che, entrando in lui, possa renderlo impuro. Ma sono le cose che escono dall''uomo a renderlo impuro». Quando entrò in una casa, lontano dalla folla, i suoi discepoli lo interrogavano sulla parabola. E disse loro: «Così neanche voi siete capaci di comprendere? Non capite che tutto ciò che entra nell''uomo dal di fuori non può renderlo impuro, perché non gli entra nel cuore ma nel ventre e va nella fogna?». Così rendeva puri tutti gli alimenti. E diceva: «Ciò che esce dall''uomo è quello che rende impuro l''uomo. Dal di dentro infatti, cioè dal cuore degli uomini, escono i propositi di male: impurità, furti, omicidi, adultèri, avidità, malvagità, inganno, dissolutezza, invidia, calunnia, superbia, stoltezza. Tutte queste cose cattive vengono fuori dall''interno e rendono impuro l''uomo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 10,1-9', 'Luca', 'In quel tempo, il Signore designò altri settantadue e li inviò a due a due davanti a sé in ogni città e luogo dove stava per recarsi. Diceva loro: «La messe è abbondante, ma sono pochi gli operai! Pregate dunque il signore della messe, perché mandi operai nella sua messe! Andate: ecco, vi mando come agnelli in mezzo a lupi; non portate borsa, né sacca, né sandali e non fermatevi a salutare nessuno lungo la strada. In qualunque casa entriate, prima dite: "Pace a questa casa!". Se vi sarà un figlio della pace, la vostra pace scenderà su di lui, altrimenti ritornerà su di voi. Restate in quella casa, mangiando e bevendo di quello che hanno, perché chi lavora ha diritto alla sua ricompensa. Non passate da una casa all''altra. Quando entrerete in una città e vi accoglieranno, mangiate quello che vi sarà offerto, guarite i malati che vi si trovano, e dite loro: "È vicino a voi il regno di Dio"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 2,22-40', 'Luca', 'Quando furono compiuti i giorni della loro purificazione rituale, secondo la legge di Mosè, [Maria e Giuseppe] portarono il bambino a Gerusalemme per presentarlo al Signore - come è scritto nella legge del Signore: «Ogni maschio primogenito sarà sacro al Signore» - e per offrire in sacrificio una coppia di tortore o due giovani colombi, come prescrive la legge del Signore. Ora a Gerusalemme c''era un uomo di nome Simeone, uomo giusto e pio, che aspettava la consolazione d''Israele, e lo Spirito Santo era su di lui. Lo Spirito Santo gli aveva preannunciato che non avrebbe visto la morte senza prima aver veduto il Cristo del Signore. Mosso dallo Spirito, si recò al tempio e, mentre i genitori vi portavano il bambino Gesù per fare ciò che la Legge prescriveva a suo riguardo, anch''egli lo accolse tra le braccia e benedisse Dio, dicendo: «Ora puoi lasciare, o Signore, che il tuo servo vada in pace, secondo la tua parola, perché i miei occhi hanno visto la tua salvezza, preparata da te davanti a tutti i popoli: luce per rivelarti alle genti e gloria del tuo popolo, Israele». Il padre e la madre di Gesù si stupivano delle cose che si dicevano di lui. Simeone li benedisse e a Maria, sua madre, disse: «Ecco, egli è qui per la caduta e la risurrezione di molti in Israele e come segno di contraddizione - e anche a te una spada trafiggerà l''anima -, affinché siano svelati i pensieri di molti cuori». C''era anche una profetessa, Anna, figlia di Fanuèle, della tribù di Aser. Era molto avanzata in età, aveva vissuto con il marito sette anni dopo il suo matrimonio, era poi rimasta vedova e ora aveva ottantaquattro anni. Non si allontanava mai dal tempio, servendo Dio notte e giorno con digiuni e preghiere. Sopraggiunta in quel momento, si mise anche lei a lodare Dio e parlava del bambino a quanti aspettavano la redenzione di Gerusalemme. Quando ebbero adempiuto ogni cosa secondo la legge del Signore, fecero ritorno in Galilea, alla loro città di Nàzaret. Il bambino cresceva e si fortificava, pieno di sapienza, e la grazia di Dio era su di lui.');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 4,26-34', 'Marco', '[In quel tempo, Gesù diceva alla folla]: «Così è il regno di Dio: come un uomo che getta il seme sul terreno; dorma o vegli, di notte o di giorno, il seme germoglia e cresce. Come, egli stesso non lo sa. Il terreno produce spontaneamente prima lo stelo, poi la spiga, poi il chicco pieno nella spiga; e quando il frutto è maturo, subito egli manda la falce, perché è arrivata la mietitura». Diceva: «A che cosa possiamo paragonare il regno di Dio o con quale parabola possiamo descriverlo? È come un granello di senape che, quando viene seminato sul terreno, è il più piccolo di tutti i semi che sono sul terreno; ma, quando viene seminato, cresce e diventa più grande di tutte le piante dell''orto e fa rami così grandi che gli uccelli del cielo possono fare il nido alla sua ombra». Con molte parabole dello stesso genere annunciava loro la Parola, come potevano intendere. Senza parabole non parlava loro ma, in privato, ai suoi discepoli spiegava ogni cosa');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 7,31-37', 'Marco', '[In quel tempo, Gesù], uscito dalla regione di Tiro, passando per Sidòne, venne verso il mare di Galilea in pieno territorio della Decàpoli. Gli portarono un sordomuto e lo pregarono di imporgli la mano. Lo prese in disparte, lontano dalla folla, gli pose le dita negli orecchi e con la saliva gli toccò la lingua; guardando quindi verso il cielo, emise un sospiro e gli disse: «Effatà», cioè: «Apriti!». E subito gli si aprirono gli orecchi, si sciolse il nodo della sua lingua e parlava correttamente. E comandò loro di non dirlo a nessuno. Ma più egli lo proibiva, più essi lo proclamavano e, pieni di stupore, dicevano: «Ha fatto bene ogni cosa: fa udire i sordi e fa parlare i muti!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 8,1-10', 'Marco', 'In quei giorni, poiché vi era di nuovo molta folla e non avevano da mangiare, Gesù chiamò a sé i discepoli e disse loro: «Sento compassione per la folla; ormai da tre giorni stanno con me e non hanno da mangiare. Se li rimando digiuni alle loro case, verranno meno lungo il cammino; e alcuni di loro sono venuti da lontano». Gli risposero i suoi discepoli: «Come riuscire a sfamarli di pane qui, in un deserto?». Domandò loro: «Quanti pani avete?». Dissero: «Sette». Ordinò alla folla di sedersi per terra. Prese i sette pani, rese grazie, li spezzò e li dava ai suoi discepoli perché li distribuissero; ed essi li distribuirono alla folla. Avevano anche pochi pesciolini; recitò la benedizione su di essi e fece distribuire anche quelli. Mangiarono a sazietà e portarono via i pezzi avanzati: sette sporte. Erano circa quattromila. E li congedò. Poi salì sulla barca con i suoi discepoli e subito andò dalle parti di Dalmanutà');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,17.20-26', 'Luca', '[In quel tempo Gesù], disceso con i Dodici, si fermò in un luogo pianeggiante. C''era gran folla di suoi discepoli e gran moltitudine di gente da tutta la Giudea, da Gerusalemme e dal litorale di Tiro e di Sidòne. Egli, alzàti gli occhi verso i suoi discepoli, diceva: «Beati voi, poveri, perché vostro è il regno di Dio. Beati voi, che ora avete fame, perché sarete saziati. Beati voi, che ora piangete, perché riderete. Beati voi, quando gli uomini vi odieranno e quando vi metteranno al bando e vi insulteranno e disprezzeranno il vostro nome come infame, a causa del Figlio dell''uomo. Rallegratevi in quel giorno ed esultate perché, ecco, la vostra ricompensa è grande nel cielo. Allo stesso modo infatti agivano i loro padri con i profeti. Ma guai a voi, ricchi, perché avete già ricevuto la vostra consolazione. Guai a voi, che ora siete sazi, perché avrete fame. Guai a voi, che ora ridete, perché sarete nel dolore e piangerete. Guai, quando tutti gli uomini diranno bene di voi. Allo stesso modo infatti agivano i loro padri con i falsi profeti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 8,11-13', 'Marco', 'Vennero i farisei e si misero a discutere con Gesù, chiedendogli un segno dal cielo, per metterlo alla prova. Ma egli sospirò profondamente e disse: «Perché questa generazione chiede un segno? In verità io vi dico: a questa generazione non sarà dato alcun segno». Li lasciò, risalì sulla barca e partì per l’altra riva');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 8,14-21', 'Marco', '[In quel tempo, i discepoli] avevano dimenticato di prendere dei pani e non avevano con sé sulla barca che un solo pane. Allora Gesù li ammoniva dicendo: «Fate attenzione, guardatevi dal lievito dei farisei e dal lievito di Erode!». Ma quelli discutevano fra loro perché non avevano pane. Si accorse di questo e disse loro: «Perché discutete che non avete pane? Non capite ancora e non comprendete? Avete il cuore indurito? Avete occhi e non vedete, avete orecchi e non udite? E non vi ricordate, quando ho spezzato i cinque pani per i cinquemila, quante ceste colme di pezzi avete portato via?». Gli dissero: «Dodici». «E quando ho spezzato i sette pani per i quattromila, quante sporte piene di pezzi avete portato via?». Gli dissero: «Sette». E disse loro: «Non comprendete ancora?»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 8,22-26', 'Marco', '[In quel tempo, Gesù e i suoi discepoli] giunsero a Betsàida, e gli condussero un cieco, pregandolo di toccarlo. Allora prese il cieco per mano, lo condusse fuori dal villaggio e, dopo avergli messo della saliva sugli occhi, gli impose le mani e gli chiese: «Vedi qualcosa?». Quello, alzando gli occhi, diceva: «Vedo la gente, perché vedo come degli alberi che camminano». Allora gli impose di nuovo le mani sugli occhi ed egli ci vide chiaramente, fu guarito e da lontano vedeva distintamente ogni cosa. E lo rimandò a casa sua dicendo: «Non entrare nemmeno nel villaggio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 8,27-33', 'Marco', 'In quel tempo, Gesù partì con i suoi discepoli verso i villaggi intorno a Cesarèa di Filippo, e per la strada interrogava i suoi discepoli dicendo: «La gente, chi dice che io sia?». Ed essi gli risposero: «Giovanni il Battista; altri dicono Elìa e altri uno dei profeti». Ed egli domandava loro: «Ma voi, chi dite che io sia?». Pietro gli rispose: «Tu sei il Cristo». E ordinò loro severamente di non parlare di lui ad alcuno. E cominciò a insegnare loro che il Figlio dell''uomo doveva soffrire molto ed essere rifiutato dagli anziani, dai capi dei sacerdoti e dagli scribi, venire ucciso e, dopo tre giorni, risorgere. Faceva questo discorso apertamente. Pietro lo prese in disparte e si mise a rimproverarlo. Ma egli, voltatosi e guardando i suoi discepoli, rimproverò Pietro e disse: «Va'' dietro a me, Satana! Perché tu non pensi secondo Dio, ma secondo gli uomini»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 16,13-19', 'Matteo', 'Gesù, giunto nella regione di Cesarèa di Filippo, domandò ai suoi discepoli: «La gente, chi dice che sia il Figlio dell''uomo?». Risposero: «Alcuni dicono Giovanni il Battista, altri Elìa, altri Geremìa o qualcuno dei profeti». Disse loro: «Ma voi, chi dite che io sia?». Rispose Simon Pietro: «Tu sei il Cristo, il Figlio del Dio vivente». E Gesù gli disse: «Beato sei tu, Simone, figlio di Giona, perché né carne né sangue te lo hanno rivelato, ma il Padre mio che è nei cieli. E io a te dico: tu sei Pietro e su questa pietra edificherò la mia Chiesa e le potenze degli inferi non prevarranno su di essa. A te darò le chiavi del regno dei cieli: tutto ciò che legherai sulla terra sarà legato nei cieli, e tutto ciò che scioglierai sulla terra sarà sciolto nei cieli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 9,2-13', 'Marco', 'In quel tempo, Gesù prese con sé Pietro, Giacomo e Giovanni e li condusse su un alto monte, in disparte, loro soli. Fu trasfigurato davanti a loro e le sue vesti divennero splendenti, bianchissime: nessun lavandaio sulla terra potrebbe renderle così bianche. E apparve loro Elìa con Mosè e conversavano con Gesù. Prendendo la parola, Pietro disse a Gesù: «Rabbì, è bello per noi essere qui; facciamo tre capanne, una per te, una per Mosè e una per Elìa». Non sapeva infatti che cosa dire, perché erano spaventati. Venne una nube che li coprì con la sua ombra e dalla nube uscì una voce: «Questi è il Figlio mio, l''amato: ascoltatelo!». E improvvisamente, guardandosi attorno, non videro più nessuno, se non Gesù solo, con loro. Mentre scendevano dal monte, ordinò loro di non raccontare ad alcuno ciò che avevano visto, se non dopo che il Figlio dell''uomo fosse risorto dai morti. Ed essi tennero fra loro la cosa, chiedendosi che cosa volesse dire risorgere dai morti. E lo interrogavano: «Perché gli scribi dicono che prima deve venire Elìa?». Egli rispose loro: «Sì, prima viene Elìa e ristabilisce ogni cosa; ma, come sta scritto del Figlio dell''uomo? Che deve soffrire molto ed essere disprezzato. Io però vi dico che Elìa è già venuto e gli hanno fatto quello che hanno voluto, come sta scritto di lui»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,27-38', 'Luca', '[In quel tempo, Gesù disse ai suoi discepoli]: «A voi che ascoltate, io dico: Amate i vostri nemici, fate del bene a coloro che vi odiano, benedite coloro che vi maledicono, pregate per coloro che vi maltrattano. A chi ti percuote sulla guancia, porgi anche l''altra; a chi ti leva il mantello, non rifiutare la tunica. Dá a chiunque ti chiede; e a chi prende del tuo, non richiederlo. Ciò che volete gli uomini facciano a voi, anche voi fatelo a loro. Se amate quelli che vi amano, che merito ne avrete? Anche i peccatori fanno lo stesso. E se fate del bene a coloro che vi fanno del bene, che merito ne avrete? Anche i peccatori fanno lo stesso. E se prestate a coloro da cui sperate ricevere, che merito ne avrete? Anche i peccatori concedono prestiti ai peccatori per riceverne altrettanto. Amate invece i vostri nemici, fate del bene e prestate senza sperarne nulla, e il vostro premio sarà grande e sarete figli dell''Altissimo; perché egli è benevolo verso gl''ingrati e i malvagi. Siate misericordiosi, come è misericordioso il Padre vostro. Non giudicate e non sarete giudicati; non condannate e non sarete condannati; perdonate e vi sarà perdonato; date e vi sarà dato; una buona misura, pigiata, scossa e traboccante vi sarà versata nel grembo, perché con la misura con cui misurate, sarà misurato a voi in cambio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 9,14-29', 'Marco', 'In quel tempo, [Gesù, Pietro, Giacomo e Giovanni, scesero dal monte] e arrivando presso i discepoli, videro attorno a loro molta folla e alcuni scribi che discutevano con loro. E subito tutta la folla, al vederlo, fu presa da meraviglia e corse a salutarlo. Ed egli li interrogò: «Di che cosa discutete con loro?». E dalla folla uno gli rispose: «Maestro, ho portato da te mio figlio, che ha uno spirito muto. Dovunque lo afferri, lo getta a terra ed egli schiuma, digrigna i denti e si irrigidisce. Ho detto ai tuoi discepoli di scacciarlo, ma non ci sono riusciti». Egli allora disse loro: «O generazione incredula! Fino a quando sarò con voi? Fino a quando dovrò sopportarvi? Portatelo da me». E glielo portarono. Alla vista di Gesù, subito lo spirito scosse con convulsioni il ragazzo ed egli, caduto a terra, si rotolava schiumando. Gesù interrogò il padre: «Da quanto tempo gli accade questo?». Ed egli rispose: «Dall''infanzia; anzi, spesso lo ha buttato anche nel fuoco e nell''acqua per ucciderlo. Ma se tu puoi qualcosa, abbi pietà di noi e aiutaci». Gesù gli disse: «Se tu puoi! Tutto è possibile per chi crede». Il padre del fanciullo rispose subito ad alta voce: «Credo; aiuta la mia incredulità!». Allora Gesù, vedendo accorrere la folla, minacciò lo spirito impuro dicendogli: «Spirito muto e sordo, io ti ordino, esci da lui e non vi rientrare più». Gridando, e scuotendolo fortemente, uscì. E il fanciullo diventò come morto, sicché molti dicevano: «È morto». Ma Gesù lo prese per mano, lo fece alzare ed egli stette in piedi. Entrato in casa, i suoi discepoli gli domandavano in privato: «Perché noi non siamo riusciti a scacciarlo?». Ed egli disse loro: «Questa specie di demòni non si può scacciare in alcun modo, se non con la preghiera»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 9,30-37', 'Marco', 'In quel tempo, Gesù e i suoi discepoli attraversavano la Galilea, ma egli non voleva che alcuno lo sapesse. Insegnava infatti ai suoi discepoli e diceva loro: «Il Figlio dell’uomo viene consegnato nelle mani degli uomini e lo uccideranno; ma, una volta ucciso, dopo tre giorni risorgerà». Essi però non capivano queste parole e avevano timore di interrogarlo. Giunsero a Cafàrnao. Quando fu in casa, chiese loro: «Di che cosa stavate discutendo per la strada?». Ed essi tacevano. Per la strada infatti avevano discusso tra loro chi fosse più grande. Sedutosi, chiamò i Dodici e disse loro: «Se uno vuole essere il primo, sia l’ultimo di tutti e il servitore di tutti». E, preso un bambino, lo pose in mezzo a loro e, abbracciandolo, disse loro: «Chi accoglie uno solo di questi bambini nel mio nome, accoglie me; e chi accoglie me, non accoglie me, ma colui che mi ha mandato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 9,38-40', 'Marco', 'Giovanni disse a Gesù: «Maestro, abbiamo visto uno che scacciava demòni nel tuo nome e volevamo impedirglielo, perché non ci seguiva». Ma Gesù disse: «Non glielo impedite, perché non c''è nessuno che faccia un miracolo nel mio nome e subito possa parlare male di me: chi non è contro di noi è per noi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 9,41-50', 'Marco', '[In quel tempo, Gesù disse]: «Chiunque infatti vi darà da bere un bicchiere d''acqua nel mio nome perché siete di Cristo, in verità io vi dico, non perderà la sua ricompensa. Chi scandalizzerà uno solo di questi piccoli che credono in me, è molto meglio per lui che gli venga messa al collo una macina da mulino e sia gettato nel mare. Se la tua mano ti è motivo di scandalo, tagliala: è meglio per te entrare nella vita con una mano sola, anziché con le due mani andare nella Geènna, nel fuoco inestinguibile. E se il tuo piede ti è motivo di scandalo, taglialo: è meglio per te entrare nella vita con un piede solo, anziché con i due piedi essere gettato nella Geènna. E se il tuo occhio ti è motivo di scandalo, gettalo via: è meglio per te entrare nel regno di Dio con un occhio solo, anziché con due occhi essere gettato nella Geènna, dove il loro verme non muore e il fuoco non si estingue. Ognuno infatti sarà salato con il fuoco. Buona cosa è il sale; ma se il sale diventa insipido, con che cosa gli darete sapore? Abbiate sale in voi stessi e siate in pace gli uni con gli altri»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 10,1-12', 'Marco', 'In quel tempo, Gesù, partito da Cafàrnao, venne nella regione della Giudea e al di là del fiume Giordano. La folla accorse di nuovo a lui e di nuovo egli insegnava loro, come era solito fare. Alcuni farisei si avvicinarono e, per metterlo alla prova, domandavano a Gesù se è lecito a un marito ripudiare la propria moglie. Ma egli rispose loro: «Che cosa vi ha ordinato Mosè?». Dissero: «Mosè ha permesso di scrivere un atto di ripudio e di ripudiarla». Gesù disse loro: «Per la durezza del vostro cuore egli scrisse per voi questa norma. Ma dall''inizio della creazione [Dio] li fece maschio e femmina; per questo l''uomo lascerà suo padre e sua madre e si unirà a sua moglie e i due diventeranno una carne sola. Così non sono più due, ma una sola carne. Dunque l''uomo non divida quello che Dio ha congiunto». A casa, i discepoli lo interrogavano di nuovo su questo argomento. E disse loro: «Chi ripudia la propria moglie e ne sposa un''altra, commette adulterio verso di lei; e se lei, ripudiato il marito, ne sposa un altro, commette adulterio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 10,13-16', 'Marco', 'In quel tempo, presentavano a Gesù dei bambini perché li toccasse, ma i discepoli li rimproverarono. Gesù, al vedere questo, s''indignò e disse loro: «Lasciate che i bambini vengano a me, non glielo impedite: a chi è come loro infatti appartiene il regno di Dio. In verità io vi dico: chi non accoglie il regno di Dio come lo accoglie un bambino, non entrerà in esso». E, prendendoli tra le braccia, li benediceva, ponendo le mani su di loro');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,39-45', 'Luca', '[In quel tempo, Gesù] disse loro anche una parabola: «Può forse un cieco guidare un altro cieco? Non cadranno tutti e due in un fosso? Un discepolo non è più del maestro; ma ognuno, che sia ben preparato, sarà come il suo maestro. Perché guardi la pagliuzza che è nell''occhio del tuo fratello e non ti accorgi della trave che è nel tuo occhio? Come puoi dire al tuo fratello: "Fratello, lascia che tolga la pagliuzza che è nel tuo occhio", mentre tu stesso non vedi la trave che è nel tuo occhio? Ipocrita! Togli prima la trave dal tuo occhio e allora ci vedrai bene per togliere la pagliuzza dall''occhio del tuo fratello. Non vi è albero buono che produca un frutto cattivo, né vi è d''altronde albero cattivo che produca un frutto buono. Ogni albero infatti si riconosce dal suo frutto: non si raccolgono fichi dagli spini, né si vendemmia uva da un rovo. L''uomo buono dal buon tesoro del suo cuore trae fuori il bene; l''uomo cattivo dal suo cattivo tesoro trae fuori il male: la sua bocca infatti esprime ciò che dal cuore sovrabbonda»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 10,17-27', 'Marco', 'In quel tempo, mentre Gesù andava per la strada, un tale gli corse incontro e, gettandosi in ginocchio davanti a lui, gli domandò: «Maestro buono, che cosa devo fare per avere in eredità la vita eterna?». Gesù gli disse: «Perché mi chiami buono? Nessuno è buono, se non Dio solo. Tu conosci i comandamenti: "Non uccidere, non commettere adulterio, non rubare, non testimoniare il falso, non frodare, onora tuo padre e tua madre"». Egli allora gli disse: «Maestro, tutte queste cose le ho osservate fin dalla mia giovinezza». Allora Gesù fissò lo sguardo su di lui, lo amò e gli disse: «Una cosa sola ti manca: va'', vendi quello che hai e dallo ai poveri, e avrai un tesoro in cielo; e vieni! Seguimi!». Ma a queste parole egli si fece scuro in volto e se ne andò rattristato; possedeva infatti molti beni. Gesù, volgendo lo sguardo attorno, disse ai suoi discepoli: «Quanto è difficile, per quelli che possiedono ricchezze, entrare nel regno di Dio!». I discepoli erano sconcertati dalle sue parole; ma Gesù riprese e disse loro: «Figli, quanto è difficile entrare nel regno di Dio! È più facile che un cammello passi per la cruna di un ago, che un ricco entri nel regno di Dio». Essi, ancora più stupiti, dicevano tra loro: «E chi può essere salvato?». Ma Gesù, guardandoli in faccia, disse: «Impossibile agli uomini, ma non a Dio! Perché tutto è possibile a Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 10,28-31', 'Marco', 'Pietro prese a dire a Gesù: «Ecco, noi abbiamo lasciato tutto e ti abbiamo seguito». Gesù gli rispose: «In verità io vi dico: non c''è nessuno che abbia lasciato casa o fratelli o sorelle o madre o padre o figli o campi per causa mia e per causa del Vangelo, che non riceva già ora, in questo tempo, cento volte tanto in case e fratelli e sorelle e madri e figli e campi, insieme a persecuzioni, e la vita eterna nel tempo che verrà. Molti dei primi saranno ultimi e gli ultimi saranno primi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 6,1-6.16-18', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «State attenti a non praticare la vostra giustizia davanti agli uomini per essere ammirati da loro, altrimenti non c''è ricompensa per voi presso il Padre vostro che è nei cieli. Dunque, quando fai l''elemosina, non suonare la tromba davanti a te, come fanno gli ipòcriti nelle sinagoghe e nelle strade, per essere lodati dalla gente. In verità io vi dico: hanno già ricevuto la loro ricompensa. Invece, mentre tu fai l''elemosina, non sappia la tua sinistra ciò che fa la tua destra, perché la tua elemosina resti nel segreto; e il Padre tuo, che vede nel segreto, ti ricompenserà. E quando pregate, non siate simili agli ipòcriti che, nelle sinagoghe e negli angoli delle piazze, amano pregare stando ritti, per essere visti dalla gente. In verità io vi dico: hanno già ricevuto la loro ricompensa. Invece, quando tu preghi, entra nella tua camera, chiudi la porta e prega il Padre tuo, che è nel segreto; e il Padre tuo, che vede nel segreto, ti ricompenserà. E quando digiunate, non diventate malinconici come gli ipòcriti, che assumono un''aria disfatta per far vedere agli altri che digiunano. In verità io vi dico: hanno già ricevuto la loro ricompensa. Invece, quando tu digiuni, profùmati la testa e làvati il volto, perché la gente non veda che tu digiuni, ma solo il Padre tuo, che è nel segreto; e il Padre tuo, che vede nel segreto, ti ricompenserà»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,22-25', 'Luca', '[In quel tempo, Gesù disse ai suoi discepoli]: «Il Figlio dell''uomo deve soffrire molto, essere rifiutato dagli anziani, dai capi dei sacerdoti e dagli scribi, venire ucciso e risorgere il terzo giorno». Poi, a tutti, diceva: «Se qualcuno vuole venire dietro a me, rinneghi se stesso, prenda la sua croce ogni giorno e mi segua. Chi vuole salvare la propria vita, la perderà, ma chi perderà la propria vita per causa mia, la salverà. Infatti, quale vantaggio ha un uomo che guadagna il mondo intero, ma perde o rovina sé stesso?»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,14-15', 'Matteo', '[In quel tempo, si avvicinarono a Gesù] i discepoli di Giovanni e gli dissero: «Perché noi e i farisei digiuniamo molte volte, mentre i tuoi discepoli non digiunano?». E Gesù disse loro: «Possono forse gli invitati a nozze essere in lutto finché lo sposo è con loro? Ma verranno giorni quando lo sposo sarà loro tolto, e allora digiuneranno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 5,27-32', 'Luca', 'Gesù vide un pubblicano di nome Levi, seduto al banco delle imposte, e gli disse: «Seguimi!». Ed egli, lasciando tutto, si alzò e lo seguì. Poi Levi gli preparò un grande banchetto nella sua casa. C''era una folla numerosa di pubblicani e d''altra gente, che erano con loro a tavola. I farisei e i loro scribi mormoravano e dicevano ai suoi discepoli: «Come mai mangiate e bevete insieme ai pubblicani e ai peccatori?». Gesù rispose loro: «Non sono i sani che hanno bisogno del medico, ma i malati; io non sono venuto a chiamare i giusti, ma i peccatori perché si convertano»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 4,1-13', 'Luca', 'Gesù, pieno di Spirito Santo, si allontanò dal Giordano ed era guidato dallo Spirito nel deserto, per quaranta giorni, tentato dal diavolo. Non mangiò nulla in quei giorni, ma quando furono terminati, ebbe fame. Allora il diavolo gli disse: «Se tu sei Figlio di Dio, di'' a questa pietra che diventi pane». Gesù gli rispose: «Sta scritto: "Non di solo pane vivrà l''uomo"». Il diavolo lo condusse in alto, gli mostrò in un istante tutti i regni della terra e gli disse: «Ti darò tutto questo potere e la loro gloria, perché a me è stata data e io la do a chi voglio. Perciò, se ti prostrerai in adorazione dinanzi a me, tutto sarà tuo». Gesù gli rispose: «Sta scritto: "Il Signore, Dio tuo, adorerai: a lui solo renderai culto"». Lo condusse a Gerusalemme, lo pose sul punto più alto del tempio e gli disse: «Se tu sei Figlio di Dio, gèttati giù di qui; sta scritto infatti: "Ai suoi angeli darà ordini a tuo riguardo affinché essi ti custodiscano"; e anche: "Essi ti porteranno sulle loro mani perché il tuo piede non inciampi in una pietra"». Gesù gli rispose: «È stato detto: "Non metterai alla prova il Signore Dio tuo"». Dopo aver esaurito ogni tentazione, il diavolo si allontanò da lui fino al momento fissato');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 25,31-46', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Quando il Figlio dell''uomo verrà nella sua gloria, e tutti gli angeli con lui, siederà sul trono della sua gloria. Davanti a lui verranno radunati tutti i popoli. Egli separerà gli uni dagli altri, come il pastore separa le pecore dalle capre, e porrà le pecore alla sua destra e le capre alla sinistra. Allora il re dirà a quelli che saranno alla sua destra: "Venite, benedetti del Padre mio, ricevete in eredità il regno preparato per voi fin dalla creazione del mondo, perché ho avuto fame e mi avete dato da mangiare, ho avuto sete e mi avete dato da bere, ero straniero e mi avete accolto, nudo e mi avete vestito, malato e mi avete visitato, ero in carcere e siete venuti a trovarmi". Allora i giusti gli risponderanno: "Signore, quando ti abbiamo visto affamato e ti abbiamo dato da mangiare, o assetato e ti abbiamo dato da bere? Quando mai ti abbiamo visto straniero e ti abbiamo accolto, o nudo e ti abbiamo vestito? Quando mai ti abbiamo visto malato o in carcere e siamo venuti a visitarti?". E il re risponderà loro: "In verità io vi dico: tutto quello che avete fatto a uno solo di questi miei fratelli più piccoli, l''avete fatto a me". Poi dirà anche a quelli che saranno alla sinistra: "Via, lontano da me, maledetti, nel fuoco eterno, preparato per il diavolo e per i suoi angeli, perché ho avuto fame e non mi avete dato da mangiare, ho avuto sete e non mi avete dato da bere, ero straniero e non mi avete accolto, nudo e non mi avete vestito, malato e in carcere e non mi avete visitato". Anch''essi allora risponderanno: "Signore, quando ti abbiamo visto affamato o assetato o straniero o nudo o malato o in carcere, e non ti abbiamo servito?". Allora egli risponderà loro: "In verità io vi dico: tutto quello che non avete fatto a uno solo di questi più piccoli, non l''avete fatto a me". E se ne andranno: questi al supplizio eterno, i giusti invece alla vita eterna»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 6,7-15', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Pregando, non sprecate parole come i pagani: essi credono di venire ascoltati a forza di parole. Non siate dunque come loro, perché il Padre vostro sa di quali cose avete bisogno prima ancora che gliele chiediate. Voi dunque pregate così: Padre nostro che sei nei cieli, sia santificato il tuo nome, venga il tuo regno, sia fatta la tua volontà, come in cielo così in terra. Dacci oggi il nostro pane quotidiano, e rimetti a noi i nostri debiti come anche noi li rimettiamo ai nostri debitori, e non abbandonarci alla tentazione, ma liberaci dal male. Se voi infatti perdonerete agli altri le loro colpe, il Padre vostro che è nei cieli perdonerà anche a voi; ma se voi non perdonerete agli altri, neppure il Padre vostro perdonerà le vostre colpe»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 11,29-32', 'Luca', 'Mentre le folle si accalcavano, Gesù cominciò a dire: «Questa generazione è una generazione malvagia; essa cerca un segno, ma non le sarà dato alcun segno, se non il segno di Giona. Poiché, come Giona fu un segno per quelli di Nìnive, così anche il Figlio dell''uomo lo sarà per questa generazione. Nel giorno del giudizio, la regina del Sud si alzerà contro gli uomini di questa generazione e li condannerà, perché ella venne dagli estremi confini della terra per ascoltare la sapienza di Salomone. Ed ecco, qui vi è uno più grande di Salomone. Nel giorno del giudizio, gli abitanti di Nìnive si alzeranno contro questa generazione e la condanneranno, perché essi alla predicazione di Giona si convertirono. Ed ecco, qui vi è uno più grande di Giona»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 7,7-12', 'Matteo', 'In quel tempo, Gesù disse ai suoi discepoli: «Chiedete e vi sarà dato; cercate e troverete, bussate e vi sarà aperto. Perché chiunque chiede riceve, e chi cerca trova, e a chi bussa sarà aperto. Chi di voi, al figlio che gli chiede un pane, darà una pietra? E se gli chiede un pesce, gli darà una serpe? Se voi, dunque, che siete cattivi, sapete dare cose buone ai vostri figli, quanto più il Padre vostro che è nei cieli darà cose buone a quelli che gliele chiedono! Tutto quanto volete che gli uomini facciano a voi, anche voi fatelo a loro: questa infatti è la Legge e i Profeti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,20-26', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Se la vostra giustizia non supererà quella degli scribi e dei farisei, non entrerete nel regno dei cieli. Avete inteso che fu detto agli antichi: "Non ucciderai"; chi avrà ucciso dovrà essere sottoposto al giudizio. Ma io vi dico: chiunque si adira con il proprio fratello dovrà essere sottoposto al giudizio. Chi poi dice al fratello: "Stupido", dovrà essere sottoposto al sinèdrio; e chi gli dice: "Pazzo", sarà destinato al fuoco della Geènna. Se dunque tu presenti la tua offerta all''altare e lì ti ricordi che tuo fratello ha qualche cosa contro di te, lascia lì il tuo dono davanti all''altare, va'' prima a riconciliarti con il tuo fratello e poi torna a offrire il tuo dono. Mettiti presto d''accordo con il tuo avversario mentre sei in cammino con lui, perché l''avversario non ti consegni al giudice e il giudice alla guardia, e tu venga gettato in prigione. In verità io ti dico: non uscirai di là finché non avrai pagato fino all''ultimo spicciolo!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,43-48', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Avete inteso che fu detto: “Amerai il tuo prossimo” e odierai il tuo nemico. Ma io vi dico: amate i vostri nemici e pregate per quelli che vi perseguitano, affinché siate figli del Padre vostro che è nei cieli; egli fa sorgere il suo sole sui cattivi e sui buoni, e fa piovere sui giusti e sugli ingiusti. Infatti, se amate quelli che vi amano, quale ricompensa ne avete? Non fanno così anche i pubblicani? E se date il saluto soltanto ai vostri fratelli, che cosa fate di straordinario? Non fanno così anche i pagani? Voi, dunque, siate perfetti come è perfetto il Padre vostro celeste»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,28-36', 'Luca', 'In quel tempo, Gesù prese con sé Pietro, Giovanni e Giacomo e salì sul monte a pregare. Mentre pregava, il suo volto cambiò d''aspetto e la sua veste divenne candida e sfolgorante. Ed ecco, due uomini conversavano con lui: erano Mosè ed Elìa, apparsi nella gloria, e parlavano del suo esodo, che stava per compiersi a Gerusalemme. Pietro e i suoi compagni erano oppressi dal sonno; ma, quando si svegliarono, videro la sua gloria e i due uomini che stavano con lui. Mentre questi si separavano da lui, Pietro disse a Gesù: «Maestro, è bello per noi essere qui. Facciamo tre capanne, una per te, una per Mosè e una per Elìa». Egli non sapeva quello che diceva. Mentre parlava così, venne una nube e li coprì con la sua ombra. All''entrare nella nube, ebbero paura. E dalla nube uscì una voce, che diceva: «Questi è il Figlio mio, l''eletto; ascoltatelo!». Appena la voce cessò, restò Gesù solo. Essi tacquero e in quei giorni non riferirono a nessuno ciò che avevano visto');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,36-38', 'Luca', '[In quel tempo, Gesù disse ai suoi discepoli]: «Siate misericordiosi, come il Padre vostro è misericordioso. Non giudicate e non sarete giudicati; non condannate e non sarete condannati; perdonate e sarete perdonati. Date e vi sarà dato: una misura buona, pigiata, colma e traboccante vi sarà versata nel grembo, perché con la misura con la quale misurate, sarà misurato a voi in cambio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 1,16.18-21.24', 'Matteo', 'Giacobbe generò Giuseppe, lo sposo di Maria, dalla quale è nato Gesù, chiamato Cristo. Così fu generato Gesù Cristo: sua madre Maria, essendo promessa sposa di Giuseppe, prima che andassero a vivere insieme si trovò incinta per opera dello Spirito Santo. Giuseppe suo sposo, poiché era uomo giusto e non voleva accusarla pubblicamente, pensò di ripudiarla in segreto. Mentre però stava considerando queste cose, ecco, gli apparve in sogno un angelo del Signore e gli disse: «Giuseppe, figlio di Davide, non temere di prendere con te Maria, tua sposa. Infatti il bambino che è generato in lei viene dallo Spirito Santo; ella darà alla luce un figlio e tu lo chiamerai Gesù: egli infatti salverà il suo popolo dai suoi peccati». Quando si destò dal sonno, Giuseppe fece come gli aveva ordinato l''angelo del Signore');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 20,17-28', 'Matteo', 'Mentre saliva a Gerusalemme, Gesù prese in disparte i dodici discepoli e lungo il cammino disse loro: «Ecco, noi saliamo a Gerusalemme e il Figlio dell''uomo sarà consegnato ai capi dei sacerdoti e agli scribi; lo condanneranno a morte e lo consegneranno ai pagani perché venga deriso e flagellato e crocifisso, e il terzo giorno risorgerà». Allora gli si avvicinò la madre dei figli di Zebedèo con i suoi figli e si prostrò per chiedergli qualcosa. Egli le disse: «Che cosa vuoi?». Gli rispose: «Di'' che questi miei due figli siedano uno alla tua destra e uno alla tua sinistra nel tuo regno». Rispose Gesù: «Voi non sapete quello che chiedete. Potete bere il calice che io sto per bere?». Gli dicono: «Lo possiamo». Ed egli disse loro: «Il mio calice, lo berrete; però sedere alla mia destra e alla mia sinistra non sta a me concederlo: è per coloro per i quali il Padre mio lo ha preparato». Gli altri dieci, avendo sentito, si sdegnarono con i due fratelli. Ma Gesù li chiamò a sé e disse: «Voi sapete che i governanti delle nazioni dòminano su di esse e i capi le opprimono. Tra voi non sarà così; ma chi vuole diventare grande tra voi, sarà vostro servitore e chi vuole essere il primo tra voi, sarà vostro schiavo. Come il Figlio dell''uomo, che non è venuto per farsi servire, ma per servire e dare la propria vita in riscatto per molti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 16,19-31', 'Luca', '[In quel tempo, Gesù disse ai farisei]: «C''era un uomo ricco, che indossava vestiti di porpora e di lino finissimo, e ogni giorno si dava a lauti banchetti. Un povero, di nome Lazzaro, stava alla sua porta, coperto di piaghe, bramoso di sfamarsi con quello che cadeva dalla tavola del ricco; ma erano i cani che venivano a leccare le sue piaghe. Un giorno il povero morì e fu portato dagli angeli accanto ad Abramo. Morì anche il ricco e fu sepolto. Stando negli inferi fra i tormenti, alzò gli occhi e vide di lontano Abramo, e Lazzaro accanto a lui. Allora gridando disse: "Padre Abramo, abbi pietà di me e manda Lazzaro a intingere nell''acqua la punta del dito e a bagnarmi la lingua, perché soffro terribilmente in questa fiamma". Ma Abramo rispose: "Figlio, ricordati che, nella vita, tu hai ricevuto i tuoi beni, e Lazzaro i suoi mali; ma ora in questo modo lui è consolato, tu invece sei in mezzo ai tormenti. Per di più, tra noi e voi è stato fissato un grande abisso: coloro che di qui vogliono passare da voi, non possono, né di lì possono giungere fino a noi". E quello replicò: "Allora, padre, ti prego di mandare Lazzaro a casa di mio padre, perché ho cinque fratelli. Li ammonisca severamente, perché non vengano anch''essi in questo luogo di tormento". Ma Abramo rispose: "Hanno Mosè e i Profeti; ascoltino loro". E lui replicò: "No, padre Abramo, ma se dai morti qualcuno andrà da loro, si convertiranno". Abramo rispose: "Se non ascoltano Mosè e i Profeti, non saranno persuasi neanche se uno risorgesse dai morti"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 21,33-43.45', 'Matteo', '[In quel tempo, Gesù disse ai capi dei sacerdoti e agli anziani del popolo]: «Ascoltate un’altra parabola: c’era un uomo che possedeva un terreno e vi piantò una vigna. La circondò con una siepe, vi scavò una buca per il torchio e costruì una torre. La diede in affitto a dei contadini e se ne andò lontano. Quando arrivò il tempo di raccogliere i frutti, mandò i suoi servi dai contadini a ritirare il raccolto. Ma i contadini presero i servi e uno lo bastonarono, un altro lo uccisero, un altro lo lapidarono. Mandò di nuovo altri servi, più numerosi dei primi, ma li trattarono allo stesso modo. Da ultimo mandò loro il proprio figlio dicendo: “Avranno rispetto per mio figlio!”. Ma i contadini, visto il figlio, dissero tra loro: “Costui è l’erede. Su, uccidiamolo e avremo noi la sua eredità!”. Lo presero, lo cacciarono fuori dalla vigna e lo uccisero. Quando verrà dunque il padrone della vigna, che cosa farà a quei contadini?». Gli risposero: «Quei malvagi, li farà morire miseramente e darà in affitto la vigna ad altri contadini, che gli consegneranno i frutti a suo tempo». E Gesù disse loro: «Non avete mai letto nelle Scritture: “La pietra che i costruttori hanno scartato è diventata la pietra d’angolo; questo è stato fatto dal Signore ed è una meraviglia ai nostri occhi”? Perciò io vi dico: a voi sarà tolto il regno di Dio e sarà dato a un popolo che ne produca i frutti». Udite queste parabole, i capi dei sacerdoti e i farisei capirono che parlava di loro. Cercavano di catturarlo, ma ebbero paura della folla, perché lo considerava un profeta');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 15,1-3.11-32', 'Luca', 'In quel tempo, si avvicinavano a lui tutti i pubblicani e i peccatori per ascoltarlo. I farisei e gli scribi mormoravano dicendo: «Costui accoglie i peccatori e mangia con loro». Ed egli disse loro questa parabola: «Un uomo aveva due figli. Il più giovane dei due disse al padre: "Padre, dammi la parte di patrimonio che mi spetta". Ed egli divise tra loro le sue sostanze. Pochi giorni dopo, il figlio più giovane, raccolte tutte le sue cose, partì per un paese lontano e là sperperò il suo patrimonio vivendo in modo dissoluto. Quando ebbe speso tutto, sopraggiunse in quel paese una grande carestia ed egli cominciò a trovarsi nel bisogno. Allora andò a mettersi al servizio di uno degli abitanti di quella regione, che lo mandò nei suoi campi a pascolare i porci. Avrebbe voluto saziarsi con le carrube di cui si nutrivano i porci; ma nessuno gli dava nulla. Allora ritornò in sé e disse: "Quanti salariati di mio padre hanno pane in abbondanza e io qui muoio di fame! Mi alzerò, andrò da mio padre e gli dirò: Padre, ho peccato verso il Cielo e davanti a te; non sono più degno di essere chiamato tuo figlio. Trattami come uno dei tuoi salariati". Si alzò e tornò da suo padre. Quando era ancora lontano, suo padre lo vide, ebbe compassione, gli corse incontro, gli si gettò al collo e lo baciò. Il figlio gli disse: "Padre, ho peccato verso il Cielo e davanti a te; non sono più degno di essere chiamato tuo figlio". Ma il padre disse ai servi: "Presto, portate qui il vestito più bello e fateglielo indossare, mettetegli l''anello al dito e i sandali ai piedi. Prendete il vitello grasso, ammazzatelo, mangiamo e facciamo festa, perché questo mio figlio era morto ed è tornato in vita, era perduto ed è stato ritrovato". E cominciarono a far festa. Il figlio maggiore si trovava nei campi. Al ritorno, quando fu vicino a casa, udì la musica e le danze; chiamò uno dei servi e gli domandò che cosa fosse tutto questo. Quello gli rispose: "Tuo fratello è qui e tuo padre ha fatto ammazzare il vitello grasso, perché lo ha riavuto sano e salvo". Egli si indignò, e non voleva entrare. Suo padre allora uscì a supplicarlo. Ma egli rispose a suo padre: "Ecco, io ti servo da tanti anni e non ho mai disobbedito a un tuo comando, e tu non mi hai mai dato un capretto per far festa con i miei amici. Ma ora che è tornato questo tuo figlio, il quale ha divorato le tue sostanze con le prostitute, per lui hai ammazzato il vitello grasso". Gli rispose il padre: "Figlio, tu sei sempre con me e tutto ciò che è mio è tuo; ma bisognava far festa e rallegrarsi, perché questo tuo fratello era morto ed è tornato in vita, era perduto ed è stato ritrovato"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 13,1-9', 'Luca', 'In quel tempo si presentarono alcuni a riferire a Gesù il fatto di quei Galilei, il cui sangue Pilato aveva fatto scorrere insieme a quello dei loro sacrifici. Prendendo la parola, Gesù disse loro: «Credete che quei Galilei fossero più peccatori di tutti i Galilei, per aver subito tale sorte? No, io vi dico, ma se non vi convertite, perirete tutti allo stesso modo. O quelle diciotto persone, sulle quali crollò la torre di Sìloe e le uccise, credete che fossero più colpevoli di tutti gli abitanti di Gerusalemme? No, io vi dico, ma se non vi convertite, perirete tutti allo stesso modo». Diceva anche questa parabola: «Un tale aveva piantato un albero di fichi nella sua vigna e venne a cercarvi frutti, ma non ne trovò. Allora disse al vignaiolo: "Ecco, sono tre anni che vengo a cercare frutti su quest''albero, ma non ne trovo. Tàglialo dunque! Perché deve sfruttare il terreno?". Ma quello gli rispose: "Padrone, lascialo ancora quest''anno, finché gli avrò zappato attorno e avrò messo il concime. Vedremo se porterà frutti per l''avvenire; se no, lo taglierai"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,26-38', 'Luca', 'In quel tempo, l''angelo Gabriele fu mandato da Dio in una città della Galilea, chiamata Nàzaret, a una vergine, promessa sposa di un uomo della casa di Davide, di nome Giuseppe. La vergine si chiamava Maria. Entrando da lei, disse: «Rallégrati, piena di grazia: il Signore è con te». A queste parole ella fu molto turbata e si domandava che senso avesse un saluto come questo. L''angelo le disse: «Non temere, Maria, perché hai trovato grazia presso Dio. Ed ecco, concepirai un figlio, lo darai alla luce e lo chiamerai Gesù. Sarà grande e verrà chiamato Figlio dell''Altissimo; il Signore Dio gli darà il trono di Davide suo padre e regnerà per sempre sulla casa di Giacobbe e il suo regno non avrà fine». Allora Maria disse all''angelo: «Come avverrà questo, poiché non conosco uomo?». Le rispose l''angelo: «Lo Spirito Santo scenderà su di te e la potenza dell''Altissimo ti coprirà con la sua ombra. Perciò colui che nascerà sarà santo e sarà chiamato Figlio di Dio. Ed ecco, Elisabetta, tua parente, nella sua vecchiaia ha concepito anch''essa un figlio e questo è il sesto mese per lei, che era detta sterile: nulla è impossibile a Dio». Allora Maria disse: «Ecco la serva del Signore: avvenga per me secondo la tua parola». E l''angelo si allontanò da lei');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 18,21-35', 'Matteo', 'Pietro si avvicinò a Gesù e gli disse: «Signore, se il mio fratello commette colpe contro di me, quante volte dovrò perdonargli? Fino a sette volte?». E Gesù gli rispose: «Non ti dico fino a sette volte, ma fino a settanta volte sette. Per questo, il regno dei cieli è simile a un re che volle regolare i conti con i suoi servi. Aveva cominciato a regolare i conti, quando gli fu presentato un tale che gli doveva diecimila talenti. Poiché costui non era in grado di restituire, il padrone ordinò che fosse venduto lui con la moglie, i figli e quanto possedeva, e così saldasse il debito. Allora il servo, prostrato a terra, lo supplicava dicendo: "Abbi pazienza con me e ti restituirò ogni cosa". Il padrone ebbe compassione di quel servo, lo lasciò andare e gli condonò il debito. Appena uscito, quel servo trovò uno dei suoi compagni, che gli doveva cento denari. Lo prese per il collo e lo soffocava, dicendo: "Restituisci quello che devi!". Il suo compagno, prostrato a terra, lo pregava dicendo: "Abbi pazienza con me e ti restituirò". Ma egli non volle, andò e lo fece gettare in prigione, fino a che non avesse pagato il debito. Visto quello che accadeva, i suoi compagni furono molto dispiaciuti e andarono a riferire al loro padrone tutto l''accaduto. Allora il padrone fece chiamare quell''uomo e gli disse: "Servo malvagio, io ti ho condonato tutto quel debito perché tu mi hai pregato. Non dovevi anche tu aver pietà del tuo compagno, così come io ho avuto pietà di te?". Sdegnato, il padrone lo diede in mano agli aguzzini, finché non avesse restituito tutto il dovuto. Così anche il Padre mio celeste farà con voi se non perdonerete di cuore, ciascuno al proprio fratello»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,17-19', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Non crediate che io sia venuto ad abolire la Legge o i Profeti; non sono venuto ad abolire, ma a dare pieno compimento. In verità io vi dico: finché non siano passati il cielo e la terra, non passerà un solo iota o un solo trattino della Legge, senza che tutto sia avvenuto. Chi dunque trasgredirà uno solo di questi minimi precetti e insegnerà agli altri a fare altrettanto, sarà considerato minimo nel regno dei cieli. Chi invece li osserverà e li insegnerà, sarà considerato grande nel regno dei cieli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 11,14-23', 'Luca', 'Gesù stava scacciando un demonio che era muto. Uscito il demonio, il muto cominciò a parlare e le folle furono prese da stupore. Ma alcuni dissero: «È per mezzo di Beelzebùl, capo dei demòni, che egli scaccia i demòni». Altri poi, per metterlo alla prova, gli domandavano un segno dal cielo. Egli, conoscendo le loro intenzioni, disse: «Ogni regno diviso in se stesso va in rovina e una casa cade sull''altra. Ora, se anche satana è diviso in se stesso, come potrà stare in piedi il suo regno? Voi dite che io scaccio i demòni per mezzo di Beelzebùl. Ma se io scaccio i demòni per mezzo di Beelzebùl, i vostri figli per mezzo di chi li scacciano? Per questo saranno loro i vostri giudici. Se invece io scaccio i demòni con il dito di Dio, allora è giunto a voi il regno di Dio. Quando un uomo forte, bene armato, fa la guardia al suo palazzo, ciò che possiede è al sicuro. Ma se arriva uno più forte di lui e lo vince, gli strappa via le armi nelle quali confidava e ne spartisce il bottino. Chi non è con me è contro di me, e chi non raccoglie con me, disperde»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 12,28-34', 'Marco', 'In quel tempo, si avvicinò a Gesù uno degli scribi e gli domandò: «Qual è il primo di tutti i comandamenti?». Gesù rispose: «Il primo è: "Ascolta, Israele! Il Signore nostro Dio è l''unico Signore; amerai il Signore tuo Dio con tutto il tuo cuore e con tutta la tua anima, con tutta la tua mente e con tutta la tua forza". Il secondo è questo: "Amerai il tuo prossimo come te stesso". Non c''è altro comandamento più grande di questi». Lo scriba gli disse: «Hai detto bene, Maestro, e secondo verità, che Egli è unico e non vi è altri all''infuori di lui; amarlo con tutto il cuore, con tutta l''intelligenza e con tutta la forza e amare il prossimo come se stesso vale più di tutti gli olocàusti e i sacrifici». Vedendo che egli aveva risposto saggiamente, Gesù gli disse: «Non sei lontano dal regno di Dio». E nessuno aveva più il coraggio di interrogarlo');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 18,9-14', 'Luca', 'In quel tempo, Gesù disse ancora questa parabola per alcuni che avevano l''intima presunzione di essere giusti e disprezzavano gli altri: «Due uomini salirono al tempio a pregare: uno era fariseo e l''altro pubblicano. Il fariseo, stando in piedi, pregava così tra sé: "O Dio, ti ringrazio perché non sono come gli altri uomini, ladri, ingiusti, adùlteri, e neppure come questo pubblicano. Digiuno due volte alla settimana e pago le decime di tutto quello che possiedo". Il pubblicano invece, fermatosi a distanza, non osava nemmeno alzare gli occhi al cielo, ma si batteva il petto dicendo: "O Dio, abbi pietà di me peccatore". Io vi dico: questi, a differenza dell''altro, tornò a casa sua giustificato, perché chiunque si esalta sarà umiliato, chi invece si umilia sarà esaltato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 4,43-54', 'Giovanni', '[In quel tempo, Gesù] partì [dalla Samarìa] per la Galilea. Gesù stesso infatti aveva dichiarato che un profeta non riceve onore nella propria patria. Quando dunque giunse in Galilea, i Galilei lo accolsero, perché avevano visto tutto quello che aveva fatto a Gerusalemme, durante la festa; anch''essi infatti erano andati alla festa. Andò dunque di nuovo a Cana di Galilea, dove aveva cambiato l''acqua in vino. Vi era un funzionario del re, che aveva un figlio malato a Cafàrnao. Costui, udito che Gesù era venuto dalla Giudea in Galilea, si recò da lui e gli chiedeva di scendere a guarire suo figlio, perché stava per morire. Gesù gli disse: «Se non vedete segni e prodigi, voi non credete». Il funzionario del re gli disse: «Signore, scendi prima che il mio bambino muoia». Gesù gli rispose: «Va'', tuo figlio vive». Quell''uomo credette alla parola che Gesù gli aveva detto e si mise in cammino. Proprio mentre scendeva, gli vennero incontro i suoi servi a dirgli: «Tuo figlio vive!». Volle sapere da loro a che ora avesse cominciato a star meglio. Gli dissero: «Ieri, un''ora dopo mezzogiorno, la febbre lo ha lasciato». Il padre riconobbe che proprio a quell''ora Gesù gli aveva detto: «Tuo figlio vive», e credette lui con tutta la sua famiglia. Questo fu il secondo segno, che Gesù fece quando tornò dalla Giudea in Galilea');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 5,1-16', 'Giovanni', 'Ricorreva una festa dei Giudei e Gesù salì a Gerusalemme. A Gerusalemme, presso la porta delle Pecore, vi è una piscina, chiamata in ebraico Betzatà, con cinque portici, sotto i quali giaceva un grande numero di infermi, ciechi, zoppi e paralitici. Si trovava lì un uomo che da trentotto anni era malato. Gesù, vedendolo giacere e sapendo che da molto tempo era così, gli disse: «Vuoi guarire?». Gli rispose il malato: «Signore, non ho nessuno che mi immerga nella piscina quando l''acqua si agita. Mentre infatti sto per andarvi, un altro scende prima di me». Gesù gli disse: «Àlzati, prendi la tua barella e cammina». E all''istante quell''uomo guarì: prese la sua barella e cominciò a camminare. Quel giorno però era un sabato. Dissero dunque i Giudei all''uomo che era stato guarito: «È sabato e non ti è lecito portare la tua barella». Ma egli rispose loro: «Colui che mi ha guarito mi ha detto: "Prendi la tua barella e cammina"». Gli domandarono allora: «Chi è l''uomo che ti ha detto: "Prendi e cammina"?». Ma colui che era stato guarito non sapeva chi fosse; Gesù infatti si era allontanato perché vi era folla in quel luogo. Poco dopo Gesù lo trovò nel tempio e gli disse: «Ecco: sei guarito! Non peccare più, perché non ti accada qualcosa di peggio». Quell''uomo se ne andò e riferì ai Giudei che era stato Gesù a guarirlo. Per questo i Giudei perseguitavano Gesù, perché faceva tali cose di sabato');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 5,17-30', 'Giovanni', 'Gesù disse ai Giudei: «Il Padre mio agisce anche ora e anch''io agisco». Per questo i Giudei cercavano ancor più di ucciderlo, perché non soltanto violava il sabato, ma chiamava Dio suo Padre, facendosi uguale a Dio. Gesù riprese a parlare e disse loro: «In verità, in verità io vi dico: il Figlio da se stesso non può fare nulla, se non ciò che vede fare dal Padre; quello che egli fa, anche il Figlio lo fa allo stesso modo. Il Padre infatti ama il Figlio, gli manifesta tutto quello che fa e gli manifesterà opere ancora più grandi di queste, perché voi ne siate meravigliati. Come il Padre risuscita i morti e dà la vita, così anche il Figlio dà la vita a chi egli vuole. Il Padre infatti non giudica nessuno, ma ha dato ogni giudizio al Figlio, perché tutti onorino il Figlio come onorano il Padre. Chi non onora il Figlio, non onora il Padre che lo ha mandato. In verità, in verità io vi dico: chi ascolta la mia parola e crede a colui che mi ha mandato, ha la vita eterna e non va incontro al giudizio, ma è passato dalla morte alla vita. In verità, in verità io vi dico: viene l''ora - ed è questa - in cui i morti udranno la voce del Figlio di Dio e quelli che l''avranno ascoltata, vivranno. Come infatti il Padre ha la vita in se stesso, così ha concesso anche al Figlio di avere la vita in se stesso, e gli ha dato il potere di giudicare, perché è Figlio dell''uomo. Non meravigliatevi di questo: viene l''ora in cui tutti coloro che sono nei sepolcri udranno la sua voce e usciranno, quanti fecero il bene per una risurrezione di vita e quanti fecero il male per una risurrezione di condanna. Da me, io non posso fare nulla. Giudico secondo quello che ascolto e il mio giudizio è giusto, perché non cerco la mia volontà, ma la volontà di colui che mi ha mandato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 5,31-47', 'Giovanni', '[In quel tempo, Gesù disse ai Giudei]: «Se fossi io a testimoniare di me stesso, la mia testimonianza non sarebbe vera. C''è un altro che dà testimonianza di me, e so che la testimonianza che egli dà di me è vera. Voi avete inviato dei messaggeri a Giovanni ed egli ha dato testimonianza alla verità. Io non ricevo testimonianza da un uomo; ma vi dico queste cose perché siate salvati. Egli era la lampada che arde e risplende, e voi solo per un momento avete voluto rallegrarvi alla sua luce. Io però ho una testimonianza superiore a quella di Giovanni: le opere che il Padre mi ha dato da compiere, quelle stesse opere che io sto facendo, testimoniano di me che il Padre mi ha mandato. E anche il Padre, che mi ha mandato, ha dato testimonianza di me. Ma voi non avete mai ascoltato la sua voce né avete mai visto il suo volto, e la sua parola non rimane in voi; infatti non credete a colui che egli ha mandato. Voi scrutate le Scritture, pensando di avere in esse la vita eterna: sono proprio esse che danno testimonianza di me. Ma voi non volete venire a me per avere vita. Io non ricevo gloria dagli uomini. Ma vi conosco: non avete in voi l''amore di Dio. Io sono venuto nel nome del Padre mio e voi non mi accogliete; se un altro venisse nel proprio nome, lo accogliereste. E come potete credere, voi che ricevete gloria gli uni dagli altri, e non cercate la gloria che viene dall''unico Dio? Non crediate che sarò io ad accusarvi davanti al Padre; vi è già chi vi accusa: Mosè, nel quale riponete la vostra speranza. Se infatti credeste a Mosè, credereste anche a me; perché egli ha scritto di me. Ma se non credete ai suoi scritti, come potrete credere alle mie parole?»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 7,1-2.10.25-30', 'Giovanni', 'Gesù se ne andava per la Galilea; infatti non voleva più percorrere la Giudea, perché i Giudei cercavano di ucciderlo. Si avvicinava intanto la festa dei Giudei, quella delle Capanne. Quando i suoi fratelli salirono per la festa, vi salì anche lui: non apertamente, ma quasi di nascosto. Alcuni abitanti di Gerusalemme dicevano: «Non è costui quello che cercano di uccidere? Ecco, egli parla liberamente, eppure non gli dicono nulla. I capi hanno forse riconosciuto davvero che egli è il Cristo? Ma costui sappiamo di dov''è; il Cristo invece, quando verrà, nessuno saprà di dove sia». Gesù allora, mentre insegnava nel tempio, esclamò: «Certo, voi mi conoscete e sapete di dove sono. Eppure non sono venuto da me stesso, ma chi mi ha mandato è veritiero, e voi non lo conoscete. Io lo conosco, perché vengo da lui ed egli mi ha mandato». Cercavano allora di arrestarlo, ma nessuno riuscì a mettere le mani su di lui, perché non era ancora giunta la sua ora');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 7,40-53', 'Giovanni', 'All’udire le parole di Gesù, alcuni fra la gente dicevano: «Costui è davvero il profeta!». Altri dicevano: «Costui è il Cristo!». Altri invece dicevano: «Il Cristo viene forse dalla Galilea? Non dice la Scrittura: "Dalla stirpe di Davide e da Betlemme, il villaggio di Davide, verrà il Cristo"?». E tra la gente nacque un dissenso riguardo a lui. Alcuni di loro volevano arrestarlo, ma nessuno mise le mani su di lui. Le guardie tornarono quindi dai capi dei sacerdoti e dai farisei e questi dissero loro: «Perché non lo avete condotto qui?». Risposero le guardie: «Mai un uomo ha parlato così!». Ma i farisei replicarono loro: «Vi siete lasciati ingannare anche voi? Ha forse creduto in lui qualcuno dei capi o dei farisei? Ma questa gente, che non conosce la Legge, è maledetta!». Allora Nicodèmo, che era andato precedentemente da Gesù, ed era uno di loro, disse: «La nostra Legge giudica forse un uomo prima di averlo ascoltato e di sapere ciò che fa?». Gli risposero: «Sei forse anche tu della Galilea? Studia, e vedrai che dalla Galilea non sorge profeta!». E ciascuno tornò a casa sua');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 8,1-11', 'Giovanni', 'Gesù si avviò verso il monte degli Ulivi. Ma al mattino si recò di nuovo nel tempio e tutto il popolo andava da lui. Ed egli sedette e si mise a insegnare loro. Allora gli scribi e i farisei gli condussero una donna sorpresa in adulterio, la posero in mezzo e gli dissero: «Maestro, questa donna è stata sorpresa in flagrante adulterio. Ora Mosè, nella Legge, ci ha comandato di lapidare donne come questa. Tu che ne dici?». Dicevano questo per metterlo alla prova e per avere motivo di accusarlo. Ma Gesù si chinò e si mise a scrivere col dito per terra. Tuttavia, poiché insistevano nell''interrogarlo, si alzò e disse loro: «Chi di voi è senza peccato, getti per primo la pietra contro di lei». E, chinatosi di nuovo, scriveva per terra. Quelli, udito ciò, se ne andarono uno per uno, cominciando dai più anziani. Lo lasciarono solo, e la donna era là in mezzo. Allora Gesù si alzò e le disse: «Donna, dove sono? Nessuno ti ha condannata?». Ed ella rispose: «Nessuno, Signore». E Gesù disse: «Neanch''io ti condanno; va'' e d''ora in poi non peccare più»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 8,12-20', 'Giovanni', 'Di nuovo Gesù parlò loro e disse: «Io sono la luce del mondo; chi segue me, non camminerà nelle tenebre, ma avrà la luce della vita». Gli dissero allora i farisei: «Tu dai testimonianza di te stesso; la tua testimonianza non è vera». Gesù rispose loro: «Anche se io do testimonianza di me stesso, la mia testimonianza è vera, perché so da dove sono venuto e dove vado. Voi invece non sapete da dove vengo o dove vado. Voi giudicate secondo la carne; io non giudico nessuno. E anche se io giudico, il mio giudizio è vero, perché non sono solo, ma io e il Padre che mi ha mandato. E nella vostra Legge sta scritto che la testimonianza di due persone è vera. Sono io che do testimonianza di me stesso, e anche il Padre, che mi ha mandato, dà testimonianza di me». Gli dissero allora: «Dov''è tuo padre?». Rispose Gesù: «Voi non conoscete né me né il Padre mio; se conosceste me, conoscereste anche il Padre mio». Gesù pronunciò queste parole nel luogo del tesoro, mentre insegnava nel tempio. E nessuno lo arrestò, perché non era ancora venuta la sua ora');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 8,21-30', 'Giovanni', 'Gesù disse ai farisei: «Io vado e voi mi cercherete, ma morirete nel vostro peccato. Dove vado io, voi non potete venire». Dicevano allora i Giudei: «Vuole forse uccidersi, dal momento che dice: "Dove vado io, voi non potete venire"?». E diceva loro: «Voi siete di quaggiù, io sono di lassù; voi siete di questo mondo, io non sono di questo mondo. Vi ho detto che morirete nei vostri peccati; se infatti non credete che Io Sono, morirete nei vostri peccati». Gli dissero allora: «Tu, chi sei?». Gesù disse loro: «Proprio ciò che io vi dico. Molte cose ho da dire di voi, e da giudicare; ma colui che mi ha mandato è veritiero, e le cose che ho udito da lui, le dico al mondo». Non capirono che egli parlava loro del Padre. Disse allora Gesù: «Quando avrete innalzato il Figlio dell''uomo, allora conoscerete che Io Sono e che non faccio nulla da me stesso, ma parlo come il Padre mi ha insegnato. Colui che mi ha mandato è con me: non mi ha lasciato solo, perché faccio sempre le cose che gli sono gradite». A queste sue parole, molti credettero in lui');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 8,31-42', 'Giovanni', 'Gesù disse a quei Giudei che gli avevano creduto: «Se rimanete nella mia parola, siete davvero miei discepoli; conoscerete la verità e la verità vi farà liberi». Gli risposero: «Noi siamo discendenti di Abramo e non siamo mai stati schiavi di nessuno. Come puoi dire: "Diventerete liberi"?». Gesù rispose loro: «In verità, in verità io vi dico: chiunque commette il peccato è schiavo del peccato. Ora, lo schiavo non resta per sempre nella casa; il figlio vi resta per sempre. Se dunque il Figlio vi farà liberi, sarete liberi davvero. So che siete discendenti di Abramo. Ma intanto cercate di uccidermi perché la mia parola non trova accoglienza in voi. Io dico quello che ho visto presso il Padre; anche voi dunque fate quello che avete ascoltato dal padre vostro». Gli risposero: «Il padre 7nostro è Abramo». Disse loro Gesù: «Se foste figli di Abramo, fareste le opere di Abramo. Ora invece voi cercate di uccidere me, un uomo che vi ha detto la verità udita da Dio. Questo, Abramo non l''ha fatto. Voi fate le opere del padre vostro». Gli risposero allora: «Noi non siamo nati da prostituzione; abbiamo un solo padre: Dio!». Disse loro Gesù: «Se Dio fosse vostro padre, mi amereste, perché da Dio sono uscito e vengo; non sono venuto da me stesso, ma lui mi ha mandato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 8,51-59', 'Giovanni', '[In quel tempo, Gesù disse ai Giudei]: «In verità, in verità io vi dico: "Se uno osserva la mia parola, non vedrà la morte in eterno"». Gli dissero allora i Giudei: «Ora sappiamo che sei indemoniato. Abramo è morto, come anche i profeti, e tu dici: "Se uno osserva la mia parola, non sperimenterà la morte in eterno". Sei tu più grande del nostro padre Abramo, che è morto? Anche i profeti sono morti. Chi credi di essere?». Rispose Gesù: «Se io glorificassi me stesso, la mia gloria sarebbe nulla. Chi mi glorifica è il Padre mio, del quale voi dite: "È nostro Dio!", e non lo conoscete. Io invece lo conosco. Se dicessi che non lo conosco, sarei come voi: un mentitore. Ma io lo conosco e osservo la sua parola. Abramo, vostro padre, esultò nella speranza di vedere il mio giorno; lo vide e fu pieno di gioia». Allora i Giudei gli dissero: «Non hai ancora cinquant''anni e hai visto Abramo?». Rispose loro Gesù: «In verità, in verità io vi dico: prima che Abramo fosse, Io Sono». Allora raccolsero delle pietre per gettarle contro di lui; ma Gesù si nascose e uscì dal tempio');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 10,31-42', 'Giovanni', 'Di nuovo i Giudei raccolsero delle pietre per lapidare Gesù. Gesù disse loro: «Vi ho fatto vedere molte opere buone da parte del Padre: per quale di esse volete lapidarmi?». Gli risposero i Giudei: «Non ti lapidiamo per un''opera buona, ma per una bestemmia: perché tu, che sei uomo, ti fai Dio». Disse loro Gesù: «Non è forse scritto nella vostra Legge: "Io ho detto: voi siete dèi"? Ora, se essa ha chiamato dèi coloro ai quali fu rivolta la parola di Dio - e la Scrittura non può essere annullata –, a colui che il Padre ha consacrato e mandato nel mondo voi dite: "Tu bestemmi", perché ho detto: "Sono Figlio di Dio"? Se non compio le opere del Padre mio, non credetemi; ma se le compio, anche se non credete a me, credete alle opere, perché sappiate e conosciate che il Padre è in me, e io nel Padre». Allora cercarono nuovamente di catturarlo, ma egli sfuggì dalle loro mani. Ritornò quindi nuovamente al di là del Giordano, nel luogo dove prima Giovanni battezzava, e qui rimase. Molti andarono da lui e dicevano: «Giovanni non ha compiuto nessun segno, ma tutto quello che Giovanni ha detto di costui era vero». E in quel luogo molti credettero in lui');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 11,45-56', 'Giovanni', 'Molti dei Giudei che erano venuti da Maria, alla vista di ciò che Gesù aveva compiuto, [ossia la risurrezione di Làzzaro,] credettero in lui. Ma alcuni di loro andarono dai farisei e riferirono loro quello che Gesù aveva fatto. Allora i capi dei sacerdoti e i farisei riunirono il sinèdrio e dissero: «Che cosa facciamo? Quest''uomo compie molti segni. Se lo lasciamo continuare così, tutti crederanno in lui, verranno i Romani e distruggeranno il nostro tempio e la nostra nazione». Ma uno di loro, Caifa, che era sommo sacerdote quell''anno, disse loro: «Voi non capite nulla! Non vi rendete conto che è conveniente per voi che un solo uomo muoia per il popolo, e non vada in rovina la nazione intera!». Questo però non lo disse da se stesso, ma, essendo sommo sacerdote quell''anno, profetizzò che Gesù doveva morire per la nazione; e non soltanto per la nazione, ma anche per riunire insieme i figli di Dio che erano dispersi. Da quel giorno dunque decisero di ucciderlo. Gesù dunque non andava più in pubblico tra i Giudei, ma da lì si ritirò nella regione vicina al deserto, in una città chiamata Èfraim, dove rimase con i discepoli. Era vicina la Pasqua dei Giudei e molti dalla regione salirono a Gerusalemme prima della Pasqua per purificarsi. Essi cercavano Gesù e, stando nel tempio, dicevano tra loro: «Che ve ne pare? Non verrà alla festa?»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 19,28-40', 'Luca', 'In quel tempo, Gesù camminava davanti a tutti salendo verso Gerusalemme. Quando fu vicino a Bètfage e a Betània, presso il monte detto degli Ulivi, inviò due discepoli dicendo: «Andate nel villaggio di fronte; entrando, troverete un puledro legato, sul quale non è mai salito nessuno. Slegatelo e conducetelo qui. E se qualcuno vi domanda: “Perché lo slegate?”, risponderete così: “Il Signore ne ha bisogno”».  Gli inviati andarono e trovarono come aveva loro detto. Mentre slegavano il puledro, i proprietari dissero loro: «Perché slegate il puledro?». Essi risposero: «Il Signore ne ha bisogno». Lo condussero allora da Gesù; e gettati i loro mantelli sul puledro, vi fecero salire Gesù. Mentre egli avanzava, stendevano i loro mantelli sulla strada. Era ormai vicino alla discesa del monte degli Ulivi, quando tutta la folla dei discepoli, pieni di gioia, cominciò a lodare Dio a gran voce per tutti i prodigi che avevano veduto, dicendo: «Benedetto colui che viene, il re, nel nome del Signore. Pace in cielo e gloria nel più alto dei cieli!». Alcuni farisei tra la folla gli dissero: «Maestro, rimprovera i tuoi discepoli». Ma egli rispose: «Io vi dico che, se questi taceranno, grideranno le pietre»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 12,1-11', 'Giovanni', 'Sei giorni prima della Pasqua, Gesù andò a Betània, dove si trovava Làzzaro, che egli aveva risuscitato dai morti. E qui fecero per lui una cena: Marta serviva e Làzzaro era uno dei commensali. Maria allora prese trecento grammi di profumo di puro nardo, assai prezioso, ne cosparse i piedi di Gesù, poi li asciugò con i suoi capelli, e tutta la casa si riempì dell''aroma di quel profumo. Allora Giuda Iscariòta, uno dei suoi discepoli, che stava per tradirlo, disse: «Perché non si è venduto questo profumo per trecento denari e non si sono dati ai poveri?». Disse questo non perché gli importasse dei poveri, ma perché era un ladro e, siccome teneva la cassa, prendeva quello che vi mettevano dentro. Gesù allora disse: «Lasciala fare, perché ella lo conservi per il giorno della mia sepoltura. I poveri infatti li avete sempre con voi, ma non sempre avete me». Intanto una grande folla di Giudei venne a sapere che egli si trovava là e accorse, non solo per Gesù, ma anche per vedere Làzzaro che egli aveva risuscitato dai morti. I capi dei sacerdoti allora decisero di uccidere anche Làzzaro, perché molti Giudei se ne andavano a causa di lui e credevano in Gesù');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 13,21-33.36-38', 'Giovanni', 'In quel tempo, [mentre era a mensa con i suoi discepoli,] Gesù fu profondamente turbato e dichiarò: «In verità, in verità io vi dico: uno di voi mi tradirà». I discepoli si guardavano l''un l''altro, non sapendo bene di chi parlasse. Ora uno dei discepoli, quello che Gesù amava, si trovava a tavola al fianco di Gesù. Simon Pietro gli fece cenno di informarsi chi fosse quello di cui parlava. Ed egli, chinandosi sul petto di Gesù, gli disse: «Signore, chi è?». Rispose Gesù: «È colui per il quale intingerò il boccone e glielo darò». E, intinto il boccone, lo prese e lo diede a Giuda, figlio di Simone Iscariòta. Allora, dopo il boccone, Satana entrò in lui. Gli disse dunque Gesù: «Quello che vuoi fare, fallo presto». Nessuno dei commensali capì perché gli avesse detto questo; alcuni infatti pensavano che, poiché Giuda teneva la cassa, Gesù gli avesse detto: «Compra quello che ci occorre per la festa», oppure che dovesse dare qualche cosa ai poveri. Egli, preso il boccone, subito uscì. Ed era notte. Quando fu uscito, Gesù disse: «Ora il Figlio dell''uomo è stato glorificato, e Dio è stato glorificato in lui. Se Dio è stato glorificato in lui, anche Dio lo glorificherà da parte sua e lo glorificherà subito. Figlioli, ancora per poco sono con voi; voi mi cercherete ma, come ho detto ai Giudei, ora lo dico anche a voi: dove vado io, voi non potete venire».  Simon Pietro gli disse: «Signore, dove vai?». Gli rispose Gesù: «Dove io vado, tu per ora non puoi seguirmi; mi seguirai più tardi». Pietro disse: «Signore, perché non posso seguirti ora? Darò la mia vita per te!». Rispose Gesù: «Darai la tua vita per me? In verità, in verità io ti dico: non canterà il gallo, prima che tu non m''abbia rinnegato tre volte»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 26,14-25', 'Matteo', 'Uno dei Dodici, chiamato Giuda Iscariòta, andò dai capi dei sacerdoti e disse: «Quanto volete darmi perché io ve lo consegni?». E quelli gli fissarono trenta monete d''argento. Da quel momento cercava l''occasione propizia per consegnare Gesù. Il primo giorno degli Ázzimi, i discepoli si avvicinarono a Gesù e gli dissero: «Dove vuoi che prepariamo per te, perché tu possa mangiare la Pasqua?». Ed egli rispose: «Andate in città da un tale e ditegli: "Il Maestro dice: Il mio tempo è vicino; farò la Pasqua da te con i miei discepoli"». I discepoli fecero come aveva loro ordinato Gesù, e prepararono la Pasqua. Venuta la sera, si mise a tavola con i Dodici. Mentre mangiavano, disse: «In verità io vi dico: uno di voi mi tradirà». Ed essi, profondamente rattristati, cominciarono ciascuno a domandargli: «Sono forse io, Signore?». Ed egli rispose: «Colui che ha messo con me la mano nel piatto, è quello che mi tradirà. Il Figlio dell''uomo se ne va, come sta scritto di lui; ma guai a quell''uomo dal quale il Figlio dell''uomo viene tradito! Meglio per quell''uomo se non fosse mai nato!». Giuda, il traditore, disse: «Rabbì, sono forse io?». Gli rispose: «Tu l''hai detto»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 13,1-15', 'Giovanni', 'Prima della festa di Pasqua, Gesù, sapendo che era venuta la sua ora di passare da questo mondo al Padre, avendo amato i suoi che erano nel mondo, li amò sino alla fine. Durante la cena, quando il diavolo aveva già messo in cuore a Giuda, figlio di Simone Iscariota, di tradirlo, Gesù, sapendo che il Padre gli aveva dato tutto nelle mani e che era venuto da Dio e a Dio ritornava, si alzò da tavola, depose le vesti, prese un asciugamano e se lo cinse attorno alla vita. Poi versò dell’acqua nel catino e cominciò a lavare i piedi dei discepoli e ad asciugarli con l’asciugamano di cui si era cinto. Venne dunque da Simon Pietro e questi gli disse: «Signore, tu lavi i piedi a me?». Rispose Gesù: «Quello che io faccio, tu ora non lo capisci; lo capirai dopo». Gli disse Pietro: «Tu non mi laverai i piedi in eterno!». Gli rispose Gesù: «Se non ti laverò, non avrai parte con me». Gli disse Simon Pietro: «Signore, non solo i miei piedi, ma anche le mani e il capo!». Soggiunse Gesù: «Chi ha fatto il bagno, non ha bisogno di lavarsi se non i piedi ed è tutto puro; e voi siete puri, ma non tutti». Sapeva infatti chi lo tradiva; per questo disse: «Non tutti siete puri». Quando ebbe lavato loro i piedi, riprese le sue vesti, sedette di nuovo e disse loro: «Capite quello che ho fatto per voi? Voi mi chiamate il Maestro e il Signore, e dite bene, perché lo sono. Se dunque io, il Signore e il Maestro, ho lavato i piedi a voi, anche voi dovete lavare i piedi gli uni agli altri. Vi ho dato un esempio, infatti, perché anche voi facciate come io ho fatto a voi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 18,1-19,42', 'Giovanni', 'Passione di nostro Signore Gesù Cristo secondo Giovanni
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv ?', 'Giovanni', 'NULL');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 24,1-12', 'Luca', 'Il primo giorno della settimana, al mattino presto esse si recarono al sepolcro, portando con sé gli aromi che avevano preparato. Trovarono che la pietra era stata rimossa dal sepolcro e, entrate, non trovarono il corpo del Signore Gesù. Mentre si domandavano che senso avesse tutto questo, ecco due uomini presentarsi a loro in abito sfolgorante. Le donne, impaurite, tenevano il volto chinato a terra, ma quelli dissero loro: «Perché cercate tra i morti colui che è vivo? Non è qui, è risorto. Ricordatevi come vi parlò quando era ancora in Galilea e diceva: "Bisogna che il Figlio dell''uomo sia consegnato in mano ai peccatori, sia crocifisso e risorga il terzo giorno"». Ed esse si ricordarono delle sue parole e, tornate dal sepolcro, annunciarono tutto questo agli Undici e a tutti gli altri. Erano Maria Maddalena, Giovanna e Maria madre di Giacomo. Anche le altre, che erano con loro, raccontavano queste cose agli apostoli. Quelle parole parvero a loro come un vaneggiamento e non credevano ad esse. Pietro tuttavia si alzò, corse al sepolcro e, chinatosi, vide soltanto i teli. E tornò indietro, pieno di stupore per l''accaduto');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 28,8-15', 'Matteo', 'Abbandonato in fretta il sepolcro con timore e gioia grande, le donne corsero a dare l''annuncio ai suoi discepoli. Ed ecco, Gesù venne loro incontro e disse: «Salute a voi!». Ed esse si avvicinarono, gli abbracciarono i piedi e lo adorarono. Allora Gesù disse loro: «Non temete; andate ad annunciare ai miei fratelli che vadano in Galilea: là mi vedranno». Mentre esse erano in cammino, ecco, alcune guardie giunsero in città e annunciarono ai capi dei sacerdoti tutto quanto era accaduto. Questi allora si riunirono con gli anziani e, dopo essersi consultati, diedero una buona somma di denaro ai soldati, dicendo: «Dite così: "I suoi discepoli sono venuti di notte e l''hanno rubato, mentre noi dormivamo". E se mai la cosa venisse all''orecchio del governatore, noi lo persuaderemo e vi libereremo da ogni preoccupazione». Quelli presero il denaro e fecero secondo le istruzioni ricevute. Così questo racconto si è divulgato fra i Giudei fino a oggi');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 20,11-18', 'Giovanni', 'Maria stava all''esterno, vicino al sepolcro, e piangeva. Mentre piangeva, si chinò verso il sepolcro e vide due angeli in bianche vesti, seduti l''uno dalla parte del capo e l''altro dei piedi, dove era stato posto il corpo di Gesù. Ed essi le dissero: «Donna, perché piangi?». Rispose loro: «Hanno portato via il mio Signore e non so dove l''hanno posto». Detto questo, si voltò indietro e vide Gesù, in piedi; ma non sapeva che fosse Gesù. Le disse Gesù: «Donna, perché piangi? Chi cerchi?». Ella, pensando che fosse il custode del giardino, gli disse: «Signore, se l''hai portato via tu, dimmi dove l''hai posto e io andrò a prenderlo». Gesù le disse: «Maria!». Ella si voltò e gli disse in ebraico: «Rabbunì!» - che significa: «Maestro!». Gesù le disse: «Non mi trattenere, perché non sono ancora salito al Padre; ma va'' dai miei fratelli e di'' loro: "Salgo al Padre mio e Padre vostro, Dio mio e Dio vostro"». Maria di Màgdala andò ad annunciare ai discepoli: «Ho visto il Signore!» e ciò che le aveva detto');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 24,13-35', 'Luca', 'Ed ecco, in quello stesso giorno, [il primo della settimana], due [dei discepoli] erano in cammino per un villaggio di nome Èmmaus, distante circa undici chilometri da Gerusalemme, e conversavano tra loro di tutto quello che era accaduto. Mentre conversavano e discutevano insieme, Gesù in persona si avvicinò e camminava con loro. Ma i loro occhi erano impediti a riconoscerlo. Ed egli disse loro: «Che cosa sono questi discorsi che state facendo tra voi lungo il cammino?». Si fermarono, col volto triste; uno di loro, di nome Clèopa, gli rispose: «Solo tu sei forestiero a Gerusalemme! Non sai ciò che vi è accaduto in questi giorni?». Domandò loro: «Che cosa?». Gli risposero: «Ciò che riguarda Gesù, il Nazareno, che fu profeta potente in opere e in parole, davanti a Dio e a tutto il popolo; come i capi dei sacerdoti e le nostre autorità lo hanno consegnato per farlo condannare a morte e lo hanno crocifisso. Noi speravamo che egli fosse colui che avrebbe liberato Israele; con tutto ciò, sono passati tre giorni da quando queste cose sono accadute. Ma alcune donne, delle nostre, ci hanno sconvolti; si sono recate al mattino alla tomba e, non avendo trovato il suo corpo, sono venute a dirci di aver avuto anche una visione di angeli, i quali affermano che egli è vivo. Alcuni dei nostri sono andati alla tomba e hanno trovato come avevano detto le donne, ma lui non l''hanno visto». Disse loro: «Stolti e lenti di cuore a credere in tutto ciò che hanno detto i profeti! Non bisognava che il Cristo patisse queste sofferenze per entrare nella sua gloria?». E, cominciando da Mosè e da tutti i profeti, spiegò loro in tutte le Scritture ciò che si riferiva a lui. Quando furono vicini al villaggio dove erano diretti, egli fece come se dovesse andare più lontano. Ma essi insistettero: «Resta con noi, perché si fa sera e il giorno è ormai al tramonto». Egli entrò per rimanere con loro. Quando fu a tavola con loro, prese il pane, recitò la benedizione, lo spezzò e lo diede loro. Allora si aprirono loro gli occhi e lo riconobbero. Ma egli sparì dalla loro vista. Ed essi dissero l''un l''altro: «Non ardeva forse in noi il nostro cuore mentre egli conversava con noi lungo la via, quando ci spiegava le Scritture?». Partirono senza indugio e fecero ritorno a Gerusalemme, dove trovarono riuniti gli Undici e gli altri che erano con loro, i quali dicevano: «Davvero il Signore è risorto ed è apparso a Simone!». Ed essi narravano ciò che era accaduto lungo la via e come l''avevano riconosciuto nello spezzare il pane');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 24,35-48', 'Luca', 'In quel tempo, [i due discepoli che erano ritornati da Èmmaus] narravano ciò che era accaduto lungo la via e come l''avevano riconosciuto nello spezzare il pane. Mentre essi parlavano di queste cose, Gesù in persona stette in mezzo a loro e disse: «Pace a voi!». Sconvolti e pieni di paura, credevano di vedere un fantasma. Ma egli disse loro: «Perché siete turbati, e perché sorgono dubbi nel vostro cuore? Guardate le mie mani e i miei piedi: sono proprio io! Toccatemi e guardate; un fantasma non ha carne e ossa, come vedete che io ho». Dicendo questo, mostrò loro le mani e i piedi. Ma poiché per la gioia non credevano ancora ed erano pieni di stupore, disse: «Avete qui qualche cosa da mangiare?». Gli offrirono una porzione di pesce arrostito; egli lo prese e lo mangiò davanti a loro. Poi disse: «Sono queste le parole che io vi dissi quando ero ancora con voi: bisogna che si compiano tutte le cose scritte su di me nella legge di Mosè, nei Profeti e nei Salmi». Allora aprì loro la mente per comprendere le Scritture e disse loro: «Così sta scritto: il Cristo patirà e risorgerà dai morti il terzo giorno, e nel suo nome saranno predicati a tutti i popoli la conversione e il perdono dei peccati, cominciando da Gerusalemme. Di questo voi siete testimoni»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 21,1-14', 'Giovanni', 'In quel tempo, Gesù si manifestò di nuovo ai discepoli sul mare di Tiberìade. E si manifestò così: si trovavano insieme Simon Pietro, Tommaso detto Dìdimo, Natanaèle di Cana di Galilea, i figli di Zebedèo e altri due discepoli. Disse loro Simon Pietro: «Io vado a pescare». Gli dissero: «Veniamo anche noi con te». Allora uscirono e salirono sulla barca; ma quella notte non presero nulla. Quando già era l''alba, Gesù stette sulla riva, ma i discepoli non si erano accorti che era Gesù. Gesù disse loro: «Figlioli, non avete nulla da mangiare?». Gli risposero: «No». Allora egli disse loro: «Gettate la rete dalla parte destra della barca e troverete». La gettarono e non riuscivano più a tirarla su per la grande quantità di pesci. Allora quel discepolo che Gesù amava disse a Pietro: «È il Signore!». Simon Pietro, appena udì che era il Signore, si strinse la veste attorno ai fianchi, perché era svestito, e si gettò in mare. Gli altri discepoli invece vennero con la barca, trascinando la rete piena di pesci: non erano infatti lontani da terra se non un centinaio di metri. Appena scesi a terra, videro un fuoco di brace con del pesce sopra, e del pane. Disse loro Gesù: «Portate un po'' del pesce che avete preso ora». Allora Simon Pietro salì nella barca e trasse a terra la rete piena di centocinquantatré grossi pesci. E benché fossero tanti, la rete non si spezzò. Gesù disse loro: «Venite a mangiare». E nessuno dei discepoli osava domandargli: «Chi sei?», perché sapevano bene che era il Signore. Gesù si avvicinò, prese il pane e lo diede loro, e così pure il pesce. Era la terza volta che Gesù si manifestava ai discepoli, dopo essere risorto dai morti');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 16,9-15', 'Marco', 'Risorto al mattino, il primo giorno dopo il sabato, Gesù apparve prima a Maria di Màgdala, dalla quale aveva scacciato sette demòni. Questa andò ad annunciarlo a quanti erano stati con lui ed erano in lutto e in pianto. Ma essi, udito che era vivo e che era stato visto da lei, non credettero. Dopo questo, apparve sotto altro aspetto a due di loro, mentre erano in cammino verso la campagna. Anch''essi ritornarono ad annunciarlo agli altri; ma non credettero neppure a loro. Alla fine apparve anche agli Undici, mentre erano a tavola, e li rimproverò per la loro incredulità e durezza di cuore, perché non avevano creduto a quelli che lo avevano visto risorto. E disse loro: «Andate in tutto il mondo e proclamate il Vangelo a ogni creatura»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 20,19-31', 'Giovanni', 'La sera di quel giorno, il primo della settimana, mentre erano chiuse le porte del luogo dove si trovavano i discepoli per timore dei Giudei, venne Gesù, stette in mezzo e disse loro: «Pace a voi!». Detto questo, mostrò loro le mani e il fianco. E i discepoli gioirono al vedere il Signore. Gesù disse loro di nuovo: «Pace a voi! Come il Padre ha mandato me, anche io mando voi». Detto questo, soffiò e disse loro: «Ricevete lo Spirito Santo. A coloro a cui perdonerete i peccati, saranno perdonati; a coloro a cui non perdonerete, non saranno perdonati». Tommaso, uno dei Dodici, chiamato Dìdimo, non era con loro quando venne Gesù. Gli dicevano gli altri discepoli: «Abbiamo visto il Signore!». Ma egli disse loro: «Se non vedo nelle sue mani il segno dei chiodi e non metto il mio dito nel segno dei chiodi e non metto la mia mano nel suo fianco, io non credo». Otto giorni dopo i discepoli erano di nuovo in casa e c''era con loro anche Tommaso. Venne Gesù, a porte chiuse, stette in mezzo e disse: «Pace a voi!». Poi disse a Tommaso: «Metti qui il tuo dito e guarda le mie mani; tendi la tua mano e mettila nel mio fianco; e non essere incredulo, ma credente!». Gli rispose Tommaso: «Mio Signore e mio Dio!». Gesù gli disse: «Perché mi hai veduto, tu hai creduto; beati quelli che non hanno visto e hanno creduto!». Gesù, in presenza dei suoi discepoli, fece molti altri segni che non sono stati scritti in questo libro. Ma questi sono stati scritti perché crediate che Gesù è il Cristo, il Figlio di Dio, e perché, credendo, abbiate la vita nel suo nome');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 11,25-30', 'Matteo', 'In quel tempo Gesù disse: «Ti rendo lode, Padre, Signore del cielo e della terra, perché hai nascosto queste cose ai sapienti e ai dotti e le hai rivelate ai piccoli. Sì, o Padre, perché così hai deciso nella tua benevolenza. Tutto è stato dato a me dal Padre mio; nessuno conosce il Figlio se non il Padre, e nessuno conosce il Padre se non il Figlio e colui al quale il Figlio vorrà rivelarlo. Venite a me, voi tutti che siete stanchi e oppressi, e io vi darò ristoro. Prendete il mio giogo sopra di voi e imparate da me, che sono mite e umile di cuore, e troverete ristoro per la vostra vita. Il mio giogo infatti è dolce e il mio peso leggero»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 3,7-15', 'Giovanni', 'Gesù disse a Nicodèmo: «Non meravigliarti se ti ho detto: dovete nascere dall’alto. Il vento soffia dove vuole e ne senti la voce, ma non sai da dove viene né dove va: così è chiunque è nato dallo Spirito». Gli replicò Nicodèmo: «Come può accadere questo?». Gli rispose Gesù: «Tu sei maestro di Israele e non conosci queste cose? In verità, in verità io ti dico: noi parliamo di ciò che sappiamo e testimoniamo ciò che abbiamo veduto; ma voi non accogliete la nostra testimonianza. Se vi ho parlato di cose della terra e non credete, come crederete se vi parlerò di cose del cielo? Nessuno è mai salito al cielo, se non colui che è disceso dal cielo, il Figlio dell’uomo. E come Mosè innalzò il serpente nel deserto, così bisogna che sia innalzato il Figlio dell’uomo, perché chiunque crede in lui abbia la vita eterna»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,54-58', 'Matteo', '[In quel tempo Gesù], venuto nella sua patria, insegnava nella loro sinagoga e la gente rimaneva stupita e diceva: «Da dove gli vengono questa sapienza e i prodigi? Non è costui il figlio del falegname? E sua madre, non si chiama Maria? E i suoi fratelli, Giacomo, Giuseppe, Simone e Giuda? E le sue sorelle, non stanno tutte da noi? Da dove gli vengono allora tutte queste cose?». Ed era per loro motivo di scandalo. Ma Gesù disse loro: «Un profeta non è disprezzato se non nella sua patria e in casa sua». E lì, a causa della loro incredulità, non fece molti prodigi');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 3,31-36', 'Giovanni', 'Chi viene dall''alto è al di sopra di tutti; ma chi viene dalla terra, appartiene alla terra e parla secondo la terra. Chi viene dal cielo è al di sopra di tutti. Egli attesta ciò che ha visto e udito, eppure nessuno accetta la sua testimonianza. Chi ne accetta la testimonianza, conferma che Dio è veritiero. Colui infatti che Dio ha mandato dice le parole di Dio: senza misura egli dà lo Spirito. Il Padre ama il Figlio e gli ha dato in mano ogni cosa. Chi crede nel Figlio ha la vita eterna; chi non obbedisce al Figlio non vedrà la vita, ma l''ira di Dio rimane su di lui');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 14,6-14', 'Giovanni', 'In quel tempo, disse Gesù a Tommaso: «Io sono la via, la verità e la vita. Nessuno viene al Padre se non per mezzo di me. Se avete conosciuto me, conoscerete anche il Padre mio: fin da ora lo conoscete e lo avete veduto». Gli disse Filippo: «Signore, mostraci il Padre e ci basta». Gli rispose Gesù: «Da tanto tempo sono con voi e tu non mi hai conosciuto, Filippo? Chi ha visto me, ha visto il Padre. Come puoi tu dire: "Mostraci il Padre"? Non credi che io sono nel Padre e il Padre è in me? Le parole che io vi dico, non le dico da me stesso; ma il Padre, che rimane in me, compie le sue opere. Credete a me: io sono nel Padre e il Padre è in me. Se non altro, credetelo per le opere stesse. In verità, in verità io vi dico: chi crede in me, anch''egli compirà le opere che io compio e ne compirà di più grandi di queste, perché io vado al Padre. E qualunque cosa chiederete nel mio nome, la farò, perché il Padre sia glorificato nel Figlio. Se mi chiederete qualche cosa nel mio nome, io la farò»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,16-21', 'Giovanni', 'Venuta la sera, i discepoli di Gesù scesero al mare, salirono in barca e si avviarono verso l''altra riva del mare in direzione di Cafàrnao. Era ormai buio e Gesù non li aveva ancora raggiunti; il mare era agitato, perché soffiava un forte vento. Dopo aver remato per circa tre o quattro miglia, videro Gesù che camminava sul mare e si avvicinava alla barca, ed ebbero paura. Ma egli disse loro: «Sono io, non abbiate paura!». Allora vollero prenderlo sulla barca, e subito la barca toccò la riva alla quale erano diretti');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 21,1-19', 'Giovanni', 'Gesù si manifestò di nuovo ai discepoli sul mare di Tiberìade. E si manifestò così: si trovavano insieme Simon Pietro, Tommaso detto Dìdimo, Natanaèle di Cana di Galilea, i figli di Zebedèo e altri due discepoli. Disse loro Simon Pietro: «Io vado a pescare». Gli dissero: «Veniamo anche noi con te». Allora uscirono e salirono sulla barca; ma quella notte non presero nulla. Quando già era l''alba, Gesù stette sulla riva, ma i discepoli non si erano accorti che era Gesù. Gesù disse loro: «Figlioli, non avete nulla da mangiare?». Gli risposero: «No». Allora egli disse loro: «Gettate la rete dalla parte destra della barca e troverete». La gettarono e non riuscivano più a tirarla su per la grande quantità di pesci. Allora quel discepolo che Gesù amava disse a Pietro: «È il Signore!». Simon Pietro, appena udì che era il Signore, si strinse la veste attorno ai fianchi, perché era svestito, e si gettò in mare. Gli altri discepoli invece vennero con la barca, trascinando la rete piena di pesci: non erano infatti lontani da terra se non un centinaio di metri. Appena scesi a terra, videro un fuoco di brace con del pesce sopra, e del pane. Disse loro Gesù: «Portate un po'' del pesce che avete preso ora». Allora Simon Pietro salì nella barca e trasse a terra la rete piena di centocinquantatré grossi pesci. E benché fossero tanti, la rete non si squarciò. Gesù disse loro: «Venite a mangiare». E nessuno dei discepoli osava domandargli: «Chi sei?», perché sapevano bene che era il Signore. Gesù si avvicinò, prese il pane e lo diede loro, e così pure il pesce. Era la terza volta che Gesù si manifestava ai discepoli, dopo essere risorto dai morti. Quand''ebbero mangiato, Gesù disse a Simon Pietro: «Simone, figlio di Giovanni, mi ami più di costoro?». Gli rispose: «Certo, Signore, tu lo sai che ti voglio bene». Gli disse: «Pasci i miei agnelli». Gli disse di nuovo, per la seconda volta: «Simone, figlio di Giovanni, mi ami?». Gli rispose: «Certo, Signore, tu lo sai che ti voglio bene». Gli disse: «Pascola le mie pecore». Gli disse per la terza volta: «Simone, figlio di Giovanni, mi vuoi bene?». Pietro rimase addolorato che per la terza volta gli domandasse: «Mi vuoi bene?», e gli disse: «Signore, tu conosci tutto; tu sai che ti voglio bene». Gli rispose Gesù: «Pasci le mie pecore. In verità, in verità io ti dico: quan-do eri più giovane ti vestivi da solo e andavi dove volevi; ma quando sarai vecchio tenderai le tue mani, e un altro ti vestirà e ti porterà dove tu non vuoi». Questo disse per indicare con quale morte egli avrebbe glorificato Dio. E, detto questo, aggiunse: «Seguimi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,22-29', 'Giovanni', 'Il giorno dopo, la folla, rimasta dall''altra parte del mare, vide che c''era soltanto una barca e che Gesù non era salito con i suoi discepoli sulla barca, ma i suoi discepoli erano partiti da soli. Altre barche erano giunte da Tiberìade, vicino al luogo dove avevano mangiato il pane, dopo che il Signore aveva reso grazie. Quando dunque la folla vide che Gesù non era più là e nemmeno i suoi discepoli, salì sulle barche e si diresse alla volta di Cafàrnao alla ricerca di Gesù. Lo trovarono di là dal mare e gli dissero: «Rabbì, quando sei venuto qua?». Gesù rispose loro: «In verità, in verità io vi dico: voi mi cercate non perché avete visto dei segni, ma perché avete mangiato di quei pani e vi siete saziati. Datevi da fare non per il cibo che non dura, ma per il cibo che rimane per la vita eterna e che il Figlio dell''uomo vi darà. Perché su di lui il Padre, Dio, ha messo il suo sigillo». Gli dissero allora: «Che cosa dobbiamo compiere per fare le opere di Dio?». Gesù rispose loro: «Questa è l''opera di Dio: che crediate in colui che egli ha mandato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,30-35', 'Giovanni', 'In quel tempo, la folla disse a Gesù: «Quale segno tu compi perché vediamo e ti crediamo? Quale opera fai? I nostri padri hanno mangiato la manna nel deserto, come sta scritto: "Diede loro da mangiare un pane dal cielo"». Rispose loro Gesù: «In verità, in verità io vi dico: non è Mosè che vi ha dato il pane dal cielo, ma è il Padre mio che vi dà il pane dal cielo, quello vero. Infatti il pane di Dio è colui che discende dal cielo e dà la vita al mondo». Allora gli dissero: «Signore, dacci sempre questo pane». Gesù rispose loro: «Io sono il pane della vita; chi viene a me non avrà fame e chi crede in me non avrà sete, mai!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,35-40', 'Giovanni', 'In quel tempo, disse Gesù alla folla: «Io sono il pane della vita; chi viene a me non avrà fame e chi crede in me non avrà sete, mai! Vi ho detto però che voi mi avete visto, eppure non credete. Tutto ciò che il Padre mi dà, verrà a me: colui che viene a me, io non lo caccerò fuori, perché sono disceso dal cielo non per fare la mia volontà, ma la volontà di colui che mi ha mandato. E questa è la volontà di colui che mi ha mandato: che io non perda nulla di quanto egli mi ha dato, ma che lo risusciti nell''ultimo giorno. Questa infatti è la volontà del Padre mio: che chiunque vede il Figlio e crede in lui abbia la vita eterna; e io lo risusciterò nell''ultimo giorno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,44-51', 'Giovanni', '[In quel tempo, disse Gesù alla folla]: «Nessuno può venire a me, se non lo attira il Padre che mi ha mandato; e io lo risusciterò nell''ultimo giorno. Sta scritto nei profeti: "E tutti saranno istruiti da Dio". Chiunque ha ascoltato il Padre e ha imparato da lui, viene a me. Non perché qualcuno abbia visto il Padre; solo colui che viene da Dio ha visto il Padre. In verità, in verità io vi dico: chi crede ha la vita eterna. Io sono il pane della vita. I vostri padri hanno mangiato la manna nel deserto e sono morti; questo è il pane che discende dal cielo, perché chi ne mangia non muoia. Io sono il pane vivo, disceso dal cielo. Se uno mangia di questo pane vivrà in eterno e il pane che io darò è la mia carne per la vita del mondo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,52-59', 'Giovanni', 'I Giudei si misero a discutere aspramente fra loro: «Come può costui darci la sua carne da mangiare?». Gesù disse loro: «In verità, in verità io vi dico: se non mangiate la carne del Figlio dell''uomo e non bevete il suo sangue, non avete in voi la vita. Chi mangia la mia carne e beve il mio sangue ha la vita eterna e io lo risusciterò nell''ultimo giorno. Perché la mia carne è vero cibo e il mio sangue vera bevanda. Chi mangia la mia carne e beve il mio sangue rimane in me e io in lui. Come il Padre, che ha la vita, ha mandato me e io vivo per il Padre, così anche colui che mangia me vivrà per me. Questo è il pane disceso dal cielo; non è come quello che mangiarono i padri e morirono. Chi mangia questo pane vivrà in eterno». Gesù disse queste cose, insegnando nella sinagoga a Cafàrnao');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,60-69', 'Giovanni', 'Molti dei discepoli di Gesù, dopo aver ascoltato, dissero: «Questa parola è dura! Chi può ascoltarla?». Gesù, sapendo dentro di sé che i suoi discepoli mormoravano riguardo a questo, disse loro: «Questo vi scandalizza? E se vedeste il Figlio dell’uomo salire là dov’era prima? È lo Spirito che dà la vita, la carne non giova a nulla; le parole che io vi ho detto sono spirito e sono vita. Ma tra voi vi sono alcuni che non credono». Gesù infatti sapeva fin da principio chi erano quelli che non credevano e chi era colui che lo avrebbe tradito. E diceva: «Per questo vi ho detto che nessuno può venire a me, se non gli è concesso dal Padre». Da quel momento molti dei suoi discepoli tornarono indietro e non andavano più con lui. Disse allora Gesù ai Dodici: «Volete andarvene anche voi?». Gli rispose Simon Pietro: «Signore, da chi andremo? Tu hai parole di vita eterna e noi abbiamo creduto e conosciuto che tu sei il Santo di Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 10,27-30', 'Giovanni', 'In quel tempo, Gesù disse: «Le mie pecore ascoltano la mia voce e io le conosco ed esse mi seguono. Io do loro la vita eterna e non andranno perdute in eterno e nessuno le strapperà dalla mia mano. Il Padre mio, che me le ha date, è più grande di tutti e nessuno può strapparle dalla mano del Padre. Io e il Padre siamo una cosa sola»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 10,1-10', 'Giovanni', '[In quel tempo, Gesù disse]: «In verità, in verità io vi dico: chi non entra nel recinto delle pecore dalla porta, ma vi sale da un’altra parte, è un ladro e un brigante. Chi invece entra dalla porta, è pastore delle pecore. Il guardiano gli apre e le pecore ascoltano la sua voce: egli chiama le sue pecore, ciascuna per nome, e le conduce fuori. E quando ha spinto fuori tutte le sue pecore, cammina davanti a esse, e le pecore lo seguono perché conoscono la sua voce. Un estraneo invece non lo seguiranno, ma fuggiranno via da lui, perché non conoscono la voce degli estranei». Gesù disse loro questa similitudine, ma essi non capirono di che cosa parlava loro. Allora Gesù disse loro di nuovo: «In verità, in verità io vi dico: io sono la porta delle pecore. Tutti coloro che sono venuti prima di me, sono ladri e briganti; ma le pecore non li hanno ascoltati. Io sono la porta: se uno entra attraverso di me, sarà salvato; entrerà e uscirà e troverà pascolo. Il ladro non viene se non per rubare, uccidere e distruggere; io sono venuto perché abbiano la vita e l’abbiano in abbondanza»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 15,9-17', 'Giovanni', '[In quel tempo, Gesù disse ai suoi discepoli]: «Come il Padre ha amato me, anche io ho amato voi. Rimanete nel mio amore. Se osserverete i miei comandamenti, rimarrete nel mio amore, come io ho osservato i comandamenti del Padre mio e rimango nel suo amore. Vi ho detto queste cose perché la mia gioia sia in voi e la vostra gioia sia piena. Questo è il mio comandamento: che vi amiate gli uni gli altri come io ho amato voi. Nessuno ha un amore più grande di questo: dare la sua vita per i propri amici. Voi siete miei amici, se fate ciò che io vi comando. Non vi chiamo più servi, perché il servo non sa quello che fa il suo padrone; ma vi ho chiamato amici, perché tutto ciò che ho udito dal Padre mio l''ho fatto conoscere a voi. Non voi avete scelto me, ma io ho scelto voi e vi ho costituiti perché andiate e portiate frutto e il vostro frutto rimanga; perché tutto quello che chiederete al Padre nel mio nome, ve lo conceda. Questo vi comando: che vi amiate gli uni gli altri»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 12,44-50', 'Giovanni', 'Gesù esclamò: «Chi crede in me, non crede in me ma in colui che mi ha mandato; chi vede me, vede colui che mi ha mandato. Io sono venuto nel mondo come luce, perché chiunque crede in me non rimanga nelle tenebre. Se qualcuno ascolta le mie parole e non le osserva, io non lo condanno; perché non sono venuto per condannare il mondo, ma per salvare il mondo. Chi mi rifiuta e non accoglie le mie parole, ha chi lo condanna: la parola che ho detto lo condannerà nell''ultimo giorno. Perché io non ho parlato da me stesso, ma il Padre, che mi ha mandato, mi ha ordinato lui di che cosa parlare e che cosa devo dire. E io so che il suo comandamento è vita eterna. Le cose dunque che io dico, le dico così come il Padre le ha dette a me»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 13,16-20', 'Giovanni', 'Dopo che ebbe lavato i piedi ai discepoli, Gesù] disse loro: «In verità, in verità io vi dico: un servo non è più grande del suo padrone, né un inviato è più grande di chi lo ha mandato. Sapendo queste cose, siete beati se le mettete in pratica. Non parlo di tutti voi; io conosco quelli che ho scelto; ma deve compiersi la Scrittura: "Colui che mangia il mio pane ha alzato contro di me il suo calcagno". Ve lo dico fin d''ora, prima che accada, perché, quando sarà avvenuto, crediate che Io sono. In verità, in verità io vi dico: chi accoglie colui che io manderò, accoglie me; chi accoglie me, accoglie colui che mi ha mandato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 14,1-6', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Non sia turbato il vostro cuore. Abbiate fede in Dio e abbiate fede anche in me. Nella casa del Padre mio vi sono molte dimore. Se no, vi avrei mai detto: "Vado a prepararvi un posto"? Quando sarò andato e vi avrò preparato un posto, verrò di nuovo e vi prenderò con me, perché dove sono io siate anche voi. E del luogo dove io vado, conoscete la via». Gli disse Tommaso: «Signore, non sappiamo dove vai; come possiamo conoscere la via?». Gli disse Gesù: «Io sono la via, la verità e la vita. Nessuno viene al Padre se non per mezzo di me»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 14,7-14', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Se avete conosciuto me, conoscerete anche il Padre mio: fin da ora lo conoscete e lo avete veduto». Gli disse Filippo: «Signore, mostraci il Padre e ci basta». Gli rispose Gesù: «Da tanto tempo sono con voi e tu non mi hai conosciuto, Filippo? Chi ha visto me, ha visto il Padre. Come puoi tu dire: "Mostraci il Padre"? Non credi che io sono nel Padre e il Padre è in me? Le parole che io vi dico, non le dico da me stesso; ma il Padre, che rimane in me, compie le sue opere. Credete a me: io sono nel Padre e il Padre è in me. Se non altro, credetelo per le opere stesse. In verità, in verità io vi dico: chi crede in me, anch''egli compirà le opere che io compio e ne compirà di più grandi di queste, perché io vado al Padre. E qualunque cosa chiederete nel mio nome, la farò, perché il Padre sia glorificato nel Figlio. Se mi chiederete qualche cosa nel mio nome, io la farò');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 13,31-33a.34-35', 'Giovanni', 'Quando Giuda fu uscito [dal cenacolo], Gesù disse: «Ora il Figlio dell''uomo è stato glorificato, e Dio è stato glorificato in lui. Se Dio è stato glorificato in lui, anche Dio lo glorificherà da parte sua e lo glorificherà subito. Figlioli, ancora per poco sono con voi. Vi do un comandamento nuovo: che vi amiate gli uni gli altri. Come io ho amato voi, così amatevi anche voi gli uni gli altri. Da questo tutti sapranno che siete miei discepoli: se avete amore gli uni per gli altri»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 14,21-26', 'Giovanni', '[In quel tempo, Gesù disse ai suoi discepoli]: «Chi accoglie i miei comandamenti e li osserva, questi è colui che mi ama. Chi ama me sarà amato dal Padre mio e anch''io lo amerò e mi manifesterò a lui». Gli disse Giuda, non l''Iscariòta: «Signore, come è accaduto che devi manifestarti a noi, e non al mondo?». Gli rispose Gesù: «Se uno mi ama, osserverà la mia parola e il Padre mio lo amerà e noi verremo a lui e prenderemo dimora presso di lui. Chi non mi ama, non osserva le mie parole; e la parola che voi ascoltate non è mia, ma del Padre che mi ha mandato. Vi ho detto queste cose mentre sono ancora presso di voi. Ma il Paràclito, lo Spirito Santo che il Padre manderà nel mio nome, lui vi insegnerà ogni cosa e vi ricorderà tutto ciò che io vi ho detto»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 14,27-31a', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Vi lascio la pace, vi do la mia pace. Non come la dà il mondo, io la do a voi. Non sia turbato il vostro cuore e non abbia timore. Avete udito che vi ho detto: "Vado e tornerò da voi". Se mi amaste, vi rallegrereste che io vado al Padre, perché il Padre è più grande di me. Ve l''ho detto ora, prima che avvenga, perché, quando avverrà, voi crediate. Non parlerò più a lungo con voi, perché viene il prìncipe del mondo; contro di me non può nulla, ma bisogna che il mondo sappia che io amo il Padre, e come il Padre mi ha comandato, così io agisco»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 15,1-8', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Io sono la vite vera e il Padre mio è l''agricoltore. Ogni tralcio che in me non porta frutto, lo taglia, e ogni tralcio che porta frutto, lo pota perché porti più frutto. Voi siete già puri, a causa della parola che vi ho annunciato. Rimanete in me e io in voi. Come il tralcio non può portare frutto da sé stesso se non rimane nella vite, così neanche voi se non rimanete in me. Io sono la vite, voi i tralci. Chi rimane in me, e io in lui, porta molto frutto, perché senza di me non potete far nulla. Chi non rimane in me viene gettato via come il tralcio e secca; poi lo raccolgono, lo gettano nel fuoco e lo bruciano. Se rimanete in me e le mie parole rimangono in voi, chiedete quello che volete e vi sarà fatto. In questo è glorificato il Padre mio: che portiate molto frutto e diventiate miei discepoli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 15,9-11', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Come il Padre ha amato me, anche io ho amato voi. Rimanete nel mio amore. Se osserverete i miei comandamenti, rimarrete nel mio amore, come io ho osservato i comandamenti del Padre mio e rimango nel suo amore. Vi ho detto queste cose perché la mia gioia sia in voi e la vostra gioia sia piena»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 15,12-17', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Questo è il mio comandamento: che vi amiate gli uni gli altri come io ho amato voi. Nessuno ha un amore più grande di questo: dare la sua vita per i propri amici. Voi siete miei amici, se fate ciò che io vi comando. Non vi chiamo più servi, perché il servo non sa quello che fa il suo padrone; ma vi ho chiamato amici, perché tutto ciò che ho udito dal Padre mio l''ho fatto conoscere a voi. Non voi avete scelto me, ma io ho scelto voi e vi ho costituiti perché andiate e portiate frutto e il vostro frutto rimanga; perché tutto quello che chiederete al Padre nel mio nome, ve lo conceda. Questo vi comando: che vi amiate gli uni gli altri»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 15,18-21', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Se il mondo vi odia, sappiate che prima di voi ha odiato me. Se foste del mondo, il mondo amerebbe ciò che è suo; poiché invece non siete del mondo, ma vi ho scelti io dal mondo, per questo il mondo vi odia. Ricordatevi della parola che io vi ho detto: "Un servo non è più grande del suo padrone". Se hanno perseguitato me, perseguiteranno anche voi; se hanno osservato la mia parola, osserveranno anche la vostra. Ma faranno a voi tutto questo a causa del mio nome, perché non conoscono colui che mi ha mandato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 14,23-29', 'Giovanni', '[In quel tempo, Gesù disse ai suoi discepoli]: «Se uno mi ama, osserverà la mia parola e il Padre mio lo amerà e noi verremo a lui e prenderemo dimora presso di lui. Chi non mi ama, non osserva le mie parole; e la parola che voi ascoltate non è mia, ma del Padre che mi ha mandato. Vi ho detto queste cose mentre sono ancora presso di voi. Ma il Paràclito, lo Spirito Santo che il Padre manderà nel mio nome, lui vi insegnerà ogni cosa e vi ricorderà tutto ciò che io vi ho detto. Vi lascio la pace, vi do la mia pace. Non come la dà il mondo, io la do a voi. Non sia turbato il vostro cuore e non abbia timore. Avete udito che vi ho detto: "Vado e tornerò da voi". Se mi amaste, vi rallegrereste che io vado al Padre, perché il Padre è più grande di me. Ve l''ho detto ora, prima che avvenga, perché, quando avverrà, voi crediate»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 15,26-16,4', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Quando verrà il Paràclito, che io vi manderò dal Padre, lo Spirito della verità che procede dal Padre, egli darà testimonianza di me; e anche voi date testimonianza, perché siete con me fin dal principio. Vi ho detto queste cose perché non abbiate a scandalizzarvi. Vi scacceranno dalle sinagoghe; anzi, viene l''ora in cui chiunque vi ucciderà crederà di rendere culto a Dio. E faranno ciò, perché non hanno conosciuto né il Padre né me. Ma vi ho detto queste cose affinché, quando verrà la loro ora, ve ne ricordiate, perché io ve l''ho detto»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 16,5-11', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Ora vado da colui che mi ha mandato e nessuno di voi mi domanda: “Dove vai?”. Anzi, perché vi ho detto questo, la tristezza ha riempito il vostro cuore. Ma io vi dico la verità: è bene per voi che io me ne vada, perché, se non me ne vado, non verrà a voi il Paràclito; se invece me ne vado, lo manderò a voi. E quando sarà venuto, dimostrerà la colpa del mondo riguardo al peccato, alla giustizia e al giudizio. Riguardo al peccato, perché non credono in me; riguardo alla giustizia, perché vado al Padre e non mi vedrete più; riguardo al giudizio, perché il principe di questo mondo è già condannato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 16,12-15', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Molte cose ho ancora da dirvi, ma per il momento non siete capaci di portarne il peso. Quando verrà lui, lo Spirito della verità, vi guiderà a tutta la verità, perché non parlerà da se stesso, ma dirà tutto ciò che avrà udito e vi annuncerà le cose future. Egli mi glorificherà, perché prenderà da quel che è mio e ve lo annuncerà. Tutto quello che il Padre possiede è mio; per questo ho detto che prenderà da quel che è mio e ve lo annuncerà»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 16,16-20', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Un poco e non mi vedrete più; un poco ancora e mi vedrete». Allora alcuni dei suoi discepoli dissero tra loro: «Che cos''è questo che ci dice: "Un poco e non mi vedrete; un poco ancora e mi vedrete", e: "Io me ne vado al Padre"?». Dicevano perciò: «Che cos''è questo "un poco", di cui parla? Non comprendiamo quello che vuol dire». Gesù capì che volevano interrogarlo e disse loro: «State indagando tra voi perché ho detto: "Un poco e non mi vedrete; un poco ancora e mi vedrete"? In verità, in verità io vi dico: voi piangerete e gemerete, ma il mondo si rallegrerà. Voi sarete nella tristezza, ma la vostra tristezza si cambierà in gioia»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,39-56', 'Luca', 'In quei giorni, Maria si alzò e andò in fretta verso la regione montuosa, in una città di Giuda.  Entrata nella casa di Zaccarìa, salutò Elisabetta. Appena Elisabetta ebbe udito il saluto di Maria, il bambino sussultò nel suo grembo. Elisabetta fu colmata di Spirito Santo ed esclamò a gran voce: «Benedetta tu fra le donne e benedetto il frutto del tuo grembo! A che cosa devo che la madre del mio Signore venga da me? Ecco, appena il tuo saluto è giunto ai miei orecchi, il bambino ha sussultato di gioia nel mio grembo. E beata colei che ha creduto nell''adempimento di ciò che il Signore le ha detto». Allora Maria disse: «L''anima mia magnifica il Signore e il mio spirito esulta in Dio, mio salvatore, perché ha guardato l''umiltà della sua serva. D''ora in poi tutte le generazioni mi chiameranno beata. Grandi cose ha fatto per me l''Onnipotente e Santo è il suo nome; di generazione in generazione la sua misericordia per quelli che lo temono. Ha spiegato la potenza del suo braccio, ha disperso i superbi nei pensieri del loro cuore; ha rovesciato i potenti dai troni, ha innalzato gli umili; ha ricolmato di beni gli affamati, ha rimandato i ricchi a mani vuote. Ha soccorso Israele, suo servo, ricordandosi della sua misericordia, come aveva detto ai nostri padri, per Abramo e la sua discendenza, per sempre». Maria rimase con lei circa tre mesi, poi tornò a casa sua');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 16,23b-28', 'Giovanni', '[In quel tempo Gesù disse ai suoi discepoli]: «In verità, in verità io vi dico: se chiederete qualche cosa al Padre nel mio nome, egli ve la darà. Finora non avete chiesto nulla nel mio nome. Chiedete e otterrete, perché la vostra gioia sia piena. Queste cose ve le ho dette in modo velato, ma viene l''ora in cui non vi parlerò più in modo velato e apertamente vi parlerò del Padre. In quel giorno chiederete nel mio nome e non vi dico che pregherò il Padre per voi: il Padre stesso infatti vi ama, perché voi avete amato me e avete creduto che io sono uscito da Dio. Sono uscito dal Padre e sono venuto nel mondo; ora lascio di nuovo il mondo e vado al Padre»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 24,46-53', 'Luca', '[In quel tempo, Gesù disse ai suoi discepoli]: «Così sta scritto: il Cristo patirà e risorgerà dai morti il terzo giorno, e nel suo nome saranno predicati a tutti i popoli la conversione e il perdono dei peccati, cominciando da Gerusalemme. Di questo voi siete testimoni. Ed ecco, io mando su di voi colui che il Padre mio ha promesso; ma voi restate in città, finché non siate rivestiti di potenza dall''alto». Poi li condusse fuori verso Betània e, alzate le mani, li benedisse. Mentre li benediceva, si staccò da loro e veniva portato su, in cielo. Ed essi si prostrarono davanti a lui; poi tornarono a Gerusalemme con grande gioia e stavano sempre nel tempio lodando Dio');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 16,29-33', 'Giovanni', 'In quel tempo, dissero i discepoli a Gesù: «Ecco, ora parli apertamente e non più in modo velato. Ora sappiamo che tu sai tutto e non hai bisogno che alcuno t''interroghi. Per questo crediamo che sei uscito da Dio». Rispose loro Gesù: «Adesso credete? Ecco, viene l''ora, anzi è già venuta, in cui vi disperderete ciascuno per conto suo e mi lascerete solo; ma io non sono solo, perché il Padre è con me. Vi ho detto questo perché abbiate pace in me. Nel mondo avete tribolazioni, ma abbiate coraggio: io ho vinto il mondo!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 17,1-11', 'Giovanni', 'In quel tempo, Gesù, alzàti gli occhi al cielo, disse: «Padre, è venuta l''ora: glorifica il Figlio tuo perché il Figlio glorifichi te. Tu gli hai dato potere su ogni essere umano, perché egli dia la vita eterna a tutti coloro che gli hai dato. Questa è la vita eterna: che conoscano te, l''unico vero Dio, e colui che hai mandato, Gesù Cristo. Io ti ho glorificato sulla terra, compiendo l''opera che mi hai dato da fare. E ora, Padre, glorificami davanti a te con quella gloria che io avevo presso di te prima che il mondo fosse. Ho manifestato il tuo nome agli uomini che mi hai dato dal mondo. Erano tuoi e li hai dati a me, ed essi hanno osservato la tua parola. Ora essi sanno che tutte le cose che mi hai dato vengono da te, perché le parole che hai dato a me io le ho date a loro. Essi le hanno accolte e sanno veramente che sono uscito da te e hanno creduto che tu mi hai mandato. Io prego per loro; non prego per il mondo, ma per coloro che tu mi hai dato, perché sono tuoi. Tutte le cose mie sono tue, e le tue sono mie, e io sono glorificato in loro. Io non sono più nel mondo; essi invece sono nel mondo, e io vengo a te»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 17,11b-19', 'Giovanni', 'In quel tempo, [Gesù, alzàti gli occhi al cielo, pregò dicendo]: «Padre santo, custodiscili nel tuo nome, quello che mi hai dato, perché siano una sola cosa, come noi. Quand''ero con loro, io li custodivo nel tuo nome, quello che mi hai dato, e li ho conservati, e nessuno di loro è andato perduto, tranne il figlio della perdizione, perché si compisse la Scrittura. Ma ora io vengo a te e dico questo mentre sono nel mondo, perché abbiano in se stessi la pienezza della mia gioia. Io ho dato loro la tua parola e il mondo li ha odiati, perché essi non sono del mondo, come io non sono del mondo. Non prego che tu li tolga dal mondo, ma che tu li custodisca dal Maligno. Essi non sono del mondo, come io non sono del mondo. Consacrali nella verità. La tua parola è verità. Come tu hai mandato me nel mondo, anche io ho mandato loro nel mondo; per loro io consacro me stesso, perché siano anch''essi consacrati nella verità»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 17,20-26', 'Giovanni', 'In quel tempo, [Gesù pregò dicendo]: «Non prego solo per questi, ma anche per quelli che crederanno in me mediante la loro parola: perché tutti siano una sola cosa; come tu, Padre, sei in me e io in te, siano anch''essi in noi, perché il mondo creda che tu mi hai mandato. E la gloria che tu hai dato a me, io l''ho data a loro, perché siano una sola cosa come noi siamo una sola cosa. Io in loro e tu in me, perché siano perfetti nell''unità e il mondo conosca che tu mi hai mandato e che li hai amati come hai amato me. Padre, voglio che quelli che mi hai dato siano anch''essi con me dove sono io, perché contemplino la mia gloria, quella che tu mi hai dato; poiché mi hai amato prima della creazione del mondo. Padre giusto, il mondo non ti ha conosciuto, ma io ti ho conosciuto, e questi hanno conosciuto che tu mi hai mandato. E io ho fatto conoscere loro il tuo nome e lo farò conoscere, perché l''amore con il quale mi hai amato sia in essi e io in loro»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 21,15-19', 'Giovanni', 'In quel tempo, [quando si fu manifestato ai discepoli ed] essi ebbero mangiato, Gesù disse a Simon Pietro: «Simone, figlio di Giovanni, mi ami più di costoro?». Gli rispose: «Certo, Signore, tu lo sai che ti voglio bene». Gli disse: «Pasci i miei agnelli». Gli disse di nuovo, per la seconda volta: «Simone, figlio di Giovanni, mi ami?». Gli rispose: «Certo, Signore, tu lo sai che ti voglio bene». Gli disse: «Pascola le mie pecore». Gli disse per la terza volta: «Simone, figlio di Giovanni, mi vuoi bene?». Pietro rimase addolorato che per la terza volta gli domandasse "Mi vuoi bene?", e gli disse: «Signore, tu conosci tutto; tu sai che ti voglio bene». Gli rispose Gesù: «Pasci le mie pecore. In verità, in verità io ti dico: quando eri più giovane ti vestivi da solo e andavi dove volevi; ma quando sarai vecchio tenderai le tue mani, e un altro ti vestirà e ti porterà dove tu non vuoi». Questo disse per indicare con quale morte egli avrebbe glorificato Dio. E, detto questo, aggiunse: «Seguimi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 21,20-25', 'Giovanni', 'Pietro si voltò e vide che li seguiva quel discepolo che Gesù amava, colui che nella cena si era chinato sul suo petto e gli aveva domandato: «Signore, chi è che ti tradisce?». Pietro dunque, come lo vide, disse a Gesù: «Signore, che cosa sarà di lui?». Gesù gli rispose: «Se voglio che egli rimanga finché io venga, a te che importa? Tu seguimi». Si diffuse perciò tra i fratelli la voce che quel discepolo non sarebbe morto. Gesù però non gli aveva detto che non sarebbe morto, ma: «Se voglio che egli rimanga finché io venga, a te che importa?». Questi è il discepolo che testimonia queste cose e le ha scritte, e noi sappiamo che la sua testimonianza è vera. Vi sono ancora molte altre cose compiute da Gesù che, se fossero scritte una per una, penso che il mondo stesso non basterebbe a contenere i libri che si dovrebbero scrivere');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 14,15-16.23b-26', 'Giovanni', '[In quel tempo, Gesù disse ai suoi discepoli]: «Se mi amate, osserverete i miei comandamenti; e io pregherò il Padre ed egli vi darà un altro Paràclito perché rimanga con voi per sempre. Se uno mi ama, osserverà la mia parola e il Padre mio lo amerà e noi verremo a lui e prenderemo dimora presso di lui. Chi non mi ama, non osserva le mie parole; e la parola che voi ascoltate non è mia, ma del Padre che mi ha mandato. Vi ho detto queste cose mentre sono ancora presso di voi. Ma il Paràclito, lo Spirito Santo che il Padre manderà nel mio nome, lui vi insegnerà ogni cosa e vi ricorderà tutto ciò che io vi ho detto»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 19,25-34', 'Giovanni', 'Stavano presso la croce di Gesù sua madre, la sorella di sua madre, Maria madre di Clèopa e Maria di Màgdala. Gesù allora, vedendo la madre e accanto a lei il discepolo che egli amava, disse alla madre: «Donna, ecco tuo figlio!». Poi disse al discepolo: «Ecco tua madre!». E da quell''ora il discepolo l''accolse con sé. Dopo questo, Gesù, sapendo che ormai tutto era compiuto, affinché si compisse la Scrittura, disse: «Ho sete». Vi era lì un vaso pieno di aceto; posero perciò una spugna, imbevuta di aceto, in cima a una canna e gliela accostarono alla bocca. Dopo aver preso l''aceto, Gesù disse: «È compiuto!». E, chinato il capo, consegnò lo spirito. Era il giorno della Parasceve e i Giudei, perché i corpi non rimanessero sulla croce durante il sabato - era infatti un giorno solenne quel sabato -, chiesero a Pilato che fossero spezzate loro le gambe e fossero portati via. Vennero dunque i soldati e spezzarono le gambe all''uno e all''altro che erano stati crocifissi insieme con lui. Venuti però da Gesù, vedendo che era già morto, non gli spezzarono le gambe, ma uno dei soldati con una lancia gli colpì il fianco, e subito ne uscì sangue e acqua');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 10,7-13', 'Matteo', '[In quel tempo, disse Gesù ai suoi apostoli]: «Strada facendo, predi-cate, dicendo che il regno dei cieli è vicino. Guarite gli infermi, risuscitate i morti, purificate i lebbrosi, scacciate i demòni. Gratuitamente avete ricevuto, gratuitamente date. Non procuratevi oro né argento né denaro nelle vostre cinture, né sacca da viaggio, né due tuniche, né sandali, né bastone, perché chi lavora ha diritto al suo nutrimento. In qualunque città o villaggio entriate, domandate chi là sia degno e rimanetevi finché non sarete partiti. Entrando nella casa, rivolgetele il saluto. Se quella casa ne è degna, la vostra pace scenda su di essa; ma se non ne è degna, la vostra pace ritorni a voi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,27-32', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Avete inteso che fu detto: “Non commetterai adulterio”. Ma io vi dico: chiunque guarda una donna per desiderarla, ha già commesso adulterio con lei nel proprio cuore. Se il tuo occhio destro ti è motivo di scandalo, cavalo e gettalo via da te: ti conviene infatti perdere una delle tue membra, piuttosto che tutto il tuo corpo venga gettato nella Geènna. E se la tua mano destra ti è motivo di scandalo, tagliala e gettala via da te: ti conviene infatti perdere una delle tue membra, piuttosto che tutto il tuo corpo vada a finire nella Geènna. Fu pure detto: “Chi ripudia la propria moglie, le dia l’atto del ripudio”. Ma io vi dico: chiunque ripudia la propria moglie, eccetto il caso di unione illegittima, la espone all’adulterio, e chiunque sposa una ripudiata, commette adulterio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,33-37', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Avete anche inteso che fu detto agli antichi: “Non giurerai il falso, ma adempirai verso il Signore i tuoi giuramenti”. Ma io vi dico: non giurate affatto, né per il cielo, perché è il trono di Dio, né per la terra, perché è lo sgabello dei suoi piedi, né per Gerusalemme, perché è la città del grande Re. Non giurare neppure per la tua testa, perché non hai il potere di rendere bianco o nero un solo capello. Sia invece il vostro parlare: “Sì, sì”; “No, no”; il di più viene dal Maligno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,38-42', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Avete inteso che fu detto: "Occhio per occhio" e "dente per dente". Ma io vi dico di non opporvi al malvagio; anzi, se uno ti dà uno schiaffo sulla guancia destra, tu pórgigli anche l''altra, e a chi vuole portarti in tribunale e toglierti la tunica, tu lascia anche il mantello. E se uno ti costringerà ad accompagnarlo per un miglio, tu con lui fanne due. Da'' a chi ti chiede, e a chi desidera da te un prestito non voltare le spalle»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 6,19-23', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Non accumulate per voi tesori sulla terra, dove tarma e ruggine consumano e dove ladri scassìnano e rubano; accumulate invece per voi tesori in cielo, dove né tarma né ruggine consumano e dove ladri non scassìnano e non rubano. Perché, dov''è il tuo tesoro, là sarà anche il tuo cuore. La lampada del corpo è l''occhio; perciò, se il tuo occhio è semplice, tutto il tuo corpo sarà luminoso; ma se il tuo occhio è cattivo, tutto il tuo corpo sarà tenebroso. Se dunque la luce che è in te è tenebra, quanto grande sarà la tenebra!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 6,24-34', 'Matteo', '[In quel tempo Gesù disse ai suoi discepoli]: «Nessuno può servire due padroni, perché o odierà l''uno e amerà l''altro, oppure si affezionerà all''uno e disprezzerà l''altro. Non potete servire Dio e la ricchezza. Perciò io vi dico: non preoccupatevi per la vostra vita, di quello che mangerete o berrete, né per il vostro corpo, di quello che indosserete; la vita non vale forse più del cibo e il corpo più del vestito? Guardate gli uccelli del cielo: non séminano e non mietono, né raccolgono nei granai; eppure il Padre vostro celeste li nutre. Non valete forse più di loro? E chi di voi, per quanto si preoccupi, può allungare anche di poco la propria vita? E per il vestito, perché vi preoccupate? Osservate come crescono i gigli del campo: non faticano e non filano. Eppure io vi dico che neanche Salomone, con tutta la sua gloria, vestiva come uno di loro. Ora, se Dio veste così l''erba del campo, che oggi c''è e domani si getta nel forno, non farà molto di più per voi, gente di poca fede? Non preoccupatevi dunque dicendo: "Che cosa mangeremo? Che cosa berremo? Che cosa indosseremo?". Di tutte queste cose vanno in cerca i pagani. Il Padre vostro celeste, infatti, sa che ne avete bisogno. Cercate invece, anzitutto, il regno di Dio e la sua giustizia, e tutte queste cose vi saranno date in aggiunta. Non preoccupatevi dunque del domani, perché il domani si preoccuperà di se stesso. A ciascun giorno basta la sua pena»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,11-17', 'Luca', 'In quel tempo, Gesù prese a parlare alle folle del regno di Dio e a guarire quanti avevano bisogno di cure. Il giorno cominciava a declinare e i Dodici gli si avvicinarono dicendo: «Congeda la folla perché vada nei villaggi e nelle campagne dei dintorni, per alloggiare e trovare cibo: qui siamo in una zona deserta». Gesù disse loro: «Voi stessi date loro da mangiare». Ma essi risposero: «Non abbiamo che cinque pani e due pesci, a meno che non andiamo noi a comprare viveri per tutta questa gente». C''erano infatti circa cinquemila uomini. Egli disse ai suoi discepoli: «Fateli sedere a gruppi di cinquanta circa». Fecero così e li fecero sedere tutti quanti. Egli prese i cinque pani e i due pesci, alzò gli occhi al cielo, recitò su di essi la benedizione, li spezzò e li dava ai discepoli perché li distribuissero alla folla. Tutti mangiarono a sazietà e furono portati via i pezzi loro avanzati: dodici ceste');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,57-66.80', 'Luca', 'Per Elisabetta si compì il tempo del parto e diede alla luce un figlio. I vicini e i parenti udirono che il Signore aveva manifestato in lei la sua grande misericordia, e si rallegravano con lei. Otto giorni dopo vennero per circoncidere il bambino e volevano chiamarlo con il nome di suo padre, Zaccarìa. Ma sua madre intervenne: «No, si chiamerà Giovanni». Le dissero: «Non c''è nessuno della tua parentela che si chiami con questo nome». Allora domandavano con cenni a suo padre come voleva che si chiamasse. Egli chiese una tavoletta e scrisse: «Giovanni è il suo nome». Tutti furono meravigliati. All''istante si aprirono la sua bocca e la sua lingua, e parlava benedicendo Dio. Tutti i loro vicini furono presi da timore, e per tutta la regione montuosa della Giudea si discorreva di tutte queste cose. Tutti coloro che le udivano, le custodivano in cuor loro, dicendo: «Che sarà mai questo bambino?». E davvero la mano del Signore era con lui. Il bambino cresceva e si fortificava nello spirito. Visse in regioni deserte fino al giorno della sua manifestazione a Israele');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 7,6.12-14', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Non date le cose sante ai cani e non gettate le vostre perle davanti ai porci, perché non le calpestino con le loro zampe e poi si voltino per sbranarvi. Tutto quanto volete che gli uomini facciano a voi, anche voi fatelo a loro: questa infatti è la Legge e i Profeti. Entrate per la porta stretta, perché larga è la porta e spaziosa la via che conduce alla perdizione, e molti sono quelli che vi entrano. Quanto stretta è la porta e angusta la via che conduce alla vita, e pochi sono quelli che la trovano!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 7,15-20', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Guardatevi dai falsi profeti, che vengono a voi in veste di pecore, ma dentro sono lupi rapaci! Dai loro frutti li riconoscerete. Si raccoglie forse uva dagli spini, o fichi dai rovi? Così ogni albero buono produce frutti buoni e ogni albero cattivo produce frutti cattivi; un albero buono non può produrre frutti cattivi, né un albero cattivo produrre frutti buoni. Ogni albero che non dà buon frutto viene tagliato e gettato nel fuoco. Dai loro frutti dunque li riconoscerete»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 7,21-29', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Non chiunque mi dice: "Signore, Signore", entrerà nel regno dei cieli, ma colui che fa la volontà del Padre mio che è nei cieli. In quel giorno molti mi diranno: "Signore, Signore, non abbiamo forse profetato nel tuo nome? E nel tuo nome non abbiamo forse scacciato demòni? E nel tuo nome non abbiamo forse compiuto molti prodigi?". Ma allora io dichiarerò loro: "Non vi ho mai conosciuti. Allontanatevi da me, voi che operate l''iniquità!". Perciò chiunque ascolta queste mie parole e le mette in pratica, sarà simile a un uomo saggio, che ha costruito la sua casa sulla roccia. Cadde la pioggia, strariparono i fiumi, soffiarono i venti e si abbatterono su quella casa, ma essa non cadde, perché era fondata sulla roccia. Chiunque ascolta queste mie parole e non le mette in pratica, sarà simile a un uomo stolto, che ha costruito la sua casa sulla sabbia. Cadde la pioggia, strariparono i fiumi, soffiarono i venti e si abbatterono su quella casa, ed essa cadde e la sua rovina fu grande». Quando Gesù ebbe terminato questi discorsi, le folle erano stupite del suo insegnamento: egli infatti insegnava loro come uno che ha autorità, e non come i loro scribi');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 15,3-7', 'Luca', 'Gesù disse ai farisei e agli scribi questa parabola: «Chi di voi, se ha cento pecore e ne perde una, non lascia le novantanove nel deserto e va in cerca di quella perduta, finché non la trova? Quando l''ha trovata, pieno di gioia se la carica sulle spalle, va a casa, chiama gli amici e i vicini e dice loro: "Rallegratevi con me, perché ho trovato la mia pecora, quella che si era perduta". Io vi dico: così vi sarà gioia nel cielo per un solo peccatore che si converte, più che per novantanove giusti i quali non hanno bisogno di conversione»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,51-62', 'Luca', 'Mentre stavano compiendosi i giorni in cui sarebbe stato elevato in alto, Gesù prese la ferma decisione di mettersi in cammino verso Gerusalemme e mandò messaggeri davanti a sé. Questi si incamminarono ed entrarono in un villaggio di Samaritani per preparargli l''ingresso. Ma essi non vollero riceverlo, perché era chiaramente in cammino verso Gerusalemme. Quando videro ciò, i discepoli Giacomo e Giovanni dissero: «Signore, vuoi che diciamo che scenda un fuoco dal cielo e li consumi?». Si voltò e li rimproverò. E si misero in cammino verso un altro villaggio. Mentre camminavano per la strada, un tale gli disse: «Ti seguirò dovunque tu vada». E Gesù gli rispose: «Le volpi hanno le loro tane e gli uccelli del cielo i loro nidi, ma il Figlio dell''uomo non ha dove posare il capo». A un altro disse: «Seguimi». E costui rispose: «Signore, permettimi di andare prima a seppellire mio padre». Gli replicò: «Lascia che i morti seppelliscano i loro morti; tu invece va'' e annuncia il regno di Dio». Un altro disse: «Ti seguirò, Signore; prima però lascia che io mi congedi da quelli di casa mia». Ma Gesù gli rispose: «Nessuno che mette mano all''aratro e poi si volge indietro, è adatto per il regno di Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 8,18-22', 'Matteo', 'Vedendo la folla attorno a sé, Gesù ordinò di passare all''altra riva. Allora uno scriba si avvicinò e gli disse: «Maestro, ti seguirò dovunque tu vada». Gli rispose Gesù: «Le volpi hanno le loro tane e gli uccelli del cielo i loro nidi, ma il Figlio dell''uomo non ha dove posare il capo». E un altro dei suoi discepoli gli disse: «Signore, permettimi di andare prima a seppellire mio padre». Ma Gesù gli rispose: «Seguimi, e lascia che i morti seppelliscano i loro morti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 8,23-27', 'Matteo', '[In quel tempo Gesù] salito sulla barca, i suoi discepoli lo seguirono. Ed ecco, avvenne nel mare un grande sconvolgimento, tanto che la barca era coperta dalle onde; ma egli dormiva. Allora si accostarono a lui e lo svegliarono, dicendo: «Salvaci, Signore, siamo perduti!». Ed egli disse loro: «Perché avete paura, gente di poca fede?». Poi si alzò, minacciò i venti e il mare e ci fu grande bonaccia. Tutti, pieni di stupore, dicevano: «Chi è mai costui, che perfino i venti e il mare gli obbediscono?»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 20,24-29', 'Giovanni', 'Tommaso, uno dei Dodici, chiamato Dìdimo, non era con loro quando venne Gesù. Gli dicevano gli altri discepoli: «Abbiamo visto il Signore!». Ma egli disse loro: «Se non vedo nelle sue mani il segno dei chiodi e non metto il mio dito nel segno dei chiodi e non metto la mia mano nel suo fianco, io non credo». Otto giorni dopo i discepoli erano di nuovo in casa e c''era con loro anche Tommaso. Venne Gesù, a porte chiuse, stette in mezzo e disse: «Pace a voi!». Poi disse a Tommaso: «Metti qui il tuo dito e guarda le mie mani; tendi la tua mano e mettila nel mio fianco; e non essere incredulo, ma credente!». Gli rispose Tommaso: «Mio Signore e mio Dio!». Gesù gli disse: «Perché mi hai veduto, tu hai creduto; beati quelli che non hanno visto e hanno creduto!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,1-8', 'Matteo', 'Salito su una barca, Gesù passò all''altra riva e giunse nella sua città. Ed ecco, gli portavano un paralitico disteso su un letto. Gesù, vedendo la loro fede, disse al paralitico: «Coraggio, figlio, ti sono perdonati i peccati». Allora alcuni scribi dissero fra sé: «Costui bestemmia». Ma Gesù, conoscendo i loro pensieri, disse: «Perché pensate cose malvagie nel vostro cuore? Che cosa infatti è più facile: dire "Ti sono perdonati i peccati", oppure dire "àlzati e cammina"? Ma, perché sappiate che il Figlio dell''uomo ha il potere sulla terra di perdonare i peccati: Àlzati - disse allora al paralitico –, prendi il tuo letto e va'' a casa tua». Ed egli si alzò e andò a casa sua. Le folle, vedendo questo, furono prese da timore e resero gloria a Dio che aveva dato un tale potere agli uomini');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,9-13', 'Matteo', 'Gesù vide un uomo, chiamato Matteo, seduto al banco delle imposte e gli disse: «Seguimi». Ed egli si alzò e lo seguì. Mentre sedeva a tavola nella casa, sopraggiunsero molti pubblicani e peccatori e se ne stavano a tavola con Gesù e con i suoi discepoli. Vedendo ciò, i farisei dicevano ai suoi discepoli: «Come mai il vostro maestro mangia insieme ai pubblicani e ai peccatori?». Udito questo, disse: «Non sono i sani che hanno bisogno del medico, ma i malati. Andate a imparare che cosa vuol dire: “misericordia io voglio e non sacrifici”. Io non sono venuto infatti a chiamare i giusti, ma i peccatori»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,14-17', 'Matteo', 'Allora si avvicinarono a Gesù i discepoli di Giovanni e gli dissero: «Perché noi e i farisei digiuniamo molte volte, mentre i tuoi discepoli non digiunano?». E disse loro: «Possono forse gli invitati a nozze essere in lutto finché lo sposo è con loro? Ma verranno giorni quando lo sposo sarà loro tolto, e allora digiuneranno. Nessuno mette un pezzo di stoffa grezza su un vestito vecchio, perché il rattoppo porta via qualcosa dal vestito e lo strappo diventa peggiore. Né si versa vino nuovo in otri vecchi, altrimenti si spaccano gli otri e il vino si spande e gli otri vanno perduti. Ma si versa vino nuovo in otri nuovi, e così l’uno e gli altri si conservano»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 10,1-12.17-20', 'Luca', 'In quel tempo, il Signore designò altri settantadue e li inviò a due a due davanti a sé in ogni città e luogo dove stava per recarsi. Diceva loro: «La messe è abbondante, ma sono pochi gli operai! Pregate dunque il signore della messe, perché mandi operai nella sua messe! Andate: ecco, vi mando come agnelli in mezzo a lupi; non portate borsa, né sacca, né sandali e non fermatevi a salutare nessuno lungo la strada. In qualunque casa entriate, prima dite: "Pace a questa casa!". Se vi sarà un figlio della pace, la vostra pace scenderà su di lui, altrimenti ritornerà su di voi. Restate in quella casa, mangiando e bevendo di quello che hanno, perché chi lavora ha diritto alla sua ricompensa. Non passate da una casa all''altra. Quando entrerete in una città e vi accoglieranno, mangiate quello che vi sarà offerto, guarite i malati che vi si trovano, e dite loro: "È vicino a voi il regno di Dio". Ma quando entrerete in una città e non vi accoglieranno, uscite sulle sue piazze e dite: "Anche la polvere della vostra città, che si è attaccata ai nostri piedi, noi la scuotiamo contro di voi; sappiate però che il regno di Dio è vicino". Io vi dico che, in quel giorno, Sòdoma sarà trattata meno duramente di quella città». I settantadue tornarono pieni di gioia, dicendo: «Signore, anche i demòni si sottomettono a noi nel tuo nome». Egli disse loro: «Vedevo Satana cadere dal cielo come una folgore. Ecco, io vi ho dato il potere di camminare sopra serpenti e scorpioni e sopra tutta la potenza del nemico: nulla potrà danneggiarvi. Non rallegratevi però perché i demòni si sottomettono a voi; rallegratevi piuttosto perché i vostri nomi sono scritti nei cieli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,18-26', 'Matteo', 'In quel tempo, [mentre Gesù parlava,] giunse uno dei capi, gli si prostrò dinanzi e disse: «Mia figlia è morta proprio ora; ma vieni, imponi la tua mano su di lei ed ella vivrà». Gesù si alzò e lo seguì con i suoi discepoli. Ed ecco, una donna, che aveva perdite di sangue da dodici anni, gli si avvicinò alle spalle e toccò il lembo del suo mantello. Diceva infatti tra sé: «Se riuscirò anche solo a toccare il suo mantello, sarò salvata». Gesù si voltò, la vide e disse: «Coraggio, figlia, la tua fede ti ha salvata». E da quell''istante la donna fu salvata. Arrivato poi nella casa del capo e veduti i flautisti e la folla in agitazione, Gesù disse: «Andate via! La fanciulla infatti non è morta, ma dorme». E lo deridevano. Ma dopo che la folla fu cacciata via, egli entrò, le prese la mano e la fanciulla si alzò. E questa notizia si diffuse in tutta quella regione');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,32-38', 'Matteo', 'Presentarono a Gesù un muto indemoniato. E dopo che il demonio fu scacciato, quel muto cominciò a parlare. E le folle, prese da stupore, dicevano: «Non si è mai vista una cosa simile in Israele!». Ma i farisei dicevano: «Egli scaccia i demòni per opera del principe dei demòni». Gesù percorreva tutte le città e i villaggi, insegnando nelle loro sinagoghe, annunciando il vangelo del Regno e guarendo ogni malattia e ogni infermità. Vedendo le folle, ne sentì compassione, perché erano stanche e sfinite come pecore che non hanno pastore. Allora disse ai suoi discepoli: «La messe è abbondante, ma sono pochi gli operai! Pregate dunque il signore della messe perché mandi operai nella sua messe!');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 10,1-7', 'Matteo', 'Chiamati a sé i suoi dodici discepoli, Gesù diede loro potere sugli spiriti impuri per scacciarli e guarire ogni malattia e ogni infermità. I nomi dei dodici apostoli sono: primo, Simone, chiamato Pietro, e Andrea suo fratello; Giacomo, figlio di Zebedèo, e Giovanni suo fratello; Filippo e Bartolomeo; Tommaso e Matteo il pubblicano; Giacomo, figlio di Alfeo, e Taddeo; Simone il Cananeo e Giuda l''Iscariota, colui che poi lo tradì. Questi sono i Dodici che Gesù inviò, ordinando loro: «Non andate fra i pagani e non entrate nelle città dei Samaritani; rivolgetevi piuttosto alle pecore perdute della casa d''Israele. Strada facendo, predicate, dicendo che il regno dei cieli è vicino»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 19,27-29', 'Matteo', 'In quel tempo, Pietro, rispose a Gesù: «Ecco, noi abbiamo lasciato tutto e ti abbiamo seguito; che cosa dunque ne avremo?». E Gesù disse loro: «In verità io vi dico: voi che mi avete seguito, quando il Figlio dell''uomo sarà seduto sul trono della sua gloria, alla rigenerazione del mondo, siederete anche voi su dodici troni a giudicare le dodici tribù d''Israele. Chiunque avrà lasciato case, o fratelli, o sorelle, o padre, o madre, o figli, o campi per il mio nome, riceverà cento volte tanto e avrà in eredità la vita eterna»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 10,16-23', 'Matteo', '[In quel tempo, disse Gesù ai suoi apostoli]: «Ecco: io vi mando come pecore in mezzo a lupi; siate dunque prudenti come i serpenti e semplici come le colombe. Guardatevi dagli uomini, perché vi consegneranno ai tribunali e vi flagelleranno nelle loro sinagoghe; e sarete condotti davanti a governatori e re per causa mia, per dare testimonianza a loro e ai pagani. Ma, quando vi consegneranno, non preoccupatevi di come o di che cosa direte, perché vi sarà dato in quell''ora ciò che dovrete dire: infatti non siete voi a parlare, ma è lo Spirito del Padre vostro che parla in voi. Il fratello farà morire il fratello e il padre il figlio, e i figli si alzeranno ad accusare i genitori e li uccideranno. Sarete odiati da tutti a causa del mio nome. Ma chi avrà perseverato fino alla fine sarà salvato. Quando sarete perseguitati in una città, fuggite in un''altra; in verità io vi dico: non avrete finito di percorrere le città d''Israele, prima che venga il Figlio dell''uomo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 10,24-33', 'Matteo', '[In quel tempo, disse Gesù ai suoi apostoli]: «Un discepolo non è più grande del maestro, né un servo è più grande del suo signore; è sufficiente per il discepolo diventare come il suo maestro e per il servo come il suo signore. Se hanno chiamato Beelzebùl il padrone di casa, quanto più quelli della sua famiglia! Non abbiate dunque paura di loro, poiché nulla vi è di nascosto che non sarà svelato né di segreto che non sarà conosciuto. Quello che io vi dico nelle tenebre voi ditelo nella luce, e quello che ascoltate all''orecchio voi annunciatelo dalle terrazze. E non abbiate paura di quelli che uccidono il corpo, ma non hanno potere di uccidere l''anima; abbiate paura piuttosto di colui che ha il potere di far perire nella Geènna e l''anima e il corpo. Due passeri non si vendono forse per un soldo? Eppure nemmeno uno di essi cadrà a terra senza il volere del Padre vostro. Perfino i capelli del vostro capo sono tutti contati. Non abbiate dunque paura: voi valete più di molti passeri! Perciò chiunque mi riconoscerà davanti agli uomini, anch''io lo riconoscerò davanti al Padre mio che è nei cieli; chi invece mi rinnegherà davanti agli uomini, anch''io lo rinnegherò davanti al Padre mio che è nei cieli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 10,25-37', 'Luca', 'Un dottore della Legge si alzò per mettere alla prova Gesù e chiese: «Maestro, che cosa devo fare per ereditare la vita eterna?». Gesù gli disse: «Che cosa sta scritto nella Legge? Come leggi?». Costui rispose: «Amerai il Signore tuo Dio con tutto il tuo cuore, con tutta la tua anima, con tutta la tua forza e con tutta la tua mente, e il tuo prossimo come te stesso». Gli disse: «Hai risposto bene; fa'' questo e vivrai». Ma quello, volendo giustificarsi, disse a Gesù: «E chi è mio prossimo?». Gesù riprese: «Un uomo scendeva da Gerusalemme a Gèrico e cadde nelle mani dei briganti, che gli portarono via tutto, lo percossero a sangue e se ne andarono, lasciandolo mezzo morto. Per caso, un sacerdote scendeva per quella medesima strada e, quando lo vide, passò oltre. Anche un levìta, giunto in quel luogo, vide e passò oltre. Invece un Samaritano, che era in viaggio, passandogli accanto, vide e ne ebbe compassione. Gli si fece vicino, gli fasciò le ferite, versandovi olio e vino; poi lo caricò sulla sua cavalcatura, lo portò in un albergo e si prese cura di lui. Il giorno seguente, tirò fuori due denari e li diede all''albergatore, dicendo: "Abbi cura di lui; ciò che spenderai in più, te lo pagherò al mio ritorno". Chi di questi tre ti sembra sia stato prossimo di colui che è caduto nelle mani dei briganti?». Quello rispose: «Chi ha avuto compassione di lui». Gesù gli disse: «Va'' e anche tu fa'' così»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 10,34-11,1', 'Matteo', '[In quel tempo, Gesù disse ai suoi apostoli]: «Non crediate che io sia venuto a portare pace sulla terra; sono venuto a portare non pace, ma spada. Sono infatti venuto a separare l’uomo da suo padre e la figlia da sua madre e la nuora da sua suocera; e nemici dell’uomo saranno quelli della sua casa. Chi ama padre o madre più di me, non è degno di me; chi ama figlio o figlia più di me, non è degno di me; chi non prende la propria croce e non mi segue, non è degno di me. Chi avrà tenuto per sé la propria vita, la perderà, e chi avrà perduto la propria vita per causa mia, la troverà. Chi accoglie voi accoglie me, e chi accoglie me accoglie colui che mi ha mandato. Chi accoglie un profeta perché è un profeta, avrà la ricompensa del profeta, e chi accoglie un giusto perché è un giusto, avrà la ricompensa del giusto. Chi avrà dato da bere anche un solo bicchiere d’acqua fresca a uno di questi piccoli perché è un discepolo, in verità io vi dico: non perderà la sua ricompensa». Quando Gesù ebbe terminato di dare queste istruzioni ai suoi dodici discepoli, partì di là per insegnare e predicare nelle loro città');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 11,20-24', 'Matteo', '[In quel tempo, Gesù] si mise a rimproverare le città nelle quali era avvenuta la maggior parte dei suoi prodigi, perché non si erano convertite: «Guai a te, Corazìn! Guai a te, Betsàida! Perché, se a Tiro e a Sidòne fossero avvenuti i prodigi che ci sono stati in mezzo a voi, già da tempo esse, vestite di sacco e cosparse di cenere, si sarebbero convertite. Ebbene, io vi dico: nel giorno del giudizio, Tiro e Sidòne saranno trattate meno duramente di voi. E tu, Cafàrnao, sarai forse innalzata fino al cielo? Fino agli inferi precipiterai! Perché, se a Sòdoma fossero avvenuti i prodigi che ci sono stati in mezzo a te, oggi essa esisterebbe ancora! Ebbene, io vi dico: nel giorno del giudizio, la terra di Sòdoma sarà trattata meno duramente di te!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 11,25-27', 'Matteo', 'In quel tempo, Gesù disse: «Ti rendo lode, Padre, Signore del cielo e della terra, perché hai nascosto queste cose ai sapienti e ai dotti e le hai rivelate ai piccoli. Sì, o Padre, perché così hai deciso nella tua benevolenza. Tutto è stato dato a me dal Padre mio; nessuno conosce il Figlio se non il Padre, e nessuno conosce il Padre se non il Figlio e colui al quale il Figlio vorrà rivelarlo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 11,28-30', 'Matteo', '[In quel tempo, Gesù disse]: «Venite a me, voi tutti che siete stanchi e oppressi, e io vi darò ristoro. Prendete il mio giogo sopra di voi e imparate da me, che sono mite e umile di cuore, e troverete ristoro per la vostra vita. Il mio giogo infatti è dolce e il mio peso leggero»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 12,1-8', 'Matteo', 'In quel tempo, Gesù passò, in giorno di sabato, fra campi di grano e i suoi discepoli ebbero fame e cominciarono a cogliere delle spighe e a mangiarle. Vedendo ciò, i farisei gli dissero: «Ecco, i tuoi discepoli stanno facendo quello che non è lecito fare di sabato».  Ma egli rispose loro: «Non avete letto quello che fece Davide, quando lui e i suoi compagni ebbero fame? Egli entrò nella casa di Dio e mangiarono i pani dell''offerta, che né a lui né ai suoi compagni era lecito mangiare, ma ai soli sacerdoti. O non avete letto nella Legge che nei giorni di sabato i sacerdoti nel tempio vìolano il sabato e tuttavia sono senza colpa? Ora io vi dico che qui vi è uno più grande del tempio. Se aveste compreso che cosa significhi: "Misericordia io voglio e non sacrifici", non avreste condannato persone senza colpa. Perché il Figlio dell''uomo è signore del sabato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 12,14-21', 'Matteo', 'I farisei uscirono e tennero consiglio contro Gesù per farlo morire. Gesù però, avendolo saputo, si allontanò di là. Molti lo seguirono ed egli li guarì tutti e impose loro di non divulgarlo, perché si compisse ciò che era stato detto per mezzo del profeta Isaìa: «Ecco il mio servo, che io ho scelto; il mio amato, nel quale ho posto il mio compiacimento. Porrò il mio spirito sopra di lui e annuncerà alle nazioni la giustizia. Non contesterà né griderà né si udrà nelle piazze la sua voce. Non spezzerà una canna già incrinata, non spegnerà una fiamma smorta, finché non abbia fatto trionfare la giustizia; nel suo nome spereranno le nazioni»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 10,38-42', 'Luca', 'Mentre erano in cammino, Gesù entrò in un villaggio e una donna, di nome Marta, lo ospitò. Ella aveva una sorella, di nome Maria, la quale, seduta ai piedi del Signore, ascoltava la sua parola. Marta invece era distolta per i molti servizi. Allora si fece avanti e disse: «Signore, non t''importa nulla che mia sorella mi abbia lasciata sola a servire? Dille dunque che mi aiuti». Ma il Signore le rispose: «Marta, Marta, tu ti affanni e ti agiti per molte cose, ma di una cosa sola c''è bisogno. Maria ha scelto la parte migliore, che non le sarà tolta»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 20,1-2.11-18', 'Giovanni', 'Il primo giorno della settimana, Maria di Màgdala si recò al sepolcro di mattino, quando era ancora buio, e vide che la pietra era stata tolta dal sepolcro. Corse allora e andò da Simon Pietro e dall''altro discepolo, quello che Gesù amava, e disse loro: «Hanno portato via il Signore dal sepolcro e non sappiamo dove l''hanno posto!». Maria stava all''esterno, vicino al sepolcro, e piangeva. Mentre piangeva, si chinò verso il sepolcro e vide due angeli in bianche vesti, seduti l''uno dalla parte del capo e l''altro dei piedi, dove era stato posto il corpo di Gesù. Ed essi le dissero: «Donna, perché piangi?». Rispose loro: «Hanno portato via il mio Signore e non so dove l''hanno posto». Detto questo, si voltò indietro e vide Gesù, in piedi; ma non sapeva che fosse Gesù. Le disse Gesù: «Donna, perché piangi? Chi cerchi?». Ella, pensando che fosse il custode del giardino, gli disse: «Signore, se l''hai portato via tu, dimmi dove l''hai posto e io andrò a prenderlo». Gesù le disse: «Maria!». Ella si voltò e gli disse in ebraico: «Rabbunì!» - che significa: «Maestro!». Gesù le disse: «Non mi trattenere, perché non sono ancora salito al Padre; ma va'' dai miei fratelli e di'' loro: "Salgo al Padre mio e Padre vostro, Dio mio e Dio vostro"». Maria di Màgdala andò ad annunciare ai discepoli: «Ho visto il Signore!» e ciò che le aveva detto');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,1-9', 'Matteo', 'Quel giorno Gesù uscì di casa e sedette in riva al mare. Si radunò attorno a lui tanta folla che egli salì su una barca e si mise a sedere, mentre tutta la folla stava sulla spiaggia. Egli parlò loro di molte cose con parabole. E disse: «Ecco, il seminatore uscì a seminare. Mentre seminava, una parte cadde lungo la strada; vennero gli uccelli e la mangiarono. Un''altra parte cadde sul terreno sassoso, dove non c''era molta terra; germogliò subito, perché il terreno non era profondo, ma quando spuntò il sole, fu bruciata e, non avendo radici, seccò. Un''altra parte cadde sui rovi, e i rovi crebbero e la soffocarono. Un''altra parte cadde sul terreno buono e diede frutto: il cento, il sessanta, il trenta per uno. Chi ha orecchi, ascolti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 20,20-28', 'Matteo', 'Si avvicinò a Gesù la madre dei figli di Zebedèo con i suoi figli e si prostrò per chiedergli qualcosa. Egli le disse: «Che cosa vuoi?». Gli rispose: «Di'' che questi miei due figli siedano uno alla tua destra e uno alla tua sinistra nel tuo regno». Rispose Gesù: «Voi non sapete quello che chiedete. Potete bere il calice che io sto per bere?». Gli dicono: «Lo possiamo». Ed egli disse loro: «Il mio calice, lo berrete; però sedere alla mia destra e alla mia sinistra non sta a me concederlo: è per coloro per i quali il Padre mio lo ha preparato». Gli altri dieci, avendo sentito, si sdegnarono con i due fratelli. Ma Gesù li chiamò a sé e disse: «Voi sapete che i governanti delle nazioni dóminano su di esse e i capi le opprimono. Tra voi non sarà così; ma chi vuole diventare grande tra voi, sarà vostro servitore e chi vuole essere il primo tra voi, sarà vostro schiavo. Come il Figlio dell''uomo, che non è venuto per farsi servire, ma per servire e dare la propria vita in riscatto per molti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,18-23', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Voi dunque ascoltate la parabola del seminatore. Ogni volta che uno ascolta la parola del Regno e non la comprende, viene il Maligno e ruba ciò che è stato seminato nel suo cuore: questo è il seme seminato lungo la strada. Quello che è stato seminato sul terreno sassoso è colui che ascolta la Parola e l’accoglie subito con gioia, ma non ha in sé radici ed è incostante, sicché, appena giunge una tribolazione o una persecuzione a causa della Parola, egli subito viene meno. Quello seminato tra i rovi è colui che ascolta la Parola, ma la preoccupazione del mondo e la seduzione della ricchezza soffocano la Parola ed essa non dà frutto. Quello seminato sul terreno buono è colui che ascolta la Parola e la comprende; questi dà frutto e produce il cento, il sessanta, il trenta per uno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,24-30', 'Matteo', 'Gesù espose alla folla un’altra parabola, dicendo: «Il regno dei cieli è simile a un uomo che ha seminato del buon seme nel suo campo. Ma, mentre tutti dormivano, venne il suo nemico, seminò della zizzania in mezzo al grano e se ne andò. Quando poi lo stelo crebbe e fece frutto, spuntò anche la zizzania. Allora i servi andarono dal padrone di casa e gli dissero: “Signore, non hai seminato del buon seme nel tuo campo? Da dove viene la zizzania?”. Ed egli rispose loro: “Un nemico ha fatto questo!”. E i servi gli dissero: “Vuoi che andiamo a raccoglierla?”. “No, rispose, perché non succeda che, raccogliendo la zizzania, con essa sradichiate anche il grano. Lasciate che l’una e l’altro crescano insieme fino alla mietitura e al momento della mietitura dirò ai mietitori: Raccogliete prima la zizzania e legatela in fasci per bruciarla; il grano invece riponetelo nel mio granaio”»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 11,1-13', 'Luca', 'Gesù si trovava in un luogo a pregare; quando ebbe finito, uno dei suoi discepoli gli disse: «Signore, insegnaci a pregare, come anche Giovanni ha insegnato ai suoi discepoli». Ed egli disse loro: «Quando pregate, dite: "Padre, sia santificato il tuo nome, venga il tuo regno; dacci ogni giorno il nostro pane quotidiano, e perdona a noi i nostri peccati, anche noi infatti perdoniamo a ogni nostro debitore, e non abbandonarci alla tentazione"». Poi disse loro: «Se uno di voi ha un amico e a mezzanotte va da lui a dirgli: "Amico, prestami tre pani, perché è giunto da me un amico da un viaggio e non ho nulla da offrirgli"; e se quello dall''interno gli risponde: "Non m''importunare, la porta è già chiusa, io e i miei bambini siamo a letto, non posso alzarmi per darti i pani", vi dico che, anche se non si alzerà a darglieli perché è suo amico, almeno per la sua invadenza si alzerà a dargliene quanti gliene occorrono. Ebbene, io vi dico: chiedete e vi sarà dato, cercate e troverete, bussate e vi sarà aperto. Perché chiunque chiede riceve e chi cerca trova e a chi bussa sarà aperto. Quale padre tra voi, se il figlio gli chiede un pesce, gli darà una serpe al posto del pesce? O se gli chiede un uovo, gli darà uno scorpione? Se voi dunque, che siete cattivi, sapete dare cose buone ai vostri figli, quanto più il Padre vostro del cielo darà lo Spirito Santo a quelli che glielo chiedono!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 11,19-27', 'Giovanni', 'Molti Giudei erano venuti da Marta e Maria a consolarle per il fratello. Marta dunque, come udì che veniva Gesù, gli andò incontro; Maria invece stava seduta in casa. Marta disse a Gesù: «Signore, se tu fossi stato qui, mio fratello non sarebbe morto! Ma anche ora so che qualunque cosa tu chiederai a Dio, Dio te la concederà». Gesù le disse: «Tuo fratello risorgerà». Gli rispose Marta: «So che risorgerà nella risurrezione dell''ultimo giorno». Gesù le disse: «Io sono la risurrezione e la vita; chi crede in me, anche se muore, vivrà; chiunque vive e crede in me, non morirà in eterno. Credi questo?». Gli rispose: «Sì, o Signore, io credo che tu sei il Cristo, il Figlio di Dio, colui che viene nel mondo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,36-43', 'Matteo', 'Gesù congedò la folla ed entrò in casa; i suoi discepoli gli si avvicinarono per dirgli: «Spiegaci la parabola della zizzania nel campo». Ed egli rispose: «Colui che semina il buon seme è il Figlio dell''uomo. Il campo è il mondo e il seme buono sono i figli del Regno. La zizzania sono i figli del Maligno e il nemico che l''ha seminata è il diavolo. La mietitura è la fine del mondo e i mietitori sono gli angeli. Come dunque si raccoglie la zizzania e la si brucia nel fuoco, così avverrà alla fine del mondo. Il Figlio dell''uomo manderà i suoi angeli, i quali raccoglieranno dal suo regno tutti gli scandali e tutti quelli che commettono iniquità e li getteranno nella fornace ardente, dove sarà pianto e stridore di denti. Allora i giusti splenderanno come il sole nel regno del Padre loro. Chi ha orecchi, ascolti!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,44-46', 'Matteo', '[In quel tempo Gesù disse ai suoi discepoli]: «Il regno dei cieli è simile a un tesoro nascosto nel campo; un uomo lo trova e lo nasconde; poi va, pieno di gioia, vende tutti i suoi averi e compra quel campo. Il regno dei cieli è simile anche a un mercante che va in cerca di perle preziose; trovata una perla di grande valore, va, vende tutti i suoi averi e la compra»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,47-53', 'Matteo', '[In quel tempo Gesù disse ai suoi discepoli]: «Ancora, il regno dei cieli è simile a una rete gettata nel mare, che raccoglie ogni genere di pesci. Quando è piena, i pescatori la tirano a riva, si mettono a sedere, raccolgono i pesci buoni nei canestri e buttano via i cattivi. Così sarà alla fine del mondo. Verranno gli angeli e separeranno i cattivi dai buoni e li getteranno nella fornace ardente, dove sarà pianto e stridore di denti. Avete compreso tutte queste cose?». Gli risposero: «Sì». Ed egli disse loro: «Per questo ogni scriba, divenuto discepolo del regno dei cieli, è simile a un padrone di casa che estrae dal suo tesoro cose nuove e cose antiche». Terminate queste parabole, Gesù partì di là');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 14,1-12', 'Matteo', 'In quel tempo al tetrarca Erode giunse notizia della fama di Gesù. Egli disse ai suoi cortigiani: «Costui è Giovanni il Battista. È risorto dai morti e per questo ha il potere di fare prodigi!». Erode infatti aveva arrestato Giovanni e lo aveva fatto incatenare e gettare in prigione a causa di Erodìade, moglie di suo fratello Filippo. Giovanni infatti gli diceva: «Non ti è lecito tenerla con te!». Erode, benché volesse farlo morire, ebbe paura della folla perché lo considerava un profeta. Quando fu il compleanno di Erode, la figlia di Erodìade danzò in pubblico e piacque tanto a Erode che egli le promise con giuramento di darle quello che avesse chiesto. Ella, istigata da sua madre, disse: «Dammi qui, su un vassoio, la testa di Giovanni il Battista». Il re si rattristò, ma a motivo del giuramento e dei commensali ordinò che le venisse data e mandò a decapitare Giovanni nella prigione. La sua testa venne portata su un vassoio, fu data alla fanciulla e lei la portò a sua madre. I suoi discepoli si presentarono a prendere il cadavere, lo seppellirono e andarono a informare Gesù');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 12,13-21', 'Luca', 'Uno della folla disse a Gesù: «Maestro, di’ a mio fratello che divida con me l’eredità». Ma egli rispose: «O uomo, chi mi ha costituito giudice o mediatore sopra di voi?». E disse loro: «Fate attenzione e tenetevi lontani da ogni cupidigia perché, anche se uno è nell’abbondanza, la sua vita non dipende da ciò che egli possiede». Poi disse loro una parabola: «La campagna di un uomo ricco aveva dato un raccolto abbondante. Egli ragionava tra sé: “Che farò, poiché non ho dove mettere i miei raccolti? Farò così - disse -: demolirò i miei magazzini e ne costruirò altri più grandi e vi raccoglierò tutto il grano e i miei beni. Poi dirò a me stesso: Anima mia, hai a disposizione molti beni, per molti anni; ripòsati, mangia, bevi e divèrtiti!”. Ma Dio gli disse: “Stolto, questa notte stessa ti sarà richiesta la tua vita. E quello che hai preparato, di chi sarà?”. Così è di chi accumula tesori per sé e non si arricchisce presso Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 14,13-21', 'Matteo', 'Avendo udito questo, Gesù partì di là su una barca e si ritirò in un luogo deserto, in disparte. Ma le folle, avendolo saputo, lo seguirono a piedi dalle città. Sceso dalla barca, egli vide una grande folla, sentì compassione per loro e guarì i loro malati. Sul far della sera, gli si avvicinarono i discepoli e gli dissero: «Il luogo è deserto ed è ormai tardi; congeda la folla perché vada nei villaggi a comprarsi da mangiare». Ma Gesù disse loro: «Non occorre che vadano; voi stessi date loro da mangiare». Gli risposero: «Qui non abbiamo altro che cinque pani e due pesci!». Ed egli disse: «Portatemeli qui». E, dopo aver ordinato alla folla di sedersi sull''erba, prese i cinque pani e i due pesci, alzò gli occhi al cielo, recitò la benedizione, spezzò i pani e li diede ai discepoli, e i discepoli alla folla. Tutti mangiarono a sazietà, e portarono via i pezzi avanzati: dodici ceste piene. Quelli che avevano mangiato erano circa cinquemila uomini, senza contare le donne e i bambini');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 9,2-10', 'Marco', 'Sei giorni dopo, Gesù prese con sé Pietro, Giacomo e Giovanni e li condusse su un alto monte, in disparte, loro soli. Fu trasfigurato davanti a loro e le sue vesti divennero splendenti, bianchissime: nessun lavandaio sulla terra potrebbe renderle così bianche. E apparve loro Elia con Mosè e conversavano con Gesù. Prendendo la parola, Pietro disse a Gesù: «Rabbì, è bello per noi essere qui; facciamo tre capanne, una per te, una per Mosè e una per Elia». Non sapeva infatti che cosa dire, perché erano spaventati. Venne una nube che li coprì con la sua ombra e dalla nube uscì una voce: «Questi è il Figlio mio, l''amato: ascoltatelo!». E improvvisamente, guardandosi attorno, non videro più nessuno, se non Gesù solo, con loro. Mentre scendevano dal monte, ordinò loro di non raccontare ad alcuno ciò che avevano visto, se non dopo che il Figlio dell''uomo fosse risorto dai morti. Ed essi tennero fra loro la cosa, chiedendosi che cosa volesse dire risorgere dai morti');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 15,21-28', 'Matteo', 'Gesù si ritirò verso la zona di Tiro e di Sidòne. Ed ecco una donna Cananea, che veniva da quella regione, si mise a gridare: «Pietà di me, Signore, figlio di Davide! Mia figlia è molto tormentata da un demonio». Ma egli non le rivolse neppure una parola. Allora i suoi discepoli gli si avvicinarono e lo implorarono: «Esaudiscila, perché ci viene dietro gridando!». Egli rispose: «Non sono stato mandato se non alle pecore perdute della casa d''Israele». Ma quella si avvicinò e si prostrò dinanzi a lui, dicendo: «Signore, aiutami!». Ed egli rispose: «Non è bene prendere il pane dei figli e gettarlo ai cagnolini». «È vero, Signore, - disse la donna - eppure i cagnolini mangiano le briciole che cadono dalla tavola dei loro padroni». Allora Gesù le replicò: «Donna, grande è la tua fede! Avvenga per te come desideri». E da quell''istante sua figlia fu guarita');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 16,13-23', 'Matteo', 'Gesù, giunto nella regione di Cesarèa di Filippo, domandò ai suoi discepoli: «La gente, chi dice che sia il Figlio dell''uomo?». Risposero: «Alcuni dicono Giovanni il Battista, altri Elìa, altri Geremìa o qualcuno dei profeti». Disse loro: «Ma voi, chi dite che io sia?». Rispose Simon Pietro: «Tu sei il Cristo, il Figlio del Dio vivente». E Gesù gli disse: «Beato sei tu, Simone, figlio di Giona, perché né carne né sangue te lo hanno rivelato, ma il Padre mio che è nei cieli. E io a te dico: tu sei Pietro e su questa pietra edificherò la mia Chiesa e le potenze degli inferi non prevarranno su di essa. A te darò le chiavi del regno dei cieli: tutto ciò che legherai sulla terra sarà legato nei cieli, e tutto ciò che scioglierai sulla terra sarà sciolto nei cieli». Allora ordinò ai discepoli di non dire ad alcuno che egli era il Cristo. Da allora Gesù cominciò a spiegare ai suoi discepoli che doveva andare a Gerusalemme e soffrire molto da parte degli anziani, dei capi dei sacerdoti e degli scribi, e venire ucciso e risorgere il terzo giorno. Pietro lo prese in disparte e si mise a rimproverarlo dicendo: «Dio non voglia, Signore; questo non ti accadrà mai». Ma egli, voltandosi, disse a Pietro: «Va'' dietro a me, Satana! Tu mi sei di scandalo, perché non pensi secondo Dio, ma secondo gli uomini!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 25,1-13', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli questa parabola]: «Il regno dei cieli sarà simile a dieci vergini che presero le loro lampade e uscirono incontro allo sposo. Cinque di esse erano stolte e cinque sagge; le stolte presero le loro lampade, ma non presero con sé l''olio; le sagge invece, insieme alle loro lampade, presero anche l''olio in piccoli vasi. Poiché lo sposo tardava, si assopirono tutte e si addormentarono. A mezzanotte si alzò un grido: "Ecco lo sposo! Andategli incontro!". Allora tutte quelle vergini si destarono e prepararono le loro lampade. Le stolte dissero alle sagge: "Dateci un po'' del vostro olio, perché le nostre lampade si spengono". Le sagge risposero: "No, perché non venga a mancare a noi e a voi; andate piuttosto dai venditori e compratevene". Ora, mentre quelle andavano a comprare l''olio, arrivò lo sposo e le vergini che erano pronte entrarono con lui alle nozze, e la porta fu chiusa. Più tardi arrivarono anche le altre vergini e incominciarono a dire: "Signore, signore, aprici!". Ma egli rispose: "In verità io vi dico: non vi conosco". Vegliate dunque, perché non sapete né il giorno né l''ora»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 12,24-26', 'Giovanni', '[In quel tempo, Gesù disse ai suoi discepoli]: «In verità, in verità io vi dico: se il chicco di grano, caduto in terra, non muore, rimane solo; se invece muore, produce molto frutto. Chi ama la propria vita, la perde e chi odia la propria vita in questo mondo, la conserverà per la vita eterna. Se uno mi vuole servire, mi segua, e dove sono io, là sarà anche il mio servitore. Se uno serve me, il Padre lo onorerà»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 12,32-48', 'Luca', '[In quel tempo, Gesù disse ai suoi discepoli]: «Non temere, piccolo gregge, perché al Padre vostro è piaciuto dare a voi il Regno. Vendete ciò che possedete e datelo in elemosina; fatevi borse che non invecchiano, un tesoro sicuro nei cieli, dove ladro non arriva e tarlo non consuma. Perché, dov''è il vostro tesoro, là sarà anche il vostro cuore. Siate pronti, con le vesti strette ai fianchi e le lampade accese; siate simili a quelli che aspettano il loro padrone quando torna dalle nozze, in modo che, quando arriva e bussa, gli aprano subito. Beati quei servi che il padrone al suo ritorno troverà ancora svegli; in verità io vi dico, si stringerà le vesti ai fianchi, li farà mettere a tavola e passerà a servirli. E se, giungendo nel mezzo della notte o prima dell''alba, li troverà così, beati loro! Cercate di capire questo: se il padrone di casa sapesse a quale ora viene il ladro, non si lascerebbe scassinare la casa. Anche voi tenetevi pronti perché, nell''ora che non immaginate, viene il Figlio dell''uomo». Allora Pietro disse: «Signore, questa parabola la dici per noi o anche per tutti?». Il Signore rispose: «Chi è dunque l''amministratore fidato e prudente, che il padrone metterà a capo della sua servitù per dare la razione di cibo a tempo debito? Beato quel servo che il padrone, arrivando, troverà ad agire così. Davvero io vi dico che lo metterà a capo di tutti i suoi averi. Ma se quel servo dicesse in cuor suo: "Il mio padrone tarda a venire", e cominciasse a percuotere i servi e le serve, a mangiare, a bere e a ubriacarsi, il padrone di quel servo arriverà un giorno in cui non se l''aspetta e a un''ora che non sa, lo punirà severamente e gli infliggerà la sorte che meritano gli infedeli. Il servo che, conoscendo la volontà del padrone, non avrà disposto o agito secondo la sua volontà, riceverà molte percosse; quello invece che, non conoscendola, avrà fatto cose meritevoli di percosse, ne riceverà poche. A chiunque fu dato molto, molto sarà chiesto; a chi fu affidato molto, sarà richiesto molto di più»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 17,22-27', 'Matteo', 'Mentre si trovavano insieme in Galilea, Gesù disse ai suoi discepoli: «Il Figlio dell''uomo sta per essere consegnato nelle mani degli uomini e lo uccideranno, ma il terzo giorno risorgerà». Ed essi furono molto rattristati. Quando furono giunti a Cafàrnao, quelli che riscuotevano la tassa per il tempio si avvicinarono a Pietro e gli dissero: «Il vostro maestro non paga la tassa?». Rispose: «Sì». Mentre entrava in casa, Gesù lo prevenne dicendo: «Che cosa ti pare, Simone? I re della terra da chi riscuotono le tasse e i tributi? Dai propri figli o dagli estranei?». Rispose: «Dagli estranei». E Gesù replicò: «Quindi i figli sono liberi. Ma, per evitare di scandalizzarli, va'' al mare, getta l''amo e prendi il primo pesce che viene su, aprigli la bocca e vi troverai una moneta d''argento. Prendila e consegnala loro per me e per te»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 18,1-5.10.12-14', 'Matteo', 'In quel momento i discepoli si avvicinarono a Gesù dicendo: «Chi dunque è più grande nel regno dei cieli?». Allora chiamò a sé un bambino, lo pose in mezzo a loro e disse: «In verità io vi dico: se non vi convertirete e non diventerete come i bambini, non entrerete nel regno dei cieli. Perciò chiunque si farà piccolo come questo bambino, costui è il più grande nel regno dei cieli. E chi accoglierà un solo bambino come questo nel mio nome, accoglie me. Guardate di non disprezzare uno solo di questi piccoli, perché io vi dico che i loro angeli nei cieli vedono sempre la faccia del Padre mio che è nei cieli. Che cosa vi pare? Se un uomo ha cento pecore e una di loro si smarrisce, non lascerà le novantanove sui monti e andrà a cercare quella che si è smarrita? In verità io vi dico: se riesce a trovarla, si rallegrerà per quella più che per le novantanove che non si erano smarrite. Così è volontà del Padre vostro che è nei cieli, che neanche uno di questi piccoli si perda»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 18,15-20', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Se il tuo fratello commetterà una colpa contro di te, va’ e ammoniscilo fra te e lui solo; se ti ascolterà, avrai guadagnato il tuo fratello; se non ascolterà, prendi ancora con te una o due persone, perché ogni cosa sia risolta sulla parola di due o tre testimoni. Se poi non ascolterà costoro, dillo alla comunità; e se non ascolterà neanche la comunità, sia per te come il pagano e il pubblicano. In verità io vi dico: tutto quello che legherete sulla terra sarà legato in cielo, e tutto quello che scioglierete sulla terra sarà sciolto in cielo. In verità io vi dico ancora: se due di voi sulla terra si metteranno d’accordo per chiedere qualunque cosa, il Padre mio che è nei cieli gliela concederà. Perché dove sono due o tre riuniti nel mio nome, lì sono io in mezzo a loro»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 19,3-12', 'Matteo', 'Si avvicinarono a Gesù alcuni farisei per metterlo alla prova e gli chiesero: «È lecito a un uomo ripudiare la propria moglie per qualsiasi motivo?». Egli rispose: «Non avete letto che il Creatore da principio li fece maschio e femmina e disse: "Per questo l''uomo lascerà il padre e la madre e si unirà a sua moglie e i due diventeranno una sola carne"? Così non sono più due, ma una sola carne. Dunque l''uomo non divida quello che Dio ha congiunto». Gli domandarono: «Perché allora Mosè ha ordinato di darle l''atto di ripudio e di ripudiarla?». Rispose loro: «Per la durezza del vostro cuore Mosè vi ha permesso di ripudiare le vostre mogli; all''inizio però non fu così. Ma io vi dico: chiunque ripudia la propria moglie, se non in caso di unione illegittima, e ne sposa un''altra, commette adulterio». Gli dissero i suoi discepoli: «Se questa è la situazione dell''uomo rispetto alla donna, non conviene sposarsi». Egli rispose loro: «Non tutti capiscono questa parola, ma solo coloro ai quali è stato concesso. Infatti vi sono eunuchi che sono nati così dal grembo della madre, e ve ne sono altri che sono stati resi tali dagli uomini, e ve ne sono altri ancora che si sono resi tali per il regno dei cieli. Chi può capire, capisca»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 19,13-15', 'Matteo', 'Furono portati a Gesù dei bambini perché imponesse loro le mani e pregasse; ma i discepoli li rimproverarono. Gesù però disse: «Lasciateli, non impedite che i bambini vengano a me; a chi è come loro, infatti, appartiene il regno dei cieli». E, dopo avere imposto loro le mani, andò via di là');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 12,49-53', 'Luca', '[In quel tempo, Gesù disse ai suoi discepoli]: «Sono venuto a gettare fuoco sulla terra, e quanto vorrei che fosse già acceso! Ho un battesimo nel quale sarò battezzato, e come sono angosciato finché non sia compiuto! Pensate che io sia venuto a portare pace sulla terra? No, io vi dico, ma divisione. D’ora innanzi, se in una famiglia vi sono cinque persone, saranno divisi tre contro due e due contro tre; si divideranno padre contro figlio e figlio contro padre, madre contro figlia e figlia contro madre, suocera contro nuora e nuora contro suocera»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 19,16-22', 'Matteo', 'Un tale si avvicinò e gli disse: «Maestro, che cosa devo fare di buono per avere la vita eterna?». Gli rispose: «Perché mi interroghi su ciò che è buono? Buono è uno solo. Se vuoi entrare nella vita, osserva i comandamenti». Gli chiese: «Quali?». Gesù rispose: «Non ucciderai, non commetterai adulterio, non ruberai, non testimonierai il falso, onora il padre e la madre e amerai il prossimo tuo come te stesso». Il giovane gli disse: «Tutte queste cose le ho osservate; che altro mi manca?». Gli disse Gesù: «Se vuoi essere perfetto, va’, vendi quello che possiedi, dallo ai poveri e avrai un tesoro nel cielo; e vieni! Seguimi!». Udita questa parola, il giovane se ne andò, triste; possedeva infatti molte ricchezze');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 19,23-30', 'Matteo', 'Gesù disse ai suoi discepoli: «In verità io vi dico: difficilmente un ricco entrerà nel regno dei cieli. Ve lo ripeto: è più facile che un cammello passi per la cruna di un ago, che un ricco entri nel regno di Dio». A queste parole i discepoli rimasero molto stupiti e dicevano: «Allora, chi può essere salvato?». Gesù li guardò e disse: «Questo è impossibile agli uomini, ma a Dio tutto è possibile». Allora Pietro gli rispose: «Ecco, noi abbiamo lasciato tutto e ti abbiamo seguito; che cosa dunque ne avremo?». E Gesù disse loro: «In verità io vi dico: voi che mi avete seguito, quando il Figlio dell''uomo sarà seduto sul trono della sua gloria, alla rigenerazione del mondo, siederete anche voi su dodici troni a giudicare le dodici tribù d''Israele. Chiunque avrà lasciato case, o fratelli, o sorelle, o padre, o madre, o figli, o campi per il mio nome, riceverà cento volte tanto e avrà in eredità la vita eterna. Molti dei primi saranno ultimi e molti degli ultimi saranno primi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 20,1-16', 'Matteo', 'In quel tempo, Gesù disse ai suoi discepoli questa parabola: «Il regno dei cieli è simile a un padrone di casa che uscì all''alba per prendere a giornata lavoratori per la sua vigna. Si accordò con loro per un denaro al giorno e li mandò nella sua vigna. Uscito poi verso le nove del mattino, ne vide altri che stavano in piazza, disoccupati, e disse loro: "Andate anche voi nella vigna; quello che è giusto ve lo darò". Ed essi andarono. Uscì di nuovo verso mezzogiorno, e verso le tre, e fece altrettanto. Uscito ancora verso le cinque, ne vide altri che se ne stavano lì e disse loro: "Perché ve ne state qui tutto il giorno senza far niente?". Gli risposero: "Perché nessuno ci ha presi a giornata". Ed egli disse loro: "Andate anche voi nella vigna". Quando fu sera, il padrone della vigna disse al suo fattore: "Chiama i lavoratori e da'' loro la paga, incominciando dagli ultimi fino ai primi". Venuti quelli delle cinque del pomeriggio, ricevettero ciascuno un denaro. Quando arrivarono i primi, pensarono che avrebbero ricevuto di più. Ma anch''essi ricevettero ciascuno un denaro. Nel ritirarlo, però, mormoravano contro il padrone dicendo: "Questi ultimi hanno lavorato un''ora soltanto e li hai trattati come noi, che abbiamo sopportato il peso della giornata e il caldo". Ma il padrone, rispondendo a uno di loro, disse: "Amico, io non ti faccio torto. Non hai forse concordato con me per un denaro? Prendi il tuo e vattene. Ma io voglio dare anche a quest''ultimo quanto a te: non posso fare delle mie cose quello che voglio? Oppure tu sei invidioso perché io sono buono?". Così gli ultimi saranno primi e i primi, ultimi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 22,1-14', 'Matteo', 'Gesù, riprese a parlare con parabole [ai capi dei sacerdoti e ai farisei] e disse: «Il regno dei cieli è simile a un re, che fece una festa di nozze per suo figlio. Egli mandò i suoi servi a chiamare gli invitati alle nozze, ma questi non volevano venire. Mandò di nuovo altri servi con quest''ordine: "Dite agli invitati: Ecco, ho preparato il mio pranzo; i miei buoi e gli animali ingrassati sono già uccisi e tutto è pronto; venite alle nozze!". Ma quelli non se ne curarono e andarono chi al proprio campo, chi ai propri affari; altri poi presero i suoi servi, li insultarono e li uccisero. Allora il re si indignò: mandò le sue truppe, fece uccidere quegli assassini e diede alle fiamme la loro città. Poi disse ai suoi servi: "La festa di nozze è pronta, ma gli invitati non erano degni; andate ora ai crocicchi delle strade e tutti quelli che troverete, chiamateli alle nozze". Usciti per le strade, quei servi radunarono tutti quelli che trovarono, cattivi e buoni, e la sala delle nozze si riempì di commensali. Il re entrò per vedere i commensali e lì scorse un uomo che non indossava l''abito nuziale. Gli disse: "Amico, come mai sei entrato qui senza l''abito nuziale?". Quello ammutolì. Allora il re ordinò ai servi: "Legatelo mani e piedi e gettatelo fuori nelle tenebre; là sarà pianto e stridore di denti". Perché molti sono chiamati, ma pochi eletti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 22,34-40', 'Matteo', 'I farisei, avendo udito che Gesù aveva chiuso la bocca ai sadducèi, si riunirono insieme e uno di loro, un dottore della Legge, lo interrogò per metterlo alla prova: «Maestro, nella Legge, qual è il grande comandamento?». Gli rispose: «"Amerai il Signore tuo Dio con tutto il tuo cuore, con tutta la tua anima e con tutta la tua mente". Questo è il grande e primo comandamento. Il secondo poi è simile a quello: "Amerai il tuo prossimo come te stesso". Da questi due comandamenti dipendono tutta la Legge e i Profeti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 1,45-51', 'Giovanni', 'Filippo trovò Natanaèle e gli disse: «Abbiamo trovato colui del quale hanno scritto Mosè, nella Legge, e i Profeti: Gesù, il figlio di Giuseppe, di Nàzaret». Natanaèle gli disse: «Da Nàzaret può venire qualcosa di buono?». Filippo gli rispose: «Vieni e vedi». Gesù intanto, visto Natanaèle che gli veniva incontro, disse di lui: «Ecco davvero un Israelita in cui non c''è falsità». Natanaèle gli domandò: «Come mi conosci?». Gli rispose Gesù: «Prima che Filippo ti chiamasse, io ti ho visto quando eri sotto l''albero di fichi». Gli replicò Natanaèle: «Rabbì, tu sei il Figlio di Dio, tu sei il re d''Israele!». Gli rispose Gesù: «Perché ti ho detto che ti avevo visto sotto l''albero di fichi, tu credi? Vedrai cose più grandi di queste!». Poi gli disse: «In verità, in verità io vi dico: vedrete il cielo aperto e gli angeli di Dio salire e scendere sopra il Figlio dell''uomo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 13,22-30', 'Luca', 'Gesù passava insegnando per città e villaggi, mentre era in cammino verso Gerusalemme. Un tale gli chiese: «Signore, sono pochi quelli che si salvano?». Disse loro: «Sforzatevi di entrare per la porta stretta, perché molti, io vi dico, cercheranno di entrare, ma non ci riusciranno. Quando il padrone di casa si alzerà e chiuderà la porta, voi, rimasti fuori, comincerete a bussare alla porta, dicendo: "Signore, aprici!". Ma egli vi risponderà: "Non so di dove siete". Allora comincerete a dire: "Abbiamo mangiato e bevuto in tua presenza e tu hai insegnato nelle nostre piazze". Ma egli vi dichiarerà: "Voi, non so di dove siete. Allontanatevi da me, voi tutti operatori di ingiustizia!". Là ci sarà pianto e stridore di denti, quando vedrete Abramo, Isacco e Giacobbe e tutti i profeti nel regno di Dio, voi invece cacciati fuori. Verranno da oriente e da occidente, da settentrione e da mezzogiorno e siederanno a mensa nel regno di Dio. Ed ecco, vi sono ultimi che saranno primi, e vi sono primi che saranno ultimi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 23,13-22', 'Matteo', '[In quel tempo, Gesù parlò dicendo]: «Guai a voi, scribi e farisei ipocriti, che chiudete il regno dei cieli davanti alla gente; di fatto non entrate voi, e non lasciate entrare nemmeno quelli che vogliono entrare. Guai a voi, scribi e farisei ipocriti, che percorrete il mare e la terra per fare un solo prosèlito e, quando lo è divenuto, lo rendete degno della Geènna due volte più di voi. Guai a voi, guide cieche, che dite: "Se uno giura per il tempio, non conta nulla; se invece uno giura per l''oro del tempio, resta obbligato". Stolti e ciechi! Che cosa è più grande: l''oro o il tempio che rende sacro l''oro? E dite ancora: "Se uno giura per l''altare, non conta nulla; se invece uno giura per l''offerta che vi sta sopra, resta obbligato". Ciechi! Che cosa è più grande: l''offerta o l''altare che rende sacra l''offerta? Ebbene, chi giura per l''altare, giura per l''altare e per quanto vi sta sopra; e chi giura per il tempio, giura per il tempio e per Colui che lo abita. E chi giura per il cielo, giura per il trono di Dio e per Colui che vi è assiso»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 23,23-26', 'Matteo', '[In quel tempo, Gesù parlò dicendo]: «Guai a voi, scribi e farisei ipocriti, che pagate la decima sulla menta, sull''anéto e sul cumìno, e trasgredite le prescrizioni più gravi della Legge: la giustizia, la misericordia e la fedeltà. Queste invece erano le cose da fare, senza tralasciare quelle. Guide cieche, che filtrate il moscerino e ingoiate il cammello! Guai a voi, scribi e farisei ipocriti, che pulite l''esterno del bicchiere e del piatto, ma all''interno sono pieni di avidità e d''intemperanza. Fariseo cieco, pulisci prima l''interno del bicchiere, perché anche l''esterno diventi pulito!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 23,27-32', 'Matteo', '[In quel tempo, Gesù parlò dicendo]: «Guai a voi, scribi e farisei ipocriti, che assomigliate a sepolcri imbiancati: all’esterno appaiono belli, ma dentro sono pieni di ossa di morti e di ogni marciume. Così anche voi: all’esterno apparite giusti davanti alla gente, ma dentro siete pieni di ipocrisia e di iniquità. Guai a voi, scribi e farisei ipocriti, che costruite le tombe dei profeti e adornate i sepolcri dei giusti, e dite: “Se fossimo vissuti al tempo dei nostri padri, non saremmo stati loro complici nel versare il sangue dei profeti”. Così testimoniate, contro voi stessi, di essere figli di chi uccise i profeti. Ebbene, voi colmate la misura dei vostri padri»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 6,17-29', 'Marco', 'Erode aveva mandato ad arrestare Giovanni e lo aveva messo in prigione a causa di Erodìade, moglie di suo fratello Filippo, perché l''aveva sposata. Giovanni infatti diceva a Erode: «Non ti è lecito tenere con te la moglie di tuo fratello». Per questo Erodìade lo odiava e voleva farlo uccidere, ma non poteva, perché Erode temeva Giovanni, sapendolo uomo giusto e santo, e vigilava su di lui; nell''ascoltarlo restava molto perplesso, tuttavia lo ascoltava volentieri. Venne però il giorno propizio, quando Erode, per il suo compleanno, fece un banchetto per i più alti funzionari della sua corte, gli ufficiali dell''esercito e i notabili della Galilea. Entrata la figlia della stessa Erodìade, danzò e piacque a Erode e ai commensali. Allora il re disse alla fanciulla: «Chiedimi quello che vuoi e io te lo darò». E le giurò più volte: «Qualsiasi cosa mi chiederai, te la darò, fosse anche la metà del mio regno». Ella uscì e disse alla madre: «Che cosa devo chiedere?». Quella rispose: «La testa di Giovanni il Battista». E subito, entrata di corsa dal re, fece la richiesta, dicendo: «Voglio che tu mi dia adesso, su un vassoio, la testa di Giovanni il Battista». Il re, fattosi molto triste, a motivo del giuramento e dei commensali non volle opporle un rifiuto. E subito il re mandò una guardia e ordinò che gli fosse portata la testa di Giovanni. La guardia andò, lo decapitò in prigione e ne portò la testa su un vassoio, la diede alla fanciulla e la fanciulla la diede a sua madre. I discepoli di Giovanni, saputo il fatto, vennero, ne presero il cadavere e lo posero in un sepolcro');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 25,14-30', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli questa parabola]: «Avverrà come a un uomo che, partendo per un viaggio, chiamò i suoi servi e consegnò loro i suoi beni. A uno diede cinque talenti, a un altro due, a un altro uno, secondo le capacità di ciascuno; poi partì. Subito colui che aveva ricevuto cinque talenti andò a impiegarli, e ne guadagnò altri cinque. Così anche quello che ne aveva ricevuti due, ne guadagnò altri due. Colui invece che aveva ricevuto un solo talento, andò a fare una buca nel terreno e vi nascose il denaro del suo padrone. Dopo molto tempo il padrone di quei servi tornò e volle regolare i conti con loro. Si presentò colui che aveva ricevuto cinque talenti e ne portò altri cinque, dicendo: "Signore, mi hai consegnato cinque talenti; ecco, ne ho guadagnati altri cinque". "Bene, servo buono e fedele - gli disse il suo padrone –, sei stato fedele nel poco, ti darò potere su molto; prendi parte alla gioia del tuo padrone". Si presentò poi colui che aveva ricevuto due talenti e disse: "Signore, mi hai consegnato due talenti; ecco, ne ho guadagnati altri due". "Bene, servo buono e fedele - gli disse il suo padrone –, sei stato fedele nel poco, ti darò potere su molto; prendi parte alla gioia del tuo padrone". Si presentò infine anche colui che aveva ricevuto un solo talento e disse: "Signore, so che sei un uomo duro, che mieti dove non hai seminato e raccogli dove non hai sparso. Ho avuto paura e sono andato a nascondere il tuo talento sotto terra: ecco ciò che è tuo". Il padrone gli rispose: "Servo malvagio e pigro, tu sapevi che mieto dove non ho seminato e raccolgo dove non ho sparso; avresti dovuto affidare il mio denaro ai banchieri e così, ritornando, avrei ritirato il mio con l''interesse. Toglietegli dunque il talento, e datelo a chi ha i dieci talenti. Perché a chiunque ha, verrà dato e sarà nell''abbondanza; ma a chi non ha, verrà tolto anche quello che ha. E il servo inutile gettatelo fuori nelle tenebre; là sarà pianto e stridore di denti"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 14,1.7-14', 'Luca', 'Un sabato Gesù si recò a casa di uno dei capi dei farisei per pranzare ed essi stavano a osservarlo. Diceva agli invitati una parabola, notando come sceglievano i primi posti: «Quando sei invitato a nozze da qualcuno, non metterti al primo posto, perché non ci sia un altro invitato più degno di te, e colui che ha invitato te e lui venga a dirti: "Cèdigli il posto!". Allora dovrai con vergogna occupare l''ultimo posto. Invece, quando sei invitato, va'' a metterti all''ultimo posto, perché quando viene colui che ti ha invitato ti dica: "Amico, vieni più avanti!". Allora ne avrai onore davanti a tutti i commensali. Perché chiunque si esalta sarà umiliato, e chi si umilia sarà esaltato». Disse poi a colui che l''aveva invitato: «Quando offri un pranzo o una cena, non invitare i tuoi amici né i tuoi fratelli né i tuoi parenti né i ricchi vicini, perché a loro volta non ti invitino anch''essi e tu abbia il contraccambio. Al contrario, quando offri un banchetto, invita poveri, storpi, zoppi, ciechi; e sarai beato perché non hanno da ricambiarti. Riceverai infatti la tua ricompensa alla risurrezione dei giusti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 4,16-30', 'Luca', '[In quel tempo, Gesù] venne a Nàzaret, dove era cresciuto, e secondo il suo solito, di sabato, entrò nella sinagoga e si alzò a leggere. Gli fu dato il rotolo del profeta Isaìa; aprì il rotolo e trovò il passo dove era scritto: «Lo Spirito del Signore è sopra di me; per questo mi ha consacrato con l’unzione e mi ha mandato a portare ai poveri il lieto annuncio, a proclamare ai prigionieri la liberazione e ai ciechi la vista; a rimettere in libertà gli oppressi e proclamare l’anno di grazia del Signore». Riavvolse il rotolo, lo riconsegnò all’inserviente e sedette. Nella sinagoga, gli occhi di tutti erano fissi su di lui. Allora cominciò a dire loro: «Oggi si è compiuta questa Scrittura che voi avete ascoltato». Tutti gli davano testimonianza ed erano meravigliati delle parole di grazia che uscivano dalla sua bocca e dicevano: «Non è costui il figlio di Giuseppe?». Ma egli rispose loro: «Certamente voi mi citerete questo proverbio: “Medico, cura te stesso. Quanto abbiamo udito che accadde a Cafàrnao, fallo anche qui, nella tua patria!”». Poi aggiunse: «In verità io vi dico: nessun profeta è bene accetto nella sua patria. Anzi, in verità io vi dico: c’erano molte vedove in Israele al tempo di Elìa, quando il cielo fu chiuso per tre anni e sei mesi e ci fu una grande carestia in tutto il paese; ma a nessuna di esse fu mandato Elìa, se non a una vedova a Sarèpta di Sidòne. C’erano molti lebbrosi in Israele al tempo del profeta Elisèo; ma nessuno di loro fu purificato, se non Naamàn, il Siro». All’udire queste cose, tutti nella sinagoga si riempirono di sdegno. Si alzarono e lo cacciarono fuori della città e lo condussero fin sul ciglio del monte, sul quale era costruita la loro città, per gettarlo giù. Ma egli, passando in mezzo a loro, si mise in cammino');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 4,31-37', 'Luca', '[In quel tempo, Gesù] scese a Cafàrnao, città della Galilea, e in giorno di sabato insegnava alla gente. Erano stupiti del suo insegnamento perché la sua parola aveva autorità. Nella sinagoga c''era un uomo che era posseduto da un demonio impuro; cominciò a gridare forte: «Basta! Che vuoi da noi, Gesù Nazareno? Sei venuto a rovinarci? Io so chi tu sei: il santo di Dio!». Gesù gli ordinò severamente: «Taci! Esci da lui!». E il demonio lo gettò a terra in mezzo alla gente e uscì da lui, senza fargli alcun male. Tutti furono presi da timore e si dicevano l''un l''altro: «Che parola è mai questa, che comanda con autorità e potenza agli spiriti impuri ed essi se ne vanno?». E la sua fama si diffondeva in ogni luogo della regione circostante');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 4,38-44', 'Luca', '[Gesù], uscito dalla sinagoga, entrò nella casa di Simone. La suocera di Simone era in preda a una grande febbre e lo pregarono per lei. Si chinò su di lei, comandò alla febbre e la febbre la lasciò. E subito si alzò in piedi e li serviva. Al calar del sole, tutti quelli che avevano infermi affetti da varie malattie li condussero a lui. Ed egli, imponendo su ciascuno le mani, li guariva. Da molti uscivano anche demòni, gridando: «Tu sei il Figlio di Dio!». Ma egli li minacciava e non li lasciava parlare, perché sapevano che era lui il Cristo. Sul far del giorno uscì e si recò in un luogo deserto. Ma le folle lo cercavano, lo raggiunsero e tentarono di trattenerlo perché non se ne andasse via. Egli però disse loro: «È necessario che io annunci la buona notizia del regno di Dio anche alle altre città; per questo sono stato mandato». E andava predicando nelle sinagoghe della Giudea');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 5,33-39', 'Luca', '[In quel tempo, i farisei e i loro scribi dissero a Gesù]: «I discepoli di Giovanni digiunano spesso e fanno preghiere, così pure i discepoli dei farisei; i tuoi invece mangiano e bevono!». Gesù rispose loro: «Potete forse far digiunare gli invitati a nozze quando lo sposo è con loro? Ma verranno giorni quando lo sposo sarà loro tolto: allora in quei giorni digiuneranno». Diceva loro anche una parabola: «Nessuno strappa un pezzo da un vestito nuovo per metterlo su un vestito vecchio; altrimenti il nuovo lo strappa e al vecchio non si adatta il pezzo preso dal nuovo. E nessuno versa vino nuovo in otri vecchi; altrimenti il vino nuovo spaccherà gli otri, si spanderà e gli otri andranno perduti. Il vino nuovo bisogna versarlo in otri nuovi. Nessuno poi che beve il vino vecchio desidera il nuovo, perché dice: "Il vecchio è gradevole!"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,1-5', 'Luca', 'Un sabato Gesù passava fra campi di grano e i suoi discepoli coglievano e mangiavano le spighe, sfregandole con le mani. Alcuni farisei dissero: «Perché fate in giorno di sabato quello che non è lecito?». Gesù rispose loro: «Non avete letto quello che fece Davide, quando lui e i suoi compagni ebbero fame? Come entrò nella casa di Dio, prese i pani dell''offerta, ne mangiò e ne diede ai suoi compagni, sebbene non sia lecito mangiarli se non ai soli sacerdoti?». E diceva loro: «Il Figlio dell''uomo è signore del sabato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 14,25-33', 'Luca', 'In quel tempo, una folla numerosa andava con Gesù. Egli si voltò e disse loro: «Se uno viene a me e non mi ama più di quanto ami suo padre, la madre, la moglie, i figli, i fratelli, le sorelle e perfino la propria vita, non può essere mio discepolo. Colui che non porta la propria croce e non viene dietro a me, non può essere mio discepolo. Chi di voi, volendo costruire una torre, non siede prima a calcolare la spesa e a vedere se ha i mezzi per portarla a termine? Per evitare che, se getta le fondamenta e non è in grado di finire il lavoro, tutti coloro che vedono comincino a deriderlo, dicendo: "Costui ha iniziato a costruire, ma non è stato capace di finire il lavoro". Oppure quale re, partendo in guerra contro un altro re, non siede prima a esaminare se può affrontare con diecimila uomini chi gli viene incontro con ventimila? Se no, mentre l''altro è ancora lontano, gli manda dei messaggeri per chiedere pace. Così chiunque di voi non rinuncia a tutti i suoi averi, non può essere mio discepolo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,6-11', 'Luca', 'Un sabato Gesù entrò nella sinagoga e si mise a insegnare. C''era là un uomo che aveva la mano destra paralizzata. Gli scribi e i farisei lo osservavano per vedere se lo guariva in giorno di sabato, per trovare di che accusarlo. Ma Gesù conosceva i loro pensieri e disse all''uomo che aveva la mano paralizzata: «Àlzati e mettiti qui in mezzo!». Si alzò e si mise in mezzo. Poi Gesù disse loro: «Domando a voi: in giorno di sabato, è lecito fare del bene o fare del male, salvare una vita o sopprimerla?». E guardandoli tutti intorno, disse all''uomo: «Tendi la tua mano!». Egli lo fece e la sua mano fu guarita. Ma essi, fuori di sé dalla collera, si misero a discutere tra loro su quello che avrebbero potuto fare a Gesù');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,12-19', 'Luca', 'In quei giorni, Gesù se ne andò sul monte a pregare e passò tutta la notte pregando Dio. Quando fu giorno, chiamò a sé i suoi discepoli e ne scelse dodici, ai quali diede anche il nome di apostoli: Simone, al quale diede anche il nome di Pietro; Andrea, suo fratello; Giacomo, Giovanni, Filippo, Bartolomeo, Matteo, Tommaso; Giacomo, figlio di Alfeo; Simone, detto Zelota; Giuda, figlio di Giacomo; e Giuda Iscariota, che divenne il traditore. Disceso con loro, si fermò in un luogo pianeggiante. C''era gran folla di suoi discepoli e gran moltitudine di gente da tutta la Giudea, da Gerusalemme e dal litorale di Tiro e di Sidòne, che erano venuti per ascoltarlo ed essere guariti dalle loro malattie; anche quelli che erano tormentati da spiriti impuri venivano guariti. Tutta la folla cercava di toccarlo, perché da lui usciva una forza che guariva tutti');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,20-26', 'Luca', '[In quel tempo, Gesù,] alzàti gli occhi verso i suoi discepoli, diceva: «Beati voi, poveri, perché vostro è il regno di Dio. Beati voi, che ora avete fame, perché sarete saziati. Beati voi, che ora piangete, perché riderete. Beati voi, quando gli uomini vi odieranno e quando vi metteranno al bando e vi insulteranno e disprezzeranno il vostro nome come infame, a causa del Figlio dell''uomo. Rallegratevi in quel giorno ed esultate perché, ecco, la vostra ricompensa è grande nel cielo. Allo stesso modo infatti agivano i loro padri con i profeti. Ma guai a voi, ricchi, perché avete già ricevuto la vostra consolazione. Guai a voi, che ora siete sazi, perché avrete fame. Guai a voi, che ora ridete, perché sarete nel dolore e piangerete. Guai, quando tutti gli uomini diranno bene di voi. Allo stesso modo infatti agivano i loro padri con i falsi profeti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,39-42', 'Luca', 'In quel tempo, Gesù disse ai suoi discepoli una parabola: «Può forse un cieco guidare un altro cieco? Non cadranno tutti e due in un fosso? Un discepolo non è più del maestro; ma ognuno, che sia ben preparato, sarà come il suo maestro. Perché guardi la pagliuzza che è nell''occhio del tuo fratello e non ti accorgi della trave che è nel tuo occhio? Come puoi dire al tuo fratello: "Fratello, lascia che tolga la pagliuzza che è nel tuo occhio", mentre tu stesso non vedi la trave che è nel tuo occhio? Ipocrita! Togli prima la trave dal tuo occhio e allora ci vedrai bene per togliere la pagliuzza dall''occhio del tuo fratello»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 3,13-17', 'Giovanni', '[In quel tempo, Gesù disse a Nicodèmo]: «Nessuno è mai salito al cielo, se non colui che è disceso dal cielo, il Figlio dell''uomo. E come Mosè innalzò il serpente nel deserto, così bisogna che sia innalzato il Figlio dell''uomo, perché chiunque crede in lui abbia la vita eterna. Dio infatti ha tanto amato il mondo da dare il Figlio unigenito, perché chiunque crede in lui non vada perduto, ma abbia la vita eterna. Dio, infatti, non ha mandato il Figlio nel mondo per condannare il mondo, ma perché il mondo sia salvato per mezzo di lui»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 15,1-32', 'Luca', 'Si avvicinavano a Gesù tutti i pubblicani e i peccatori per ascoltarlo. I farisei e gli scribi mormoravano dicendo: «Costui accoglie i peccatori e mangia con loro». Ed egli disse loro questa parabola: «Chi di voi, se ha cento pecore e ne perde una, non lascia le novantanove nel deserto e va in cerca di quella perduta, finché non la trova? Quando l''ha trovata, pieno di gioia se la carica sulle spalle, va a casa, chiama gli amici e i vicini e dice loro: "Rallegratevi con me, perché ho trovato la mia pecora, quella che si era perduta". Io vi dico: così vi sarà gioia nel cielo per un solo peccatore che si converte, più che per novantanove giusti i quali non hanno bisogno di conversione. Oppure, quale donna, se ha dieci monete e ne perde una, non accende la lampada e spazza la casa e cerca accuratamente finché non la trova? E dopo averla trovata, chiama le amiche e le vicine, e dice: "Rallegratevi con me, perché ho trovato la moneta che avevo perduto". Così, io vi dico, vi è gioia davanti agli angeli di Dio per un solo peccatore che si converte». Disse ancora: «Un uomo aveva due figli. Il più giovane dei due disse al padre: "Padre, dammi la parte di patrimonio che mi spetta". Ed egli divise tra loro le sue sostanze. Pochi giorni dopo, il figlio più giovane, raccolte tutte le sue cose, partì per un paese lontano e là sperperò il suo patrimonio vivendo in modo dissoluto. Quando ebbe speso tutto, sopraggiunse in quel paese una grande carestia ed egli cominciò a trovarsi nel bisogno. Allora andò a mettersi al servizio di uno degli abitanti di quella regione, che lo mandò nei suoi campi a pascolare i porci. Avrebbe voluto saziarsi con le carrube di cui si nutrivano i porci; ma nessuno gli dava nulla. Allora ritornò in sé e disse: "Quanti salariati di mio padre hanno pane in abbondanza e io qui muoio di fame! Mi alzerò, andrò da mio padre e gli dirò: Padre, ho peccato verso il Cielo e davanti a te; non sono più degno di essere chiamato tuo figlio. Trattami come uno dei tuoi salariati". Si alzò e tornò da suo padre. Quando era ancora lontano, suo padre lo vide, ebbe compassione, gli corse incontro, gli si gettò al collo e lo baciò. Il figlio gli disse: "Padre, ho peccato verso il Cielo e davanti a te; non sono più degno di essere chiamato tuo figlio". Ma il padre disse ai servi: "Presto, portate qui il vestito più bello e fateglielo indossare, mettetegli l''anello al dito e i sandali ai piedi. Prendete il vitello grasso, ammazzatelo, mangiamo e facciamo festa, perché questo mio figlio era morto ed è tornato in vita, era perduto ed è stato ritrovato". E cominciarono a far festa. Il figlio maggiore si trovava nei campi. Al ritorno, quando fu vicino a casa, udì la musica e le danze; chiamò uno dei servi e gli domandò che cosa fosse tutto questo. Quello gli rispose: "Tuo fratello è qui e tuo padre ha fatto ammazzare il vitello grasso, perché lo ha riavuto sano e salvo". Egli si indignò, e non voleva entrare. Suo padre allora uscì a supplicarlo. Ma egli rispose a suo padre: "Ecco, io ti servo da tanti anni e non ho mai disobbedito a un tuo comando, e tu non mi hai mai dato un capretto per far festa con i miei amici. Ma ora che è tornato questo tuo figlio, il quale ha divorato le tue sostanze con le prostitute, per lui hai ammazzato il vitello grasso". Gli rispose il padre: "Figlio, tu sei sempre con me e tutto ciò che è mio è tuo; ma bisognava far festa e rallegrarsi, perché questo tuo fratello era morto ed è tornato in vita, era perduto ed è stato ritrovato"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 7,1-10', 'Luca', 'Gesù, quando ebbe terminato di rivolgere tutte le sue parole al popolo che stava in ascolto, entrò in Cafàrnao. Il servo di un centurione era ammalato e stava per morire. Il centurione l''aveva molto caro. Perciò, avendo udito parlare di Gesù, gli mandò alcuni anziani dei Giudei a pregarlo di venire e di salvare il suo servo. Costoro, giunti da Gesù, lo supplicavano con insistenza: «Egli merita che tu gli conceda quello che chiede - dicevano –, perché ama il nostro popolo ed è stato lui a costruirci la sinagoga». Gesù si incamminò con loro. Non era ormai molto distante dalla casa, quando il centurione mandò alcuni amici a dirgli: «Signore, non disturbarti! Io non sono degno che tu entri sotto il mio tetto; per questo io stesso non mi sono ritenuto degno di venire da te; ma di'' una parola e il mio servo sarà guarito. Anch''io infatti sono nella condizione di subalterno e ho dei soldati sotto di me e dico a uno: "Va''!", ed egli va; e a un altro: "Vieni!", ed egli viene; e al mio servo: "Fa'' questo!", ed egli lo fa». All''udire questo, Gesù lo ammirò e, volgendosi alla folla che lo seguiva, disse: «Io vi dico che neanche in Israele ho trovato una fede così grande!». E gli inviati, quando tornarono a casa, trovarono il servo guarito');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 7,11-17', 'Luca', 'Gesù si recò in una città chiamata Nain, e con lui camminavano i suoi discepoli e una grande folla. Quando fu vicino alla porta della città, ecco, veniva portato alla tomba un morto, unico figlio di una madre rimasta vedova; e molta gente della città era con lei. Vedendola, il Signore fu preso da grande compassione per lei e le disse: «Non piangere!». Si avvicinò e toccò la bara, mentre i portatori si fermarono. Poi disse: «Ragazzo, dico a te, àlzati!». Il morto si mise seduto e cominciò a parlare. Ed egli lo restituì a sua madre. Tutti furono presi da timore e glorificavano Dio, dicendo: «Un grande profeta è sorto tra noi», e: «Dio ha visitato il suo popolo». Questa fama di lui si diffuse per tutta quanta la Giudea e in tutta la regione circostante');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 7,31-35', 'Luca', '[In quel tempo, il Signore disse]: «A chi posso paragonare la gente di questa generazione? A chi è simile? È simile a bambini che, seduti in piazza, gridano gli uni agli altri così: “Vi abbiamo suonato il flauto e non avete ballato, abbiamo cantato un lamento e non avete pianto!”. È venuto infatti Giovanni il Battista, che non mangia pane e non beve vino, e voi dite: “È indemoniato”. È venuto il Figlio dell’uomo, che mangia e beve, e voi dite: “Ecco un mangione e un beone, un amico di pubblicani e di peccatori!”. Ma la Sapienza è stata riconosciuta giusta da tutti i suoi figli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 7,36-50', 'Luca', 'Uno dei farisei invitò Gesù a mangiare da lui. Egli entrò nella casa del fariseo e si mise a tavola. Ed ecco, una donna, una peccatrice di quella città, saputo che si trovava nella casa del fariseo, portò un vaso di profumo; stando dietro, presso i piedi di lui, piangendo, cominciò a bagnarli di lacrime, poi li asciugava con i suoi capelli, li baciava e li cospargeva di profumo. Vedendo questo, il fariseo che l’aveva invitato disse tra sé: «Se costui fosse un profeta, saprebbe chi è, e di quale genere è la donna che lo tocca: è una peccatrice!». Gesù allora gli disse: «Simone, ho da dirti qualcosa». Ed egli rispose: «Di’ pure, maestro». «Un creditore aveva due debitori: uno gli doveva cinquecento denari, l’altro cinquanta. Non avendo essi di che restituire, condonò il debito a tutti e due. Chi di loro dunque lo amerà di più?». Simone rispose: «Suppongo sia colui al quale ha condonato di più». Gli disse Gesù: «Hai giudicato bene». E, volgendosi verso la donna, disse a Simone: «Vedi questa donna? Sono entrato in casa tua e tu non mi hai dato l’acqua per i piedi; lei invece mi ha bagnato i piedi con le lacrime e li ha asciugati con i suoi capelli. Tu non mi hai dato un bacio; lei invece, da quando sono entrato, non ha cessato di baciarmi i piedi. Tu non hai unto con olio il mio capo; lei invece mi ha cosparso i piedi di profumo. Per questo io ti dico: sono perdonati i suoi molti peccati, perché ha molto amato. Invece colui al quale si perdona poco, ama poco». Poi disse a lei: «I tuoi peccati sono perdonati». Allora i commensali cominciarono a dire tra sé: «Chi è costui che perdona anche i peccati?». Ma egli disse alla donna: «La tua fede ti ha salvata; va’ in pace!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 8,1-3', 'Luca', 'Gesù se ne andava per città e villaggi, predicando e annunciando la buona notizia del regno di Dio. C''erano con lui i Dodici e alcune donne che erano state guarite da spiriti cattivi e da infermità: Maria, chiamata Maddalena, dalla quale erano usciti sette demòni; Giovanna, moglie di Cuza, amministratore di Erode; Susanna e molte altre, che li servivano con i loro beni');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 16,1-13', 'Luca', 'Gesù diceva ai discepoli: «Un uomo ricco aveva un amministratore, e questi fu accusato dinanzi a lui di sperperare i suoi averi. Lo chiamò e gli disse: "Che cosa sento dire di te? Rendi conto della tua amministrazione, perché non potrai più amministrare". L''amministratore disse tra sé: "Che cosa farò, ora che il mio padrone mi toglie l''amministrazione? Zappare, non ne ho la forza; mendicare, mi vergogno. So io che cosa farò perché, quando sarò stato allontanato dall''amministrazione, ci sia qualcuno che mi accolga in casa sua". Chiamò uno per uno i debitori del suo padrone e disse al primo: "Tu quanto devi al mio padrone?". Quello rispose: "Cento barili d''olio". Gli disse: "Prendi la tua ricevuta, siediti subito e scrivi cinquanta". Poi disse a un altro: "Tu quanto devi?". Rispose: "Cento misure di grano". Gli disse: "Prendi la tua ricevuta e scrivi ottanta". Il padrone lodò quell''amministratore disonesto, perché aveva agito con scaltrezza. I figli di questo mondo, infatti, verso i loro pari sono più scaltri dei figli della luce. Ebbene, io vi dico: fatevi degli amici con la ricchezza disonesta, perché, quando questa verrà a mancare, essi vi accolgano nelle dimore eterne. Chi è fedele in cose di poco conto, è fedele anche in cose importanti; e chi è disonesto in cose di poco conto, è disonesto anche in cose importanti. Se dunque non siete stati fedeli nella ricchezza disonesta, chi vi affiderà quella vera? E se non siete stati fedeli nella ricchezza altrui, chi vi darà la vostra? Nessun servitore può servire due padroni, perché o odierà l''uno e amerà l''altro, oppure si affezionerà all''uno e disprezzerà l''altro. Non potete servire Dio e la ricchezza»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 8,16-18', 'Luca', '[In quel tempo, Gesù disse alla folla]: «Nessuno accende una lampada e la copre con un vaso o la mette sotto un letto, ma la pone su un candelabro, perché chi entra veda la luce. Non c''è nulla di segreto che non sia manifestato, nulla di nascosto che non sia conosciuto e venga in piena luce. Fate attenzione dunque a come ascoltate; perché a chi ha, sarà dato, ma a chi non ha, sarà tolto anche ciò che crede di avere»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 8,19-21', 'Luca', 'Andarono da Gesù la madre e i suoi fratelli, ma non potevano avvicinarlo a causa della folla. Gli fecero sapere: «Tua madre e i tuoi fratelli stanno fuori e desiderano vederti». Ma egli rispose loro: «Mia madre e miei fratelli sono questi: coloro che ascoltano la parola di Dio e la mettono in pratica»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,1-6', 'Luca', '[In quel tempo, Gesù] convocò i Dodici e diede loro forza e potere su tutti i demòni e di guarire le malattie. E li mandò ad annunciare il regno di Dio e a guarire gli infermi. Disse loro: «Non prendete nulla per il viaggio, né bastone, né sacca, né pane, né denaro, e non portatevi due tuniche. In qualunque casa entriate, rimanete là, e di là poi ripartite. Quanto a coloro che non vi accolgono, uscite dalla loro città e scuotete la polvere dai vostri piedi come testimonianza contro di loro». Allora essi uscirono e giravano di villaggio in villaggio, ovunque annunciando la buona notizia e operando guarigioni');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,7-9', 'Luca', 'Il tetràrca Erode sentì parlare di tutti questi avvenimenti e non sapeva che cosa pensare, perché alcuni dicevano: «Giovanni è risorto dai morti», altri: «È apparso Elìa», e altri ancora: «È risorto uno degli antichi profeti». Ma Erode diceva: «Giovanni, l''ho fatto decapitare io; chi è dunque costui, del quale sento dire queste cose?». E cercava di vederlo');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,18-22', 'Luca', 'Un giorno Gesù si trovava in un luogo solitario a pregare. I discepoli erano con lui ed egli pose loro questa domanda: «Le folle, chi dicono che io sia?». Essi risposero: «Giovanni il Battista; altri dicono Elìa; altri uno degli antichi profeti che è risorto». Allora domandò loro: «Ma voi, chi dite che io sia?». Pietro rispose: «Il Cristo di Dio». Egli ordinò loro severamente di non riferirlo ad alcuno. «Il Figlio dell''uomo - disse - deve soffrire molto, essere rifiutato dagli anziani, dai capi dei sacerdoti e dagli scribi, venire ucciso e risorgere il terzo giorno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,43b-45', 'Luca', 'Mentre tutti erano ammirati di tutte le cose che faceva, Gesù disse ai suoi discepoli: «Mettetevi bene in mente queste parole: il Figlio dell''uomo sta per essere consegnato nelle mani degli uomini». Essi però non capivano queste parole: restavano per loro così misteriose che non ne coglievano il senso, e avevano timore di interrogarlo su questo argomento');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,46-50', 'Luca', 'In quel tempo, nacque una discussione tra i discepoli, chi di loro fosse più grande. Allora Gesù, conoscendo il pensiero del loro cuore, prese un bambino, se lo mise vicino e disse loro: «Chi accoglierà questo bambino nel mio nome, accoglie me; e chi accoglie me, accoglie colui che mi ha mandato. Chi infatti è il più piccolo fra tutti voi, questi è grande». Giovanni prese la parola dicendo: «Maestro, abbiamo visto uno che scacciava demòni nel tuo nome e glielo abbiamo impedito, perché non ti segue insieme con noi». Ma Gesù gli rispose: «Non lo impedite, perché chi non è contro di voi, è per voi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,51-56', 'Luca', 'Mentre stavano compiendosi i giorni in cui sarebbe stato elevato in alto, Gesù prese la ferma decisione di mettersi in cammino verso Gerusalemme e mandò messaggeri davanti a sé. Questi si incamminarono ed entrarono in un villaggio di Samaritani per preparargli l''ingresso. Ma essi non vollero riceverlo, perché era chiaramente in cammino verso Gerusalemme. Quando videro ciò, i discepoli Giacomo e Giovanni dissero: «Signore, vuoi che diciamo che scenda un fuoco dal cielo e li consumi?». Si voltò e li rimproverò. E si misero in cammino verso un altro villaggio');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 18,1-5.10', 'Matteo', 'In quel momento i discepoli si avvicinarono a Gesù dicendo: "Chi dunque è più grande nel regno dei cieli?". Allora chiamò a sé un bambino, lo pose in mezzo a loro e disse: "In verità io vi dico: se non vi convertirete e non diventerete come i bambini, non entrerete nel regno dei cieli. Perciò chiunque si farà piccolo come questo bambino, costui è il più grande nel regno dei cieli. E chi accoglierà un solo bambino come questo nel mio nome, accoglie me. Guardate di non disprezzare uno solo di questi piccoli, perché io vi dico che i loro angeli nei cieli vedono sempre la faccia del Padre mio che è nei cieli.');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 10,1-12', 'Luca', 'Il Signore designò altri settantadue e li inviò a due a due davanti a sé in ogni città e luogo dove stava per recarsi. Diceva loro: «La messe è abbondante, ma sono pochi gli operai! Pregate dunque il signore della messe, perché mandi operai nella sua messe! Andate: ecco, vi mando come agnelli in mezzo a lupi; non portate borsa, né sacca, né sandali e non fermatevi a salutare nessuno lungo la strada. In qualunque casa entriate, prima dite: “Pace a questa casa!”. Se vi sarà un figlio della pace, la vostra pace scenderà su di lui, altrimenti ritornerà su di voi. Restate in quella casa, mangiando e bevendo di quello che hanno, perché chi lavora ha diritto alla sua ricompensa. Non passate da una casa all’altra. Quando entrerete in una città e vi accoglieranno, mangiate quello che vi sarà offerto, guarite i malati che vi si trovano, e dite loro: “È vicino a voi il regno di Dio”. Ma quando entrerete in una città e non vi accoglieranno, uscite sulle sue piazze e dite: “Anche la polvere della vostra città, che si è attaccata ai nostri piedi, noi la scuotiamo contro di voi; sappiate però che il regno di Dio è vicino”. Io vi dico che, in quel giorno, Sòdoma sarà trattata meno duramente di quella città»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 10,17-24', 'Luca', 'I settantadue tornarono pieni di gioia, dicendo: «Signore, anche i demòni si sottomettono a noi nel tuo nome». Egli disse loro: «Vedevo Satana cadere dal cielo come una folgore. Ecco, io vi ho dato il potere di camminare sopra serpenti e scorpioni e sopra tutta la potenza del nemico: nulla potrà danneggiarvi. Non rallegratevi però perché i demòni si sottomettono a voi; rallegratevi piuttosto perché i vostri nomi sono scritti nei cieli». In quella stessa ora Gesù esultò di gioia nello Spirito Santo e disse: «Ti rendo lode, o Padre, Signore del cielo e della terra, perché hai nascosto queste cose ai sapienti e ai dotti e le hai rivelate ai piccoli. Sì, o Padre, perché così hai deciso nella tua benevolenza. Tutto è stato dato a me dal Padre mio e nessuno sa chi è il Figlio se non il Padre, né chi è il Padre se non il Figlio e colui al quale il Figlio vorrà rivelarlo». E, rivolto ai discepoli, in disparte, disse: «Beati gli occhi che vedono ciò che voi vedete. Io vi dico che molti profeti e re hanno voluto vedere ciò che voi guardate, ma non lo videro, e ascoltare ciò che voi ascoltate, ma non lo ascoltarono»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 17,5-10', 'Luca', 'Gli apostoli dissero al Signore: «Accresci in noi la fede!». Il Signore rispose: «Se aveste fede quanto un granello di senape, potreste dire a questo gelso: "Sràdicati e vai a piantarti nel mare", ed esso vi obbedirebbe. Chi di voi, se ha un servo ad arare o a pascolare il gregge, gli dirà, quando rientra dal campo: "Vieni subito e mettiti a tavola"? Non gli dirà piuttosto: "Prepara da mangiare, stríngiti le vesti ai fianchi e sérvimi, finché avrò mangiato e bevuto, e dopo mangerai e berrai tu"? Avrà forse gratitudine verso quel servo, perché ha eseguito gli ordini ricevuti? Così anche voi, quando avrete fatto tutto quello che vi è stato ordinato, dite: "Siamo servi inutili. Abbiamo fatto quanto dovevamo fare"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 11,1-4', 'Luca', 'Gesù si trovava in un luogo a pregare; quando ebbe finito, uno dei suoi discepoli gli disse: «Signore, insegnaci a pregare, come anche Giovanni ha insegnato ai suoi discepoli». Ed egli disse loro: «Quando pregate, dite: Padre, sia santificato il tuo nome, venga il tuo regno; dacci ogni giorno il nostro pane quotidiano, e perdona a noi i nostri peccati, anche noi infatti perdoniamo a ogni nostro debitore, e non abbandonarci alla tentazione»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 11,5-13', 'Luca', '[In quel tempo, Gesù disse ai discepoli]: «Se uno di voi ha un amico e a mezzanotte va da lui a dirgli: "Amico, prestami tre pani, perché è giunto da me un amico da un viaggio e non ho nulla da offrirgli", e se quello dall''interno gli risponde: "Non m''importunare, la porta è già chiusa, io e i miei bambini siamo a letto, non posso alzarmi per darti i pani", vi dico che, anche se non si alzerà a darglieli perché è suo amico, almeno per la sua invadenza si alzerà a dargliene quanti gliene occorrono. Ebbene, io vi dico: chiedete e vi sarà dato, cercate e troverete, bussate e vi sarà aperto. Perché chiunque chiede riceve e chi cerca trova e a chi bussa sarà aperto. Quale padre tra voi, se il figlio gli chiede un pesce, gli darà una serpe al posto del pesce? O se gli chiede un uovo, gli darà uno scorpione? Se voi dunque, che siete cattivi, sapete dare cose buone ai vostri figli, quanto più il Padre vostro del cielo darà lo Spirito Santo a quelli che glielo chiedono!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 11,15-26', 'Luca', 'In quel tempo, [dopo che Gesù ebbe scacciato un demonio,] alcuni dissero: «È per mezzo di Beelzebùl, capo dei demòni, che egli scaccia i demòni». Altri poi, per metterlo alla prova, gli domandavano un segno dal cielo. Egli, conoscendo le loro intenzioni, disse: «Ogni regno diviso in se stesso va in rovina e una casa cade sull''altra. Ora, se anche Satana è diviso in se stesso, come potrà stare in piedi il suo regno? Voi dite che io scaccio i demòni per mezzo di Beelzebùl. Ma se io scaccio i demòni per mezzo di Beelzebùl, i vostri figli per mezzo di chi li scacciano? Per questo saranno loro i vostri giudici. Se invece io scaccio i demòni con il dito di Dio, allora è giunto a voi il regno di Dio. Quando un uomo forte, bene armato, fa la guardia al suo palazzo, ciò che possiede è al sicuro. Ma se arriva uno più forte di lui e lo vince, gli strappa via le armi nelle quali confidava e ne spartisce il bottino. Chi non è con me, è contro di me, e chi non raccoglie con me, disperde. Quando lo spirito impuro esce dall''uomo, si aggira per luoghi deserti cercando sollievo e, non trovandone, dice: "Ritornerò nella mia casa, da cui sono uscito". Venuto, la trova spazzata e adorna. Allora va, prende altri sette spiriti peggiori di lui, vi entrano e vi prendono dimora. E l''ultima condizione di quell''uomo diventa peggiore della prima»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 11,27-28', 'Luca', 'In quel tempo, mentre Gesù parlava, una donna dalla folla alzò la voce e gli disse: «Beato il grembo che ti ha portato e il seno che ti ha allattato!». Ma egli disse: «Beati piuttosto coloro che ascoltano la parola di Dio e la osservano!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 17,11-19', 'Luca', 'Lungo il cammino verso Gerusalemme, Gesù attraversava la Samarìa e la Galilea. Entrando in un villaggio, gli vennero incontro dieci lebbrosi, che si fermarono a distanza e dissero ad alta voce: «Gesù, maestro, abbi pietà di noi!». Appena li vide, Gesù disse loro: «Andate a presentarvi ai sacerdoti». E mentre essi andavano, furono purificati. Uno di loro, vedendosi guarito, tornò indietro lodando Dio a gran voce, e si prostrò davanti a Gesù, ai suoi piedi, per ringraziarlo. Era un Samaritano. Ma Gesù osservò: «Non ne sono stati purificati dieci? E gli altri nove dove sono? Non si è trovato nessuno che tornasse indietro a rendere gloria a Dio, all''infuori di questo straniero?». E gli disse: «Àlzati e va''; la tua fede ti ha salvato!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 11,37-41', 'Luca', 'Mentre Gesù stava parlando, un fariseo lo invitò a pranzo. Egli andò e si mise a tavola. Il fariseo vide e si meravigliò che non avesse fatto le abluzioni prima del pranzo. Allora il Signore gli disse: «Voi farisei pulite l''esterno del bicchiere e del piatto, ma il vostro interno è pieno di avidità e di cattiveria. Stolti! Colui che ha fatto l''esterno non ha forse fatto anche l''interno? Date piuttosto in elemosina quello che c''è dentro, ed ecco, per voi tutto sarà puro»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 11,42-46', 'Luca', '[In quel tempo, il Signore disse]: «Guai a voi, farisei, che pagate la decima sulla menta, sulla ruta e su tutte le erbe, e lasciate da parte la giustizia e l''amore di Dio. Queste invece erano le cose da fare, senza trascurare quelle. Guai a voi, farisei, che amate i primi posti nelle sinagoghe e i saluti sulle piazze. Guai a voi, perché siete come quei sepolcri che non si vedono e la gente vi passa sopra senza saperlo». Intervenne uno dei dottori della Legge e gli disse: «Maestro, dicendo questo, tu offendi anche noi». Egli rispose: «Guai anche a voi, dottori della Legge, che caricate gli uomini di pesi insopportabili, e quei pesi voi non li toccate nemmeno con un dito!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 11,47-54', 'Luca', '[In quel tempo, il Signore disse]: «Guai a voi, che costruite i sepolcri dei profeti, e i vostri padri li hanno uccisi. Così voi testimoniate e approvate le opere dei vostri padri: essi li uccisero e voi costruite. Per questo la sapienza di Dio ha detto: "Manderò loro profeti e apostoli ed essi li uccideranno e perseguiteranno", perché a questa generazione sia chiesto conto del sangue di tutti i profeti, versato fin dall''inizio del mondo: dal sangue di Abele fino al sangue di Zaccarìa, che fu ucciso tra l''altare e il santuario. Sì, io vi dico, ne sarà chiesto conto a questa generazione. Guai a voi, dottori della Legge, che avete portato via la chiave della conoscenza; voi non siete entrati, e a quelli che volevano entrare voi l''avete impedito». Quando fu uscito di là, gli scribi e i farisei cominciarono a trattarlo in modo ostile e a farlo parlare su molti argomenti, tendendogli insidie, per sorprenderlo in qualche parola uscita dalla sua stessa bocca');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 12,8-12', 'Luca', '[In quel tempo, Gesù disse ai suoi discepoli]: «Io vi dico: chiunque mi riconoscerà davanti agli uomini, anche il Figlio dell''uomo lo riconoscerà davanti agli angeli di Dio; ma chi mi rinnegherà davanti agli uomini, sarà rinnegato davanti agli angeli di Dio. Chiunque parlerà contro il Figlio dell''uomo, gli sarà perdonato; ma a chi bestemmierà lo Spirito Santo, non sarà perdonato. Quando vi porteranno davanti alle sinagoghe, ai magistrati e alle autorità, non preoccupatevi di come o di che cosa discolparvi, o di che cosa dire, perché lo Spirito Santo vi insegnerà in quel momento ciò che bisogna dire»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 18,1-8', 'Luca', 'In quel tempo, Gesù diceva ai suoi discepoli una parabola sulla necessità di pregare sempre, senza stancarsi mai: «In una città viveva un giudice, che non temeva Dio né aveva riguardo per alcuno. In quella città c''era anche una vedova, che andava da lui e gli diceva: "Fammi giustizia contro il mio avversario". Per un po'' di tempo egli non volle; ma poi disse tra sé: "Anche se non temo Dio e non ho riguardo per alcuno, dato che questa vedova mi dà tanto fastidio, le farò giustizia perché non venga continuamente a importunarmi"». E il Signore soggiunse: «Ascoltate ciò che dice il giudice disonesto. E Dio non farà forse giustizia ai suoi eletti, che gridano giorno e notte verso di lui? Li farà forse aspettare a lungo? Io vi dico che farà loro giustizia prontamente. Ma il Figlio dell''uomo, quando verrà, troverà la fede sulla terra?»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 12,35-38', 'Luca', '[In quel tempo, Gesù disse ai suoi discepoli]: «Siate pronti, con le vesti strette ai fianchi e le lampade accese; siate simili a quelli che aspettano il loro padrone quando torna dalle nozze, in modo che, quando arriva e bussa, gli aprano subito. Beati quei servi che il padrone al suo ritorno troverà ancora svegli; in verità io vi dico, si stringerà le vesti ai fianchi, li farà mettere a tavola e passerà a servirli. E se, giungendo nel mezzo della notte o prima dell’alba, li troverà così, beati loro!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 12,39-48', 'Luca', '[In quel tempo, Gesù disse ai suoi discepoli]: «Cercate di capire questo: se il padrone di casa sapesse a quale ora viene il ladro, non si lascerebbe scassinare la casa. Anche voi tenetevi pronti perché, nell''ora che non immaginate, viene il Figlio dell''uomo». Allora Pietro disse: «Signore, questa parabola la dici per noi o anche per tutti?». Il Signore rispose: «Chi è dunque l''amministratore fidato e prudente, che il padrone metterà a capo della sua servitù per dare la razione di cibo a tempo debito? Beato quel servo che il padrone, arrivando, troverà ad agire così. Davvero io vi dico che lo metterà a capo di tutti i suoi averi. Ma se quel servo dicesse in cuor suo: "Il mio padrone tarda a venire", e cominciasse a percuotere i servi e le serve, a mangiare, a bere e a ubriacarsi, il padrone di quel servo arriverà un giorno in cui non se l''aspetta e a un''ora che non sa, lo punirà severamente e gli infliggerà la sorte che meritano gli infedeli. Il servo che, conoscendo la volontà del padrone, non avrà disposto o agito secondo la sua volontà, riceverà molte percosse; quello invece che, non conoscendola, avrà fatto cose meritevoli di percosse, ne riceverà poche. A chiunque fu dato molto, molto sarà chiesto; a chi fu affidato molto, sarà richiesto molto di più»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 12,54-59', 'Luca', 'Gesù diceva alle folle: «Quando vedete una nuvola salire da ponente, subito dite: "Arriva la pioggia", e così accade. E quando soffia lo scirocco, dite: "Farà caldo", e così accade. Ipocriti! Sapete valutare l''aspetto della terra e del cielo; come mai questo tempo non sapete valutarlo? E perché non giudicate voi stessi ciò che è giusto? Quando vai con il tuo avversario davanti al magistrato, lungo la strada cerca di trovare un accordo con lui, per evitare che ti trascini davanti al giudice e il giudice ti consegni all''esattore dei debiti e costui ti getti in prigione. Io ti dico: non uscirai di là finché non avrai pagato fino all''ultimo spicciolo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,12-16', 'Luca', 'In quei giorni, Gesù se ne andò sul monte a pregare e passò tutta la notte pregando Dio. Quando fu giorno, chiamò a sé i suoi discepoli e ne scelse dodici, ai quali diede anche il nome di apostoli: Simone, al quale diede anche il nome di Pietro; Andrea, suo fratello; Giacomo, Giovanni, Filippo, Bartolomeo, Matteo, Tommaso; Giacomo, figlio di Alfeo; Simone, detto Zelota; Giuda, figlio di Giacomo; e Giuda Iscariota, che divenne il traditore. Disceso con loro, si fermò in un luogo pianeggiante. C''era gran folla di suoi discepoli e gran moltitudine di gente da tutta la Giudea, da Gerusalemme e dal litorale di Tiro e di Sidòne, che erano venuti per ascoltarlo ed essere guariti dalle loro malattie; anche quelli che erano tormentati da spiriti impuri venivano guariti. Tutta la folla cercava di toccarlo, perché da lui usciva una forza che guariva tutti');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 13,18-21', 'Luca', 'Diceva Gesù: «A che cosa è simile il regno di Dio, e a che cosa lo posso paragonare? È simile a un granello di senape, che un uomo prese e gettò nel suo giardino; crebbe, divenne un albero e gli uccelli del cielo vennero a fare il nido fra i suoi rami». E disse ancora: «A che cosa posso paragonare il regno di Dio? È simile al lievito, che una donna prese e mescolò in tre misure di farina, finché non fu tutta lievitata»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 13,31-35', 'Luca', 'In quel momento si avvicinarono a Gesù alcuni farisei a dirgli: «Parti e vattene via di qui, perché Erode ti vuole uccidere». Egli rispose loro: «Andate a dire a quella volpe: "Ecco, io scaccio demòni e compio guarigioni oggi e domani; e il terzo giorno la mia opera è compiuta. Però è necessario che oggi, domani e il giorno seguente io prosegua nel cammino, perché non è possibile che un profeta muoia fuori di Gerusalemme". Gerusalemme, Gerusalemme, tu che uccidi i profeti e lapidi quelli che sono stati mandati a te: quante volte ho voluto raccogliere i tuoi figli, come una chioccia i suoi pulcini sotto le ali, e voi non avete voluto! Ecco, la vostra casa è abbandonata a voi! Vi dico infatti che non mi vedrete, finché verrà il tempo in cui direte: "Benedetto colui che viene nel nome del Signore!"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,1-12a', 'Matteo', 'Vedendo le folle, Gesù salì sul monte: si pose a sedere e si avvicinarono a lui i suoi discepoli. Si mise a parlare e insegnava loro dicendo: «Beati i poveri in spirito, perché di essi è il regno dei cieli. Beati quelli che sono nel pianto, perché saranno consolati. Beati i miti, perché avranno in eredità la terra. Beati quelli che hanno fame e sete della giustizia, perché saranno saziati. Beati i misericordiosi, perché troveranno misericordia. Beati i puri di cuore, perché vedranno Dio. Beati gli operatori di pace, perché saranno chiamati figli di Dio. Beati i perseguitati per la giustizia, perché di essi è il regno dei cieli. Beati voi quando vi insulteranno, vi perseguiteranno e, mentendo, diranno ogni sorta di male contro di voi per causa mia. Rallegratevi ed esultate, perché grande è la vostra ricompensa nei cieli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,37-40', 'Giovanni', '[Gesù disse:] «Tutto ciò che il Padre mi dà, verrà a me: colui che viene a me, io non lo caccerò fuori, perché sono disceso dal cielo non per fare la mia volontà, ma la volontà di colui che mi ha mandato. E questa è la volontà di colui che mi ha mandato: che io non perda nulla di quanto egli mi ha dato, ma che lo risusciti nell''ultimo giorno. Questa infatti è la volontà del Padre mio: che chiunque vede il Figlio e crede in lui abbia la vita eterna; e io lo risusciterò nell''ultimo giorno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 19,1-10', 'Luca', 'Gesù entrò nella città di Gerico e la stava attraversando, quand''ecco un uomo, di nome Zaccheo, capo dei pubblicani e ricco, cercava di vedere chi era Gesù, ma non gli riusciva a causa della folla, perché era piccolo di statura. Allora corse avanti e, per riuscire a vederlo, salì su un sicomoro, perché doveva passare di là. Quando giunse sul luogo, Gesù alzò lo sguardo e gli disse: «Zaccheo, scendi subito, perché oggi devo fermarmi a casa tua». Scese in fretta e lo accolse pieno di gioia. Vedendo ciò, tutti mormoravano: «È entrato in casa di un peccatore!». Ma Zaccheo, alzatosi, disse al Signore: «Ecco, Signore, io do la metà di ciò che possiedo ai poveri e, se ho rubato a qualcuno, restituisco quattro volte tanto». Gesù gli rispose: «Oggi per questa casa è venuta la salvezza, perché anch''egli è figlio di Abramo. Il Figlio dell''uomo infatti è venuto a cercare e a salvare ciò che era perduto»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 14,12-14', 'Luca', '[In quel tempo Gesù] disse poi a colui che l''aveva invitato: «Quando offri un pranzo o una cena, non invitare i tuoi amici né i tuoi fratelli né i tuoi parenti né i ricchi vicini, perché a loro volta non ti invitino anch''essi e tu abbia il contraccambio. Al contrario, quando offri un banchetto, invita poveri, storpi, zoppi, ciechi; e sarai beato perché non hanno da ricambiarti. Riceverai infatti la tua ricompensa alla risurrezione dei giusti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 14,15-24', 'Luca', 'Uno dei commensali, avendo udito questo, disse a Gesù: «Beato chi prenderà cibo nel regno di Dio!». Gli rispose: «Un uomo diede una grande cena e fece molti inviti. All''ora della cena, mandò il suo servo a dire agli invitati: "Venite, è pronto". Ma tutti, uno dopo l''altro, cominciarono a scusarsi. Il primo gli disse: "Ho comprato un campo e devo andare a vederlo; ti prego di scusarmi". Un altro disse: "Ho comprato cinque paia di buoi e vado a provarli; ti prego di scusarmi". Un altro disse: "Mi sono appena sposato e perciò non posso venire". Al suo ritorno il servo riferì tutto questo al suo padrone. Allora il padrone di casa, adirato, disse al servo: "Esci subito per le piazze e per le vie della città e conduci qui i poveri, gli storpi, i ciechi e gli zoppi". Il servo disse: "Signore, è stato fatto come hai ordinato, ma c''è ancora posto". Il padrone allora disse al servo: "Esci per le strade e lungo le siepi e costringili ad entrare, perché la mia casa si riempia. Perché io vi dico: nessuno di quelli che erano stati invitati gusterà la mia cena"».');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 15,1-10', 'Luca', 'Si avvicinavano a Gesù tutti i pubblicani e i peccatori per ascoltarlo. I farisei e gli scribi mormoravano dicendo: «Costui accoglie i peccatori e mangia con loro». Ed egli disse loro questa parabola: «Chi di voi, se ha cento pecore e ne perde una, non lascia le novantanove nel deserto e va in cerca di quella perduta, finché non la trova? Quando l''ha trovata, pieno di gioia se la carica sulle spalle, va a casa, chiama gli amici e i vicini, e dice loro: "Rallegratevi con me, perché ho trovato la mia pecora, quella che si era perduta". Io vi dico: così vi sarà gioia nel cielo per un solo peccatore che si converte, più che per novantanove giusti i quali non hanno bisogno di conversione. Oppure, quale donna, se ha dieci monete e ne perde una, non accende la lampada e spazza la casa e cerca accuratamente finché non la trova? E dopo averla trovata, chiama le amiche e le vicine, e dice: "Rallegratevi con me, perché ho trovato la moneta che avevo perduto". Così, io vi dico, vi è gioia davanti agli angeli di Dio per un solo peccatore che si converte»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 16,1-8', 'Luca', '[Gesù] Diceva anche ai discepoli: «Un uomo ricco aveva un amministratore, e questi fu accusato dinanzi a lui di sperperare i suoi averi. Lo chiamò e gli disse: "Che cosa sento dire di te? Rendi conto della tua amministrazione, perché non potrai più amministrare". L''amministratore disse tra sé: "Che cosa farò, ora che il mio padrone mi toglie l''amministrazione? Zappare, non ne ho la forza; mendicare, mi vergogno. So io che cosa farò perché, quando sarò stato allontanato dall''amministrazione, ci sia qualcuno che mi accolga in casa sua". Chiamò uno per uno i debitori del suo padrone e disse al primo: "Tu quanto devi al mio padrone?". Quello rispose: "Cento barili d''olio". Gli disse: "Prendi la tua ricevuta, siediti subito e scrivi cinquanta". Poi disse a un altro: "Tu quanto devi?". Rispose: "Cento misure di grano". Gli disse: "Prendi la tua ricevuta e scrivi ottanta". Il padrone lodò quell''amministratore disonesto, perché aveva agito con scaltrezza. I figli di questo mondo, infatti, verso i loro pari sono più scaltri dei figli della luce»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 2,13-22', 'Giovanni', 'Si avvicinava intanto la Pasqua dei Giudei e Gesù salì a Gerusalemme. Trovò nel tempio gente che vendeva buoi, pecore e colombe e, là seduti, i cambiamonete. Allora fece una frusta di cordicelle e scacciò tutti fuori dal tempio, con le pecore e i buoi; gettò a terra il denaro dei cambiamonete e ne rovesciò i banchi, e ai venditori di colombe disse: «Portate via di qui queste cose e non fate della casa del Padre mio un mercato!». I suoi discepoli si ricordarono che sta scritto: Lo zelo per la tua casa mi divorerà. Allora i Giudei presero la parola e gli dissero: «Quale segno ci mostri per fare queste cose?». Rispose loro Gesù: «Distruggete questo tempio e in tre giorni lo farò risorgere». Gli dissero allora i Giudei: «Questo tempio è stato costruito in quarantasei anni e tu in tre giorni lo farai risorgere?». Ma egli parlava del tempio del suo corpo. Quando poi fu risuscitato dai morti, i suoi discepoli si ricordarono che aveva detto questo, e credettero alla Scrittura e alla parola detta da Gesù');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 20,27-38', 'Luca', 'Gli si avvicinarono alcuni sadducei - i quali dicono che non c''è risurrezione - e gli posero questa domanda: «Maestro, Mosè ci ha prescritto: Se muore il fratello di qualcuno che ha moglie, ma è senza figli, suo fratello prenda la moglie e dia una discendenza al proprio fratello. C''erano dunque sette fratelli: il primo, dopo aver preso moglie, morì senza figli. Allora la prese il secondo e poi il terzo e così tutti e sette morirono senza lasciare figli. Da ultimo morì anche la donna. La donna dunque, alla risurrezione, di chi sarà moglie? Poiché tutti e sette l''hanno avuta in moglie». Gesù rispose loro: «I figli di questo mondo prendono moglie e prendono marito; ma quelli che sono giudicati degni della vita futura e della risurrezione dai morti, non prendono né moglie né marito: infatti non possono più morire, perché sono uguali agli angeli e, poiché sono figli della risurrezione, sono figli di Dio. Che poi i morti risorgano, lo ha indicato anche Mosè a proposito del roveto, quando dice: Il Signore è il Dio di Abramo, Dio di Isacco e Dio di Giacobbe. Dio non è dei morti, ma dei viventi; perché tutti vivono per lui»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 17,1-6', 'Luca', 'Gesù disse ai suoi discepoli: «È inevitabile che vengano scandali, ma guai a colui a causa del quale vengono. È meglio per lui che gli venga messa al collo una macina da mulino e sia gettato nel mare, piuttosto che scandalizzare uno di questi piccoli. State attenti a voi stessi! Se il tuo fratello commetterà una colpa, rimproveralo; ma se si pentirà, perdonagli. E se commetterà una colpa sette volte al giorno contro di te e sette volte ritornerà a te dicendo: "Sono pentito", tu gli perdonerai». Gli apostoli dissero al Signore: «Accresci in noi la fede!». Il Signore rispose: «Se aveste fede quanto un granello di senape, potreste dire a questo gelso: "Sràdicati e vai a piantarti nel mare", ed esso vi obbedirebbe»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 17,7-10', 'Luca', '[Disse Gesù]: «Chi di voi, se ha un servo ad arare o a pascolare il gregge, gli dirà, quando rientra dal campo: "Vieni subito e mettiti a tavola"? Non gli dirà piuttosto: "Prepara da mangiare, stringiti le vesti ai fianchi e servimi, finché avrò mangiato e bevuto, e dopo mangerai e berrai tu"? Avrà forse gratitudine verso quel servo, perché ha eseguito gli ordini ricevuti? Così anche voi, quando avrete fatto tutto quello che vi è stato ordinato, dite: "Siamo servi inutili. Abbiamo fatto quanto dovevamo fare"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 17,20-25', 'Luca', 'I farisei gli domandarono: «Quando verrà il regno di Dio?». Egli rispose loro: «Il regno di Dio non viene in modo da attirare l''attenzione, e nessuno dirà: "Eccolo qui", oppure: "Eccolo là". Perché, ecco, il regno di Dio è in mezzo a voi!». Disse poi ai discepoli: «Verranno giorni in cui desidererete vedere anche uno solo dei giorni del Figlio dell''uomo, ma non lo vedrete. Vi diranno: "Eccolo là", oppure: "Eccolo qui"; non andateci, non seguiteli. Perché come la folgore, guizzando, brilla da un capo all''altro del cielo, così sarà il Figlio dell''uomo nel suo giorno. Ma prima è necessario che egli soffra molto e venga rifiutato da questa generazione»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 17,26-37', 'Luca', '[In quel tempo Gesù disse] «come avvenne nei giorni di Noè, così sarà nei giorni del Figlio dell''uomo: mangiavano, bevevano, prendevano moglie, prendevano marito, fino al giorno in cui Noè entrò nell''arca e venne il diluvio e li fece morire tutti. Come avvenne anche nei giorni di Lot: mangiavano, bevevano, compravano, vendevano, piantavano, costruivano; ma, nel giorno in cui Lot uscì da Sòdoma, piovve fuoco e zolfo dal cielo e li fece morire tutti. Così accadrà nel giorno in cui il Figlio dell''uomo si manifesterà. In quel giorno, chi si troverà sulla terrazza e avrà lasciato le sue cose in casa, non scenda a prenderle; così, chi si troverà nel campo, non torni indietro. Ricordatevi della moglie di Lot. Chi cercherà di salvare la propria vita, la perderà; ma chi la perderà, la manterrà viva. Io vi dico: in quella notte, due si troveranno nello stesso letto: l''uno verrà portato via e l''altro lasciato; due donne staranno a macinare nello stesso luogo: l''una verrà portata via e l''altra lasciata». Allora gli chiesero: «Dove, Signore?». Ed egli disse loro: «Dove sarà il cadavere, lì si raduneranno insieme anche gli avvoltoi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 21,5-19', 'Luca', 'Mentre alcuni parlavano del tempio, che era ornato di belle pietre e di doni votivi,Gesù disse: «Verranno giorni nei quali, di quello che vedete, non sarà lasciata pietra su pietra che non sarà distrutta». Gli domandarono: «Maestro, quando dunque accadranno queste cose e quale sarà il segno, quando esse staranno per accadere?». Rispose: «Badate di non lasciarvi ingannare. Molti infatti verranno nel mio nome dicendo: "Sono io", e: "Il tempo è vicino". Non andate dietro a loro! Quando sentirete di guerre e di rivoluzioni, non vi terrorizzate, perché prima devono avvenire queste cose, ma non è subito la fine». Poi diceva loro: «Si solleverà nazione contro nazione e regno contro regno, e vi saranno in diversi luoghi terremoti, carestie e pestilenze; vi saranno anche fatti terrificanti e segni grandiosi dal cielo. Ma prima di tutto questo metteranno le mani su di voi e vi perseguiteranno, consegnandovi alle sinagoghe e alle prigioni, trascinandovi davanti a re e governatori, a causa del mio nome. Avrete allora occasione di dare testimonianza. Mettetevi dunque in mente di non preparare prima la vostra difesa; io vi darò parola e sapienza, cosicché tutti i vostri avversari non potranno resistere né controbattere. Sarete traditi perfino dai genitori, dai fratelli, dai parenti e dagli amici, e uccideranno alcuni di voi; sarete odiati da tutti a causa del mio nome. Ma nemmeno un capello del vostro capo andrà perduto. Con la vostra perseveranza salverete la vostra vita»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 18,35-43', 'Luca', 'Mentre si avvicinava a Gerico, un cieco era seduto lungo la strada a mendicare. Sentendo passare la gente, domandò che cosa accadesse. Gli annunciarono: «Passa Gesù, il Nazareno!». Allora gridò dicendo: «Gesù, figlio di Davide, abbi pietà di me!». Quelli che camminavano avanti lo rimproveravano perché tacesse; ma egli gridava ancora più forte: «Figlio di Davide, abbi pietà di me!». Gesù allora si fermò e ordinò che lo conducessero da lui. Quando fu vicino, gli domandò: «Che cosa vuoi che io faccia per te?». Egli rispose: «Signore, che io veda di nuovo!». E Gesù gli disse: «Abbi di nuovo la vista! La tua fede ti ha salvato». Subito ci vide di nuovo e cominciò a seguirlo glorificando Dio. E tutto il popolo, vedendo, diede lode a Dio');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 19,11-28', 'Luca', 'Mentre essi [la folla] stavano ad ascoltare queste cose, [Gesù] disse ancora una parabola, perché era vicino a Gerusalemme ed essi pensavano che il regno di Dio dovesse manifestarsi da un momento all''altro. Disse dunque: «Un uomo di nobile famiglia partì per un paese lontano, per ricevere il titolo di re e poi ritornare. Chiamati dieci dei suoi servi, consegnò loro dieci monete d''oro, dicendo: "Fatele fruttare fino al mio ritorno". Ma i suoi cittadini lo odiavano e mandarono dietro di lui una delegazione a dire: “Non vogliamo che costui venga a regnare su di noi". Dopo aver ricevuto il titolo di re, egli ritornò e fece chiamare quei servi a cui aveva consegnato il denaro, per sapere quanto ciascuno avesse guadagnato. Si presentò il primo e disse: "Signore, la tua moneta d''oro ne ha fruttate dieci". Gli disse: "Bene, servo buono! Poiché ti sei mostrato fedele nel poco, ricevi il potere sopra dieci città". Poi si presentò il secondo e disse: "Signore, la tua moneta d''oro ne ha fruttate cinque". Anche a questo disse: "Tu pure sarai a capo di cinque città". Venne poi anche un altro e disse: "Signore, ecco la tua moneta d''oro, che ho tenuto nascosta in un fazzoletto; avevo paura di te, che sei un uomo severo: prendi quello che non hai messo in deposito e mieti quello che non hai seminato". Gli rispose: "Dalle tue stesse parole ti giudico, servo malvagio! Sapevi che sono un uomo severo, che prendo quello che non ho messo in deposito e mieto quello che non ho seminato: perché allora non hai consegnato il mio denaro a una banca? Al mio ritorno l''avrei riscosso con gli interessi". Disse poi ai presenti: "Toglietegli la moneta d''oro e datela a colui che ne ha dieci". Gli risposero: "Signore, ne ha già dieci!". "Io vi dico: A chi ha, sarà dato; invece a chi non ha, sarà tolto anche quello che ha. E quei miei nemici, che non volevano che io diventassi loro re, conduceteli qui e uccideteli davanti a me"». Dette queste cose, Gesù camminava davanti a tutti salendo verso Gerusalemme');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 19,41-44', 'Luca', '[Gesù] quando fu vicino, alla vista della città pianse su di essa dicendo: «Se avessi compreso anche tu, in questo giorno, quello che porta alla pace! Ma ora è stato nascosto ai tuoi occhi. Per te verranno giorni in cui i tuoi nemici ti circonderanno di trincee, ti assedieranno e ti stringeranno da ogni parte; distruggeranno te e i tuoi figli dentro di te e non lasceranno in te pietra su pietra, perché non hai riconosciuto il tempo in cui sei stata visitata»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 19,45-48', 'Luca', 'Ed entrato nel tempio, [Gesù] si mise a scacciare quelli che vendevano, dicendo loro: «Sta scritto: “La mia casa sarà casa di preghiera.” Voi invece ne avete fatto un covo di ladri».  Ogni giorno insegnava nel tempio. I capi dei sacerdoti e gli scribi cercavano di farlo morire e così anche i capi del popolo; ma non sapevano che cosa fare, perché tutto il popolo pendeva dalle sue labbra nell''ascoltarlo');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 20,27-40', 'Luca', 'Gli si avvicinarono alcuni sadducei [a Gesù] - i quali dicono che non c''è risurrezione - e gli posero questa domanda: «Maestro, Mosè ci ha prescritto: Se muore il fratello di qualcuno che ha moglie, ma è senza figli, suo fratello prenda la moglie e dia una discendenza al proprio fratello. C''erano dunque sette fratelli: il primo, dopo aver preso moglie, morì senza figli. Allora la prese il secondo e poi il terzo e così tutti e sette morirono senza lasciare figli. Da ultimo morì anche la donna. La donna dunque, alla risurrezione, di chi sarà moglie? Poiché tutti e sette l''hanno avuta in moglie». Gesù rispose loro: «I figli di questo mondo prendono moglie e prendono marito; ma quelli che sono giudicati degni della vita futura e della risurrezione dai morti, non prendono né moglie né marito: infatti non possono più morire, perché sono uguali agli angeli e, poiché sono figli della risurrezione, sono figli di Dio. Che poi i morti risorgano, lo ha indicato anche Mosè a proposito del roveto, quando dice: Il Signore è il Dio di Abramo, Dio di Isacco e Dio di Giacobbe. Dio non è dei morti, ma dei viventi; perché tutti vivono per lui». Dissero allora alcuni scribi: «Maestro, hai parlato bene». E non osavano più rivolgergli alcuna domanda');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 23,35-43', 'Luca', 'Il popolo stava a vedere; i capi invece lo deridevano dicendo: «Ha salvato altri! Salvi se stesso, se è lui il Cristo di Dio, l''eletto». Anche i soldati lo deridevano, gli si accostavano per porgergli dell''aceto e dicevano: «Se tu sei il re dei Giudei, salva te stesso». Sopra di lui c''era anche una scritta: "Costui è il re dei Giudei". Uno dei malfattori appesi alla croce lo insultava: «Non sei tu il Cristo? Salva te stesso e noi!». L''altro invece lo rimproverava dicendo: «Non hai alcun timore di Dio, tu che sei condannato alla stessa pena? Noi, giustamente, perché riceviamo quello che abbiamo meritato per le nostre azioni; egli invece non ha fatto nulla di male». E disse: «Gesù, ricordati di me quando entrerai nel tuo regno». Gli rispose: «In verità io ti dico: oggi con me sarai nel paradiso»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 21,1-4', 'Luca', 'Alzati gli occhi [Gesù], vide i ricchi che gettavano le loro offerte nel tesoro del tempio. Vide anche una vedova povera, che vi gettava due monetine, e disse: «In verità vi dico: questa vedova, così povera, ha gettato più di tutti. Tutti costoro, infatti, hanno gettato come offerta parte del loro superfluo. Ella invece, nella sua miseria, ha gettato tutto quello che aveva per vivere»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 21,5-11', 'Luca', 'Mentre alcuni parlavano del tempio, che era ornato di belle pietre e di doni votivi, [Gesù] disse: «Verranno giorni nei quali, di quello che vedete, non sarà lasciata pietra su pietra che non sarà distrutta». Gli domandarono: «Maestro, quando dunque accadranno queste cose e quale sarà il segno, quando esse staranno per accadere?». Rispose: «Badate di non lasciarvi ingannare. Molti infatti verranno nel mio nome dicendo: "Sono io", e: "Il tempo è vicino". Non andate dietro a loro! Quando sentirete di guerre e di rivoluzioni, non vi terrorizzate, perché prima devono avvenire queste cose, ma non è subito la fine». Poi diceva loro: «Si solleverà nazione contro nazione e regno contro regno, e vi saranno in diversi luoghi terremoti, carestie e pestilenze; vi saranno anche fatti terrificanti e segni grandiosi dal cielo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 21,12-19', 'Luca', '[Gesù disse] «ma prima di tutto questo metteranno le mani su di voi e vi perseguiteranno, consegnandovi alle sinagoghe e alle prigioni, trascinandovi davanti a re e governatori, a causa del mio nome. Avrete allora occasione di dare testimonianza. Mettetevi dunque in mente di non preparare prima la vostra difesa; io vi darò parola e sapienza, cosicché tutti i vostri avversari non potranno resistere né controbattere. Sarete traditi perfino dai genitori, dai fratelli, dai parenti e dagli amici, e uccideranno alcuni di voi; sarete odiati da tutti a causa del mio nome. Ma nemmeno un capello del vostro capo andrà perduto. Con la vostra perseveranza salverete la vostra vita»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 21,20-28', 'Luca', '[Gesù disse] «quando vedrete Gerusalemme circondata da eserciti, allora sappiate che la sua devastazione è vicina. Allora coloro che si trovano nella Giudea fuggano verso i monti, coloro che sono dentro la città se ne allontanino, e quelli che stanno in campagna non tornino in città; quelli infatti saranno giorni di vendetta, affinché tutto ciò che è stato scritto si compia. In quei giorni guai alle donne che sono incinte e a quelle che allattano, perché vi sarà grande calamità nel paese e ira contro questo popolo. Cadranno a fil di spada e saranno condotti prigionieri in tutte le nazioni; Gerusalemme sarà calpestata dai pagani finché i tempi dei pagani non siano compiuti. Vi saranno segni nel sole, nella luna e nelle stelle, e sulla terra angoscia di popoli in ansia per il fragore del mare e dei flutti, mentre gli uomini moriranno per la paura e per l''attesa di ciò che dovrà accadere sulla terra. Le potenze dei cieli infatti saranno sconvolte. Allora vedranno il Figlio dell''uomo venire su una nube con grande potenza e gloria. Quando cominceranno ad accadere queste cose, risollevatevi e alzate il capo, perché la vostra liberazione è vicina»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 21,29-33', 'Luca', 'Gesù disse loro una parabola: «Osservate la pianta di fico e tutti gli alberi: quando già germogliano, capite voi stessi, guardandoli, che ormai l''estate è vicina. Così anche voi: quando vedrete accadere queste cose, sappiate che il regno di Dio è vicino. In verità io vi dico: non passerà questa generazione prima che tutto avvenga. Il cielo e la terra passeranno, ma le mie parole non passeranno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 4,18-22', 'Matteo', 'Mentre Gesù camminava lungo il mare di Galilea, vide due fratelli, Simone, chiamato Pietro, e Andrea suo fratello, che gettavano le reti in mare; erano infatti pescatori. E disse loro: «Venite dietro a me, vi farò pescatori di uomini». Ed essi subito lasciarono le reti e lo seguirono. Andando oltre, vide altri due fratelli, Giacomo, figlio di Zebedeo, e Giovanni suo fratello, che nella barca, insieme a Zebedeo loro padre, riparavano le loro reti, e li chiamò. Ed essi subito lasciarono la barca e il loro padre e lo seguirono');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 24,37-44', 'Matteo', '[In quel tempo Gesù disse ai suoi discepoli]: «Come furono i giorni di Noè, così sarà la venuta del Figlio dell''uomo. Infatti, come nei giorni che precedettero il diluvio mangiavano e bevevano, prendevano moglie e prendevano marito, fino al giorno in cui Noè entrò nell''arca, e non si accorsero di nulla finché venne il diluvio e travolse tutti: così sarà anche la venuta del Figlio dell''uomo. Allora due uomini saranno nel campo: uno verrà portato via e l''altro lasciato. Due donne macineranno alla mola: una verrà portata via e l''altra lasciata. Vegliate dunque, perché non sapete in quale giorno il Signore vostro verrà. Cercate di capire questo: se il padrone di casa sapesse a quale ora della notte viene il ladro, veglierebbe e non si lascerebbe scassinare la casa. Perciò anche voi tenetevi pronti perché, nell''ora che non immaginate, viene il Figlio dell''uomo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 8,5-11', 'Matteo', 'Entrato Gesù in Cafàrnao, gli venne incontro un centurione che lo scongiurava e diceva: «Signore, il mio servo è in casa, a letto, paralizzato e soffre terribilmente». Gli disse: «Verrò e lo guarirò». Ma il centurione rispose: «Signore, io non sono degno che tu entri sotto il mio tetto, ma di'' soltanto una parola e il mio servo sarà guarito. Pur essendo anch''io un subalterno, ho dei soldati sotto di me e dico a uno: "Va''!", ed egli va; e a un altro: "Vieni!", ed egli viene; e al mio servo: "Fa'' questo!", ed egli lo fa». Ascoltandolo, Gesù si meravigliò e disse a quelli che lo seguivano: «In verità io vi dico, in Israele non ho trovato nessuno con una fede così grande! Ora io vi dico che molti verranno dall''oriente e dall''occidente e siederanno a mensa con Abramo, Isacco e Giacobbe nel regno dei cieli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 10,21-24', 'Luca', 'In quella stessa ora Gesù esultò di gioia nello Spirito Santo e disse: «Ti rendo lode, o Padre, Signore del cielo e della terra, perché hai nascosto queste cose ai sapienti e ai dotti e le hai rivelate ai piccoli. Sì, o Padre, perché così hai deciso nella tua benevolenza. Tutto è stato dato a me dal Padre mio e nessuno sa chi è il Figlio se non il Padre, né chi è il Padre se non il Figlio e colui al quale il Figlio vorrà rivelarlo». E, rivolto ai discepoli, in disparte, disse: «Beati gli occhi che vedono ciò che voi vedete. Io vi dico che molti profeti e re hanno voluto vedere ciò che voi guardate, ma non lo videro, e ascoltare ciò che voi ascoltate, ma non lo ascoltarono»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 15,29-37', 'Matteo', 'Gesù giunse presso il mare di Galilea e, salito sul monte, lì si fermò. Attorno a lui si radunò molta folla, recando con sé zoppi, storpi, ciechi, sordi e molti altri malati; li deposero ai suoi piedi, ed egli li guarì, tanto che la folla era piena di stupore nel vedere i muti che parlavano, gli storpi guariti, gli zoppi che camminavano e i ciechi che vedevano. E lodava il Dio d''Israele. Allora Gesù chiamò a sé i suoi discepoli e disse: «Sento compassione per la folla. Ormai da tre giorni stanno con me e non hanno da mangiare. Non voglio rimandarli digiuni, perché non vengano meno lungo il cammino». E i discepoli gli dissero: «Come possiamo trovare in un deserto tanti pani da sfamare una folla così grande?». Gesù domandò loro: «Quanti pani avete?». Dissero: «Sette, e pochi pesciolini». Dopo aver ordinato alla folla di sedersi per terra, prese i sette pani e i pesci, rese grazie, li spezzò e li dava ai discepoli, e i discepoli alla folla. Tutti mangiarono a sazietà. Portarono via i pezzi avanzati: sette sporte piene');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 7,21.24-27', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Non chiunque mi dice: "Signore, Signore", entrerà nel regno dei cieli, ma colui che fa la volontà del Padre mio che è nei cieli. Perciò chiunque ascolta queste mie parole e le mette in pratica, sarà simile a un uomo saggio, che ha costruito la sua casa sulla roccia. Cadde la pioggia, strariparono i fiumi, soffiarono i venti e si abbatterono su quella casa, ma essa non cadde, perché era fondata sulla roccia. Chiunque ascolta queste mie parole e non le mette in pratica, sarà simile a un uomo stolto, che ha costruito la sua casa sulla sabbia. Cadde la pioggia, strariparono i fiumi, soffiarono i venti e si abbatterono su quella casa, ed essa cadde e la sua rovina fu grande»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,27-31', 'Matteo', 'Mentre Gesù si allontanava, due ciechi lo seguirono gridando: «Figlio di Davide, abbi pietà di noi!». Entrato in casa, i ciechi gli si avvicinarono e Gesù disse loro: «Credete che io possa fare questo?». Gli risposero: «Sì, o Signore!». Allora toccò loro gli occhi e disse: «Avvenga per voi secondo la vostra fede». E si aprirono loro gli occhi. Quindi Gesù li ammonì dicendo: «Badate che nessuno lo sappia!». Ma essi, appena usciti, ne diffusero la notizia in tutta quella regione');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,35-10,1.6-8', 'Matteo', 'Gesù percorreva tutte le città e i villaggi, insegnando nelle loro sinagoghe, annunciando il vangelo del Regno e guarendo ogni malattia e ogni infermità. Vedendo le folle, ne sentì compassione, perché erano stanche e sfinite come pecore che non hanno pastore. Allora disse ai suoi discepoli: «La messe è abbondante, ma sono pochi gli operai! Pregate dunque il signore della messe, perché mandi operai nella sua messe!». Chiamati a sé i suoi dodici discepoli, diede loro potere sugli spiriti impuri per scacciarli e guarire ogni malattia e ogni infermità. E li inviò ordinando loro: «Rivolgetevi alle pecore perdute della casa d''Israele. Strada facendo, predicate, dicendo che il regno dei cieli è vicino. Guarite gli infermi, risuscitate i morti, purificate i lebbrosi, scacciate i demoni. Gratuitamente avete ricevuto, gratuitamente date»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 3,1-12', 'Matteo', 'In quei giorni venne Giovanni il Battista e predicava nel deserto della Giudea dicendo: «Convertitevi, perché il regno dei cieli è vicino!». Egli infatti è colui del quale aveva parlato il profeta Isaia quando disse: “Voce di uno che grida nel deserto: Preparate la via del Signore, raddrizzate i suoi sentieri!” E lui, Giovanni, portava un vestito di peli di cammello e una cintura di pelle attorno ai fianchi; il suo cibo erano cavallette e miele selvatico. Allora Gerusalemme, tutta la Giudea e tutta la zona lungo il Giordano accorrevano a lui e si facevano battezzare da lui nel fiume Giordano, confessando i loro peccati. Vedendo molti farisei e sadducei venire al suo battesimo, disse loro: «Razza di vipere! Chi vi ha fatto credere di poter sfuggire all''ira imminente? Fate dunque un frutto degno della conversione, e non crediate di poter dire dentro di voi: "Abbiamo Abramo per padre!". Perché io vi dico che da queste pietre Dio può suscitare figli ad Abramo. Già la scure è posta alla radice degli alberi; perciò ogni albero che non dà buon frutto viene tagliato e gettato nel fuoco. Io vi battezzo nell''acqua per la conversione; ma colui che viene dopo di me è più forte di me e io non sono degno di portargli i sandali; egli vi battezzerà in Spirito Santo e fuoco. Tiene in mano la pala e pulirà la sua aia e raccoglierà il suo frumento nel granaio, ma brucerà la paglia con un fuoco inestinguibile»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 18,12-14', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Che cosa vi pare? Se un uomo ha cento pecore e una di loro si smarrisce, non lascerà le novantanove sui monti e andrà a cercare quella che si è smarrita? In verità io vi dico: se riesce a trovarla, si rallegrerà per quella più che per le novantanove che non si erano smarrite. Così è volontà del Padre vostro che è nei cieli, che neanche uno di questi piccoli si perda»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 11,11-15', 'Matteo', '[In quel tempo, Gesù disse alle folle]: «In verità io vi dico: fra i nati da donna non è sorto alcuno più grande di Giovanni il Battista; ma il più piccolo nel regno dei cieli è più grande di lui. Dai giorni di Giovanni il Battista fino ad ora, il regno dei cieli subisce violenza e i violenti se ne impadroniscono. Tutti i Profeti e la Legge infatti hanno profetato fino a Giovanni. E, se volete comprendere, è lui quell''Elìa che deve venire. Chi ha orecchi, ascolti!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 11,16-19', 'Matteo', '[In quel tempo, Gesù disse alle folle]: «A chi posso paragonare questa generazione? È simile a bambini che stanno seduti in piazza e, rivolti ai compagni, gridano: "Vi abbiamo suonato il flauto e non avete ballato, abbiamo cantato un lamento e non vi siete battuti il petto!". È venuto Giovanni, che non mangia e non beve, e dicono: "È indemoniato". È venuto il Figlio dell''uomo, che mangia e beve, e dicono: "Ecco, è un mangione e un beone, un amico di pubblicani e di peccatori". Ma la sapienza è stata riconosciuta giusta per le opere che essa compie»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 17,10-13', 'Matteo', 'Allora i discepoli gli domandarono [a Gesù]: «Perché dunque gli scribi dicono che prima deve venire Elia?». Ed egli rispose: «Sì, verrà Elia e ristabilirà ogni cosa. Ma io vi dico: Elia è già venuto e non l''hanno riconosciuto; anzi, hanno fatto di lui quello che hanno voluto. Così anche il Figlio dell''uomo dovrà soffrire per opera loro». Allora i discepoli compresero che egli parlava loro di Giovanni il Battista');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 11,2-11', 'Matteo', 'In quel tempo, Giovanni, che era in carcere, avendo sentito parlare delle opere del Cristo, per mezzo dei suoi discepoli mandò a dirgli: «Sei tu colui che deve venire o dobbiamo aspettare un altro?». Gesù rispose loro: «Andate e riferite a Giovanni ciò che udite e vedete: I ciechi riacquistano la vista, gli zoppi camminano, i lebbrosi sono purificati, i sordi odono, i morti risuscitano, ai poveri è annunciato il Vangelo. E beato è colui che non trova in me motivo di scandalo!». Mentre quelli se ne andavano, Gesù si mise a parlare di Giovanni alle folle: «Che cosa siete andati a vedere nel deserto? Una canna sbattuta dal vento? Allora, che cosa siete andati a vedere? Un uomo vestito con abiti di lusso? Ecco, quelli che vestono abiti di lusso stanno nei palazzi dei re! Ebbene, che cosa siete andati a vedere? Un profeta? Sì, io vi dico, anzi, più che un profeta. Egli è colui del quale sta scritto: "Ecco, dinanzi a te io mando il mio messaggero, davanti a te egli preparerà la tua via". In verità io vi dico: fra i nati da donna non è sorto alcuno più grande di Giovanni il Battista; ma il più piccolo nel regno dei cieli è più grande di lui»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 21,23-27', 'Matteo', 'Gesù entrò nel tempio e, mentre insegnava, gli si avvicinarono i capi dei sacerdoti e gli anziani del popolo e dissero: «Con quale autorità fai queste cose? E chi ti ha dato questa autorità?». Gesù rispose loro: «Anch''io vi farò una sola domanda. Se mi rispondete, anch''io vi dirò con quale autorità faccio questo. Il battesimo di Giovanni da dove veniva? Dal cielo o dagli uomini?». Essi discutevano fra loro dicendo: «Se diciamo: "Dal cielo", ci risponderà: "Perché allora non gli avete creduto?". Se diciamo: "Dagli uomini", abbiamo paura della folla, perché tutti considerano Giovanni un profeta». Rispondendo a Gesù dissero: «Non lo sappiamo». Allora anch''egli disse loro: «Neanch''io vi dico con quale autorità faccio queste cose»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 1,1-17', 'Matteo', 'Genealogia di Gesù Cristo figlio di Davide, figlio di Abramo. Abramo generò Isacco, Isacco generò Giacobbe, Giacobbe generò Giuda e i suoi fratelli, Giuda generò Fares e Zara da Tamar, Fares generò Esrom, Esrom generò Aram, Aram generò Aminadàb, Aminadàb generò Naassòn, Naassòn generò Salmon, Salmon generò Booz da Racab, Booz generò Obed da Rut, Obed generò Iesse, Iesse generò il re Davide. Davide generò Salomone da quella che era stata la moglie di Uria, Salomone generò Roboamo, Roboamo generò Abia, Abia generò Asaf, Asaf generò Giòsafat, Giòsafat generò Ioram, Ioram generò Ozia, Ozia generò Ioatàm, Ioatàm generò Acaz, Acaz generò Ezechia, Ezechia generò Manasse, Manasse generò Amos, Amos generò Giosia, Giosia generò Ieconia e i suoi fratelli, al tempo della deportazione in Babilonia. Dopo la deportazione in Babilonia, Ieconia generò Salatièl, Salatièl generò Zorobabele, Zorobabele generò Abiùd, Abiùd generò Eliachìm, Eliachìm generò Azor, Azor generò Sadoc, Sadoc generò Achim, Achim generò Eliùd, Eliùd generò Eleazar, Eleazar generò Mattan, Mattan generò Giacobbe, Giacobbe generò Giuseppe, lo sposo di Maria, dalla quale è nato Gesù, chiamato Cristo. In tal modo, tutte le generazioni da Abramo a Davide sono quattordici, da Davide fino alla deportazione in Babilonia quattordici, dalla deportazione in Babilonia a Cristo quattordici');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 1,18-24', 'Matteo', 'Così fu generato Gesù Cristo: sua madre Maria, essendo promessa sposa di Giuseppe, prima che andassero a vivere insieme si trovò incinta per opera dello Spirito Santo. Giuseppe suo sposo, poiché era uomo giusto e non voleva accusarla pubblicamente, pensò di ripudiarla in segreto. Mentre però stava considerando queste cose, ecco, gli apparve in sogno un angelo del Signore e gli disse: «Giuseppe, figlio di Davide, non temere di prendere con te Maria, tua sposa. Infatti il bambino che è generato in lei viene dallo Spirito Santo; ella darà alla luce un figlio e tu lo chiamerai Gesù: egli infatti salverà il suo popolo dai suoi peccati». Tutto questo è avvenuto perché si compisse ciò che era stato detto dal Signore per mezzo del profeta: ″Ecco, la vergine concepirà e darà alla luce un figlio: a lui sarà dato il nome di Emmanuele, che significa Dio con noi″. Quando si destò dal sonno, Giuseppe fece come gli aveva ordinato l''angelo del Signore e prese con sé la sua sposa');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,5-25', 'Luca', 'Al tempo di Erode, re della Giudea, vi era un sacerdote di nome Zaccarìa, della classe di Abìa, che aveva in moglie una discendente di Aronne, di nome Elisabetta. Ambedue erano giusti davanti a Dio e osservavano irreprensibili tutte le leggi e le prescrizioni del Signore. Essi non avevano figli, perché Elisabetta era sterile e tutti e due erano avanti negli anni. Avvenne che, mentre Zaccarìa svolgeva le sue funzioni sacerdotali davanti al Signore durante il turno della sua classe, gli toccò in sorte, secondo l''usanza del servizio sacerdotale, di entrare nel tempio del Signore per fare l''offerta dell''incenso. Fuori, tutta l''assemblea del popolo stava pregando nell''ora dell''incenso. Apparve a lui un angelo del Signore, ritto alla destra dell''altare dell''incenso. Quando lo vide, Zaccarìa si turbò e fu preso da timore. Ma l''angelo gli disse: «Non temere, Zaccarìa, la tua preghiera è stata esaudita e tua moglie Elisabetta ti darà un figlio, e tu lo chiamerai Giovanni. Avrai gioia ed esultanza, e molti si rallegreranno della sua nascita, perché egli sarà grande davanti al Signore; non berrà vino né bevande inebrianti, sarà colmato di Spirito Santo fin dal seno di sua madre e ricondurrà molti figli d''Israele al Signore loro Dio. Egli camminerà innanzi a lui con lo spirito e la potenza di Elìa, per ricondurre i cuori dei padri verso i figli e i ribelli alla saggezza dei giusti e preparare al Signore un popolo ben disposto». Zaccarìa disse all''angelo: «Come potrò mai conoscere questo? Io sono vecchio e mia moglie è avanti negli anni». L''angelo gli rispose: «Io sono Gabriele, che sto dinanzi a Dio e sono stato mandato a parlarti e a portarti questo lieto annuncio. Ed ecco, tu sarai muto e non potrai parlare fino al giorno in cui queste cose avverranno, perché non hai creduto alle mie parole, che si compiranno a loro tempo». Intanto il popolo stava in attesa di Zaccarìa, e si meravigliava per il suo indugiare nel tempio. Quando poi uscì e non poteva parlare loro, capirono che nel tempio aveva avuto una visione. Faceva loro dei cenni e restava muto. Compiuti i giorni del suo servizio, tornò a casa. Dopo quei giorni Elisabetta, sua moglie, concepì e si tenne nascosta per cinque mesi e diceva: «Ecco che cosa ha fatto per me il Signore, nei giorni in cui si è degnato di togliere la mia vergogna fra gli uomini»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,39-45', 'Luca', 'In quei giorni Maria si alzò e andò in fretta verso la regione montuosa, in una città di Giuda. Entrata nella casa di Zaccaria, salutò Elisabetta. Appena Elisabetta ebbe udito il saluto di Maria, il bambino sussultò nel suo grembo. Elisabetta fu colmata di Spirito Santo ed esclamò a gran voce: «Benedetta tu fra le donne e benedetto il frutto del tuo grembo! A che cosa devo che la madre del mio Signore venga da me? Ecco, appena il tuo saluto è giunto ai miei orecchi, il bambino ha sussultato di gioia nel mio grembo. E beata colei che ha creduto nell''adempimento di ciò che il Signore le ha detto»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,57-66', 'Luca', 'In quei giorni, per Elisabetta si compì il tempo del parto e diede alla luce un figlio. I vicini e i parenti udirono che il Signore aveva manifestato in lei la sua grande misericordia, e si rallegravano con lei. Otto giorni dopo vennero per circoncidere il bambino e volevano chiamarlo con il nome di suo padre, Zaccarìa. Ma sua madre intervenne: «No, si chiamerà Giovanni». Le dissero: «Non c''è nessuno della tua parentela che si chiami con questo nome». Allora domandavano con cenni a suo padre come voleva che si chiamasse. Egli chiese una tavoletta e scrisse: «Giovanni è il suo nome». Tutti furono meravigliati. All''istante gli si aprì la bocca e gli si sciolse la lingua, e parlava benedicendo Dio. Tutti i loro vicini furono presi da timore, e per tutta la regione montuosa della Giudea si discorreva di tutte queste cose. Tutti coloro che le udivano, le custodivano in cuor loro, dicendo: «Che sarà mai questo bambino?». E davvero la mano del Signore era con lui');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,67-79', 'Luca', 'Zaccaria, suo padre, fu colmato di Spirito Santo e profetò dicendo: «Benedetto il Signore, Dio d''Israele, perché ha visitato e redento il suo popolo, e ha suscitato per noi un Salvatore potente nella casa di Davide, suo servo, come aveva detto per bocca dei suoi santi profeti d''un tempo: salvezza dai nostri nemici, e dalle mani di quanti ci odiano. Così egli ha concesso misericordia ai nostri padri e si è ricordato della sua santa alleanza, del giuramento fatto ad Abramo, nostro padre, di concederci, liberati dalle mani dei nemici, di servirlo senza timore, in santità e giustizia al suo cospetto, per tutti i nostri giorni. E tu, bambino, sarai chiamato profeta dell''Altissimo perché andrai innanzi al Signore a preparargli le strade, per dare al suo popolo la conoscenza della salvezza nella remissione dei suoi peccati. Grazie alla tenerezza e misericordia del nostro Dio, ci visiterà un sole che sorge dall''alto, per risplendere su quelli che stanno nelle tenebre e nell''ombra di morte, e dirigere i nostri passi sulla via della pace»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 2,1-14', 'Luca', 'In quei giorni un decreto di Cesare Augusto ordinò che si facesse il censimento di tutta la terra. Questo primo censimento fu fatto quando Quirinio era governatore della Siria. Tutti andavano a farsi censire, ciascuno nella propria città. Anche Giuseppe, dalla Galilea, dalla città di Nàzaret, salì in Giudea alla città di Davide chiamata Betlemme: egli apparteneva infatti alla casa e alla famiglia di Davide. Doveva farsi censire insieme a Maria, sua sposa, che era incinta. Mentre si trovavano in quel luogo, si compirono per lei i giorni del parto. Diede alla luce il suo figlio primogenito, lo avvolse in fasce e lo pose in una mangiatoia, perché per loro non c''era posto nell''alloggio. C''erano in quella regione alcuni pastori che, pernottando all''aperto, vegliavano tutta la notte facendo la guardia al loro gregge. Un angelo del Signore si presentò a loro e la gloria del Signore li avvolse di luce. Essi furono presi da grande timore, ma l''angelo disse loro: «Non temete: ecco, vi annuncio una grande gioia, che sarà di tutto il popolo: oggi, nella città di Davide, è nato per voi un Salvatore, che è Cristo Signore. Questo per voi il segno: troverete un bambino avvolto in fasce, adagiato in una mangiatoia». E subito apparve con l''angelo una moltitudine dell''esercito celeste, che lodava Dio e diceva: «Gloria a Dio nel più alto dei cieli e sulla terra pace agli uomini, che egli ama»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 10,17-22', 'Matteo', '[Gesù disse]: «Guardatevi dagli uomini, perché vi consegneranno ai tribunali e vi flagelleranno nelle loro sinagoghe; e sarete condotti davanti a governatori e re per causa mia, per dare testimonianza a loro e ai pagani. Ma, quando vi consegneranno, non preoccupatevi di come o di che cosa direte, perché vi sarà dato in quell''ora ciò che dovrete dire: infatti non siete voi a parlare, ma è lo Spirito del Padre vostro che parla in voi. Il fratello farà morire il fratello e il padre il figlio, e i figli si alzeranno ad accusare i genitori e li uccideranno. Sarete odiati da tutti a causa del mio nome. Ma chi avrà perseverato fino alla fine sarà salvato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 20,2-8', 'Giovanni', 'Corse allora e andò da Simon Pietro e dall''altro discepolo, quello che Gesù amava, e disse loro: «Hanno portato via il Signore dal sepolcro e non sappiamo dove l''hanno posto!». Pietro allora uscì insieme all''altro discepolo e si recarono al sepolcro. Correvano insieme tutti e due, ma l''altro discepolo corse più veloce di Pietro e giunse per primo al sepolcro. Si chinò, vide i teli posati là, ma non entrò. Giunse intanto anche Simon Pietro, che lo seguiva, ed entrò nel sepolcro e osservò i teli posati là, e il sudario - che era stato sul suo capo - non posato là con i teli, ma avvolto in un luogo a parte. Allora entrò anche l''altro discepolo, che era giunto per primo al sepolcro, e vide e credette');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 2,13-18', 'Matteo', 'Essi erano appena partiti, quando un angelo del Signore apparve in sogno a Giuseppe e gli disse: «Àlzati, prendi con te il bambino e sua madre, fuggi in Egitto e resta là finché non ti avvertirò: Erode infatti vuole cercare il bambino per ucciderlo». Egli si alzò, nella notte, prese il bambino e sua madre e si rifugiò in Egitto, dove rimase fino alla morte di Erode, perché si compisse ciò che era stato detto dal Signore per mezzo del profeta: ″Dall''Egitto ho chiamato mio figlio″. Quando Erode si accorse che i Magi si erano presi gioco di lui, si infuriò e mandò a uccidere tutti i bambini che stavano a Betlemme e in tutto il suo territorio e che avevano da due anni in giù, secondo il tempo che aveva appreso con esattezza dai Magi. Allora si compì ciò che era stato detto per mezzo del profeta Geremia: ″Un grido è stato udito in Rama, un pianto e un lamento grande: Rachele piange i suoi figli e non vuole essere consolata, perché non sono più″');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 2,13-15.19-23', 'Matteo', 'Quando furono compiuti i giorni della loro purificazione rituale, secondo la legge di Mosè, portarono il bambino a Gerusalemme per presentarlo al Signore - come è scritto nella legge del Signore: Ogni maschio primogenito sarà sacro al Signore - e per offrire in sacrificio una coppia di tortore o due giovani colombi, come prescrive la legge del Signore. Ora a Gerusalemme c''era un uomo di nome Simeone, uomo giusto e pio, che aspettava la consolazione d''Israele, e lo Spirito Santo era su di lui. Lo Spirito Santo gli aveva preannunciato che non avrebbe visto la morte senza prima aver veduto il Cristo del Signore. Mosso dallo Spirito, si recò al tempio e, mentre i genitori vi portavano il bambino Gesù per fare ciò che la Legge prescriveva a suo riguardo, anch''egli lo accolse tra le braccia e benedisse Dio, dicendo: «Ora puoi lasciare, o Signore, che il tuo servo vada in pace, secondo la tua parola, perché i miei occhi hanno visto la tua salvezza, preparata da te davanti a tutti i popoli: luce per rivelarti alle genti e gloria del tuo popolo, Israele». Il padre e la madre di Gesù si stupivano delle cose che si dicevano di lui. Simeone li benedisse e a Maria, sua madre, disse: «Ecco, egli è qui per la caduta e la risurrezione di molti in Israele e come segno di contraddizione - e anche a te una spada trafiggerà l''anima -, affinché siano svelati i pensieri di molti cuori»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 2,41-52', 'Luca', '[Maria e Giuseppe portarono il bambino a Gerusalemme per presentarlo al Signore.] C''era una profetessa, Anna, figlia di Fanuèle, della tribù di Aser. Era molto avanzata in età, aveva vissuto con il marito sette anni dopo il suo matrimonio, era poi rimasta vedova e ora aveva ottantaquattro anni. Non si allontanava mai dal tempio, servendo Dio notte e giorno con digiuni e preghiere. Sopraggiunta in quel momento, si mise anche lei a lodare Dio e parlava del bambino a quanti aspettavano la redenzione di Gerusalemme. Quando ebbero adempiuto ogni cosa secondo la legge del Signore, fecero ritorno in Galilea, alla loro città di Nàzaret. Il bambino cresceva e si fortificava, pieno di sapienza, e la grazia di Dio era su di lui');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 1,1-18', 'Giovanni', 'In principio era il Verbo, e il Verbo era presso Dio e il Verbo era Dio. Egli era, in principio, presso Dio: tutto è stato fatto per mezzo di lui e senza di lui nulla è stato fatto di ciò che esiste. In lui era la vita e la vita era la luce degli uomini; la luce splende nelle tenebre e le tenebre non l''hanno vinta. Venne un uomo mandato da Dio: il suo nome era Giovanni. Egli venne come testimone per dare testimonianza alla luce, perché tutti credessero per mezzo di lui. Non era lui la luce, ma doveva dare testimonianza alla luce. Veniva nel mondo la luce vera, quella che illumina ogni uomo. Era nel mondo e il mondo è stato fatto per mezzo di lui; eppure il mondo non lo ha riconosciuto. Venne fra i suoi, e i suoi non lo hanno accolto. A quanti però lo hanno accolto ha dato potere di diventare figli di Dio: a quelli che credono nel suo nome, i quali, non da sangue né da volere di carne né da volere di uomo, ma da Dio sono stati generati. E il Verbo si fece carne e venne ad abitare in mezzo a noi; e noi abbiamo contemplato la sua gloria, gloria come del Figlio unigenito che viene dal Padre, pieno di grazia e di verità. Giovanni gli dà testimonianza e proclama: "Era di lui che io dissi: Colui che viene dopo di me è avanti a me, perché era prima di me". Dalla sua pienezza noi tutti abbiamo ricevuto: grazia su grazia. Perché la Legge fu data per mezzo di Mosè, la grazia e la verità vennero per mezzo di Gesù Cristo. Dio, nessuno lo ha mai visto: il Figlio unigenito, che è Dio ed è nel seno del Padre, è lui che lo ha rivelato');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 2,16-21', 'Luca', '[I pastori] Andarono, senza indugio, e trovarono Maria e Giuseppe e il bambino, adagiato nella mangiatoia. E dopo averlo visto, riferirono ciò che del bambino era stato detto loro. Tutti quelli che udivano si stupirono delle cose dette loro dai pastori. Maria, da parte sua, custodiva tutte queste cose, meditandole nel suo cuore.  I pastori se ne tornarono, glorificando e lodando Dio per tutto quello che avevano udito e visto, com''era stato detto loro. Quando furono compiuti gli otto giorni prescritti per la circoncisione, gli fu messo nome Gesù, come era stato chiamato dall''angelo prima che fosse concepito nel grembo');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 1,19-28', 'Giovanni', 'Questa è la testimonianza di Giovanni, quando i Giudei gli inviarono da Gerusalemme sacerdoti e leviti a interrogarlo: «Tu, chi sei?». Egli confessò e non negò. Confessò: «Io non sono il Cristo». Allora gli chiesero: «Chi sei, dunque? Sei tu Elia?». «Non lo sono», disse. «Sei tu il profeta?». «No», rispose. Gli dissero allora: «Chi sei? Perché possiamo dare una risposta a coloro che ci hanno mandato. Che cosa dici di te stesso?». Rispose: «Io sono voce di uno che grida nel deserto : Rendete diritta la via del Signore , come disse il profeta Isaia». Quelli che erano stati inviati venivano dai farisei. Essi lo interrogarono e gli dissero: «Perché dunque tu battezzi, se non sei il Cristo, né Elia, né il profeta?». Giovanni rispose loro: «Io battezzo nell''acqua. In mezzo a voi sta uno che voi non conoscete, colui che viene dopo di me: a lui io non sono degno di slegare il laccio del sandalo». Questo avvenne in Betània, al di là del Giordano, dove Giovanni stava battezzando');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 1,29-34', 'Giovanni', '[Giovanni Battista] Il giorno dopo, vedendo Gesù venire verso di lui, disse: «Ecco l''agnello di Dio, colui che toglie il peccato del mondo! Egli è colui del quale ho detto: “Dopo di me viene un uomo che è avanti a me, perché era prima di me”. Io non lo conoscevo, ma sono venuto a battezzare nell''acqua, perché egli fosse manifestato a Israele». Giovanni testimoniò dicendo: «Ho contemplato lo Spirito discendere come una colomba dal cielo e rimanere su di lui. Io non lo conoscevo, ma proprio colui che mi ha inviato a battezzare nell''acqua mi disse: “Colui sul quale vedrai discendere e rimanere lo Spirito, è lui che battezza nello Spirito Santo”. E io ho visto e ho testimoniato che questi è il Figlio di Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 1,35-42', 'Giovanni', 'Il giorno dopo Giovanni stava ancora là con due dei suoi discepoli e, fissando lo sguardo su Gesù che passava, disse: «Ecco l''agnello di Dio!». E i suoi due discepoli, sentendolo parlare così, seguirono Gesù. Gesù allora si voltò e, osservando che essi lo seguivano, disse loro: «Che cosa cercate?». Gli risposero: «Rabbì - che, tradotto, significa Maestro -, dove dimori?». Disse loro: «Venite e vedrete». Andarono dunque e videro dove egli dimorava e quel giorno rimasero con lui; erano circa le quattro del pomeriggio. Uno dei due che avevano udito le parole di Giovanni e lo avevano seguito, era Andrea, fratello di Simon Pietro. Egli incontrò per primo suo fratello Simone e gli disse: «Abbiamo trovato il Messia» - che si traduce Cristo - e lo condusse da Gesù. Fissando lo sguardo su di lui, Gesù disse: «Tu sei Simone, il figlio di Giovanni; sarai chiamato Cefa» - che significa Pietro');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 2,1-12', 'Matteo', 'Nato Gesù a Betlemme di Giudea, al tempo del re Erode, ecco, alcuni Magi vennero da oriente a Gerusalemme e dicevano: «Dov''è colui che è nato, il re dei Giudei? Abbiamo visto spuntare la sua stella e siamo venuti ad adorarlo». All''udire questo, il re Erode restò turbato e con lui tutta Gerusalemme. Riuniti tutti i capi dei sacerdoti e gli scribi del popolo, si informava da loro sul luogo in cui doveva nascere il Cristo. Gli risposero: «A Betlemme di Giudea, perché così è scritto per mezzo del profeta: “E tu, Betlemme, terra di Giuda, non sei davvero l''ultima delle città principali di Giuda: da te infatti uscirà un capo che sarà il pastore del mio popolo, Israele”». Allora Erode, chiamati segretamente i Magi, si fece dire da loro con esattezza il tempo in cui era apparsa la stella e li inviò a Betlemme dicendo: «Andate e informatevi accuratamente sul bambino e, quando l''avrete trovato, fatemelo sapere, perché anch''io venga ad adorarlo». Udito il re, essi partirono. Ed ecco, la stella, che avevano visto spuntare, li precedeva, finché giunse e si fermò sopra il luogo dove si trovava il bambino.  Al vedere la stella, provarono una gioia grandissima. Entrati nella casa, videro il bambino con Maria sua madre, si prostrarono e lo adorarono. Poi aprirono i loro scrigni e gli offrirono in dono oro, incenso e mirra. Avvertiti in sogno di non tornare da Erode, per un''altra strada fecero ritorno al loro paese');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 4,12-17.23-25', 'Matteo', 'Quando Gesù seppe che Giovanni era stato arrestato, si ritirò nella Galilea, lasciò Nàzaret e andò ad abitare a Cafàrnao, sulla riva del mare, nel territorio di Zàbulon e di Nèftali, perché si compisse ciò che era stato detto per mezzo del profeta Isaia: "Terra di Zàbulon e terra di Nèftali, sulla via del mare, oltre il Giordano, Galilea delle genti! Il popolo che abitava nelle tenebre vide una grande luce, per quelli che abitavano in regione e ombra di morte una luce è sorta. " Da allora Gesù cominciò a predicare e a dire: «Convertitevi, perché il regno dei cieli è vicino» . Gesù percorreva tutta la Galilea, insegnando nelle loro sinagoghe, annunciando il vangelo del Regno e guarendo ogni sorta di malattie e di infermità nel popolo. La sua fama si diffuse per tutta la Siria e conducevano a lui tutti i malati, tormentati da varie malattie e dolori, indemoniati, epilettici e paralitici; ed egli li guarì. Grandi folle cominciarono a seguirlo dalla Galilea, dalla Decàpoli, da Gerusalemme, dalla Giudea e da oltre il Giordano.');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 6,34-44', 'Marco', '[Gesù], sceso dalla barca, vide una grande folla, ebbe compassione di loro, perché erano come pecore che non hanno pastore, e si mise a insegnare loro molte cose. Essendosi ormai fatto tardi, gli si avvicinarono i suoi discepoli dicendo: «Il luogo è deserto ed è ormai tardi; congedali, in modo che, andando per le campagne e i villaggi dei dintorni, possano comprarsi da mangiare». Ma egli rispose loro: «Voi stessi date loro da mangiare». Gli dissero: «Dobbiamo andare a comprare duecento denari di pane e dare loro da mangiare?». Ma egli disse loro: «Quanti pani avete? Andate a vedere». Si informarono e dissero: «Cinque, e due pesci». E ordinò loro di farli sedere tutti, a gruppi, sull''erba verde. E sedettero, a gruppi di cento e di cinquanta. Prese i cinque pani e i due pesci, alzò gli occhi al cielo, recitò la benedizione, spezzò i pani e li dava ai suoi discepoli perché li distribuissero a loro; e divise i due pesci fra tutti. Tutti mangiarono a sazietà, e dei pezzi di pane portarono via dodici ceste piene e quanto restava dei pesci. Quelli che avevano mangiato i pani erano cinquemila uomini');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 6,45-52', 'Marco', 'E, Gesù, subito costrinse i suoi discepoli a salire sulla barca e a precederlo sull''altra riva, a Betsàida, finché non avesse congedato la folla. Quando li ebbe congedati, andò sul monte a pregare. Venuta la sera, la barca era in mezzo al mare ed egli, da solo, a terra. Vedendoli però affaticati nel remare, perché avevano il vento contrario, sul finire della notte egli andò verso di loro, camminando sul mare, e voleva oltrepassarli. Essi, vedendolo camminare sul mare, pensarono: «È un fantasma!», e si misero a gridare, perché tutti lo avevano visto e ne erano rimasti sconvolti. Ma egli subito parlò loro e disse: «Coraggio, sono io, non abbiate paura!». E salì sulla barca con loro e il vento cessò. E dentro di sé erano fortemente meravigliati, perché non avevano compreso il fatto dei pani: il loro cuore era indurito');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 4,12-22a', 'Luca', 'Gesù rispose al diavolo: «È stato detto: Non metterai alla prova il Signore Dio tuo». Dopo aver esaurito ogni tentazione, il diavolo si allontanò da lui fino al momento fissato. Gesù ritornò in Galilea con la potenza dello Spirito e la sua fama si diffuse in tutta la regione. Insegnava nelle loro sinagoghe e gli rendevano lode. Venne a Nàzaret, dove era cresciuto, e secondo il suo solito, di sabato, entrò nella sinagoga e si alzò a leggere. Gli fu dato il rotolo del profeta Isaia; aprì il rotolo e trovò il passo dove era scritto: Lo Spirito del Signore è sopra di me; per questo mi ha consacrato con l''unzione e mi ha mandato a portare ai poveri il lieto annuncio, a proclamare ai prigionieri la liberazione e ai ciechi la vista; a rimettere in libertà gli oppressi, a proclamare l''anno di grazia del Signore. Riavvolse il rotolo, lo riconsegnò all''inserviente e sedette. Nella sinagoga, gli occhi di tutti erano fissi su di lui. Allora cominciò a dire loro: «Oggi si è compiuta questa Scrittura che voi avete ascoltato». Tutti gli davano testimonianza ed erano meravigliati delle parole di grazia che uscivano dalla sua bocca e dicevano: «Non è costui il figlio di Giuseppe?»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 5,12-16', 'Luca', 'Mentre Gesù si trovava in una città, ecco, un uomo coperto di lebbra lo vide e gli si gettò dinanzi, pregandolo: «Signore, se vuoi, puoi purificarmi». Gesù tese la mano e lo toccò dicendo: «Lo voglio, sii purificato!». E immediatamente la lebbra scomparve da lui. Gli ordinò di non dirlo a nessuno: «Va'' invece a mostrarti al sacerdote e fa'' l''offerta per la tua purificazione, come Mosè ha prescritto, a testimonianza per loro». Di lui si parlava sempre di più, e folle numerose venivano per ascoltarlo e farsi guarire dalle loro malattie. Ma egli si ritirava in luoghi deserti a pregare');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 3,13-17', 'Matteo', 'Allora Gesù dalla Galilea venne al Giordano da Giovanni, per farsi battezzare da lui. Giovanni però voleva impedirglielo, dicendo: «Sono io che ho bisogno di essere battezzato da te, e tu vieni da me?». Ma Gesù gli rispose: «Lascia fare per ora, perché conviene che adempiamo ogni giustizia». Allora egli lo lasciò fare. Appena battezzato, Gesù uscì dall''acqua: ed ecco, si aprirono per lui i cieli ed egli vide lo Spirito di Dio discendere come una colomba e venire sopra di lui. Ed ecco una voce dal cielo che diceva: "Questi è il Figlio mio, l''amato: in lui ho posto il mio compiacimento”');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 1,14-20', 'Marco', 'Dopo che Giovanni fu arrestato, Gesù andò nella Galilea, proclamando il vangelo di Dio, e diceva: «Il tempo è compiuto e il regno di Dio è vicino; convertitevi e credete nel Vangelo». Passando lungo il mare di Galilea, vide Simone e Andrea, fratello di Simone, mentre gettavano le reti in mare; erano infatti pescatori. Gesù disse loro: «Venite dietro a me, vi farò diventare pescatori di uomini». E subito lasciarono le reti e lo seguirono. Andando un poco oltre, vide Giacomo, figlio di Zebedeo, e Giovanni suo fratello, mentre anch''essi nella barca riparavano le reti. E subito li chiamò. Ed essi lasciarono il loro padre Zebedeo nella barca con i garzoni e andarono dietro a lui (Mc 1, 14-20).Dopo che Giovanni fu arrestato, Gesù andò nella Galilea, proclamando il vangelo di Dio, e diceva: «Il tempo è compiuto e il regno di Dio è vicino; convertitevi e credete nel Vangelo». Passando lungo il mare di Galilea, vide Simone e Andrea, fratello di Simone, mentre gettavano le reti in mare; erano infatti pescatori. Gesù disse loro: «Venite dietro a me, vi farò diventare pescatori di uomini». E subito lasciarono le reti e lo seguirono. Andando un poco oltre, vide Giacomo, figlio di Zebedeo, e Giovanni suo fratello, mentre anch''essi nella barca riparavano le reti. E subito li chiamò. Ed essi lasciarono il loro padre Zebedeo nella barca con i garzoni e andarono dietro a lui');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 1,21-28', 'Marco', 'Giunsero a Cafàrnao e subito Gesù, entrato di sabato nella sinagoga, insegnava. Ed erano stupiti del suo insegnamento: egli infatti insegnava loro come uno che ha autorità, e non come gli scribi. Ed ecco, nella loro sinagoga vi era un uomo posseduto da uno spirito impuro e cominciò a gridare, dicendo: «Che vuoi da noi, Gesù Nazareno? Sei venuto a rovinarci? Io so chi tu sei: il santo di Dio!». E Gesù gli ordinò severamente: «Taci! Esci da lui!». E lo spirito impuro, straziandolo e gr dando forte, uscì da lui. Tutti furono presi da timore, tanto che si chiedevano a vicenda: «Che è mai questo? Un insegnamento nuovo, dato con autorità. Comanda persino agli spiriti impuri e gli obbediscono!». La sua fama si diffuse subito dovunque, in tutta la regione della Galilea');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 1,29-39', 'Marco', 'E subito, usciti dalla sinagoga, andarono nella casa di Simone e An-drea, in compagnia di Giacomo e Giovanni. La suocera di Simone era a letto con la febbre e subito gli parlarono di lei. Gesù si avvicinò e la fece alzare prendendola per mano; la febbre la lasciò ed ella li serviva. Venuta la sera, dopo il tramonto del sole, gli portavano tutti i malati e gli indemoniati. Tutta la città era riunita davanti alla porta. Guarì molti che erano affetti da varie malattie e scacciò molti demòni; ma non permetteva ai demòni di parlare, perché lo conoscevano. Al mat-tino presto si alzò quando ancora era buio e, uscito, si ritirò in un luogo deserto, e là pregava.  Ma Simone e quelli che erano con lui si misero sulle sue tracce. Lo trovarono e gli dissero: «Tutti ti cercano!». Egli disse loro: «Andiamocene altrove, nei villaggi vicini, perché io predichi anche là; per questo infatti sono venuto!». E andò per tutta la Galilea, predicando nelle loro sinagoghe e scacciando i demòni');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 1,40-45', 'Marco', 'Venne da Gesù un lebbroso, che lo supplicava in ginocchio e gli diceva: «Se vuoi, puoi purificarmi!». Ne ebbe compassione, tese la mano, lo toccò e gli disse: «Lo voglio, sii purificato!». E subito la lebbra scomparve da lui ed egli fu purificato. E, ammonendolo severamente, lo cacciò via subito e gli disse: «Guarda di non dire niente a nessuno; va'', invece, a mostrarti al sacerdote e offri per la tua purificazione quello che Mosè ha prescritto, come testimonianza per loro».  Ma quello si allontanò e si mise a proclamare e a divulgare il fatto, tanto che Gesù non poteva più entrare pubblicamente in una città, ma rimaneva fuori, in luoghi deserti; e venivano a lui da ogni parte');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 2,1-12', 'Marco', '[Gesù] Entrò di nuovo a Cafàrnao, dopo alcuni giorni. Si seppe che era in casa e si radunarono tante persone che non vi era più poso neanche davanti alla porta; ed egli annunciava loro la Parola. Si recarono da Gesù portando un paralitico, sorretto da quattro persone. Non potendo però portarglielo innanzi, a causa della folla, scoperchiarono il tetto nel punto dove egli si trovava e, fatta un''apertura, calarono la barella su cui era adagiato il paralitico. Gesù, vedendo la loro fede, disse al paralitico: «Figlio, ti sono perdonati i peccati». Erano seduti là alcuni scribi e pensavano in cuor loro: «Perché costui parla così? Bestemmia! Chi può perdonare i peccati, se non Dio solo?». E subito Gesù, conoscendo nel suo spirito che così pensavano tra sé, disse loro: «Perché pensate queste cose nel vostro cuore? Che cosa è più facile: dire al paralitico "Ti sono perdonati i peccati", oppure dire "Àlzati, prendi la tua barella e cammina"? Ora, perché sappiate che il Figlio dell''uomo ha il potere di perdonare i peccati sulla terra, dico a te, disse al paralitico: àlzati, prendi la tua barella e va'' a casa tua». Quello si alzò e subito presa la sua barella, sotto gli occhi di tutti se ne andò, e tutti si meravigliarono e lodavano Dio, dicendo: «Non abbiamo mai visto nulla di simile!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 2,13-17', 'Marco', 'Gesù uscì di nuovo lungo il mare; tutta la folla veniva a lui ed egli insegnava loro. Passando, vide Levi, il figlio di Alfeo, seduto al banco delle imposte, e gli disse: «Seguimi». Ed egli si alzò e lo seguì.  Mentre stava a tavola in casa di lui, anche molti pubblicani e peccatori erano a tavola con Gesù e i suoi discepoli; erano molti infatti quelli che lo seguivano. Allora gli scribi dei farisei, vedendolo mangiare con i peccatori e i pubblicani, dicevano ai suoi discepoli: «Perché mangia e beve insieme ai pubblicani e ai peccatori?». Udito questo, Gesù disse loro: «Non sono i sani che hanno bisogno del medico, ma i malati; io non sono venuto a chiamare i giusti, ma i peccatori»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 2,18-22', 'Marco', 'I discepoli di Giovanni e i farisei stavano facendo un digiuno. Vennero da lui e gli dissero: «Perché i discepoli di Giovanni e i discepoli dei farisei digiunano, mentre i tuoi discepoli non digiunano?». Gesù disse loro: «Possono forse digiunare gli invitati a nozze, quando lo sposo è con loro? Finché hanno lo sposo con loro, non possono digiunare. Ma verranno giorni quando lo sposo sarà loro tolto: allora, in quel giorno, digiuneranno. Nessuno cuce un pezzo di stoffa grezza su un vestito vecchio; altrimenti il rattoppo nuovo porta via qualcosa alla stoffa vecchia e lo strappo diventa peggiore. E nessuno versa vino nuovo in otri vecchi, altrimenti il vino spaccherà gli otri, e si perdono vino e otri. Ma vino nuovo in otri nuovi!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 2,23-28', 'Marco', 'Avvenne che di sabato Gesù passava fra campi di grano e i suoi discepoli, mentre camminavano, si misero a cogliere le spighe. I farisei gli dicevano: «Guarda! Perché fanno in giorno di sabato quello che non è lecito?». Ed egli rispose loro: «Non avete mai letto quello che fece Davide quando si trovò nel bisogno e lui e i suoi compagni ebbero fame? Sotto il sommo sacerdote Abiatàr, entrò nella casa di Dio e mangiò i pani dell''offerta, che non è lecito mangiare se non ai sacerdoti, e ne diede anche ai suoi compagni!». E diceva loro: «Il sabato è stato fatto per l''uomo e non l''uomo per il sabato! Perciò il Figlio dell''uomo è signore anche del sabato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 3,1-6', 'Marco', 'Gesù entrò di nuovo nella sinagoga. Vi era lì un uomo che aveva una mano paralizzata, e stavano a vedere se lo guariva in giorno di sabato, per accusarlo. Egli disse all''uomo che aveva la mano paralizzata: «Àlzati, vieni qui in mezzo!». Poi domandò loro: «È lecito in giorno di sabato fare del bene o fare del male, salvare una vita o ucciderla?». Ma essi tacevano. E guardandoli tutt''intorno con indignazione, rattristato per la durezza dei loro cuori, disse all''uomo: «Tendi la mano!». Egli la tese e la sua mano fu guarita. E i farisei uscirono subito con gli erodiani e tennero consiglio contro di lui per farlo morire');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 3,7-12', 'Marco', 'Gesù, intanto, con i suoi discepoli si ritirò presso il mare e lo seguì molta folla dalla Galilea. Dalla Giudea e da Gerusalemme, dall''Idumea e da oltre il Giordano e dalle parti di Tiro e Sidone, una grande folla, sentendo quanto faceva, andò da lui. Allora egli disse ai suoi discepoli di tenergli pronta una barca, a causa della folla, perché non lo schiacciassero. Infatti aveva guarito molti, cosicché quanti avevano qualche male si gettavano su di lui per toccarlo. Gli spiriti impuri, quando lo vedevano, cadevano ai suoi piedi e gridavano: «Tu sei il Figlio di Dio!». Ma egli imponeva loro severamente di non svelare chi egli fosse');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 3,13-19', 'Marco', '[Gesù] Salì poi sul monte, chiamò a sé quelli che voleva ed essi andarono da lui. Ne costituì Dodici, che chiamò apostoli, perché stessero con lui e per mandarli a predicare con il potere di scacciare i demòni. Costituì dunque i Dodici: Simone, al quale impose il nome di Pietro, poi Giacomo, figlio di Zebedeo, e Giovanni fratello di Giacomo, ai quali diede il nome di Boanèrghes, cioè "figli del tuono"; e Andrea, Filippo, Bartolomeo, Matteo, Tommaso, Giacomo, figlio di Alfeo, Taddeo, Simone il Cananeo e Giuda Iscariota, il quale poi lo tradì.');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 16,15-18', 'Marco', 'E [Gesù] disse loro: «Andate in tutto il mondo e proclamate il Vangelo a ogni creatura. Chi crederà e sarà battezzato sarà salvato, ma chi non crederà sarà condannato. Questi saranno i segni che accompagneranno quelli che credono: nel mio nome scacceranno demòni, parleranno lingue nuove, prenderanno in mano serpenti e, se berranno qualche veleno, non recherà loro danno; imporranno le mani ai malati e questi guariranno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 4,12-23', 'Matteo', 'Quando Gesù seppe che Giovanni era stato arrestato, si ritirò nella Galilea, lasciò Nàzaret e andò ad abitare a Cafàrnao, sulla riva del mare, nel territorio di Zàbulon e di Nèftali, perché si compisse ciò che era stato detto per mezzo del profeta Isaia: Terra di Zàbulon e terra di Nèftali, sulla via del mare, oltre il Giordano, Galilea delle genti! Il popolo che abitava nelle tenebre vide una grande luce, per quelli che abitavano in regione e ombra di morte una luce è sorta. Da allora Gesù cominciò a predicare e a dire: «Convertitevi, perché il regno dei cieli è vicino». Mentre camminava lungo il mare di Galilea, vide due fratelli, Simone, chiamato Pietro, e Andrea suo fratello, che gettavano le reti in mare; erano infatti pescatori. E disse loro: «Venite dietro a me, vi farò pescatori di uomini». Ed essi subito lasciarono le reti e lo seguirono.  Andando oltre, vide altri due fratelli, Giacomo, figlio di Zebedeo, e Giovanni suo fratello, che nella barca, insieme a Zebedeo loro padre, riparavano le loro reti, e li chiamò. Ed essi subito lasciarono la barca e il loro padre e lo seguirono. Gesù percorreva tutta la Galilea, insegnando nelle loro sinagoghe, annunciando il vangelo del Regno e guarendo ogni sorta di malattie e di infermità nel popolo');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 3,22-30', 'Marco', 'Gli scribi, che erano scesi da Gerusalemme, dicevano verso Gesù: «Costui è posseduto da Beelzebùl e scaccia i demòni per mezzo del capo dei demòni». Ma egli li chiamò e con parabole diceva loro: «Come può Satana scacciare Satana?  Se un regno è diviso in se stesso, quel regno non potrà restare in piedi; se una casa è divisa in se stessa, quella casa non potrà restare in piedi. Anche Satana, se si ribella contro se stesso ed è diviso, non può restare in piedi, ma è finito. Nessuno può entrare nella casa di un uomo forte e rapire i suoi beni, se prima non lo lega. Soltanto allora potrà saccheggiargli la casa. In verità io vi dico: tutto sarà perdonato ai figli degli uomini, i peccati e anche tutte le bestemmie che diranno; ma chi avrà bestemmiato contro lo Spirito Santo non sarà perdonato in eterno: è reo di colpa eterna». Poiché dicevano: «È posseduto da uno spirito impuro»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 3,31-35', 'Marco', 'Giunsero sua madre e i suoi fratelli e, stando fuori, mandarono a chiamarlo [a Gesù]. Attorno a lui era seduta una folla, e gli dissero: «Ecco, tua madre, i tuoi fratelli e le tue sorelle stanno fuori e ti cercano». Ma egli rispose loro: «Chi è mia madre e chi sono i miei fratelli?». Girando lo sguardo su quelli che erano seduti attorno a lui, disse: «Ecco mia madre e i miei fratelli! Perché chi fa la volontà di Dio, costui per me è fratello, sorella e madre»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 4,1-20', 'Marco', 'Gesù cominciò di nuovo a insegnare lungo il mare. Si riunì attorno a lui una folla enorme, tanto che egli, salito su una barca, si mise a sedere stando in mare, mentre tutta la folla era a terra lungo la riva. Insegnava loro molte cose con parabole e diceva loro nel suo insegnamento: «Ascoltate. Ecco, il seminatore uscì a seminare. Mentre seminava, una parte cadde lungo la strada; vennero gli uccelli e la mangiarono. Un''altra parte cadde sul terreno sassoso, dove non c''era molta terra; e subito germogliò perché il terreno non era profondo, ma quando spuntò il sole, fu bruciata e, non avendo radici, seccò. Un''altra parte cadde tra i rovi, e i rovi crebbero, la soffocarono e non diede frutto. Altre parti caddero sul terreno buono e diedero frutto: spuntarono, crebbero e resero il trenta, il sessanta, il cento per uno».  E diceva: «Chi ha orecchi per ascoltare, ascolti!». Quando poi furono da soli, quelli che erano intorno a lui insieme ai Dodici lo interrogavano sulle parabole. Ed egli diceva loro: «A voi è stato dato il mistero del regno di Dio; per quelli che sono fuori invece tutto avviene in parabole, affinché guardino, sì, ma non vedano, ascoltino, sì, ma non comprendano, perché non si convertano e venga loro perdonato». E disse loro: «Non capite questa parabola, e come potrete comprendere tutte le parabole?  Il seminatore semina la Parola. Quelli lungo la strada sono coloro nei quali viene seminata la Parola, ma, quando l''ascoltano, subito viene Satana e porta via la Parola seminata in loro. Quelli seminati sul terreno sassoso sono coloro che, quando ascoltano la Parola, subito l''accolgono con gioia, ma non hanno radice in se stessi, sono incostanti e quindi, al sopraggiungere di qualche tribolazione o persecuzione a causa della Parola, subito vengono meno. Altri sono quelli seminati tra i rovi: questi sono coloro che hanno ascoltato la Parola, ma sopraggiungono le preoccupazioni del mondo e la seduzione della ricchezza e tutte le altre passioni, soffocano la Parola e questa rimane senza frutto.  Altri ancora sono quelli seminati sul terreno buono: sono coloro che ascoltano la Parola, l''accolgono e portano frutto: il trenta, il sessanta, il cento per uno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 4,21-25', 'Marco', 'Gesù diceva loro: «Viene forse la lampada per essere messa sotto il moggio o sotto il letto? O non invece per essere messa sul candelabro? Non vi è infatti nulla di segreto che non debba essere manifestato e nulla di nascosto che non debba essere messo in luce. Se uno ha orecchi per ascoltare, ascolti!». Diceva loro: «Fate attenzione a quello che ascoltate. Con la misura con la quale misurate sarà misurato a voi; anzi, vi sarà dato di più. Perché a chi ha, sarà dato; ma a chi non ha, sarà tolto anche quello che ha»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 4,35-41', 'Marco', 'In quel medesimo giorno, venuta la sera, Gesù disse loro: «Passiamo all''altra riva». E, congedata la folla, lo presero con sé, così com''era, nella barca. C''erano anche altre barche con lui. Ci fu una grande tempesta di vento e le onde si rovesciavano nella barca, tanto che ormai era piena. Egli se ne stava a poppa, sul cuscino, e dormiva. Allora lo svegliarono e gli dissero: «Maestro, non t''importa che siamo perduti?». Si destò, minacciò il vento e disse al mare: «Taci, calmati!». Il vento cessò e ci fu grande bonaccia. Poi disse loro: «Perché avete paura? Non avete ancora fede?». E furono presi da grande timore e si dicevano l''un l''altro: «Chi è dunque costui, che anche il vento e il mare gli obbediscono?»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,13-16', 'Matteo', '[In quel tempo Gesù diceva] «Voi siete il sale della terra; ma se il sale perde il sapore, con che cosa lo si renderà salato? A null''altro serve che ad essere gettato via e calpestato dalla gente. Voi siete la luce del mondo; non può restare nascosta una città che sta sopra un monte, né si accende una lampada per metterla sotto il moggio, ma sul candelabro, e così fa luce a tutti quelli che sono nella casa. Così risplenda la vostra luce davanti agli uomini, perché vedano le vostre opere buone e rendano gloria al Padre vostro che è nei cieli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 7,24-30', 'Marco', '[In quel tempo, Gesù], Partito di là, andò nella regione di Tiro. Entrato in una casa, non voleva che alcuno lo sapesse, ma non poté restare nascosto. Una donna, la cui figlioletta era posseduta da uno spirito impuro, appena seppe di lui, andò e si gettò ai suoi piedi. Questa donna era di lingua greca e di origine siro-fenicia. Ella lo supplicava di scacciare il demonio da sua figlia. Ed egli le rispondeva: «Lascia prima che si sazino i figli, perché non è bene prendere il pane dei figli e gettarlo ai cagnolini». Ma lei gli replicò: «Signore, anche i cagnolini sotto la tavola mangiano le briciole dei figli». Allora le disse: «Per questa tua parola, va'': il demonio è uscito da tua figlia». Tornata a casa sua, trovò la bambina coricata sul letto e il demonio se n''era andato');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,17-37', 'Matteo', '[Gesù disse], «Non crediate che io sia venuto ad abolire la Legge o i Profeti; non sono venuto ad abolire, ma a dare pieno compimento. In verità io vi dico: finché non siano passati il cielo e la terra, non passerà un solo iota o un solo trattino della Legge, senza che tutto sia avvenuto. Chi dunque trasgredirà uno solo di questi minimi precetti e insegnerà agli altri a fare altrettanto, sarà considerato minimo nel regno dei cieli. Chi invece li osserverà e li insegnerà, sarà considerato grande nel regno dei cieli. Io vi dico infatti: se la vostra giustizia non supererà quella degli scribi e dei farisei, non entrerete nel regno dei cieli. Avete inteso che fu detto agli antichi: Non ucciderai; chi avrà ucciso dovrà essere sottoposto al giudizio. Ma io vi dico: chiunque si adira con il proprio fratello dovrà essere sottoposto al giudizio. Chi poi dice al fratello: "Stupido", dovrà essere sottoposto al sinedrio; e chi gli dice: "Pazzo", sarà destinato al fuoco della Geènna. Se dunque tu presenti la tua offerta all''altare e lì ti ricordi che tuo fratello ha qualche cosa contro di te, lascia lì il tuo dono davanti all''altare, va'' prima a riconciliarti con il tuo fratello e poi torna a offrire il tuo dono. Mettiti presto d''accordo con il tuo avversario mentre sei in cammino con lui, perché l''avversario non ti consegni al giudice e il giudice alla guardia, e tu venga gettato in prigione. In verità io ti dico: non uscirai di là finché non avrai pagato fino all''ultimo spicciolo! Avete inteso che fu detto: Non commetterai adulterio. Ma io vi dico: chiunque guarda una donna per desiderarla, ha già commesso adulterio con lei nel proprio cuore. Se il tuo occhio destro ti è motivo di scandalo, cavalo e gettalo via da te: ti conviene infatti perdere una delle tue membra, piuttosto che tutto il tuo corpo venga gettato nella Geènna. E se la tua mano destra ti è motivo di scandalo, tagliala e gettala via da te: ti conviene infatti perdere una delle tue membra, piuttosto che tutto il tuo corpo vada a finire nella Geènna. Fu pure detto: "Chi ripudia la propria moglie, le dia l''atto del ripudio". Ma io vi dico: chiunque ripudia la propria moglie, eccetto il caso di unione illegittima, la espone all''adulterio, e chiunque sposa una ripudiata, commette adulterio. Avete anche inteso che fu detto agli antichi: "Non giurerai il falso, ma adempirai verso il Signore i tuoi giuramenti". Ma io vi dico: non giurate affatto, né per il cielo, perché è il trono di Dio, né per la terra, perché è lo sgabello dei suoi piedi, né per Gerusalemme, perché è la città del grande Re. Non giurare neppure per la tua testa, perché non hai il potere di rendere bianco o nero un solo capello. Sia invece il vostro parlare: "Sì, sì", "No, no"; il di più viene dal Maligno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 8,34-9,1', 'Marco', 'Convocata la folla insieme ai suoi discepoli, [Gesù] disse loro: «Se qualcuno vuol venire dietro a me, rinneghi se stesso, prenda la sua croce e mi segua. Perché chi vuole salvare la propria vita, la perderà; ma chi perderà la propria vita per causa mia e del Vangelo, la salverà. Infatti quale vantaggio c''è che un uomo guadagni il mondo intero e perda la propria vita? Che cosa potrebbe dare un uomo in cambio della propria vita? Chi si vergognerà di me e delle mie parole davanti a questa generazione adultera e peccatrice, anche il Figlio dell''uomo si vergognerà di lui, quando verrà nella gloria del Padre suo con gli angeli santi» Diceva loro: «In verità io vi dico: vi sono alcuni, qui presenti, che non morranno prima di aver visto giungere il regno di Dio nella sua potenza»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,38-48', 'Matteo', '[Dice Gesù], «Avete inteso che fu detto: Occhio per occhio e dente per dente. Ma io vi dico di non opporvi al malvagio; anzi, se uno ti dà uno schiaffo sulla guancia destra, tu porgigli anche l''altra, e a chi vuole portarti in tribunale e toglierti la tunica, tu lascia anche il mantello. E se uno ti costringerà ad accompagnarlo per un miglio, tu con lui fanne due. Da'' a chi ti chiede, e a chi desidera da te un prestito non voltare le spalle. Avete inteso che fu detto: Amerai il tuo prossimo e odierai il tuo nemico. Ma io vi dico: amate i vostri nemici e pregate per quelli che vi perseguitano, affinché siate figli del Padre vostro che è nei cieli; egli fa sorgere il suo sole sui cattivi e sui buoni, e fa piovere sui giusti e sugli ingiusti. Infatti, se amate quelli che vi amano, quale ricompensa ne avete? Non fanno così anche i pubblicani? E se date il saluto soltanto ai vostri fratelli, che cosa fate di straordinario? Non fanno così anche i pagani? Voi, dunque, siate perfetti come è perfetto il Padre vostro celeste»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 4,1-11', 'Matteo', 'Allora Gesù fu condotto dallo Spirito nel deserto, per essere tentato dal diavolo. Dopo aver digiunato quaranta giorni e quaranta notti, alla fine ebbe fame. Il tentatore gli si avvicinò e gli disse: «Se tu sei Figlio di Dio, di'' che queste pietre diventino pane». Ma egli rispose: «Sta scritto: Non di solo pane vivrà l''uomo, ma di ogni parola che esce dalla bocca di Dio». Allora il diavolo lo portò nella città santa, lo pose sul punto più alto del tempio e gli disse: «Se tu sei Figlio di Dio, gèttati giù; sta scritto infatti: Ai suoi angeli darà ordini a tuo riguardo ed essi ti porteranno sulle loro mani perché il tuo piede non inciampi in una pietra».  Gesù gli rispose: «Sta scritto anche: Non metterai alla prova il Signore Dio tuo». Di nuovo il diavolo lo portò sopra un monte altissimo e gli mostrò tutti i regni del mondo e la loro gloria e gli disse: «Tutte queste cose io ti darò se, gettandoti ai miei piedi, mi adorerai». Allora Gesù gli rispose: «Vattene, Satana! Sta scritto infatti: Il Signore, Dio tuo, adorerai: a lui solo renderai culto». Allora il diavolo lo lasciò, ed ecco, degli angeli gli si avvicinarono e lo servivano');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 17,1-9', 'Matteo', 'Sei giorni dopo, Gesù prese con sé Pietro, Giacomo e Giovanni suo fratello e li condusse in disparte, su un alto monte. E fu trasfigurato davanti a loro: il suo volto brillò come il sole e le sue vesti divennero candide come la luce. Ed ecco, apparvero loro Mosè ed Elia, che conversavano con lui. Prendendo la parola, Pietro disse a Gesù: «Signore, è bello per noi essere qui! Se vuoi, farò qui tre capanne, una per te, una per Mosè e una per Elia». Egli stava ancora parlando, quando una nube luminosa li coprì con la sua ombra. Ed ecco una voce dalla nube che diceva: «Questi è il Figlio mio, l''amato: in lui ho posto il mio compiacimento. Ascoltatelo». All''udire ciò, i discepoli caddero con la faccia a terra e furono presi da grande timore. Ma Gesù si avvicinò, li toccò e disse: «Alzatevi e non temete». Alzando gli occhi non videro nessuno, se non Gesù solo. Mentre scendevano dal monte, Gesù ordinò loro: «Non parlate a nessuno di questa visione, prima che il Figlio dell''uomo non sia risorto dai morti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 23,1-12', 'Matteo', 'Allora Gesù si rivolse alla folla e ai suoi discepoli dicendo: «Sulla cattedra di Mosè si sono seduti gli scribi e i farisei. Praticate e osservate tutto ciò che vi dicono, ma non agite secondo le loro opere, perché essi dicono e non fanno. Legano infatti fardelli pesanti e difficili da portare e li pongono sulle spalle della gente, ma essi non vogliono muoverli neppure con un dito. Tutte le loro opere le fanno per essere ammirati dalla gente: allargano i loro filattèri e allungano le frange; si compiacciono dei posti d''onore nei banchetti, dei primi seggi nelle sinagoghe, dei saluti nelle piazze, come anche di essere chiamati "rabbì" dalla gente. Ma voi non fatevi chiamare "rabbì", perché uno solo è il vostro Maestro e voi siete tutti fratelli. E non chiamate "padre" nessuno di voi sulla terra, perché uno solo è il Padre vostro, quello celeste. E non fatevi chiamare "guide", perché uno solo è la vostra Guida, il Cristo. Chi tra voi è più grande, sarà vostro servo; chi invece si esalterà, sarà umiliato e chi si umilierà sarà esaltato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 21,33-43.45-46', 'Matteo', '[Disse Gesù ai Sacerdoti e agli anziani del popolo], «Ascoltate un''altra parabola: c''era un uomo che possedeva un terreno e vi piantò una vigna. La circondò con una siepe, vi scavò una buca per il torchio e costruì una torre. La diede in affitto a dei contadini e se ne andò lontano. Quando arrivò il tempo di raccogliere i frutti, mandò i suoi servi dai contadini a ritirare il raccolto. Ma i contadini presero i servi e uno lo bastonarono, un altro lo uccisero, un altro lo lapidarono. Mandò di nuovo altri servi, più numerosi dei primi, ma li trattarono allo stesso modo. Da ultimo mandò loro il proprio figlio dicendo: "Avranno rispetto per mio figlio!". Ma i contadini, visto il figlio, dissero tra loro: "Costui è l''erede. Su, uccidiamolo e avremo noi la sua eredità!". Lo presero, lo cacciarono fuori dalla vigna e lo uccisero. Quando verrà dunque il padrone della vigna, che cosa farà a quei contadini?». Gli risposero: «Quei malvagi, li farà morire miseramente e darà in affitto la vigna ad altri contadini, che gli consegneranno i frutti a suo tempo». E Gesù disse loro: «Non avete mai letto nelle Scritture: La pietra che i costruttori hanno scartato è diventata la pietra d''angolo; questo è stato fatto dal Signore ed è una meraviglia ai nostri occhi? Perciò io vi dico: a voi sarà tolto il regno di Dio e sarà dato a un popolo che ne produca i frutti». Udite queste parabole, i capi dei sacerdoti e i farisei capirono che parlava di loro. Cercavano di catturarlo, ma ebbero paura della folla, perché lo considerava un profeta');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 4,5-42', 'Giovanni', '[Gesù] Giunse a una città della Samaria chiamata Sicar, vicina al terreno che Giacobbe aveva dato a Giuseppe suo figlio: qui c''era un pozzo di Giacobbe. Gesù dunque, affaticato per il viaggio, sedeva presso il pozzo. Era circa mezzogiorno. Giunge una donna samaritana ad attingere acqua. Le dice Gesù: «Dammi da bere». I suoi discepoli erano andati in città a fare provvista di cibi. Allora la donna samaritana gli dice: «Come mai tu, che sei giudeo, chiedi da bere a me, che sono una donna samaritana?». I Giudei infatti non hanno rapporti con i Samaritani. Gesù le risponde: «Se tu conoscessi il dono di Dio e chi è colui che ti dice: "Dammi da bere!", tu avresti chiesto a lui ed egli ti avrebbe dato acqua viva». Gli dice la donna: «Signore, non hai un secchio e il pozzo è profondo; da dove prendi dunque quest''acqua viva? Sei tu forse più grande del nostro padre Giacobbe, che ci diede il pozzo e ne bevve lui con i suoi figli e il suo bestiame?». Gesù le risponde: «Chiunque beve di quest''acqua avrà di nuovo sete; ma chi berrà dell''acqua che io gli darò, non avrà più sete in eterno. Anzi, l''acqua che io gli darò diventerà in lui una sorgente d''acqua che zampilla per la vita eterna». «Signore - gli dice la donna -, dammi quest''acqua, perché io non abbia più sete e non continui a venire qui ad attingere acqua». Le dice: «Va'' a chiamare tuo marito e ritorna qui». Gli risponde la donna: «Io non ho marito». Le dice Gesù: «Hai detto bene: "Io non ho marito". Infatti hai avuto cinque mariti e quello che hai ora non è tuo marito; in questo hai detto il vero». Gli replica la donna: «Signore, vedo che tu sei un profeta! I nostri padri hanno adorato su questo monte; voi invece dite che è a Gerusalemme il luogo in cui bisogna adorare». Gesù le dice: «Credimi, donna, viene l''ora in cui né su questo monte né a Gerusalemme adorerete il Padre. Voi adorate ciò che non conoscete, noi adoriamo ciò che conosciamo, perché la salvezza viene dai Giudei. Ma viene l''ora - ed è questa - in cui i veri adoratori adoreranno il Padre in spirito e verità: così infatti il Padre vuole che siano quelli che lo adorano. Dio è spirito, e quelli che lo adorano devono adorare in spirito e verità». Gli rispose la donna: «So che deve venire il Messia, chiamato Cristo: quando egli verrà, ci annuncerà ogni cosa». Le dice Gesù: «Sono io, che parlo con te». In quel momento giunsero i suoi discepoli e si meravigliavano che parlasse con una donna. Nessuno tuttavia disse: "Che cosa cerchi?", o: "Di che cosa parli con lei?". La donna intanto lasciò la sua anfora, andò in città e disse alla gente: «Venite a vedere un uomo che mi ha detto tutto quello che ho fatto. Che sia lui il Cristo?». Uscirono dalla città e andavano da lui. Intanto i discepoli lo pregavano: «Rabbì, mangia». Ma egli rispose loro: «Io ho da mangiare un cibo che voi non conoscete». E i discepoli si domandavano l''un l''altro: «Qualcuno gli ha forse portato da mangiare?». Gesù disse loro: «Il mio cibo è fare la volontà di colui che mi ha mandato e compiere la sua opera. Voi non dite forse: "Ancora quattro mesi e poi viene la mietitura"? Ecco, io vi dico: alzate i vostri occhi e guardate i campi che già biondeggiano per la mietitura. Chi miete riceve il salario e raccoglie frutto per la vita eterna, perché chi semina gioisca insieme a chi miete. In questo infatti si dimostra vero il proverbio: uno semina e l''altro miete. Io vi ho mandati a mietere ciò per cui non avete faticato; altri hanno faticato e voi siete subentrati nella loro fatica». Molti Samaritani di quella città credettero in lui per la parola della donna, che testimoniava: «Mi ha detto tutto quello che ho fatto». E quando i Samaritani giunsero da lui, lo pregavano di rimanere da loro ed egli rimase là due giorni. Molti di più credettero per la sua parola e alla donna dicevano: «Non è più per i tuoi discorsi che noi crediamo, ma perché noi stessi abbiamo udito e sappiamo che questi è veramente il salvatore del mondo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 4,24-30', 'Luca', '[Gesù], Poi aggiunse: «In verità io vi dico: nessun profeta è bene accetto nella sua patria. Anzi, in verità io vi dico: c''erano molte vedove in Israele al tempo di Elia, quando il cielo fu chiuso per tre anni e sei mesi e ci fu una grande carestia in tutto il paese; ma a nessuna di esse fu mandato Elia, se non a una vedova a Sarepta di Sidone. C''erano molti lebbrosi in Israele al tempo del profeta Eliseo; ma nessuno di loro fu purificato, se non Naamàn, il Siro». All''udire queste cose, tutti nella sinagoga si riempirono di sdegno. Si alzarono e lo cacciarono fuori della città e lo condussero fin sul ciglio del monte, sul quale era costruita la loro città, per gettarlo giù');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 9,1-41', 'Giovanni', '[Gesù], Passando, vide un uomo cieco dalla nascita e i suoi discepoli lo interrogarono: «Rabbì, chi ha peccato, lui o i suoi genitori, perché sia nato cieco?». Rispose Gesù: «Né lui ha peccato né i suoi genitori, ma è perché in lui siano manifestate le opere di Dio. Bisogna che noi compiamo le opere di colui che mi ha mandato finché è giorno; poi viene la notte, quando nessuno può agire. Finché io sono nel mondo, sono la luce del mondo». Detto questo, sputò per terra, fece del fango con la saliva, spalmò il fango sugli occhi del cieco e gli disse: «Va'' a lavarti nella piscina di Sìloe» - che significa Inviato. Quegli andò, si lavò e tornò che ci vedeva. Allora i vicini e quelli che lo avevano visto prima, perché era un mendicante, dicevano: «Non è lui quello che stava seduto a chiedere l''elemosina?». Alcuni dicevano: «È lui»; altri dicevano: «No, ma è uno che gli assomiglia». Ed egli diceva: «Sono io!». Allora gli domandarono: «In che modo ti sono stati aperti gli occhi?». Egli rispose: «L''uomo che si chiama Gesù ha fatto del fango, mi ha spalmato gli occhi e mi ha detto: "Va'' a Sìloe e làvati!". Io sono andato, mi sono lavato e ho acquistato la vista». Gli dissero: «Dov''è costui?». Rispose: «Non lo so». Condussero dai farisei quello che era stato cieco: era un sabato, il giorno in cui Gesù aveva fatto del fango e gli aveva aperto gli occhi. Anche i farisei dunque gli chiesero di nuovo come aveva acquistato la vista. Ed egli disse loro: «Mi ha messo del fango sugli occhi, mi sono lavato e ci vedo». Allora alcuni dei farisei dicevano: «Quest''uomo non viene da Dio, perché non osserva il sabato». Altri invece dicevano: «Come può un peccatore compiere segni di questo genere?». E c''era dissenso tra loro. Allora dissero di nuovo al cieco: «Tu, che cosa dici di lui, dal momento che ti ha aperto gli occhi?». Egli rispose: «È un profeta!». Ma i Giudei non credettero di lui che fosse stato cieco e che avesse acquistato la vista, finché non chiamarono i genitori di colui che aveva ricuperato la vista. E li interrogarono: «È questo il vostro figlio, che voi dite essere nato cieco? Come mai ora ci vede?». I genitori di lui risposero: «Sappiamo che questo è nostro figlio e che è nato cieco; ma come ora ci veda non lo sappiamo, e chi gli abbia aperto gli occhi, noi non lo sappiamo. Chiedetelo a lui: ha l''età, parlerà lui di sé». Questo dissero i suoi genitori, perché avevano paura dei Giudei; infatti i Giudei avevano già stabilito che, se uno lo avesse riconosciuto come il Cristo, venisse espulso dalla sinagoga. Per questo i suoi genitori dissero: «Ha l''età: chiedetelo a lui!». Allora chiamarono di nuovo l''uomo che era stato cieco e gli dissero: «Da'' gloria a Dio! Noi sappiamo che quest''uomo è un peccatore». Quello rispose: «Se sia un peccatore, non lo so. Una cosa io so: ero cieco e ora ci vedo». Allora gli dissero: «Che cosa ti ha fatto? Come ti ha aperto gli occhi?». Rispose loro: «Ve l''ho già detto e non avete ascoltato; perché volete udirlo di nuovo? Volete forse diventare anche voi suoi discepoli?». Lo insultarono e dissero: «Suo discepolo sei tu! Noi siamo discepoli di Mosè! Noi sappiamo che a Mosè ha parlato Dio; ma costui non sappiamo di dove sia». Rispose loro quell''uomo: «Proprio questo stupisce: che voi non sapete di dove sia, eppure mi ha aperto gli occhi. Sappiamo che Dio non ascolta i peccatori, ma che, se uno onora Dio e fa la sua volontà, egli lo ascolta. Da che mondo è mondo, non si è mai sentito dire che uno abbia aperto gli occhi a un cieco nato. Se costui non venisse da Dio, non avrebbe potuto far nulla». Gli replicarono: «Sei nato tutto nei peccati e insegni a noi?». E lo cacciarono fuori. Gesù seppe che l''avevano cacciato fuori; quando lo trovò, gli disse: «Tu, credi nel Figlio dell''uomo?». Egli rispose: «E chi è, Signore, perché io creda in lui?». Gli disse Gesù: «Lo hai visto: è colui che parla con te». Ed egli disse: «Credo, Signore!». E si prostrò dinanzi a lui. Gesù allora disse: «È per un giudizio che io sono venuto in questo mondo, perché coloro che non vedono, vedano e quelli che vedono, diventino ciechi». Alcuni dei farisei che erano con lui udirono queste parole e gli dissero: «Siamo ciechi anche noi?». Gesù rispose loro: «Se foste ciechi, non avreste alcun peccato; ma siccome dite: “Noi vediamo", il vostro peccato rimane»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 11,1-45', 'Giovanni', 'Un certo Lazzaro di Betània, il villaggio di Maria e di Marta sua sorella, era malato. Maria era quella che cosparse di profumo il Signore e gli asciugò i piedi con i suoi capelli; suo fratello Lazzaro era malato. Le sorelle mandarono dunque a dirgli: «Signore, ecco, colui che tu ami è malato». All''udire questo, Gesù disse: «Questa malattia non porterà alla morte, ma è per la gloria di Dio, affinché per mezzo di essa il Figlio di Dio venga glorificato». Gesù amava Marta e sua sorella e Lazzaro.  Quando sentì che era malato, rimase per due giorni nel luogo dove si trovava. Poi disse ai discepoli: «Andiamo di nuovo in Giudea!». I discepoli gli dissero: «Rabbì, poco fa i Giudei cercavano di lapidarti e tu ci vai di nuovo?».  Gesù rispose: «Non sono forse dodici le ore del giorno? Se uno cammina di giorno, non inciampa, perché vede la luce di questo mondo; ma se cammina di notte, inciampa, perché la luce non è in lui». Disse queste cose e poi soggiunse loro: «Lazzaro, il nostro amico, si è addormentato; ma io vado a svegliarlo». Gli dissero allora i discepoli: «Signore, se si è addormentato, si salverà». Gesù aveva parlato della morte di lui; essi invece pensarono che parlasse del riposo del sonno. Allora Gesù disse loro apertamente: «Lazzaro è morto e io sono contento per voi di non essere stato là, affinché voi crediate; ma andiamo da lui!». Allora Tommaso, chiamato Dìdimo, disse agli altri discepoli: «Andiamo anche noi a morire con lui!». Quando Gesù arrivò, trovò Lazzaro che già da quattro giorni era nel sepolcro. Betània distava da Gerusalemme meno di tre chilometri e molti Giudei erano venuti da Marta e Maria a consolarle per il fratello. Marta dunque, come udì che veniva Gesù, gli andò incontro; Maria invece stava seduta in casa. Marta disse a Gesù: «Signore, se tu fossi stato qui, mio fratello non sarebbe morto! Ma anche ora so che qualunque cosa tu chiederai a Dio, Dio te la concederà». Gesù le disse: «Tuo fratello risorgerà». Gli rispose Marta: «So che risorgerà nella risurrezione dell''ultimo giorno». Gesù le disse: «Io sono la risurrezione e la vita; chi crede in me, anche se muore, vivrà; chiunque vive e crede in me, non morirà in eterno. Credi questo?». Gli rispose: «Sì, o Signore, io credo che tu sei il Cristo, il Figlio di Dio, colui che viene nel mondo». Dette queste parole, andò a chiamare Maria, sua sorella, e di nascosto le disse: «Il Maestro è qui e ti chiama».  Udito questo, ella si alzò subito e andò da lui. Gesù non era entrato nel villaggio, ma si trovava ancora là dove Marta gli era andata incontro.  Allora i Giudei, che erano in casa con lei a consolarla, vedendo Maria alzarsi in fretta e uscire, la seguirono, pensando che andasse a piangere al sepolcro. Quando Maria giunse dove si trovava Gesù, appena lo vide si gettò ai suoi piedi dicendogli: «Signore, se tu fossi stato qui, mio fratello non sarebbe morto!». Gesù allora, quando la vide piangere, e piangere anche i Giudei che erano venuti con lei, si commosse profondamente e, molto turbato, domandò: «Dove lo avete posto?». Gli dissero: «Signore, vieni a vedere!». Gesù scoppiò in pianto. Dissero allora i Giudei: «Guarda come lo amava!». Ma alcuni di loro dissero: «Lui, che ha aperto gli occhi al cieco, non poteva anche far sì che costui non morisse?». Allora Gesù, ancora una volta commosso profondamente, si recò al sepolcro: era una grotta e contro di essa era posta una pietra. Disse Gesù: «Togliete la pietra!». Gli rispose Marta, la sorella del morto: «Signore, manda già cattivo odore: è lì da quattro giorni». Le disse Gesù: «Non ti ho detto che, se crederai, vedrai la gloria di Dio?». Tolsero dunque la pietra. Gesù allora alzò gli occhi e disse: «Padre, ti rendo grazie perché mi hai ascoltato. Io sapevo che mi dai sempre ascolto, ma l''ho detto per la gente che mi sta attorno, perché credano che tu mi hai mandato». Detto questo, gridò a gran voce: «Lazzaro, vieni fuori!». Il morto uscì, i piedi e le mani legati con bende, e il viso avvolto da un sudario. Gesù disse loro: «Liberàtelo e lasciàtelo andare». Molti dei Giudei che erano venuti da Maria, alla vista di ciò che egli aveva compiuto, credettero in lui');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 26,14-27,66', 'Matteo', 'Allora uno dei Dodici, chiamato Giuda Iscariota, andò dai capi dei sacerdoti e disse: «Quanto volete darmi perché io ve lo consegni?». E quelli gli fissarono trenta monete d''argento. Da quel momento cercava l''occasione propizia per consegnarlo. Il primo giorno degli Azzimi, i discepoli si avvicinarono a Gesù e gli dissero: «Dove vuoi che prepariamo per te, perché tu possa mangiare la Pasqua?». Ed egli rispose: «Andate in città da un tale e ditegli: "Il Maestro dice: Il mio tempo è vicino; farò la Pasqua da te con i miei discepoli"». I discepoli fecero come aveva loro ordinato Gesù, e prepararono la Pasqua. Venuta la sera, si mise a tavola con i Dodici. Mentre mangiavano, disse: «In verità io vi dico: uno di voi mi tradirà». Ed essi, profondamente rattristati, cominciarono ciascuno a domandargli: «Sono forse io, Signore?». Ed egli rispose: «Colui che ha messo con me la mano nel piatto, è quello che mi tradirà. Il Figlio dell''uomo se ne va, come sta scritto di lui; ma guai a quell''uomo dal quale il Figlio dell''uomo viene tradito! Meglio per quell''uomo se non fosse mai nato!». Giuda, il traditore, disse: «Rabbì, sono forse io?». Gli rispose: «Tu l''hai detto». Ora, mentre mangiavano, Gesù prese il pane, recitò la benedizione, lo spezzò e, mentre lo dava ai discepoli, disse: «Prendete, mangiate: questo è il mio corpo». Poi prese il calice, rese grazie e lo diede loro, dicendo: «Bevetene tutti, perché questo è il mio sangue dell''alleanza, che è versato per molti per il perdono dei peccati. Io vi dico che d''ora in poi non berrò di questo frutto della vite fino al giorno in cui lo berrò nuovo con voi, nel regno del Padre mio». Dopo aver cantato l''inno, uscirono verso il monte degli Ulivi. Allora Gesù disse loro: «Questa notte per tutti voi sarò motivo di scandalo. Sta scritto infatti: Percuoterò il pastore e saranno disperse le pecore del gregge. Ma, dopo che sarò risorto, vi precederò in Galilea». Pietro gli disse: «Se tutti si scandalizzeranno di te, io non mi scandalizzerò mai». Gli disse Gesù: «In verità io ti dico: questa notte, prima che il gallo canti, tu mi rinnegherai tre volte». Pietro gli rispose: «Anche se dovessi morire con te, io non ti rinnegherò». Lo stesso dissero tutti i discepoli. Allora Gesù andò con loro in un podere, chiamato Getsèmani, e disse ai discepoli: «Sedetevi qui, mentre io vado là a pregare». E, presi con sé Pietro e i due figli di Zebedeo, cominciò a provare tristezza e angoscia. E disse loro: «La mia anima è triste fino alla morte; restate qui e vegliate con me». Andò un poco più avanti, cadde faccia a terra e pregava, dicendo: «Padre mio, se è possibile, passi via da me questo calice! Però non come voglio io, ma come vuoi tu!». Poi venne dai discepoli e li trovò addormentati. E disse a Pietro: «Così, non siete stati capaci di vegliare con me una sola ora? Vegliate e pregate, per non entrare in tentazione. Lo spirito è pronto, ma la carne è debole». Si allontanò una seconda volta e pregò dicendo: «Padre mio, se questo calice non può passare via senza che io lo beva, si compia la tua volontà». Poi venne e li trovò di nuovo addormentati, perché i loro occhi si erano fatti pesanti. Li lasciò, si allontanò di nuovo e pregò per la terza volta, ripetendo le stesse parole. Poi si avvicinò ai discepoli e disse loro: «Dormite pure e riposatevi! Ecco, l''ora è vicina e il Figlio dell''uomo viene consegnato in mano ai peccatori. Alzatevi, andiamo! Ecco, colui che mi tradisce è vicino». Mentre ancora egli parlava, ecco arrivare Giuda, uno dei Dodici, e con lui una grande folla con spade e bastoni, mandata dai capi dei sacerdoti e dagli anziani del popolo. Il traditore aveva dato loro un segno, dicendo: «Quello che bacerò, è lui; arrestatelo!». Subito si avvicinò a Gesù e disse: «Salve, Rabbì!». E lo baciò. E Gesù gli disse: «Amico, per questo sei qui!». Allora si fecero avanti, misero le mani addosso a Gesù e lo arrestarono. Ed ecco, uno di quelli che erano con Gesù impugnò la spada, la estrasse e colpì il servo del sommo sacerdote, staccandogli un orecchio. Allora Gesù gli disse: «Rimetti la tua spada al suo posto, perché tutti quelli che prendono la spada, di spada moriranno. O credi che io non possa pregare il Padre mio, che metterebbe subito a mia disposizione più di dodici legioni di angeli? Ma allora come si compirebbero le Scritture, secondo le quali così deve avvenire?». In quello stesso momento Gesù disse alla folla: «Come se fossi un ladro siete venuti a prendermi con spade e bastoni. Ogni giorno sedevo nel tempio a insegnare, e non mi avete arrestato. Ma tutto questo è avvenuto perché si compissero le Scritture dei profeti». Allora tutti i discepoli lo abbandonarono e fuggirono. Quelli che avevano arrestato Gesù lo condussero dal sommo sacerdote Caifa, presso il quale si erano riuniti gli scribi e gli anziani. Pietro intanto lo aveva seguito, da lontano, fino al palazzo del sommo sacerdote; entrò e stava seduto fra i servi, per vedere come sarebbe andata a finire. I capi dei sacerdoti e tutto il sinedrio cercavano una falsa testimonianza contro Gesù, per metterlo a morte; ma non la trovarono, sebbene si fossero presentati molti falsi testimoni. Finalmente se ne presentarono due, che affermarono: «Costui ha dichiarato: "Posso distruggere il tempio di Dio e ricostruirlo in tre giorni"». Il sommo sacerdote si alzò e gli disse: «Non rispondi nulla? Che cosa testimoniano costoro contro di te?». Ma Gesù taceva. Allora il sommo sacerdote gli disse: «Ti scongiuro, per il Dio vivente, di dirci se sei tu il Cristo, il Figlio di Dio». «Tu l''hai detto - gli rispose Gesù -; anzi io vi dico: d''ora innanzi vedrete il Figlio dell''uomo seduto alla destra della Potenza e venire sulle nubi del cielo». Allora il sommo sacerdote si stracciò le vesti dicendo: «Ha bestemmiato! Che bisogno abbiamo ancora di testimoni? Ecco, ora avete udito la bestemmia; che ve ne pare?». E quelli risposero: «È reo di morte!». Allora gli sputarono in faccia e lo percossero; altri lo schiaffeggiarono, dicendo: «Fa'' il profeta per noi, Cristo! Chi è che ti ha colpito?». Pietro intanto se ne stava seduto fuori, nel cortile. Una giovane serva gli si avvicinò e disse: «Anche tu eri con Gesù, il Galileo!». Ma egli negò davanti a tutti dicendo: «Non capisco che cosa dici». Mentre usciva verso l''atrio, lo vide un''altra serva e disse ai presenti: «Costui era con Gesù, il Nazareno». Ma egli negò di nuovo, giurando: «Non conosco quell''uomo!». Dopo un poco, i presenti si avvicinarono e dissero a Pietro: «È vero, anche tu sei uno di loro: infatti il tuo accento ti tradisce!». Allora egli cominciò a imprecare e a giurare: «Non conosco quell''uomo!». E subito un gallo cantò. E Pietro si ricordò della parola di Gesù, che aveva detto: «Prima che il gallo canti, tu mi rinnegherai tre volte». E, uscito fuori, pianse amaramente. Venuto il mattino, tutti i capi dei sacerdoti e gli anziani del popolo tennero consiglio contro Gesù per farlo morire. Poi lo misero in catene, lo condussero via e lo consegnarono al governatore Pilato. Allora Giuda - colui che lo tradì -, vedendo che Gesù era stato condannato, preso dal rimorso, riportò le trenta monete d''argen-to ai capi dei sacerdoti e agli anziani, dicendo: «Ho peccato, perché ho tradito sangue innocente». Ma quelli dissero: «A noi che importa? Pensaci tu!». Egli allora, gettate le monete d''argento nel tempio, si allontanò e andò a impiccarsi. I capi dei sacerdoti, raccolte le monete, dissero: «Non è lecito metterle nel tesoro, perché sono prezzo di sangue». Tenuto consiglio, comprarono con esse il "Campo del vasaio" per la sepoltura degli stranieri. Perciò quel campo fu chiamato "Campo di sangue" fino al giorno d''oggi. Allora si compì quanto era stato detto per mezzo del profeta Geremia: E presero trenta monete d''argento, il prezzo di colui che a tal prezzo fu valutato dai figli d''Israele, e le diedero per il campo del vasaio, come mi aveva ordinato il Signore. Gesù intanto comparve davanti al governatore, e il governatore lo interrogò dicendo: «Sei tu il re dei Giudei?». Gesù rispose: «Tu lo dici». E mentre i capi dei sacerdoti e gli anziani lo accusavano, non rispose nulla. Allora Pilato gli disse: «Non senti quante testimonianze portano contro di te?». Ma non gli rispose neanche una parola, tanto che il governatore rimase assai stupito. A ogni festa, il governatore era solito rimettere in libertà per la folla un carcerato, a loro scelta. In quel momento avevano un carcerato famoso, di nome Barabba. Perciò, alla gente che si era radunata, Pilato disse: «Chi volete che io rimetta in libertà per voi: Barabba o Gesù, chiamato Cristo?». Sapeva bene infatti che glielo avevano consegnato per invidia. Mentre egli sedeva in tribunale, sua moglie gli mandò a dire: «Non avere a che fare con quel giusto, perché oggi, in sogno, sono stata molto turbata per causa sua». Ma i capi dei sacerdoti e gli anziani persuasero la folla a chiedere Barabba e a far morire Gesù. Allora il governatore domandò loro: «Di questi due, chi volete che io rimetta in libertà per voi?». Quelli risposero: «Barabba!». Chiese loro Pilato: «Ma allora, che farò di Gesù, chiamato Cristo?». Tutti risposero: «Sia crocifisso!». Ed egli disse: «Ma che male ha fatto?». Essi allora gridavano più forte: «Sia crocifisso!». Pilato, visto che non otteneva nulla, anzi che il tumulto aumentava, prese dell''acqua e si lavò le mani davanti alla folla, dicendo: «Non sono responsabile di questo sangue. Pensateci voi!». E tutto il popolo rispose: «Il suo sangue ricada su di noi e sui nostri figli». Allora rimise in libertà per loro Barabba e, dopo aver fatto flagellare Gesù, lo consegnò perché fosse crocifisso. Allora i soldati del governatore condussero Gesù nel pretorio e gli radunarono attorno tutta la truppa. Lo spogliarono, gli fecero indossare un mantello scarlatto, intrecciarono una corona di spine, gliela posero sul capo e gli misero una canna nella mano destra. Poi, inginocchiandosi davanti a lui, lo deridevano: «Salve, re dei Giudei!». Sputandogli addosso, gli tolsero di mano la canna e lo percuotevano sul capo. Dopo averlo deriso, lo spogliarono del mantello e gli rimisero le sue vesti, poi lo condussero via per crocifiggerlo. Mentre uscivano, incontrarono un uomo di Cirene, chiamato Simone, e lo costrinsero a portare la sua croce. Giunti al luogo detto Gòlgota, che significa "Luogo del cranio", gli diedero da bere vino mescolato con fiele. Egli lo assaggiò, ma non ne volle bere. Dopo averlo crocifisso, si divisero le sue vesti, tirandole a sorte. Poi, seduti, gli facevano la guardia. Al di sopra del suo capo posero il motivo scritto della sua condanna: "Costui è Gesù, il re dei Giudei". Insieme a lui vennero crocifissi due ladroni, uno a destra e uno a sinistra. Quelli che passavano di lì lo insultavano, scuotendo il capo e dicendo: «Tu, che distruggi il tempio e in tre giorni lo ricostruisci, salva te stesso, se tu sei Figlio di Dio, e scendi dalla croce!». Così anche i capi dei sacerdoti, con gli scribi e gli anziani, facendosi beffe di lui dicevano: «Ha salvato altri e non può salvare se stesso! È il re d''Israele; scenda ora dalla croce e crederemo in lui. Ha confidato in Dio; lo liberi lui, ora, se gli vuol bene. Ha detto infatti: "Sono Figlio di Dio"!». Anche i ladroni crocifissi con lui lo insultavano allo stesso modo. A mezzogiorno si fece buio su tutta la terra, fino alle tre del pomeriggio. Verso le tre, Gesù gridò a gran voce: «Elì, Elì, lemà sabactàni?», che significa: «Dio mio, Dio mio, perché mi hai abbandonato?». Udendo questo, alcuni dei presenti dicevano: «Costui chiama Elia». E subito uno di loro corse a prendere una spugna, la inzuppò di aceto, la fissò su una canna e gli dava da bere. Gli altri dicevano: «Lascia! Vediamo se viene Elia a salvarlo!». Ma Gesù di nuovo gridò a gran voce ed emise lo spirito. Ed ecco, il velo del tempio si squarciò in due, da cima a fondo, la terra tremò, le rocce si spezzarono, i sepolcri si aprirono e molti corpi di santi, che erano morti, risuscitarono. Uscendo dai sepolcri, dopo la sua risurrezione, entrarono nella città santa e apparvero a molti. Il centurione, e quelli che con lui facevano la guardia a Gesù, alla vista del terremoto e di quello che succedeva, furono presi da grande timore e dicevano: «Davvero costui era Figlio di Dio!». Vi erano là anche molte donne, che osservavano da lontano; esse avevano seguito Gesù dalla Galilea per servirlo. Tra queste c''erano Maria di Màgdala, Maria madre di Giacomo e di Giuseppe, e la madre dei figli di Zebedeo. Venuta la sera, giunse un uomo ricco, di Arimatea, chiamato Giuseppe; anche lui era diventato discepolo di Gesù. Questi si presentò a Pilato e chiese il corpo di Gesù. Pilato allora ordinò che gli fosse consegnato. Giuseppe prese il corpo, lo avvolse in un lenzuolo pulito e lo depose nel suo sepolcro nuovo, che si era fatto scavare nella roccia; rotolata poi una grande pietra all''entrata del sepolcro, se ne andò. Lì, sedute di fronte alla tomba, c''erano Maria di Màgdala e l''altra Maria. Il giorno seguente, quello dopo la Parasceve, si riunirono presso Pilato i capi dei sacerdoti e i farisei, dicendo: «Signore, ci siamo ricordati che quell''impostore, mentre era vivo, disse: "Dopo tre giorni risorgerò". Ordina dunque che la tomba venga vigilata fino al terzo giorno, perché non arrivino i suoi discepoli, lo rubino e poi dicano al popolo: "È risorto dai morti". Così quest''ultima impostura sarebbe peggiore della prima!». Pilato disse loro: «Avete le guardie: andate e assicurate la sorveglianza come meglio credete». Essi andarono e, per rendere sicura la tomba, sigillarono la pietra e vi lasciarono le guardie');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 28,1-10', 'Matteo', 'Dopo il sabato, all''alba del primo giorno della settimana, Maria di Màgdala e l''altra Maria andarono a visitare la tomba. Ed ecco, vi fu un gran terremoto. Un angelo del Signore, infatti, sceso dal cielo, si avvicinò, rotolò la pietra e si pose a sedere su di essa. Il suo aspetto era come folgore e il suo vestito bianco come neve. Per lo spavento che ebbero di lui, le guardie furono scosse e rimasero come morte. L''angelo disse alle donne: «Voi non abbiate paura! So che cercate Gesù, il crocifisso. Non è qui. È risorto, infatti, come aveva detto; venite, guardate il luogo dove era stato deposto. Presto, andate a dire ai suoi discepoli: "È risorto dai morti, ed ecco, vi precede in Galilea; là lo vedrete". Ecco, io ve l''ho detto». Abbandonato in fretta il sepolcro con timore e gioia grande, le donne corsero a dare l''annuncio ai suoi discepoli. Ed ecco, Gesù venne loro incontro e disse: «Salute a voi!». Ed esse si avvicinarono, gli abbracciarono i piedi e lo adorarono. Allora Gesù disse loro: «Non temete; andate ad annunciare ai miei fratelli che vadano in Galilea: là mi vedranno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 20,1-9', 'Giovanni', 'Il primo giorno della settimana, Maria di Màgdala si recò al sepolcro di mattino, quando era ancora buio, e vide che la pietra era stata tolta dal sepolcro. Corse allora e andò da Simon Pietro e dall''altro discepolo, quello che Gesù amava, e disse loro: «Hanno portato via il Signore dal sepolcro e non sappiamo dove l''hanno posto!». Pietro allora uscì insieme all''altro discepolo e si recarono al sepolcro. Correvano insieme tutti e due, ma l''altro discepolo corse più veloce di Pietro e giunse per primo al sepolcro. Si chinò, vide i teli posati là, ma non entrò. Giunse intanto anche Simon Pietro, che lo seguiva, ed entrò nel sepolcro e osservò i teli posati là, e il sudario - che era stato sul suo capo - non posato là con i teli, ma avvolto in un luogo a parte. Allora entrò anche l''altro discepolo, che era giunto per primo al sepolcro, e vide e credette. Infatti non avevano ancora compreso la Scrittura, che cioè egli doveva risorgere dai morti');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 3,1-8', 'Giovanni', 'Vi era tra i farisei un uomo di nome Nicodèmo, uno dei capi dei Giudei. Costui andò da Gesù, di notte, e gli disse: «Rabbì, sappiamo che sei venuto da Dio come maestro; nessuno infatti può compiere questi segni che tu compi, se Dio non è con lui». Gli rispose Gesù: «In verità, in verità io ti dico, se uno non nasce dall''alto, non può vedere il regno di Dio». Gli disse Nicodèmo: «Come può nascere un uomo quando è vecchio? Può forse entrare una seconda volta nel grembo di sua madre e rinascere?». Rispose Gesù: «In verità, in verità io ti dico, se uno non nasce da acqua e Spirito, non può entrare nel regno di Dio. Quello che è nato dalla carne è carne, e quello che è nato dallo Spirito è spirito. Non meravigliarti se ti ho detto: dovete nascere dall''alto. Il vento soffia dove vuole e ne senti la voce, ma non sai da dove viene né dove va: così è chiunque è nato dallo Spirito»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 3,16-21', 'Giovanni', '[Gesù disse a Nicòdemo], «Dio infatti ha tanto amato il mondo da dare il Figlio unigenito, perché chiunque crede in lui non vada perduto, ma abbia la vita eterna. Dio, infatti, non ha mandato il Figlio nel mondo per condannare il mondo, ma perché il mondo sia salvato per mezzo di lui. Chi crede in lui non è condannato; ma chi non crede è già stato condannato, perché non ha creduto nel nome dell''unigenito Figlio di Dio. E il giudizio è questo: la luce è venuta nel mondo, ma gli uomini hanno amato più le tenebre che la luce, perché le loro opere erano malvagie. Chiunque infatti fa il male, odia la luce, e non viene alla luce perché le sue opere non vengano riprovate. Invece chi fa la verità viene verso la luce, perché appaia chiaramente che le sue opere sono state fatte in Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,1-15', 'Giovanni', 'Dopo questi fatti, Gesù passò all''altra riva del mare di Galilea, cioè di Tiberìade, e lo seguiva una grande folla, perché vedeva i segni che compiva sugli infermi. Gesù salì sul monte e là si pose a sedere con i suoi discepoli. Era vicina la Pasqua, la festa dei Giudei. Allora Gesù, alzàti gli occhi, vide che una grande folla veniva da lui e disse a Filippo: «Dove potremo comprare il pane perché costoro abbiano da mangiare?». Diceva così per metterlo alla prova; egli infatti sapeva quello che stava per compiere. Gli rispose Filippo: «Duecento denari di pane non sono sufficienti neppure perché ognuno possa riceverne un pezzo». Gli disse allora uno dei suoi discepoli, Andrea, fratello di Simon Pietro: «C''è qui un ragazzo che ha cinque pani d''orzo e due pesci; ma che cos''è questo per tanta gente?». Rispose Gesù: «Fateli sedere». C''era molta erba in quel luogo. Si misero dunque a sedere ed erano circa cinquemila uomini. Allora Gesù prese i pani e, dopo aver reso grazie, li diede a quelli che erano seduti, e lo stesso fece dei pesci, quanto ne volevano. E quando furono saziati, disse ai suoi discepoli: «Raccogliete i pezzi avanzati, perché nulla vada perduto». Li raccolsero e riempirono dodici canestri con i pezzi dei cinque pani d''orzo, avanzati a coloro che avevano mangiato. Allora la gente, visto il segno che egli aveva compiuto, diceva: «Questi è davvero il profeta, colui che viene nel mondo!». Ma Gesù, sapendo che venivano a prenderlo per farlo re, si ritirò di nuovo sul monte, lui da solo');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 16,15-20', 'Marco', 'E Gesù disse loro: «Andate in tutto il mondo e proclamate il Vangelo a ogni creatura. Chi crederà e sarà battezzato sarà salvato, ma chi non crederà sarà condannato. Questi saranno i segni che accompagneranno quelli che credono: nel mio nome scacceranno demòni, parleranno lingue nuove, prenderanno in mano serpenti e, se berranno qualche veleno, non recherà loro danno; imporranno le mani ai malati e questi guariranno». Il Signore Gesù, dopo aver parlato con loro, fu elevato in cielo e sedette alla destra di Dio. Allora essi partirono e predicarono dappertutto, mentre il Signore agiva insieme con loro e confermava la Parola con i segni che la accompagnavano');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 10,11-18', 'Giovanni', '[In quel tempo, Gesù disse]: «Io sono il buon pastore. Il buon pastore dà la propria vita per le pecore. Il mercenario - che non è pastore e al quale le pecore non appartengono - vede venire il lupo, abbandona le pecore e fugge, e il lupo le rapisce e le disperde; perché è un mercenario e non gli importa delle pecore. Io sono il buon pastore, conosco le mie pecore e le mie pecore conoscono me, così come il Padre conosce me e io conosco il Padre, e do la mia vita per le pecore. E ho altre pecore che non provengono da questo recinto: anche quelle io devo guidare. Ascolteranno la mia voce e diventeranno un solo gregge, un solo pastore. Per questo il Padre mi ama: perché io do la mia vita, per poi riprenderla di nuovo. Nessuno me la toglie: io la do da me stesso. Ho il potere di darla e il potere di riprenderla di nuovo. Questo è il comando che ho ricevuto dal Padre mio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 10,22-30', 'Giovanni', 'Ricorreva, in quei giorni, a Gerusalemme la festa della Dedicazione. Era inverno. Gesù camminava nel tempio, nel portico di Salomone. Allora i Giudei gli si fecero attorno e gli dicevano: «Fino a quando ci terrai nell''incertezza? Se tu sei il Cristo, dillo a noi apertamente». Gesù rispose loro: «Ve l''ho detto, e non credete; le opere che io compio nel nome del Padre mio, queste danno testimonianza di me. Ma voi non credete perché non fate parte delle mie pecore. Le mie pecore ascoltano la mia voce e io le conosco ed esse mi seguono. Io do loro la vita eterna e non andranno perdute in eterno e nessuno le strapperà dalla mia mano. Il Padre mio, che me le ha date, è più grande di tutti e nessuno può strapparle dalla mano del Padre. Io e il Padre siamo una cosa sola»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 14,1-12', 'Giovanni', '[In quel tempo, Gesù disse ai suoi discepoli]: «Non sia turbato il vostro cuore. Abbiate fede in Dio e abbiate fede anche in me. Nella casa del Padre mio vi sono molte dimore. Se no, vi avrei mai detto: "Vado a prepararvi un posto"? Quando sarò andato e vi avrò preparato un posto, verrò di nuovo e vi prenderò con me, perché dove sono io siate anche voi. E del luogo dove io vado, conoscete la via». Gli disse Tommaso: «Signore, non sappiamo dove vai; come possiamo conoscere la via?». Gli disse Gesù: «Io sono la via, la verità e la vita. Nessuno viene al Padre se non per mezzo di me. Se avete conosciuto me, conoscerete anche il Padre mio: fin da ora lo conoscete e lo avete veduto». Gli disse Filippo: «Signore, mostraci il Padre e ci basta». Gli rispose Gesù: «Da tanto tempo sono con voi e tu non mi hai conosciuto, Filippo? Chi ha visto me, ha visto il Padre. Come puoi tu dire: "Mostraci il Padre"? Non credi che io sono nel Padre e il Padre è in me? Le parole che io vi dico, non le dico da me stesso; ma il Padre, che rimane in me, compie le sue opere. Credete a me: io sono nel Padre e il Padre è in me. Se non altro, credetelo per le opere stesse. In verità, in verità io vi dico: chi crede in me, anch''egli compirà le opere che io compio e ne compirà di più grandi di queste, perché io vado al Padre»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 14,15-21', 'Giovanni', '[In quel tempo, Gesù disse ai suoi discepoli]: «Se mi amate, osserverete i miei comandamenti; e io pregherò il Padre ed egli vi darà un altro Paràclito perché rimanga con voi per sempre, lo Spirito della verità, che il mondo non può ricevere perché non lo vede e non lo conosce. Voi lo conoscete perché egli rimane presso di voi e sarà in voi. Non vi lascerò orfani: verrò da voi. Ancora un poco e il mondo non mi vedrà più; voi invece mi vedrete, perché io vivo e voi vivrete. In quel giorno voi saprete che io sono nel Padre mio e voi in me e io in voi. Chi accoglie i miei comandamenti e li osserva, questi è colui che mi ama. Chi ama me sarà amato dal Padre mio e anch''io lo amerò e mi manifesterò a lui»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 15,26-16,4a', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «Quando verrà il Paràclito, che io vi manderò dal Padre, lo Spirito della verità che procede dal Padre, egli darà testimonianza di me; e anche voi date testimonianza, perché siete con me fin dal principio. Vi ho detto queste cose perché non abbiate a scandalizzarvi. Vi scacceranno dalle sinagoghe; anzi, viene l''ora in cui chiunque vi ucciderà crederà di rendere culto a Dio. E faranno ciò, perché non hanno conosciuto né il Padre né me. Ma vi ho detto queste cose affinché, quando verrà la loro ora, ve ne ricordiate, perché io ve l''ho detto»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 16,20-23a', 'Giovanni', '[In quel tempo, disse Gesù ai suoi discepoli]: «In verità, in verità io vi dico: voi piangerete e gemerete, ma il mondo si rallegrerà. Voi sarete nella tristezza, ma la vostra tristezza si cambierà in gioia. La donna, quando partorisce, è nel dolore, perché è venuta la sua ora; ma, quando ha dato alla luce il bambino, non si ricorda più della sofferenza, per la gioia che è venuto al mondo un uomo. Così anche voi, ora, siete nel dolore; ma vi vedrò di nuovo e il vostro cuore si rallegrerà e nessuno potrà togliervi la vostra gioia. Quel giorno non mi domanderete più nulla»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 28,16-20', 'Matteo', 'In quel tempo, gli undici discepoli andarono in Galilea, sul monte che Gesù aveva loro indicato. Quando lo videro, si prostrarono. Essi però dubitarono. Gesù si avvicinò e disse loro: «A me è stato dato ogni potere in cielo e sulla terra. Andate dunque e fate discepoli tutti i popoli, battezzandoli nel nome del Padre e del Figlio e dello Spirito Santo, insegnando loro a osservare tutto ciò che vi ho comandato. Ed ecco, io sono con voi tutti i giorni, fino alla fine del mondo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 17,1-11a', 'Giovanni', 'In quel tempo, Gesù, alzàti gli occhi al cielo, disse: «Padre, è venuta l''ora: glorifica il Figlio tuo perché il Figlio glorifichi te. Tu gli hai dato potere su ogni essere umano, perché egli dia la vita eterna a tutti coloro che gli hai dato. Questa è la vita eterna: che conoscano te, l''unico vero Dio, e colui che hai mandato, Gesù Cristo. Io ti ho glorificato sulla terra, compiendo l''opera che mi hai dato da fare. E ora, Padre, glorificami davanti a te con quella gloria che io avevo presso di te prima che il mondo fosse. Ho manifestato il tuo nome agli uomini che mi hai dato dal mondo. Erano tuoi e li hai dati a me, ed essi hanno osservato la tua parola. Ora essi sanno che tutte le cose che mi hai dato vengono da te, perché le parole che hai dato a me io le ho date a loro. Essi le hanno accolte e sanno veramente che sono uscito da te e hanno creduto che tu mi hai mandato. Io prego per loro; non prego per il mondo, ma per coloro che tu mi hai dato, perché sono tuoi. Tutte le cose mie sono tue, e le tue sono mie, e io sono glorificato in loro. Io non sono più nel mondo; essi invece sono nel mondo, e io vengo a te»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 20,19-23', 'Giovanni', 'La sera di quel giorno, il primo della settimana, mentre erano chiuse le porte del luogo dove si trovavano i discepoli per timore dei Giudei, venne Gesù, stette in mezzo e disse loro: «Pace a voi!». Detto questo, mostrò loro le mani e il fianco. E i discepoli gioirono al vedere il Signore. Gesù disse loro di nuovo: «Pace a voi! Come il Padre ha mandato me, anche io mando voi». Detto questo, soffiò e disse loro: «Ricevete lo Spirito Santo. A coloro a cui perdonerete i peccati, saranno perdonati; a coloro a cui non perdonerete, non saranno perdonati»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 12,13-17', 'Marco', 'In quel tempo, mandarono da Gesù alcuni farisei ed erodiani, per coglierlo in fallo nel discorso. Vennero e gli dissero: «Maestro, sappiamo che sei veritiero e non hai soggezione di alcuno, perché non guardi in faccia a nessuno, ma insegni la via di Dio secondo verità. È lecito o no pagare il tributo a Cesare? Lo dobbiamo dare, o no?». Ma egli, conoscendo la loro ipocrisia, disse loro: «Perché volete mettermi alla prova? Portatemi un denaro: voglio vederlo». Ed essi glielo portarono. Allora disse loro: «Questa immagine e l''iscrizione, di chi sono?». Gli risposero: «Di Cesare». Gesù disse loro: «Quello che è di Cesare rendetelo a Cesare, e quello che è di Dio, a Dio». E rimasero ammirati di lui');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 12,18-27', 'Marco', 'In quel tempo, vennero da Gesù alcuni sadducei - i quali dicono che non c''è risurrezione - e lo interrogavano dicendo: «Maestro, Mosè ci ha lasciato scritto che, se muore il fratello di qualcuno e lascia la moglie senza figli, suo fratello prenda la moglie e dia una discendenza al proprio fratello. C''erano sette fratelli: il primo prese moglie, morì e non lasciò discendenza. Allora la prese il secondo e morì senza lasciare discendenza; e il terzo egualmente, e nessuno dei sette lasciò discendenza. Alla fine, dopo tutti, morì anche la donna. Alla risurrezione, quando risorgeranno, di quale di loro sarà moglie? Poiché tutti e sette l''hanno avuta in moglie». Rispose loro Gesù: «Non è forse per questo che siete in errore, perché non conoscete le Scritture né la potenza di Dio? Quando risorgeranno dai morti, infatti, non prenderanno né moglie né marito, ma saranno come angeli nei cieli. Riguardo al fatto che i morti risorgono, non avete letto nel libro di Mosè, nel racconto del roveto, come Dio gli parlò dicendo: "Io sono il Dio di Abramo, il Dio di Isacco e il Dio di Giacobbe"? Non è Dio dei morti, ma dei viventi! Voi siete in grave errore»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 12,28b-34', 'Marco', 'In quel tempo, si avvicinò a Gesù uno degli scribi e gli domandò: «Qual è il primo di tutti i comandamenti?». Gesù rispose: «Il primo è: "Ascolta, Israele! Il Signore nostro Dio è l''unico Signore; amerai il Signore tuo Dio con tutto il tuo cuore e con tutta la tua anima, con tutta la tua mente e con tutta la tua forza". Il secondo è questo: "Amerai il tuo prossimo come te stesso". Non c''è altro comandamento più grande di questi». Lo scriba gli disse: «Hai detto bene, Maestro, e secondo verità, che Egli è unico e non vi è altri all''infuori di lui; amarlo con tutto il cuore, con tutta l''intelligenza e con tutta la forza e amare il prossimo come se stesso vale più di tutti gli olocausti e i sacrifici». Vedendo che egli aveva risposto saggiamente, Gesù gli disse: «Non sei lontano dal regno di Dio». E nessuno aveva più il coraggio di interrogarlo');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 12,35-37', 'Marco', 'In quel tempo, insegnando nel tempio, Gesù diceva: «Come mai gli scribi dicono che il Cristo è figlio di Davide? Disse infatti Davide stesso, mosso dallo Spirito Santo: "Disse il Signore al mio Signore: Siedi alla mia destra, finché io ponga i tuoi nemici sotto i tuoi piedi". Davide stesso lo chiama Signore: da dove risulta che è suo figlio?». E la folla numerosa lo ascoltava volentieri');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 12,38-44', 'Marco', 'In quel tempo, Gesù [nel tempio] diceva alla folla nel suo insegnamento: «Guardatevi dagli scribi, che amano passeggiare in lunghe vesti, ricevere saluti nelle piazze, avere i primi seggi nelle sinagoghe e i primi posti nei banchetti. Divorano le case delle vedove e pregano a lungo per farsi vedere. Essi riceveranno una condanna più severa». Seduto di fronte al tesoro, osservava come la folla vi gettava monete. Tanti ricchi ne gettavano molte. Ma, venuta una vedova povera, vi gettò due monetine, che fanno un soldo. Allora, chiamati a sé i suoi discepoli, disse loro: «In verità io vi dico: questa vedova, così povera, ha gettato nel tesoro più di tutti gli altri. Tutti infatti hanno gettato parte del loro superfluo. Lei invece, nella sua miseria, vi ha gettato tutto quello che aveva, tutto quanto aveva per vivere»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 3,16-18', 'Giovanni', '[In quel tempo, disse Gesù a Nicodèmo]: «Dio ha tanto amato il mondo da dare il Figlio, unigenito, perché chiunque crede in lui non vada perduto, ma abbia la vita eterna. Dio, infatti, non ha mandato il Figlio nel mondo per condannare il mondo, ma perché il mondo sia salvato per mezzo di lui. Chi crede in lui non è condannato; ma chi non crede è già stato condannato, perché non ha creduto nel nome dell''unigenito Figlio di Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,1-12', 'Matteo', 'In quel tempo, vedendo le folle, Gesù salì sul monte: si pose a sedere e si avvicinarono a lui i suoi discepoli. Si mise a parlare e insegnava loro dicendo: «Beati i poveri in spirito, perché di essi è il regno dei cieli. Beati quelli che sono nel pianto, perché saranno consolati. Beati i miti, perché avranno in eredità la terra. Beati quelli che hanno fame e sete della giustizia, perché saranno saziati. Beati i misericordiosi, perché troveranno misericordia. Beati i puri di cuore, perché vedranno Dio. Beati gli operatori di pace, perché saranno chiamati figli di Dio. Beati i perseguitati per la giustizia, perché di essi è il regno dei cieli. Beati voi quando vi insulteranno, vi perseguiteranno e, mentendo, diranno ogni sorta di male contro di voi per causa mia. Rallegratevi ed esultate, perché grande è la vostra ricompensa nei cieli. Così infatti perseguitarono i profeti che furono prima di voi»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,51-58', 'Giovanni', '[In quel tempo, Gesù disse alla folla]: «Io sono il pane vivo, disceso dal cielo. Se uno mangia di questo pane vivrà in eterno e il pane che io darò è la mia carne per la vita del mondo». Allora i Giudei si misero a discutere aspramente fra loro: «Come può costui darci la sua carne da mangiare?». Gesù disse loro: «In verità, in verità io vi dico: se non mangiate la carne del Figlio dell''uomo e non bevete il suo sangue, non avete in voi la vita. Chi mangia la mia carne e beve il mio sangue ha la vita eterna e io lo risusciterò nell''ultimo giorno. Perché la mia carne è vero cibo e il mio sangue vera bevanda. Chi mangia la mia carne e beve il mio sangue rimane in me e io in lui. Come il Padre, che ha la vita, ha mandato me e io vivo per il Padre, così anche co-lui che mangia me vivrà per me. Questo è il pane disceso dal cielo; non è come quello che mangiarono i padri e morirono. Chi mangia questo pane vivrà in eterno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 2,41-51', 'Luca', 'I genitori di Gesù si recavano ogni anno a Gerusalemme per la festa di Pasqua. Quando egli ebbe dodici anni, vi salirono secondo la consuetudine della festa. Ma, trascorsi i giorni, mentre riprendevano la via del ritorno, il fanciullo Gesù rimase a Gerusalemme, senza che i genitori se ne accorgessero. Credendo che egli fosse nella comitiva, fecero una giornata di viaggio e poi si misero a cercarlo tra i parenti e i conoscenti; non avendolo trovato, tornarono in cerca di lui a Gerusalemme. Dopo tre giorni lo trovarono nel tempio, seduto in mezzo ai maestri, mentre li ascoltava e li interrogava. E tutti quelli che l''udivano erano pieni di stupore per la sua intelligenza e le sue risposte. Al vederlo restarono stupiti, e sua madre gli disse: «Figlio, perché ci hai fatto questo? Ecco, tuo padre e io, angosciati, ti cercavamo». Ed egli rispose loro: «Perché mi cercavate? Non sapevate che io devo occuparmi delle cose del Padre mio?». Ma essi non compresero ciò che aveva detto loro. Scese dunque con loro e venne a Nàzaret e stava loro sottomesso. Sua madre custodiva tutte queste cose nel suo cuore');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 10,26-33', 'Matteo', '[In quel tempo, Gesù disse ai suoi apostoli]: «Non abbiate paura degli uomini, poiché nulla vi è di nascosto che non sarà svelato né di segreto che non sarà conosciuto. Quello che io vi dico nelle tenebre voi ditelo nella luce, e quello che ascoltate all''orecchio voi annunciatelo dalle terrazze. E non abbiate paura di quelli che uccidono il corpo, ma non hanno potere di uccidere l''anima; abbiate paura piuttosto di colui che ha il potere di far perire nella Geènna e l''anima e il corpo. Due passeri non si vendono forse per un soldo? Eppure nemmeno uno di essi cadrà a terra senza il volere del Padre vostro. Perfino i capelli del vostro capo sono tutti contati. Non abbiate dunque paura: voi valete più di molti passeri! Perciò chiunque mi riconoscerà davanti agli uomini, anch''io lo riconoscerò davanti al Padre mio che è nei cieli; chi invece mi rinnegherà davanti agli uomini, anch''io lo rinnegherò davanti al Padre mio che è nei cieli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 7,1-5', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Non giudicate, per non essere giudicati; perché con il giudizio con il quale giudicate sarete giudicati voi e con la misura con la quale misurate sarà misurato a voi. Perché guardi la pagliuzza che è nell''occhio del tuo fratello, e non ti accorgi della trave che è nel tuo occhio? O come dirai al tuo fratello: "Lascia che tolga la pagliuzza dal tuo occhio", mentre nel tuo occhio c''è la trave? Ipocrita! Togli prima la trave dal tuo occhio e allora ci vedrai bene per togliere la pagliuzza dall''occhio del tuo fratello»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 8,1-4', 'Matteo', 'Quando Gesù scese dal monte, molta folla lo seguì. Ed ecco, si avvicinò un lebbroso, si prostrò davanti a lui e disse: «Signore, se vuoi, puoi purificarmi». Tese la mano e lo toccò dicendo: «Lo voglio: sii purificato!». E subito la sua lebbra fu guarita. Poi Gesù gli disse: «Guàrdati bene dal dirlo a qualcuno; va'' invece a mostrarti al sacerdote e presenta l''offerta prescritta da Mosè come testimonianza per loro»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 8,5-17', 'Matteo', 'In quel tempo, entrato Gesù in Cafàrnao, gli venne incontro un centurione che lo scongiurava e diceva: «Signore, il mio servo è in casa, a letto, paralizzato e soffre terribilmente». Gli disse: «Verrò e lo guarirò». Ma il centurione rispose: «Signore, io non sono degno che tu entri sotto il mio tetto, ma di'' soltanto una parola e il mio servo sarà guarito. Pur essendo anch''io un subalterno, ho dei soldati sotto di me e dico a uno: "Va''!", ed egli va; e a un altro: "Vieni!", ed egli viene; e al mio servo: "Fa'' questo!", ed egli lo fa». Ascoltandolo, Gesù si meravigliò e disse a quelli che lo seguivano: «In verità io vi dico, in Israele non ho trovato nessuno con una fede così grande! Ora io vi dico che molti verranno dall''oriente e dall''occidente e siederanno a mensa con Abramo, Isacco e Giacobbe nel regno dei cieli, mentre i figli del regno saranno cacciati fuori, nelle tenebre, dove sarà pianto e stridore di denti». E Gesù disse al centurione: «Va'', avvenga per te come hai creduto». In quell''istante il suo servo fu guarito. Entrato nella casa di Pietro, Gesù vide la suocera di lui che era a letto con la febbre. Le toccò la mano e la febbre la lasciò; poi ella si alzò e lo serviva. Venuta la sera, gli portarono molti indemoniati ed egli scacciò gli spiriti con la parola e guarì tutti i malati, perché si compisse ciò che era stato detto per mezzo del profeta Isaìa: "Egli ha preso le nostre infermità e si è caricato delle malattie"');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 10,37-42', 'Matteo', '[In quel tempo, disse Gesù ai suoi discepoli]: "Chi ama il padre o la madre più di me non è degno di me; chi ama il figlio o la figlia più di me non è degno di me; chi non prende la sua croce e non mi segue, non è degno di me. Chi avrà trovato la sua vita, la perderà: e chi avrà perduto la sua vita per causa mia, la troverà. Chi accoglie voi accoglie me, e chi accoglie me accoglie colui che mi ha mandato. Chi accoglie un profeta come profeta, avrà la ricompensa del profeta, e chi accoglie un giusto come giusto, avrà la ricompensa del giusto. E chi avrà dato anche solo un bicchiere di acqua fresca a uno di questi piccoli, perché è mio discepolo, in verità io vi dico: non perderà la sua ricompensa"');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 8,28-34', 'Matteo', 'In quel tempo, giunto Gesù all''altra riva, nel paese dei Gadarèni, due indemoniati, uscendo dai sepolcri, gli andarono incontro; erano tanto furiosi che nessuno poteva passare per quella strada. Ed ecco, si misero a gridare: «Che vuoi da noi, Figlio di Dio? Sei venuto qui a tormentarci prima del tempo?». A qualche distanza da loro c''era una numerosa mandria di porci al pascolo; e i demòni lo scongiuravano dicendo: «Se ci scacci, mandaci nella mandria dei porci». Egli disse loro: «Andate!». Ed essi uscirono, ed entrarono nei porci: ed ecco, tutta la mandria si precipitò giù dalla rupe nel mare e morirono nelle acque. I mandriani allora fuggirono e, entrati in città, raccontarono ogni cosa e anche il fatto degli indemoniati. Tutta la città allora uscì incontro a Gesù: quando lo videro, lo pregarono di allontanarsi dal loro territorio');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 10,7-15', 'Matteo', '[In quel tempo, disse Gesù ai suoi apostoli]: «Strada facendo, predicate, dicendo che il regno dei cieli è vicino. Guarite gli infermi, risuscitate i morti, purificate i lebbrosi, scacciate i demòni. Gratuitamente avete ricevuto, gratuitamente date. Non procuratevi oro né argento né denaro nelle vostre cinture, né sacca da viaggio, né due tuniche, né sandali, né bastone, perché chi lavora ha diritto al suo nutrimento. In qualunque città o villaggio entriate, domandate chi là sia degno e rimanetevi finché non sarete partiti. Entrando nella casa, rivolgetele il saluto. Se quella casa ne è degna, la vostra pace scenda su di essa; ma se non ne è degna, la vostra pace ritorni a voi. Se qualcuno poi non vi accoglie e non dà ascolto alle vostre parole, uscite da quella casa o da quella città e scuotete la polvere dei vostri piedi. In verità io vi dico: nel giorno del giudizio la terra di Sòdoma e Gomorra sarà trattata meno duramente di quella città»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,1-23', 'Matteo', 'Quel giorno Gesù uscì di casa e sedette in riva al mare. Si radunò attorno a lui tanta folla che egli salì su una barca e si mise a sedere, mentre tutta la folla stava sulla spiaggia. Egli parlò loro di molte cose con parabole. E disse: «Ecco, il seminatore uscì a seminare. Mentre seminava, una parte cadde lungo la strada; vennero gli uccelli e la mangiarono. Un''altra parte cadde sul terreno sassoso, dove non c''era molta terra; germogliò subito, perché il terreno non era profondo, ma quando spuntò il sole fu bruciata e, non avendo radici, seccò. Un''altra parte cadde sui rovi, e i rovi crebbero e la soffocarono. Un''altra parte cadde sul terreno buono e diede frutto: il cento, il sessanta, il trenta per uno. Chi ha orecchi, ascolti». Gli si avvicinarono allora i discepoli e gli dissero: «Perché a loro parli con parabole?». Egli rispose loro: «Perché a voi è dato conoscere i misteri del regno dei cieli, ma a loro non è dato. Infatti a colui che ha, verrà dato e sarà nell''abbondanza; ma a colui che non ha, sarà tolto anche quello che ha. Per questo a loro parlo con parabole: perché guardando non vedono, udendo non ascoltano e non comprendono. Così si compie per loro la profezia di Isaìa che dice: "Udrete, sì, ma non comprenderete, guarderete, sì, ma non vedrete. Perché il cuore di questo popolo è diventato insensibile, sono diventati duri di orecchi e hanno chiuso gli occhi, perché non vedano con gli occhi, non ascoltino con gli orecchi e non comprendano con il cuore e non si convertano e io li guarisca!". Beati invece i vostri occhi perché vedono e i vostri orecchi perché ascoltano. In verità io vi dico: molti profeti e molti giusti hanno desiderato vedere ciò che voi guardate, ma non lo videro, e ascoltare ciò che voi ascoltate, ma non lo ascoltarono! Voi dunque ascoltate la parabola del seminatore. Ogni volta che uno ascolta la parola del Regno e non la comprende, viene il Maligno e ruba ciò che è stato seminato nel suo cuore: questo è il seme seminato lungo la strada. Quello che è stato seminato sul terreno sassoso è colui che ascolta la Parola e l''accoglie subito con gioia, ma non ha in sé radici ed è incostante, sicché, appena giunge una tribolazione o una persecuzione a causa della Parola, egli subito viene meno. Quello seminato tra i rovi è colui che ascolta la Parola, ma la preoccupazione del mondo e la seduzione della ricchezza soffocano la Parola ed essa non dà frutto. Quello seminato sul terreno buono è colui che ascolta la Parola e la comprende; questi dà frutto e produce il cento, il sessanta, il trenta per uno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,24-43', 'Matteo', '[In quel tempo, Gesù] espose alla folla un''altra parabola, dicendo: «Il regno dei cieli è simile a un uomo che ha seminato del buon seme nel suo campo. Ma, mentre tutti dormivano, venne il suo nemico, seminò della zizzania in mezzo al grano e se ne andò. Quando poi lo stelo crebbe e fece frutto, spuntò anche la zizzania. Allora i servi andarono dal padrone di casa e gli dissero: "Signore, non hai seminato del buon seme nel tuo campo? Da dove viene la zizzania?". Ed egli rispose loro: "Un nemico ha fatto questo!". E i servi gli dissero: "Vuoi che andiamo a raccoglierla?". "No, rispose, perché non succeda che, raccogliendo la zizzania, con essa sradichiate anche il grano. Lasciate che l''una e l''altro crescano insieme fino alla mietitura e al momento della mietitura dirò ai mietitori: Raccogliete prima la zizzania e legatela in fasci per bruciarla; il grano invece riponètelo nel mio granaio"». Espose loro un''altra parabola, dicendo: «Il regno dei cieli è simile a un granello di senape, che un uomo prese e seminò nel suo campo. Esso è il più piccolo di tutti i semi ma, una volta cresciuto, è più grande delle altre piante dell''orto e diventa un albero, tanto che gli uccelli del cielo vengono a fare il nido fra i suoi rami». Disse loro un''altra parabola: «Il regno dei cieli è simile al lievito, che una donna prese e mescolò in tre misure di farina, finché non fu tutta lievitata». Tutte queste cose Gesù disse alle folle con parabole e non parlava ad esse se non con parabole, perché si compisse ciò che era stato detto per mezzo del profeta: «Aprirò la mia bocca con parabole, proclamerò cose nascoste fin dalla fondazione del mondo». Poi congedò la folla ed entrò in casa; i suoi discepoli gli si avvicinarono per dirgli: «Spiegaci la parabola della zizzania nel campo». Ed egli rispose: «Colui che semina il buon seme è il Figlio dell''uomo. Il campo è il mondo e il seme buono sono i figli del Regno. La zizzania sono i figli del Maligno e il nemico che l''ha seminata è il diavolo. La mietitura è la fine del mondo e i mietitori sono gli angeli. Come dunque si raccoglie la zizzania e la si brucia nel fuoco, così avverrà alla fine del mondo. Il Figlio dell''uomo manderà i suoi angeli, i quali raccoglieranno dal suo regno tutti gli scandali e tutti quelli che commettono iniquità e li getteranno nella fornace ardente, dove sarà pianto e stridore di denti. Allora i giusti splenderanno come il sole nel regno del Padre loro. Chi ha orecchi, ascolti!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 12,38-42', 'Matteo', 'In quel tempo, alcuni scribi e farisei dissero a Gesù: «Maestro, da te vogliamo vedere un segno». Ed egli rispose loro: «Una generazione malvagia e adultera pretende un segno! Ma non le sarà dato alcun segno, se non il segno di Giona il profeta. Come infatti Giona rimase tre giorni e tre notti nel ventre del pesce, così il Figlio dell''uomo resterà tre giorni e tre notti nel cuore della terra. Nel giorno del giudizio, quelli di Nìnive si alzeranno contro questa generazione e la condanneranno, perché essi alla predicazione di Giona si convertirono. Ed ecco, qui vi è uno più grande di Giona! Nel giorno del giudizio, la regina del Sud si alzerà contro questa generazione e la condannerà, perché ella venne dagli estremi confini della terra per ascoltare la sapienza di Salomone. Ed ecco, qui vi è uno più grande di Salomone!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 12,46-50', 'Matteo', 'In quel tempo, mentre Gesù parlava ancora alla folla, ecco, sua madre e i suoi fratelli stavano fuori e cercavano di parlargli. Qualcuno gli disse: «Ecco, tua madre e i tuoi fratelli stanno fuori e cercano di parlarti». Ed egli, rispondendo a chi gli parlava, disse: «Chi è mia madre e chi sono i miei fratelli?». Poi, tendendo la mano verso i suoi discepoli, disse: «Ecco mia madre e i miei fratelli! Perché chiunque fa la volontà del Padre mio che è nei cieli, egli è per me fratello, sorella e madre»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,44-52', 'Matteo', 'In quel tempo Gesù disse ai suoi discepoli: «Il regno dei cieli è simile a un tesoro nascosto nel campo; un uomo lo trova e lo nasconde; poi va, pieno di gioia, vende tutti i suoi averi e compra quel campo. Il regno dei cieli è simile anche a un mercante che va in cerca di perle preziose; trovata una perla di grande valore, va, vende tutti i suoi averi e la compra. Ancora, il regno dei cieli è simile a una rete gettata nel mare, che raccoglie ogni genere di pesci. Quando è piena, i pescatori la tirano a riva, si mettono a sedere, raccolgono i pesci buoni nei canestri e buttano via i cattivi. Così sarà alla fine del mondo. Verranno gli angeli e separeranno i cattivi dai buoni e li getteranno nella fornace ardente, dove sarà pianto e stridore di denti. Avete compreso tutte queste cose?». Gli risposero: «Sì». Ed egli disse loro: «Per questo ogni scriba, divenuto discepolo del regno dei cieli, è simile a un padrone di casa che estrae dal suo tesoro cose nuove e cose antiche»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,31-35', 'Matteo', 'In quel tempo, Gesù espose alla folla un''altra parabola, dicendo: «Il regno dei cieli è simile a un granello di senape, che un uomo prese e seminò nel suo campo. Esso è il più piccolo di tutti i semi ma, una volta cresciuto, è più grande delle altre piante dell''orto e diventa un albero, tanto che gli uccelli del cielo vengono a fare il nido fra i suoi rami». Disse loro un''altra parabola: «Il regno dei cieli è simile al lievito, che una donna prese e mescolò in tre misure di farina, finché non fu tutta lievitata». Tutte queste cose Gesù disse alle folle con parabole e non parlava ad esse se non con parabole, perché si compisse ciò che era stato detto per mezzo del profeta: «Aprirò la mia bocca con parabole, proclamerò cose nascoste fin dalla fondazione del mondo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 14,22-36', 'Matteo', 'Subito dopo [la moltiplicazione dei mani e dei pesci] costrinse i discepoli a salire sulla barca e a precederlo sull''altra riva, finché non avesse congedato la folla. Congedata la folla, salì sul monte, in disparte, a pregare. Venuta la sera, egli se ne stava lassù, da solo. La barca intanto distava già molte miglia da terra ed era agitata dalle onde: il vento infatti era contrario. Sul finire della notte egli andò verso di loro camminando sul mare. Vedendolo camminare sul mare, i discepoli furono sconvolti e dissero: «È un fantasma!» e gridarono dalla paura. Ma subito Gesù parlò loro dicendo: «Coraggio, sono io, non abbiate paura!». Pietro allora gli rispose: «Signore, se sei tu, comandami di venire verso di te sulle acque».  Ed egli disse: "Vieni!". Pietro scese dalla barca, si mise a camminare sulle acque e andò verso Gesù. Ma, vedendo che il vento era forte, s''impaurì e, cominciando ad affondare, gridò: "Signore, salvami!". E subito Gesù tese la mano, lo afferrò e gli disse: "Uomo di poca fede, perché hai dubitato?".  Appena saliti sulla barca, il vento cessò. Quelli che erano sulla barca si prostrarono davanti a lui, dicendo: "Davvero tu sei Figlio di Dio!". Compiuta la traversata, approdarono a Gennèsaret. E la gente del luogo, riconosciuto Gesù, diffuse la notizia in tutta la regione; gli portarono tutti i malati e lo pregavano di poter toccare almeno il lembo del suo mantello. E quanti lo toccarono furono guariti');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 15,1-2.10-14', 'Matteo', 'In quel tempo alcuni farisei e alcuni scribi, venuti da Gerusalemme, si avvicinarono a Gesù e gli dissero: «Perché i tuoi discepoli trasgrediscono la tradizione degli antichi? Infatti quando prendono cibo non si lavano le mani!». Poi, riunita la folla, disse loro: «Ascoltate e comprendete bene!  Non ciò che entra nella bocca rende impuro l''uomo; ciò che esce dalla bocca, questo rende impuro l''uomo!». Allora i discepoli si avvicinarono per dirgli: «Sai che i farisei, a sentire questa parola, si sono scandalizzati?». Ed egli rispose: «Ogni pianta, che non è stata piantata dal Padre mio celeste, verrà sradicata.  Lasciateli stare! Sono ciechi e guide di ciechi. E quando un cieco guida un altro cieco, tutti e due cadranno in un fosso!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 16,24-28', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Se qualcuno vuole venire dietro a me, rinneghi se stesso, prenda la sua croce e mi segua. Perché chi vuole salvare la propria vita, la perderà; ma chi perderà la propria vita per causa mia, la troverà. Infatti quale vantaggio avrà un uomo se guadagnerà il mondo intero, ma perderà la propria vita? O che cosa un uomo potrà dare in cambio della propria vita? Perché il Figlio dell’uomo sta per venire nella gloria del Padre suo, con i suoi angeli, e allora renderà a ciascuno secondo le sue azioni. In verità io vi dico: vi sono alcuni tra i presenti che non moriranno, prima di aver visto venire il Figlio dell’uomo con il suo regno»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 17,14-20', 'Matteo', 'In quel tempo, si avvicinò a Gesù un uomo che gli si gettò in ginocchio e disse: «Signore, abbi pietà di mio figlio! È epilettico e soffre molto; cade spesso nel fuoco e sovente nell''acqua. L''ho portato dai tuoi discepoli, ma non sono riusciti a guarirlo». E Gesù rispose: «O generazione incredula e perversa! Fino a quando sarò con voi? Fino a quando dovrò sopportarvi? Portatelo qui da me». Gesù lo minacciò e il demonio uscì da lui, e da quel momento il ragazzo fu guarito. Allora i discepoli si avvicinarono a Gesù, in disparte, e gli chiesero: «Perché noi non siamo riusciti a scacciarlo?». Ed egli rispose loro: «Per la vostra poca fede. In verità io vi dico: se avrete fede pari a un granello di senape, direte a questo monte: "Spòstati da qui a là", ed esso si sposterà, e nulla vi sarà impossibile»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 14,22-33', 'Matteo', '[Dopo che la folla ebbe mangiato], subito Gesù costrinse i discepoli a salire sulla barca e a precederlo sull''altra riva, finché non avesse congedato la folla. Congedata la folla, salì sul monte, in disparte, a pregare. Venuta la sera, egli se ne stava lassù, da solo. La barca intanto distava già molte miglia da terra ed era agitata dalle onde: il vento infatti era contrario. Sul finire della notte egli andò verso di loro camminando sul mare. Vedendolo camminare sul mare, i discepoli furono sconvolti e dissero: «È un fantasma!» e gridarono dalla paura. Ma subito Gesù parlò loro dicendo: «Coraggio, sono io, non abbiate paura!». Pietro allora gli rispose: «Signore, se sei tu, comandami di venire verso di te sulle acque». Ed egli disse: «Vieni!». Pietro scese dalla barca, si mise a camminare sulle acque e andò verso Gesù. Ma, vedendo che il vento era forte, s''impaurì e, cominciando ad affondare, gridò: «Signore, salvami!». E subito Gesù tese la mano, lo afferrò e gli disse: «Uomo di poca fede, perché hai dubitato?». Appena saliti sulla barca, il vento cessò. Quelli che erano sulla barca si prostrarono davanti a lui, dicendo: «Davvero tu sei Figlio di Dio!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 18,21-19,1', 'Matteo', 'In quel tempo, Pietro si avvicinò a Gesù e gli disse: «Signore, se il mio fratello commette colpe contro di me, quante volte dovrò perdonargli? Fino a sette volte?». E Gesù gli rispose: «Non ti dico fino a sette volte, ma fino a settanta volte sette. Per questo, il regno dei cieli è simile a un re che volle regolare i conti con i suoi servi. Aveva cominciato a regolare i conti, quando gli fu presentato un tale che gli doveva diecimila talenti. Poiché costui non era in grado di restituire, il padrone ordinò che fosse venduto lui con la moglie, i figli e quanto possedeva, e così saldasse il debito. Allora il servo, prostrato a terra, lo supplicava dicendo: "Abbi pazienza con me e ti restituirò ogni cosa". Il padrone ebbe compassione di quel servo, lo lasciò andare e gli condonò il debito. Appena uscito, quel servo trovò uno dei suoi compagni, che gli doveva cento denari. Lo prese per il collo e lo soffocava, dicendo: "Restituisci quello che devi!". Il suo compagno, prostrato a terra, lo pregava dicendo: "Abbi pazienza con me e ti restituirò". Ma egli non volle, andò e lo fece gettare in prigione, fino a che non avesse pagato il debito. Visto quello che accadeva, i suoi compagni furono molto dispiaciuti e andarono a riferire al loro padrone tutto l''accaduto. Allora il padrone fece chiamare quell''uomo e gli disse: "Servo malvagio, io ti ho condonato tutto quel debito perché tu mi hai pregato. Non dovevi anche tu aver pietà del tuo compagno, così come io ho avuto pietà di te?". Sdegnato, il padrone lo diede in mano agli aguzzini, finché non avesse restituito tutto il dovuto. Così anche il Padre mio celeste farà con voi se non perdonerete di cuore, ciascuno al proprio fratello». Terminati questi discorsi, Gesù lasciò la Galilea e andò nella regione della Giudea, al di là del Giordano');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 16,13-20', 'Matteo', 'In quel tempo, Gesù, giunto nella regione di Cesarèa di Filippo, domandò ai suoi discepoli: «La gente, chi dice che sia il Figlio dell''uomo?». Risposero: «Alcuni dicono Giovanni il Battista, altri Elìa, altri Geremìa o qualcuno dei profeti». Disse loro: «Ma voi, chi dite che io sia?». Rispose Simon Pietro: «Tu sei il Cristo, il Figlio del Dio vivente». E Gesù gli disse: «Beato sei tu, Simone, figlio di Giona, perché né carne né sangue te lo hanno rivelato, ma il Padre mio che è nei cieli. E io a te dico: tu sei Pietro e su questa pietra edificherò la mia Chiesa e le potenze degli inferi non prevarranno su di essa. A te darò le chiavi del regno dei cieli: tutto ciò che legherai sulla terra sarà legato nei cieli, e tutto ciò che scioglierai sulla terra sarà sciolto nei cieli». Allora ordinò ai discepoli di non dire ad alcuno che egli era il Cristo');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 24,42-51', 'Matteo', '[In quel tempo, Gesù disse ai suoi discepoli]: «Vegliate, perché non sapete in quale giorno il Signore vostro verrà. Cercate di capire questo: se il padrone di casa sapesse a quale ora della notte viene il ladro, veglierebbe e non si lascerebbe scassinare la casa. Perciò anche voi tenetevi pronti perché, nell''ora che non immaginate, viene il Figlio dell''uomo. Chi è dunque il servo fidato e prudente, che il padrone ha messo a capo dei suoi domestici per dare loro il cibo a tempo debito? Beato quel servo che il padrone, arrivando, troverà ad agire così! Davvero io vi dico: lo metterà a capo di tutti i suoi beni. Ma se quel servo malvagio dicesse in cuor suo: "Il mio padrone tarda", e cominciasse a percuotere i suoi compagni e a mangiare e a bere con gli ubriaconi, il padrone di quel servo arriverà un giorno in cui non se l''aspetta e a un''ora che non sa, lo punirà severamente e gli infliggerà la sorte che meritano gli ipocriti: là sarà pianto e stridore di denti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 16,21-27', 'Matteo', 'In quel tempo, Gesù cominciò a spiegare ai suoi discepoli che doveva andare a Gerusalemme e soffrire molto da parte degli anziani, dei capi dei sacerdoti e degli scribi, e venire ucciso e risorgere il terzo giorno. Pietro lo prese in disparte e si mise a rimproverarlo dicendo: «Dio non voglia, Signore; questo non ti accadrà mai». Ma egli, voltandosi, disse a Pietro: «Va'' dietro a me, Satana! Tu mi sei di scandalo, perché non pensi secondo Dio, ma secondo gli uomini!». Allora Gesù disse ai suoi discepoli: «Se qualcuno vuole venire dietro a me, rinneghi se stesso, prenda la sua croce e mi segua. Perché chi vuole salvare la propria vita, la perderà; ma chi perderà la propria vita per causa mia, la troverà. Infatti quale vantaggio avrà un uomo se guadagnerà il mondo intero, ma perderà la propria vita? O che cosa un uomo potrà dare in cambio della propria vita? Perché il Figlio dell''uomo sta per venire nella gloria del Padre suo, con i suoi angeli, e allora renderà a ciascuno secondo le sue azioni»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 1,1-16.18-23', 'Matteo', 'Genealogia di Gesù Cristo figlio di Davide, figlio di Abramo. Abramo generò Isacco, Isacco generò Giacobbe, Giacobbe generò Giuda e i suoi fratelli, Giuda generò Fares e Zara da Tamar, Fares generò Esrom, Esrom generò Aram, Aram generò Aminadàb, Aminadàb generò Naassòn, Naassòn generò Salmon, Salmon generò Booz da Racab, Booz generò Obed da Rut, Obed generò Iesse, Iesse generò il re Davide. Davide generò Salomone da quella che era stata la moglie di Urìa, Salomone generò Roboamo, Roboamo generò Abìa, Abìa generò Asaf, Asaf generò Giosafat, Giosafat generò Ioram, Ioram generò Ozìa, Ozìa generò Ioatàm, Ioatàm generò Acaz, Acaz generò Ezechìa, Ezechìa generò Manasse, Manasse generò Amos, Amos generò Giosìa, Giosìa generò Ieconìa e i suoi fratelli, al tempo della deportazione in Babilonia. Dopo la deportazione in Babilonia, Ieconìa generò Salatièl, Salatièl generò Zorobabele, Zorobabele generò Abiùd, Abiùd generò Eliachìm, Eliachìm generò Azor, Azor generò Sadoc, Sadoc generò Achim, Achim generò Eliùd, Eliùd generò Eleàzar, Eleàzar generò Mattan, Mattan generò Giacobbe, Giacobbe generò Giuseppe, lo sposo di Maria, dalla quale è nato Gesù, chiamato Cristo. Così fu generato Gesù Cristo: sua madre Maria, essendo promessa sposa di Giuseppe, prima che andassero a vivere insieme si trovò incinta per opera dello Spirito Santo. Giuseppe suo sposo, poiché era uomo giusto e non voleva accusarla pubblicamente, pensò di ripudiarla in segreto. Mentre però stava considerando queste cose, ecco, gli apparve in sogno un angelo del Signore e gli disse: «Giuseppe, figlio di Davide, non temere di prendere con te Maria, tua sposa. Infatti il bambino che è generato in lei viene dallo Spirito Santo; ella darà alla luce un figlio e tu lo chiamerai Gesù: egli infatti salverà il suo popolo dai suoi peccati». Tutto questo è avvenuto perché si compisse ciò che era stato detto dal Signore per mezzo del profeta: «Ecco, la vergine concepirà e darà alla luce un figlio: a lui sarà dato il nome di Emmanuele», che significa Dio con noi');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 6,43-49', 'Luca', '[In quel tempo, Gesù disse ai suoi discepoli]: «Non vi è albero buono che produca un frutto cattivo, né vi è d''altronde albero cattivo che produca un frutto buono. Ogni albero infatti si riconosce dal suo frutto: non si raccolgono fichi dagli spini, né si vendemmia uva da un rovo. L''uomo buono dal buon tesoro del suo cuore trae fuori il bene; l''uomo cattivo dal suo cattivo tesoro trae fuori il male: la sua bocca infatti esprime ciò che dal cuore sovrabbonda. Perché mi invocate: "Signore, Signore!" e non fate quello che dico? Chiunque viene a me e ascolta le mie parole e le mette in pratica, vi mostrerò a chi è simile: è simile a un uomo che, costruendo una casa, ha scavato molto profondo e ha posto le fondamenta sulla roccia. Venuta la piena, il fiume investì quella casa, ma non riuscì a smuoverla perché era costruita bene. Chi invece ascolta e non mette in pratica, è simile a un uomo che ha costruito una casa sulla terra, senza fondamenta. Il fiume la investì e subito crollò; e la distruzione di quella casa fu grande»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 19,25-27', 'Giovanni', 'In quel tempo, stavano presso la croce di Gesù sua madre, la sorella di sua madre, Maria madre di Clèopa e Maria di Màgdala. Gesù allora, vedendo la madre e accanto a lei il discepolo che egli amava, disse alla madre: «Donna, ecco tuo figlio!». Poi disse al discepolo: «Ecco tua madre!». E da quell''ora il discepolo l''accolse con sé');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 8,4-15', 'Luca', 'In quel tempo, poiché una grande folla si radunava e accorreva a lui gente da ogni città, Gesù disse con una parabola: «Il seminatore uscì a seminare il suo seme. Mentre seminava, una parte cadde lungo la strada e fu calpestata, e gli uccelli del cielo la mangiarono. Un''altra parte cadde sulla pietra e, appena germogliata, seccò per mancanza di umidità. Un''altra parte cadde in mezzo ai rovi e i rovi, cresciuti insieme con essa, la soffocarono. Un''altra parte cadde sul terreno buono, germogliò e fruttò cento volte tanto». Detto questo, esclamò: «Chi ha orecchi per ascoltare, ascolti!». I suoi discepoli lo interrogavano sul significato della parabola. Ed egli disse: «A voi è dato conoscere i misteri del regno di Dio, ma agli altri solo con parabole, affinché vedendo non vedano e ascoltando non comprendano. Il significato della parabola è questo: il seme è la parola di Dio. I semi caduti lungo la strada sono coloro che l''hanno ascoltata, ma poi viene il diavolo e porta via la Parola dal loro cuore, perché non avvenga che, credendo, siano salvati. Quelli sulla pietra sono coloro che, quando ascoltano, ricevono la Parola con gioia, ma non hanno radici; credono per un certo tempo, ma nel tempo della prova vengono meno. Quello caduto in mezzo ai rovi sono coloro che, dopo aver ascoltato, strada facendo si lasciano soffocare da preoccupazioni, ricchezze e piaceri della vita e non giungono a maturazione. Quello sul terreno buono sono coloro che, dopo aver ascoltato la Parola con cuore integro e buono, la custodiscono e producono frutto con perseveranza');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 21,28-32', 'Matteo', '[In quel tempo, Gesù disse ai capi dei sacerdoti e agli anziani del popolo]: «Che ve ne pare? Un uomo aveva due figli. Si rivolse al primo e disse: "Figlio, oggi va'' a lavorare nella vigna". Ed egli rispose: "Non ne ho voglia". Ma poi si pentì e vi andò. Si rivolse al secondo e disse lo stesso. Ed egli rispose: "Sì, signore". Ma non vi andò. Chi dei due ha compiuto la volontà del padre?». Risposero: «Il primo». E Gesù disse loro: «In verità io vi dico: i pubblicani e le prostitute vi passano avanti nel regno di Dio. Giovanni infatti venne a voi sulla via della giustizia, e non gli avete creduto; i pubblicani e le prostitute invece gli hanno creduto. Voi, al contrario, avete visto queste cose, ma poi non vi siete nemmeno pentiti così da credergli»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 1,47-51', 'Giovanni', 'In quel tempo, Gesù, visto Natanaèle che gli veniva incontro, disse di lui: «Ecco davvero un Israelita in cui non c''è falsità». Natanaèle gli domandò: «Come mi conosci?». Gli rispose Gesù: «Prima che Filippo ti chiamasse, io ti ho visto quando eri sotto l''albero di fichi». Gli replicò Natanaèle: «Rabbì, tu sei il Figlio di Dio, tu sei il re d''Israele!». Gli rispose Gesù: «Perché ti ho detto che ti avevo visto sotto l''albero di fichi, tu credi? Vedrai cose più grandi di queste!». Poi gli disse: «In verità, in verità io vi dico: vedrete il cielo aperto e gli angeli di Dio salire e scendere sopra il Figlio dell''uomo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,57-62', 'Matteo', 'In quel tempo, mentre camminavano per la strada, un tale disse a Gesù: «Ti seguirò dovunque tu vada». E Gesù gli rispose: «Le volpi hanno le loro tane e gli uccelli del cielo i loro nidi, ma il Figlio dell’uomo non ha dove posare il capo». A un altro disse: «Seguimi». E costui rispose: «Signore, permettimi di andare prima a seppellire mio padre». Gli replicò: «Lascia che i morti seppelliscano i loro morti; tu invece va’ e annuncia il regno di Dio». Un altro disse: «Ti seguirò, Signore; prima però lascia che io mi congedi da quelli di casa mia». Ma Gesù gli rispose: «Nessuno che mette mano all’aratro e poi si volge indietro è adatto per il regno di Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 21,33-43', 'Matteo', '[In quel tempo, Gesù disse ai capi dei sacerdoti e agli anziani del popolo]: «Ascoltate un''altra parabola: c''era un uomo, che possedeva un terreno e vi piantò una vigna. La circondò con una siepe, vi scavò una buca per il torchio e costruì una torre. La diede in affitto a dei contadini e se ne andò lontano. Quando arrivò il tempo di raccogliere i frutti, mandò i suoi servi dai contadini a ritirare il raccolto. Ma i contadini presero i servi e uno lo bastonarono, un altro lo uccisero, un altro lo lapidarono. Mandò di nuovo altri servi, più numerosi dei primi, ma li trattarono allo stesso modo. Da ultimo mandò loro il proprio figlio dicendo: "Avranno rispetto per mio figlio!". Ma i contadini, visto il figlio, dissero tra loro: "Costui è l''erede. Su, uccidiamolo e avremo noi la sua eredità!". Lo presero, lo cacciarono fuori dalla vigna e lo uccisero. Quando verrà dunque il padrone della vigna, che cosa farà a quei contadini?». Gli risposero: «Quei malvagi, li farà morire miseramente e darà in affitto la vigna ad altri contadini, che gli consegneranno i frutti a suo tempo». E Gesù disse loro: «Non avete mai letto nelle Scritture: "La pietra che i costruttori hanno scartato è diventata la pietra d''angolo; questo è stato fatto dal Signore ed è una meraviglia ai nostri occhi"? Perciò io vi dico: a voi sarà tolto il regno di Dio e sarà dato a un popolo che ne produca i frutti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 12,1-7', 'Luca', 'In quel tempo, si erano radunate migliaia di persone, al punto che si calpestavano a vicenda, e Gesù cominciò a dire anzitutto ai suoi discepoli: «Guardatevi bene dal lievito dei farisei, che è l''ipocrisia. Non c''è nulla di nascosto che non sarà svelato, né di segreto che non sarà conosciuto. Quindi ciò che avrete detto nelle tenebre sarà udito in piena luce, e ciò che avrete detto all''orecchio nelle stanze più interne sarà annunciato dalle terrazze. Dico a voi, amici miei: non abbiate paura di quelli che uccidono il corpo e dopo questo non possono fare più nulla. Vi mostrerò invece di chi dovete aver paura: temete colui che, dopo aver ucciso, ha il potere di gettare nella Geènna. Sì, ve lo dico, temete costui. Cinque passeri non si vendono forse per due soldi? Eppure nemmeno uno di essi è dimenticato davanti a Dio. Anche i capelli del vostro capo sono tutti contati. Non abbiate paura: valete più di molti passeri!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 22,15-21', 'Matteo', 'In quel tempo, i farisei se ne andarono e tennero consiglio per vedere come cogliere in fallo Gesù nei suoi discorsi. Mandarono dunque da lui i propri discepoli, con gli erodiàni, a dirgli: «Maestro, sappiamo che sei veritiero e insegni la via di Dio secondo verità. Tu non hai soggezione di alcuno, perché non guardi in faccia a nessuno. Dunque, di'' a noi il tuo parere: è lecito, o no, pagare il tributo a Cesare?». Ma Gesù, conoscendo la loro malizia, rispose: «Ipocriti, perché volete mettermi alla prova? Mostratemi la moneta del tributo». Ed essi gli presentarono un denaro. Egli domandò loro: «Questa immagine e l''iscrizione, di chi sono?». Gli risposero: «Di Cesare». Allora disse loro: «Rendete dunque a Cesare quello che è di Cesare e a Dio quello che è di Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 13,10-17', 'Luca', 'In quel tempo, Gesù stava insegnando in una sinagoga in giorno di sabato. C''era là una donna che uno spirito teneva inferma da diciotto anni; era curva e non riusciva in alcun modo a stare diritta. Gesù la vide, la chiamò a sé e le disse: «Donna, sei liberata dalla tua malattia». Impose le mani su di lei e subito quella si raddrizzò e glorificava Dio. Ma il capo della sinagoga, sdegnato perché Gesù aveva operato quella guarigione di sabato, prese la parola e disse alla folla: «Ci sono sei giorni in cui si deve lavorare; in quelli dunque venite a farvi guarire e non in giorno di sabato». Il Signore gli replicò: «Ipocriti, non è forse vero che, di sabato, ciascuno di voi slega il suo bue o l''asino dalla mangiatoia, per condurlo ad abbeverarsi? E questa figlia di Abramo, che Satana ha tenuto prigioniera per ben diciotto anni, non doveva essere liberata da questo legame nel giorno di sabato?». Quando egli diceva queste cose, tutti i suoi avversari si vergognavano, mentre la folla intera esultava per tutte le meraviglie da lui compiute');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 14,1-6', 'Luca', 'Un sabato Gesù si recò a casa di uno dei capi dei farisei per pranzare ed essi stavano a osservarlo. Ed ecco, davanti a lui vi era un uomo malato di idropisìa. Rivolgendosi ai dottori della Legge e ai farisei, Gesù disse: «È lecito o no guarire di sabato?». Ma essi tacquero. Egli lo prese per mano, lo guarì e lo congedò. Poi disse loro: «Chi di voi, se un figlio o un bue gli cade nel pozzo, non lo tirerà fuori subito in giorno di sabato?». E non potevano rispondere nulla a queste parole');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 14,1.7-11', 'Luca', 'Un sabato Gesù si recò a casa di uno dei capi dei farisei per pranzare ed essi stavano a osservarlo. Diceva agli invitati una parabola, notando come sceglievano i primi posti: «Quando sei invitato a nozze da qualcuno, non metterti al primo posto, perché non ci sia un altro invitato più degno di te, e colui che ha invitato te e lui venga a dirti: "Cédigli il posto!". Allora dovrai con vergogna occupare l''ultimo posto. Invece, quando sei invitato, va'' a metterti all''ultimo posto, perché quando viene colui che ti ha invitato ti dica: "Amico, vieni più avanti!". Allora ne avrai onore davanti a tutti i commensali. Perché chiunque si esalta sarà umiliato, e chi si umilia sarà esaltato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 16,9-15', 'Luca', '[In quel tempo, Gesù diceva ai discepoli]: «Fatevi degli amici con la ricchezza disonesta, perché, quando questa verrà a mancare, essi vi accolgano nelle dimore eterne. Chi è fedele in cose di poco conto, è fedele anche in cose importanti; e chi è disonesto in cose di poco conto, è disonesto anche in cose importanti. Se dunque non siete stati fedeli nella ricchezza disonesta, chi vi affiderà quella vera? E se non siete stati fedeli nella ricchezza altrui, chi vi darà la vostra? Nessun servitore può servire due padroni, perché o odierà l''uno e amerà l''altro, oppure si affezionerà all''uno e disprezzerà l''altro. Non potete servire Dio e la ricchezza». I farisei, che erano attaccati al denaro, ascoltavano tutte queste cose e si facevano beffe di lui. Egli disse loro: «Voi siete quelli che si ritengono giusti davanti agli uomini, ma Dio conosce i vostri cuori: ciò che fra gli uomini viene esaltato, davanti a Dio è cosa abominevole»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 17,20-25', 'Matteo', 'In quel tempo, i farisei domandarono a Gesù: «Quando verrà il regno di Dio?». Egli rispose loro: «Il regno di Dio non viene in modo da attirare l''attenzione, e nessuno dirà: "Eccolo qui", oppure: "Eccolo là". Perché, ecco, il regno di Dio è in mezzo a voi!». Disse poi ai discepoli: «Verranno giorni in cui desidererete vedere anche uno solo dei giorni del Figlio dell''uomo, ma non lo vedrete. Vi diranno: "Eccolo là", oppure: "Eccolo qui"; non andateci, non seguiteli. Perché come la folgore, guizzando, brilla da un capo all''altro del cielo, così sarà il Figlio dell''uomo nel suo giorno. Ma prima è necessario che egli soffra molto e venga rifiutato da questa generazione»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 21,34-36', 'Luca', 'In quel tempo, Gesù disse ai suoi discepoli: «State attenti a voi stessi, che i vostri cuori non si appesantiscano in dissipazioni, ubriachezze e affanni della vita e che quel giorno non vi piombi addosso all''improvviso; come un laccio infatti esso si abbatterà sopra tutti coloro che abitano sulla faccia di tutta la terra. Vegliate in ogni momento pregando, perché abbiate la forza di sfuggire a tutto ciò che sta per accadere e di comparire davanti al Figlio dell''uomo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 13,33-37', 'Marco', 'In quel tempo, Gesù disse ai suoi discepoli: «Fate attenzione, vegliate, perché non sapete quando è il momento. È come un uomo, che è partito dopo aver lasciato la propria casa e dato il potere ai suoi servi, a ciascuno il suo compito, e ha ordinato al portiere di vegliare. Vegliate dunque: voi non sapete quando il padrone di casa ritornerà, se alla sera o a mezzanotte o al canto del gallo o al mattino; fate in modo che, giungendo all''improvviso, non vi trovi addormentati. Quello che dico a voi, lo dico a tutti: vegliate!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,35-38-10,1.6-8', 'Matteo', 'In quel tempo, Gesù percorreva tutte le città e i villaggi, insegnando nelle loro sinagoghe, annunciando il vangelo del Regno e guarendo ogni malattia e ogni infermità. Vedendo le folle, ne sentì compassione, perché erano stanche e sfinite come pecore che non hanno pastore. Allora disse ai suoi discepoli: «La messe è abbondante, ma sono pochi gli operai! Pregate dunque il signore della messe, perché mandi operai nella sua messe!». Chiamati a sé i suoi dodici discepoli, diede loro potere sugli spiriti impuri per scacciarli e guarire ogni malattia e ogni infermità. E li inviò ordinando loro: «Rivolgetevi alle pecore perdute della casa d''Israele. Strada facendo, predicate, dicendo che il regno dei cieli è vicino. Guarite gli infermi, risuscitate i morti, purificate i lebbrosi, scacciate i demòni. Gratuitamente avete ricevuto, gratuitamente date»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 1,1-8', 'Marco', 'Inizio del vangelo di Gesù, Cristo, Figlio di Dio. Come sta scritto nel profeta Isaìa: «Ecco, dinanzi a te io mando il mio messaggero: egli preparerà la tua via. Voce di uno che grida nel deserto: Preparate la via del Signore, raddrizzate i suoi sentieri», vi fu Giovanni, che battezzava nel deserto e proclamava un battesimo di conversione per il perdono dei peccati. Accorrevano a lui tutta la regione della Giudea e tutti gli abitanti di Gerusalemme. E si facevano battezzare da lui nel fiume Giordano, confessando i loro peccati. Giovanni era vestito di peli di cammello, con una cintura di pelle attorno ai fianchi, e mangiava cavallette e miele selvatico. E proclamava: «Viene dopo di me colui che è più forte di me: io non sono degno di chinarmi per slegare i lacci dei suoi sandali. Io vi ho battezzato con acqua, ma egli vi battezzerà in Spirito Santo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 5,17-26', 'Luca', 'Un giorno Gesù stava insegnando. Sedevano là anche dei farisei e maestri della Legge, venuti da ogni villaggio della Galilea e della Giudea, e da Gerusalemme. E la potenza del Signore gli faceva operare guarigioni. Ed ecco, alcuni uomini, portando su un letto un uomo che era paralizzato, cercavano di farlo entrare e di metterlo davanti a lui. Non trovando da quale parte farlo entrare a causa della folla, salirono sul tetto e, attraverso le tegole, lo calarono con il lettuccio davanti a Gesù nel mezzo della stanza. Vedendo la loro fede, disse: «Uomo, ti sono perdonati i tuoi peccati». Gli scribi e i farisei cominciarono a discutere, dicendo: «Chi è costui che dice bestemmie? Chi può perdonare i peccati, se non Dio soltanto?». Ma Gesù, conosciuti i loro ragionamenti, rispose: «Perché pensate così nel vostro cuore? Che cosa è più facile: dire "Ti sono perdonati i tuoi peccati", oppure dire "Àlzati e cammina"? Ora, perché sappiate che il Figlio dell''uomo ha il potere sulla terra di perdonare i peccati, dico a te - disse al paralitico –: àlzati, prendi il tuo lettuccio e torna a casa tua». Subito egli si alzò davanti a loro, prese il lettuccio su cui era disteso e andò a casa sua, glorificando Dio. Tutti furono colti da stupore e davano gloria a Dio; pieni di timore dicevano: «Oggi abbiamo visto cose prodigiose»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 1,6-8.19-28', 'Giovanni', 'Venne un uomo mandato da Dio: il suo nome era Giovanni. Egli venne come testimone per dare testimonianza alla luce, perché tutti credessero per mezzo di lui. Non era lui la luce, ma doveva dare testimonianza alla luce. Questa è la testimonianza di Giovanni, quando i Giudei gli inviarono da Gerusalemme sacerdoti e levìti a interrogarlo: «Tu, chi sei?». Egli confessò e non negò. Confessò: «Io non sono il Cristo». Allora gli chiesero: «Chi sei, dunque? Sei tu Elia?». «Non lo sono», disse. «Sei tu il profeta?». «No», rispose. Gli dissero allora: «Chi sei? Perché possiamo dare una risposta a coloro che ci hanno mandato. Che cosa dici di te stesso?». Rispose: «Io sono voce di uno che grida nel deserto: Rendete diritta la via del Signore, come disse il profeta Isaìa». Quelli che erano stati inviati venivano dai farisei. Essi lo interrogarono e gli dissero: «Perché dunque tu battezzi, se non sei il Cristo, né Elia, né il profeta?». Giovanni rispose loro: «Io battezzo nell''acqua. In mezzo a voi sta uno che voi non conoscete, colui che viene dopo di me: a lui io non sono degno di slegare il laccio del sandalo». Questo avvenne in Betània, al di là del Giordano, dove Giovanni stava battezzando');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 7,19-23', 'Luca', '[In quel tempo, Giovanni chiamati due dei suoi discepoli] li mandò a dire al Signore: «Sei tu colui che deve venire o dobbiamo aspettare un altro?». Venuti da lui, quegli uomini dissero: «Giovanni il Battista ci ha mandati da te per domandarti: "Sei tu colui che deve venire o dobbiamo aspettare un altro?"». In quello stesso momento Gesù guarì molti da malattie, da infermità, da spiriti cattivi e donò la vista a molti ciechi. Poi diede loro questa risposta: «Andate e riferite a Giovanni ciò che avete visto e udito: i ciechi riacquistano la vista, gli zoppi camminano, i lebbrosi sono purificati, i sordi odono, i morti risuscitano, ai poveri è annunciata la buona notizia. E beato è colui che non trova in me motivo di scandalo!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,46-55', 'Luca', 'In quel tempo, Maria disse: «L''anima mia magnifica il Signore e il mio spirito esulta in Dio, mio salvatore, perché ha guardato l''umiltà della sua serva. D''ora in poi tutte le generazioni mi chiameranno beata. Grandi cose ha fatto per me l''Onnipotente e Santo è il suo nome; di generazione in generazione la sua misericordia per quelli che lo temono. Ha spiegato la potenza del suo braccio, ha disperso i superbi nei pensieri del loro cuore; ha rovesciato i potenti dai troni, ha innalzato gli umili; ha ricolmato di beni gli affamati, ha rimandato i ricchi a mani vuote. Ha soccorso Israele, suo servo, ricordandosi della sua misericordia, come aveva detto ai nostri padri, per Abramo e la sua discendenza, per sempre»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 2,22-35', 'Luca', 'Quando furono compiuti i giorni della loro purificazione rituale, secondo la legge di Mosè, [Maria e Giuseppe] portarono il bambino [Gesù] a Gerusalemme per presentarlo al Signore come è scritto nella legge del Signore: «Ogni maschio primogenito sarà sacro al Signore» e per offrire in sacrificio una coppia di tortore o due giovani colombi, come prescrive la legge del Signore. Ora a Gerusalemme c''era un uomo di nome Simeone, uomo giusto e pio, che aspettava la consolazione d''Israele, e lo Spirito Santo era su di lui. Lo Spirito Santo gli aveva preannunciato che non avrebbe visto la morte senza prima aver veduto il Cristo del Signore. Mosso dallo Spirito, si recò al tempio e, mentre i genitori vi portavano il bambino Gesù per fare ciò che la Legge prescriveva a suo riguardo, anch''egli lo accolse tra le braccia e benedisse Dio, dicendo: «Ora puoi lasciare, o Signore, che il tuo servo vada in pace, secondo la tua parola, perché i miei occhi hanno visto la tua salvezza, preparata da te davanti a tutti i popoli: luce per rivelarti alle genti e gloria del tuo popolo, Israele». Il padre e la madre di Gesù si stupivano delle cose che si dicevano di lui. Simeone li benedisse e a Maria, sua madre, disse: «Ecco, egli è qui per la caduta e la risurrezione di molti in Israele e come segno di contraddizione e anche a te una spada trafiggerà l''anima -, affinché siano svelati i pensieri di molti cuori»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 2,36-40', 'Luca', '[Maria e Giuseppe portarono il bambino a Gerusalemme per presentarlo al Signore.] C''era una profetessa, Anna, figlia di Fanuèle, della tribù di Aser. Era molto avanzata in età, aveva vissuto con il marito sette anni dopo il suo matrimonio, era poi rimasta vedova e ora aveva ottantaquattro anni. Non si allontanava mai dal tempio, servendo Dio notte e giorno con digiuni e preghiere. Sopraggiunta in quel momento, si mise anche lei a lodare Dio e parlava del bambino a quanti aspettavano la redenzione di Gerusalemme. Quando ebbero adempiuto ogni cosa secondo la legge del Signore, fecero ritorno in Galilea, alla loro città di Nàzaret. Il bambino cresceva e si fortificava, pieno di sapienza, e la grazia di Dio era su di lui');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 1,43-51', 'Giovanni', 'In quel tempo, Gesù volle partire per la Galilea; trovò Filippo e gli disse: «Seguimi!». Filippo era di Betsàida, la città di Andrea e di Pietro. Filippo trovò Natanaèle e gli disse: «Abbiamo trovato colui del quale hanno scritto Mosè, nella Legge, e i Profeti: Gesù, il figlio di Giuseppe, di Nàzaret». Natanaèle gli disse: «Da Nàzaret può venire qualcosa di buono?». Filippo gli rispose: «Vieni e vedi». Gesù intanto, visto Natanaèle che gli veniva incontro, disse di lui: «Ecco davvero un Israelita in cui non c''è falsità». Natanaèle gli domandò: «Come mi conosci?». Gli rispose Gesù: «Prima che Filippo ti chiamasse, io ti ho visto quando eri sotto l''albero di fichi». Gli replicò Natanaèle: «Rabbì, tu sei il Figlio di Dio, tu sei il re d''Israele!». Gli rispose Gesù: «Perché ti ho detto che ti avevo visto sotto l''albero di fichi, tu credi? Vedrai cose più grandi di queste!». Poi gli disse: «In verità, in verità io vi dico: vedrete il cielo aperto e gli angeli di Dio salire e scendere sopra il Figlio dell''uomo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 1,7-11', 'Marco', 'In quel tempo, Giovanni proclamava: «Viene dopo di me colui che è più forte di me: io non sono degno di chinarmi per slegare i lacci dei suoi sandali. Io vi ho battezzato con acqua, ma egli vi battezzerà in Spirito Santo». Ed ecco, in quei giorni, Gesù venne da Nàzaret di Galilea e fu battezzato nel Giordano da Giovanni. E, subito, uscendo dall''acqua, vide squarciarsi i cieli e lo Spirito discendere verso di lui come una colomba. E venne una voce dal cielo: «Tu sei il Figlio mio, l''amato: in te ho posto il mio compiacimento»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 1,21b-28', 'Marco', 'Giunsero a Cafàrnao e subito Gesù, entrato di sabato nella sinagoga, insegnava. Ed erano stupiti del suo insegnamento: egli infatti insegnava loro come uno che ha autorità, e non come gli scribi. Ed ecco, nella loro sinagoga vi era un uomo posseduto da uno spirito impuro e cominciò a gridare, dicendo: «Che vuoi da noi, Gesù Nazareno? Sei venuto a rovinarci? Io so chi tu sei: il santo di Dio!». E Gesù gli ordinò severamente: «Taci! Esci da lui!». E lo spirito impuro, straziandolo e gridando forte, uscì da lui. Tutti furono presi da timore, tanto che si chiedevano a vicenda: «Che è mai questo? Un insegnamento nuovo, dato con autorità. Comanda persino agli spiriti impuri e gli obbediscono!». La sua fama si diffuse subito dovunque, in tutta la regione della Galilea');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 3,20-21', 'Marco', 'In quel tempo, Gesù entrò in una casa e di nuovo si radunò una folla, tanto che non potevano neppure mangiare. Allora i suoi, sentito questo, uscirono per andare a prenderlo; dicevano infatti: «È fuori di sé»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 1,12-15', 'Marco', 'In quel tempo, lo Spirito sospinse Gesù nel deserto e nel deserto rimase quaranta giorni, tentato da Satana. Stava con le bestie selvatiche e gli angeli lo servivano. Dopo che Giovanni fu arrestato, Gesù andò nella Galilea, proclamando il vangelo di Dio, e diceva: «Il tempo è compiuto e il regno di Dio è vicino; convertitevi e credete nel Vangelo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 9,2-9', 'Marco', 'In quel tempo, Gesù prese con sé Pietro, Giacomo e Giovanni e li condusse su un alto monte, in disparte, loro soli. Fu trasfigurato davanti a loro e le sue vesti divennero splendenti, bianchissime: nessun lavandaio sulla terra potrebbe renderle così bianche. E apparve loro Elia con Mosè e conversavano con Gesù. Prendendo la parola, Pietro disse a Gesù: «Rabbì, è bello per noi essere qui; facciamo tre capanne, una per te, una per Mosè e una per Elia». Non sapeva infatti che cosa dire, perché erano spaventati. Venne una nube che li coprì con la sua ombra e dalla nube uscì una voce: «Questi è il Figlio mio, l''amato: ascoltatelo!». E improvvisamente, guardandosi attorno, non videro più nessuno, se non Gesù solo, con loro. Mentre scendevano dal monte, ordinò loro di non raccontare ad alcuno ciò che avevano visto, se non dopo che il Figlio dell''uomo fosse risorto dai morti. Ed essi tennero fra loro la cosa, chiedendosi che cosa volesse dire risorgere dai morti');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 2,13-25', 'Giovanni', 'Si avvicinava la Pasqua dei Giudei e Gesù salì a Gerusalemme. Trovò nel tempio gente che vendeva buoi, pecore e colombe e, là seduti, i cambiamonete. Allora fece una frusta di cordicelle e scacciò tutti fuori del tempio, con le pecore e i buoi; gettò a terra il denaro dei cambiamonete e ne rovesciò i banchi, e ai venditori di colombe disse: «Portate via di qui queste cose e non fate della casa del Padre mio un mercato!». I suoi discepoli si ricordarono che sta scritto: «Lo zelo per la tua casa mi divorerà». Allora i Giudei presero la parola e gli dissero: «Quale segno ci mostri per fare queste cose?». Rispose loro Gesù: «Distruggete questo tempio e in tre giorni lo farò risorgere». Gli dissero allora i Giudei: «Questo tempio è stato costruito in quarantasei anni e tu in tre giorni lo farai risorgere?». Ma egli parlava del tempio del suo corpo. Quando poi fu risuscitato dai morti, i suoi discepoli si ricordarono che aveva detto questo, e credettero alla Scrittura e alla parola detta da Gesù. Mentre era a Gerusalemme per la Pasqua, durante la festa, molti, vedendo i segni che egli compiva, credettero nel suo nome. Ma lui, Gesù, non si fidava di loro, perché conosceva tutti e non aveva bisogno che alcuno desse testimonianza sull''uomo. Egli infatti conosceva quello che c''è nell''uomo');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 3,14-21', 'Giovanni', 'In quel tempo, Gesù disse a Nicodèmo: «Come Mosè innalzò il serpente nel deserto, così bisogna che sia innalzato il Figlio dell''uomo, perché chiunque crede in lui abbia la vita eterna. Dio infatti ha tanto amato il mondo da dare il Figlio unigenito perché chiunque crede in lui non vada perduto, ma abbia la vita eterna. Dio, infatti, non ha mandato il Figlio nel mondo per condannare il mondo, ma perché il mondo sia salvato per mezzo di lui. Chi crede in lui non è condannato; ma chi non crede è già stato condannato, perché non ha creduto nel nome dell''unigenito Figlio di Dio. E il giudizio è questo: la luce è venuta nel mondo, ma gli uomini hanno amato più le tenebre che la luce, perché le loro opere erano malvagie. Chiunque infatti fa il male, odia la luce, e non viene alla luce perché le sue opere non vengano riprovate. Invece chi fa la verità viene verso la luce, perché appaia chiaramente che le sue opere sono state fatte in Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 12,20-33', 'Giovanni', 'In quel tempo, tra quelli che erano saliti per il culto durante la festa c''erano anche alcuni Greci. Questi si avvicinarono a Filippo, che era di Betsàida di Galilea, e gli domandarono: «Signore, vogliamo vedere Gesù». Filippo andò a dirlo ad Andrea, e poi Andrea e Filippo andarono a dirlo a Gesù. Gesù rispose loro: «È venuta l''ora che il Figlio dell''uomo sia glorificato. In verità, in verità io vi dico: se il chicco di grano, caduto in terra, non muore, rimane solo; se invece muore, produce molto frutto. Chi ama la propria vita, la perde e chi odia la propria vita in questo mondo, la conserverà per la vita eterna. Se uno mi vuole servire, mi segua, e dove sono io, là sarà anche il mio servitore. Se uno serve me, il Padre lo onorerà. Adesso l''anima mia è turbata; che cosa dirò? Padre, salvami da quest''ora? Ma proprio per questo sono giunto a quest''ora! Padre, glorifica il tuo nome». Venne allora una voce dal cielo: «L''ho glorificato e lo glorificherò ancora!». La folla, che era presente e aveva udito, diceva che era stato un tuono. Altri dicevano: «Un angelo gli ha parlato». Disse Gesù: «Questa voce non è venuta per me, ma per voi. Ora è il giudizio di questo mondo; ora il principe di questo mondo sarà gettato fuori. E io, quando sarò innalzato da terra, attirerò tutti a me». Diceva questo per indicare di quale morte doveva morire');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 16,1-7', 'Marco', 'Passato il sabato, Maria di Màgdala, Maria madre di Giacomo e Salome comprarono oli aromatici per andare a ungerlo. Di buon mattino, il primo giorno della settimana, vennero al sepolcro al levare del sole. Dicevano tra loro: «Chi ci farà rotolare via la pietra dall''ingresso del sepolcro?».  Alzando lo sguardo, osservarono che la pietra era già stata fatta rotolare, benché fosse molto grande. Entrate nel sepolcro, videro un giovane, seduto sulla destra, vestito d''una veste bianca, ed ebbero paura. Ma egli disse loro: «Non abbiate paura! Voi cercate Gesù Nazareno, il crocifisso. È risorto, non è qui. Ecco il luogo dove l''avevano posto. Ma andate, dite ai suoi discepoli e a Pietro: "Egli vi precede in Galilea. Là lo vedrete, come vi ha detto"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 21,20.25', 'Giovanni', 'Pietro dunque, come lo vide, disse a Gesù: «Signore, che cosa sarà di lui?». Gesù gli rispose: «Se voglio che egli rimanga finché io venga, a te che importa? Tu seguimi». Si diffuse perciò tra i fratelli la voce che quel discepolo non sarebbe morto. Gesù però non gli aveva detto che non sarebbe morto, ma: «Se voglio che egli rimanga finché io venga, a te che importa?». Questi è il discepolo che testimonia queste cose e le ha scritte, e noi sappiamo che la sua testimonianza è vera. Vi sono ancora molte altre cose compiute da Gesù che, se fossero scritte una per una, penso che il mondo stesso non basterebbe a contenere i libri che si dovrebbero scrivere!');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 15,26-27;16,12-15', 'Giovanni', 'In quel tempo, Gesù disse ai discepoli: «Quando verrà il Paràclito, che io vi manderò dal Padre, lo Spirito della verità che procede dal Padre, egli darà testimonianza di me; e anche voi date testimonianza, perché siete con me fin dal principio. Molte cose ho ancora da dirvi, ma per il momento non siete capaci di portarne il peso. Quando verrà lui, lo Spirito della verità, vi guiderà a tutta la verità, perché non parlerà da se stesso, ma dirà tutto ciò che avrà udito e vi annuncerà le cose future. Egli mi glorificherà, perché prenderà da quel che è mio e ve lo annuncerà. Tutto quello che il Padre possiede è mio; per questo ho detto che prenderà da quel che è mio e ve lo annuncerà»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 10,32-45', 'Marco', 'Mentre erano sulla strada per salire a Gerusalemme, Gesù camminava davanti a loro ed essi erano sgomenti; coloro che lo seguivano erano impauriti. Presi di nuovo in disparte i Dodici, si mise a dire loro quello che stava per accadergli: «Ecco, noi saliamo a Gerusalemme e il Figlio dell''uomo sarà consegnato ai capi dei sacerdoti e agli scribi; lo condanneranno a morte e lo consegneranno ai pagani, lo derideranno, gli sputeranno addosso, lo flagelleranno e lo uccideranno, e dopo tre giorni risorgerà». Gli si avvicinarono Giacomo e Giovanni, i figli di Zebedeo, dicendogli: «Maestro, vogliamo che tu faccia per noi quello che ti chiederemo». Egli disse loro: «Che cosa volete che io faccia per voi?». Gli risposero: «Concedici di sedere, nella tua gloria, uno alla tua destra e uno alla tua sinistra». Gesù disse loro: «Voi non sapete quello che chiedete. Potete bere il calice che io bevo, o essere battezzati nel battesimo in cui io sono battezzato?». Gli risposero: «Lo possiamo». E Gesù disse loro: «Il calice che io bevo anche voi lo berrete, e nel battesimo in cui io sono battezzato anche voi sarete battezzati. Ma sedere alla mia destra o alla mia sinistra non sta a me concederlo; è per coloro per i quali è stato preparato». Gli altri dieci, avendo sentito, cominciarono a indignarsi con Giacomo e Giovanni. Allora Gesù li chiamò a sé e disse loro: «Voi sapete che coloro i quali sono considerati i governanti delle nazioni dominano su di esse e i loro capi le opprimono. Tra voi però non è così; ma chi vuole diventare grande tra voi sarà vostro servitore, e chi vuole essere il primo tra voi sarà schiavo di tutti. Anche il Figlio dell''uomo infatti non è venuto per farsi servire, ma per servire e dare la propria vita in riscatto per molti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 10,46-52', 'Marco', 'E giunsero a Gerico. Mentre partiva da Gerico insieme ai suoi discepoli e a molta folla, il figlio di Timeo, Bartimeo, che era cieco, sedeva lungo la strada a mendicare. Sentendo che era Gesù Nazareno, cominciò a gridare e a dire: «Figlio di Davide, Gesù, abbi pietà di me!». Molti lo rimproveravano perché tacesse, ma egli gridava ancora più forte: «Figlio di Davide, abbi pietà di me!». Gesù si fermò e disse: «Chiamatelo!». Chiamarono il cieco, dicendogli: «Coraggio! Àlzati, ti chiama!». Egli, gettato via il suo mantello, balzò in piedi e venne da Gesù. Allora Gesù gli disse: «Che cosa vuoi che io faccia per te?». E il cieco gli rispose: «Rabbunì, che io veda di nuovo!». E Gesù gli disse: «Va'', la tua fede ti ha salvato». E subito vide di nuovo e lo seguiva lungo la strada');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 11,11-25', 'Marco', 'Ed entrò a Gerusalemme, nel tempio. E dopo aver guardato ogni cosa attorno, essendo ormai l''ora tarda, uscì con i Dodici verso Betània. La mattina seguente, mentre uscivano da Betània, ebbe fame. Avendo visto da lontano un albero di fichi che aveva delle foglie, si avvicinò per vedere se per caso vi trovasse qualcosa ma, quando vi giunse vicino, non trovò altro che foglie. Non era infatti la stagione dei fichi. Rivolto all''albero, disse: «Nessuno mai più in eterno mangi i tuoi frutti!». E i suoi discepoli l''udirono. Giunsero a Gerusalemme. Entrato nel tempio, si mise a scacciare quelli che vendevano e quelli che compravano nel tempio; rovesciò i tavoli dei cambiamonete e le sedie dei venditori di colombe e non permetteva che si trasportassero cose attraverso il tempio. E insegnava loro dicendo: «Non sta forse scritto: La mia casa sarà chiamata casa di preghiera per tutte le nazioni? Voi invece ne avete fatto un covo di ladri». Lo udirono i capi dei sacerdoti e gli scribi e cercavano il modo di farlo morire. Avevano infatti paura di lui, perché tutta la folla era stupita del suo insegnamento. Quando venne la sera, uscirono fuori dalla città. La mattina seguente, passando, videro l''albero di fichi seccato fin dalle radici. Pietro si ricordò e gli disse: «Maestro, guarda: l''albero di fichi che hai maledetto è seccato». Rispose loro Gesù: «Abbiate fede in Dio! In verità io vi dico: se uno dicesse a questo monte: "Lèvati e gèttati nel mare", senza dubitare in cuor suo, ma credendo che quanto dice avviene, ciò gli avverrà. Per questo vi dico: tutto quello che chiederete nella preghiera, abbiate fede di averlo ottenuto e vi accadrà. Quando vi mettete a pregare, se avete qualcosa contro qualcuno, perdonate, perché anche il Padre vostro che è nei cieli perdoni a voi le vostre colpe»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 11,27-33', 'Marco', 'Andarono di nuovo a Gerusalemme. E, mentre egli camminava nel tempio, vennero da lui i capi dei sacerdoti, gli scribi e gli anziani e gli dissero: «Con quale autorità fai queste cose? O chi ti ha dato l''autorità di farle?». Ma Gesù disse loro: «Vi farò una sola domanda. Se mi rispondete, vi dirò con quale autorità faccio questo. Il battesimo di Giovanni veniva dal cielo o dagli uomini? Rispondetemi». Essi discutevano fra loro dicendo: «Se diciamo: "Dal cielo", risponderà: "Perché allora non gli avete creduto?". Diciamo dunque: "Dagli uomini"?». Ma temevano la folla, perché tutti ritenevano che Giovanni fosse veramente un profeta. Rispondendo a Gesù dissero: «Non lo sappiamo». E Gesù disse loro: «Neanche io vi dico con quale autorità faccio queste cose»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 14,12-16.22-26', 'Marco', 'Il primo giorno degli Azzimi, quando si immolava la Pasqua, i suoi discepoli gli dissero: «Dove vuoi che andiamo a preparare, perché tu possa mangiare la Pasqua?». Allora mandò due dei suoi discepoli, dicendo loro: «Andate in città e vi verrà incontro un uomo con una brocca d''acqua; seguitelo. Là dove entrerà, dite al padrone di casa: "Il Maestro dice: Dov''è la mia stanza, in cui io possa mangiare la Pasqua con i miei discepoli?". Egli vi mostrerà al piano superiore una grande sala, arredata e già pronta; lì preparate la cena per noi». I discepoli andarono e, entrati in città, trovarono come aveva detto loro e prepararono la Pasqua. E, mentre mangiavano, prese il pane e recitò la benedizione, lo spezzò e lo diede loro, dicendo: «Prendete, questo è il mio corpo». Poi prese un calice e rese grazie, lo diede loro e ne bevvero tutti. E disse loro: «Questo è il mio sangue dell''alleanza, che è versato per molti. In verità io vi dico che non berrò mai più del frutto della vite fino al giorno in cui lo berrò nuovo, nel regno di Dio». Dopo aver cantato l''inno, uscirono verso il monte degli Ulivi');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 19,31-37', 'Giovanni', 'Era il giorno della Parasceve e i Giudei, perché i corpi non rimanessero sulla croce durante il sabato - era infatti un giorno solenne quel sabato -, chiesero a Pilato che fossero spezzate loro le gambe e fossero portati via. Vennero dunque i soldati e spezzarono le gambe all''uno e all''altro che erano stati crocifissi insieme con lui. Venuti però da Gesù, vedendo che era già morto, non gli spezzarono le gambe, ma uno dei soldati con una lancia gli colpì il fianco, e subito ne uscì sangue e acqua. Chi ha visto ne dà testimonianza e la sua testimonianza è vera; egli sa che dice il vero, perché anche voi crediate. Questo infatti avvenne perché si compisse la Scrittura: Non gli sarà spezzato alcun osso. E un altro passo della Scrittura dice ancora: Volgeranno lo sguardo a colui che hanno trafitto');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,24-35', 'Giovanni', 'Quando dunque la folla vide che Gesù non era più là e nemmeno i suoi discepoli, salì sulle barche e si diresse alla volta di Cafàrnao alla ricerca di Gesù. Lo trovarono di là dal mare e gli dissero: «Rabbì, quando sei venuto qua?». Gesù rispose loro: «In verità, in verità io vi dico: voi mi cercate non perché avete visto dei segni, ma perché avete mangiato di quei pani e vi siete saziati. Datevi da fare non per il cibo che non dura, ma per il cibo che rimane per la vita eterna e che il Figlio dell''uomo vi darà. Perché su di lui il Padre, Dio, ha messo il suo sigillo». Gli dissero allora: «Che cosa dobbiamo compiere per fare le opere di Dio?». Gesù rispose loro: «Questa è l''opera di Dio: che crediate in colui che egli ha mandato». Allora gli dissero: «Quale segno tu compi perché vediamo e ti crediamo? Quale opera fai? I nostri padri hanno mangiato la manna nel deserto, come sta scritto: Diede loro da mangiare un pane dal cielo». Rispose loro Gesù: «In verità, in verità io vi dico: non è Mosè che vi ha dato il pane dal cielo, ma è il Padre mio che vi dà il pane dal cielo, quello vero. Infatti il pane di Dio è colui che discende dal cielo e dà la vita al mondo». Allora gli dissero: «Signore, dacci sempre questo pane». Gesù rispose loro: «Io sono il pane della vita; chi viene a me non avrà fame e chi crede in me non avrà sete, mai!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 6,41-51', 'Giovanni', 'Allora i Giudei si misero a mormorare contro di lui perché aveva detto: «Io sono il pane disceso dal cielo». E dicevano: «Costui non è forse Gesù, il figlio di Giuseppe? Di lui non conosciamo il padre e la madre? Come dunque può dire: "Sono disceso dal cielo"?». Gesù rispose loro: «Non mormorate tra voi. Nessuno può venire a me, se non lo attira il Padre che mi ha mandato; e io lo risusciterò nell''ultimo giorno. Sta scritto nei profeti: E tutti saranno istruiti da Dio. Chiunque ha ascoltato il Padre e ha imparato da lui, viene a me. Non perché qualcuno abbia visto il Padre; solo colui che viene da Dio ha visto il Padre. In verità, in verità io vi dico: chi crede ha la vita eterna. Io sono il pane della vita. I vostri padri hanno mangiato la manna nel deserto e sono morti; questo è il pane che discende dal cielo, perché chi ne mangia non muoia. Io sono il pane vivo, disceso dal cielo. Se uno mangia di questo pane vivrà in eterno e il pane che io darò è la mia carne per la vita del mondo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 7,1-8.14-15.21-23', 'Marco', 'Si riunirono attorno a lui i farisei e alcuni degli scribi, venuti da Gerusalemme. Avendo visto che alcuni dei suoi discepoli prendevano cibo con mani impure, cioè non lavate - i farisei infatti e tutti i Giudei non mangiano se non si sono lavati accuratamente le mani, attenendosi alla tradizione degli antichi e, tornando dal mercato, non mangiano senza aver fatto le abluzioni, e osservano molte altre cose per tradizione, come lavature di bicchieri, di stoviglie, di oggetti di rame e di letti -, quei farisei e scribi lo interrogarono: «Perché i tuoi discepoli non si comportano secondo la tradizione degli antichi, ma prendono cibo con mani impure?». Ed egli rispose loro: «Bene ha profetato Isaia di voi, ipocriti, come sta scritto: Questo popolo mi onora con le labbra, ma il suo cuore è lontano da me. Invano mi rendono culto, insegnando dottrine che sono precetti di uomini. Trascurando il comandamento di Dio, voi osservate la tradizione degli uomini». Chiamata di nuovo la folla, diceva loro: «Ascoltatemi tutti e comprendete bene! Non c''è nulla fuori dell''uomo che, entrando in lui, possa renderlo impuro. Ma sono le cose che escono dall''uomo a renderlo impuro dal di dentro infatti, cioè dal cuore degli uomini, escono i propositi di male: impurità, furti, omicidi, adultèri, avidità, malvagità, inganno, dissolutezza, invidia, calunnia, superbia, stoltezza. Tutte queste cose cattive vengono fuori dall''interno e rendono impuro l''uomo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 8,27-35', 'Marco', 'Poi Gesù partì con i suoi discepoli verso i villaggi intorno a Cesarèa di Filippo, e per la strada interrogava i suoi discepoli dicendo: «La gente, chi dice che io sia?». Ed essi gli risposero: «Giovanni il Battista; altri dicono Elia e altri uno dei profeti». Ed egli domandava loro: «Ma voi, chi dite che io sia?». Pietro gli rispose: «Tu sei il Cristo». E ordinò loro severamente di non parlare di lui ad alcuno. E cominciò a insegnare loro che il Figlio dell''uomo doveva soffrire molto ed essere rifiutato dagli anziani, dai capi dei sacerdoti e dagli scribi, venire ucciso e, dopo tre giorni, risorgere. Faceva questo discorso apertamente. Pietro lo prese in disparte e si mise a rimproverarlo. Ma egli, voltatosi e guardando i suoi discepoli, rimproverò Pietro e disse: «Va'' dietro a me, Satana! Perché tu non pensi secondo Dio, ma secondo gli uomini». Convocata la folla insieme ai suoi discepoli, disse loro: «Se qualcuno vuol venire dietro a me, rinneghi se stesso, prenda la sua croce e mi segua. Perché chi vuole salvare la propria vita, la perderà; ma chi perderà la propria vita per causa mia e del Vangelo, la salverà»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 9,38-43.45.47-48', 'Marco', 'In quel tempo Giovanni gli disse: «Maestro, abbiamo visto uno che scacciava demòni nel tuo nome e volevamo impedirglielo, perché non ci seguiva». Ma Gesù disse: «Non glielo impedite, perché non c''è nessuno che faccia un miracolo nel mio nome e subito possa parlare male di me: chi non è contro di noi è per noi. Chiunque infatti vi darà da bere un bicchiere d''acqua nel mio nome perché siete di Cristo, in verità io vi dico, non perderà la sua ricompensa. Chi scandalizzerà uno solo di questi piccoli che credono in me, è molto meglio per lui che gli venga messa al collo una macina da mulino e sia gettato nel mare. Se la tua mano ti è motivo di scandalo, tagliala: è meglio per te entrare nella vita con una mano sola, anziché con le due mani andare nella Geènna, nel fuoco inestinguibile. E se il tuo piede ti è motivo di scandalo, taglialo: è meglio per te entrare nella vita con un piede solo, anziché con i due piedi essere gettato nella Geènna. E se il tuo occhio ti è motivo di scandalo, gettalo via: è meglio per te entrare nel regno di Dio con un occhio solo, anziché con due occhi essere gettato nella Geènna, dove il loro verme non muore e il fuoco non si estingue»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 10,13-16', 'Luca', 'In quel tempo diceva Gesù ai discepoli: «Guai a te, Corazìn, guai a te, Betsàida! Perché, se a Tiro e a Sidone fossero avvenuti i prodigi che avvennero in mezzo a voi, già da tempo, vestite di sacco e cosparse di cenere, si sarebbero convertite. Ebbene, nel giudizio, Tiro e Sidone saranno trattate meno duramente di voi. E tu, Cafàrnao, sarai forse innalzata fino al cielo? Fino agli inferi precipiterai! Chi ascolta voi ascolta me, chi disprezza voi disprezza me. E chi disprezza me disprezza colui che mi ha mandato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 10,2-16', 'Marco', 'Alcuni farisei si avvicinarono e, per metterlo alla prova, gli domandavano se è lecito a un marito ripudiare la propria moglie. Ma egli rispose loro: «Che cosa vi ha ordinato Mosè?». Dissero: «Mosè ha permesso di scrivere un atto di ripudio e di ripudiarla». Gesù disse loro: «Per la durezza del vostro cuore egli scrisse per voi questa norma. Ma dall''inizio della creazione li fece maschio e femmina; per questo l''uomo lascerà suo padre e sua madre e si unirà a sua moglie e i due diventeranno una carne sola. Così non sono più due, ma una sola carne. Dunque l''uomo non divida quello che Dio ha congiunto». A casa, i discepoli lo interrogavano di nuovo su questo argomento. E disse loro: «Chi ripudia la propria moglie e ne sposa un''altra, commette adulterio verso di lei; e se lei, ripudiato il marito, ne sposa un altro, commette adulterio». Gli presentavano dei bambini perché li toccasse, ma i discepoli li rimproverarono. Gesù, al vedere questo, s''indignò e disse loro: «Lasciate che i bambini vengano a me, non glielo impedite: a chi è come loro infatti appartiene il regno di Dio. In verità io vi dico: chi non accoglie il regno di Dio come lo accoglie un bambino, non entrerà in esso». E, prendendoli tra le braccia, li benediceva, imponendo le mani su di loro');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 10,17-30', 'Marco', 'Mentre andava per la strada, un tale gli corse incontro e, gettandosi in ginocchio davanti a lui, gli domandò: «Maestro buono, che cosa devo fare per avere in eredità la vita eterna?». Gesù gli disse: «Perché mi chiami buono? Nessuno è buono, se non Dio solo. Tu conosci i comandamenti: Non uccidere, non commettere adulterio, non rubare, non testimoniare il falso, non frodare, onora tuo padre e tua madre». Egli allora gli disse: «Maestro, tutte queste cose le ho osservate fin dalla mia giovinezza». Allora Gesù fissò lo sguardo su di lui, lo amò e gli disse: «Una cosa sola ti manca: va'', vendi quello che hai e dallo ai poveri, e avrai un tesoro in cielo; e vieni! Seguimi!». Ma a queste parole egli si fece scuro in volto e se ne andò rattristato; possedeva infatti molti beni. Gesù, volgendo lo sguardo attorno, disse ai suoi discepoli: «Quanto è difficile, per quelli che possiedono ricchezze, entrare nel regno di Dio!». I discepoli erano sconcertati dalle sue parole; ma Gesù riprese e disse loro: «Figli, quanto è difficile entrare nel regno di Dio! È più facile che un cammello passi per la cruna di un ago, che un ricco entri nel regno di Dio». Essi, ancora più stupiti, dicevano tra loro: «E chi può essere salvato?». Ma Gesù, guardandoli in faccia, disse: «Impossibile agli uomini, ma non a Dio! Perché tutto è possibile a Dio». Pietro allora prese a dirgli: «Ecco, noi abbiamo lasciato tutto e ti abbiamo seguito». Gesù gli rispose: «In verità io vi dico: non c''è nessuno che abbia lasciato casa o fratelli o sorelle o madre o padre o figli o campi per causa mia e per causa del Vangelo, che non riceva già ora, in questo tempo, cento volte tanto in case e fratelli e sorelle e madri e figli e campi, insieme a persecuzioni, e la vita eterna nel tempo che verrà»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 10,35-45', 'Marco', 'Gli si avvicinarono [a Gesù] Giacomo e Giovanni, i figli di Zebedeo, dicendogli: «Maestro, vogliamo che tu faccia per noi quello che ti chiederemo». Egli disse loro: «Che cosa volete che io faccia per voi?». Gli risposero: «Concedici di sedere, nella tua gloria, uno alla tua destra e uno alla tua sinistra». Gesù disse loro: «Voi non sapete quello che chiedete. Potete bere il calice che io bevo, o essere battezzati nel battesimo in cui io sono battezzato?». Gli risposero: «Lo possiamo». E Gesù disse loro: «Il calice che io bevo anche voi lo berrete, e nel battesimo in cui io sono battezzato anche voi sarete battezzati. Ma sedere alla mia destra o alla mia sinistra non sta a me concederlo; è per coloro per i quali è stato preparato». Gli altri dieci, avendo sentito, cominciarono a indignarsi con Giacomo e Giovanni. Allora Gesù li chiamò a sé e disse loro: «Voi sapete che coloro i quali sono considerati i governanti delle nazioni dominano su di esse e i loro capi le opprimono. Tra voi però non è così; ma chi vuole diventare grande tra voi sarà vostro servitore, e chi vuole essere il primo tra voi sarà schiavo di tutti. Anche il Figlio dell''uomo infatti non è venuto per farsi servire, ma per servire e dare la propria vita in riscatto per molti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 13,24-32', 'Marco', '[In quel tempo Gesù disse ai suoi discepoli]: «In quei giorni, dopo quella tribolazione, il sole si oscurerà, la luna non darà più la sua luce, le stelle cadranno dal cielo e le potenze che sono nei cieli saranno sconvolte. Allora vedranno il Figlio dell''uomo venire sulle nubi con grande potenza e gloria. Egli manderà gli angeli e radunerà i suoi eletti dai quattro venti, dall''estremità della terra fino all''estremità del cielo. Dalla pianta di fico imparate la parabola: quando ormai il suo ramo diventa tenero e spuntano le foglie, sapete che l''estate è vicina. Così anche voi: quando vedrete accadere queste cose, sappiate che egli è vicino, è alle porte. In verità io vi dico: non passerà questa generazione prima che tutto questo avvenga. Il cielo e la terra passeranno, ma le mie parole non passeranno. Quanto però a quel giorno o a quell''ora, nessuno lo sa, né gli angeli nel cielo né il Figlio, eccetto il Padre. Fate attenzione, vegliate, perché non sapete quando è il momento. È come un uomo, che è partito dopo aver lasciato la propria casa e dato il potere ai suoi servi, a ciascuno il suo compito, e ha ordinato al portiere di vegliare»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 18,33b-37', 'Giovanni', 'Pilato allora rientrò nel pretorio, fece chiamare Gesù e gli disse: «Sei tu il re dei Giudei?». Gesù rispose: «Dici questo da te, oppure altri ti hanno parlato di me?». Pilato disse: «Sono forse io Giudeo? La tua gente e i capi dei sacerdoti ti hanno consegnato a me. Che cosa hai fatto?». Rispose Gesù: «Il mio regno non è di questo mondo; se il mio regno fosse di questo mondo, i miei servitori avrebbero combattuto perché non fossi consegnato ai Giudei; ma il mio regno non è di quaggiù». Allora Pilato gli disse: «Dunque tu sei re?». Rispose Gesù: «Tu lo dici: io sono re. Per questo io sono nato e per questo sono venuto nel mondo: per dare testimonianza alla verità. Chiunque è dalla verità, ascolta la mia voce»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 21,25-28.34-36', 'Luca', 'In quel tempo, Gesù disse ai discepoli: «Vi saranno segni nel sole, nella luna e nelle stelle, e sulla terra angoscia di popoli in ansia per il fragore del mare e dei flutti, mentre gli uomini moriranno per la paura e per l''attesa di ciò che dovrà accadere sulla terra. Le potenze dei cieli infatti saranno sconvolte. Allora vedranno il Figlio dell''uomo venire su una nube con grande potenza e gloria. Quando cominceranno ad accadere queste cose, risollevatevi e alzate il capo, perché la vostra liberazione è vicina. State attenti a voi stessi, che i vostri cuori non si appesantiscano in dissipazioni, ubriachezze e affanni della vita e che quel giorno non vi piombi addosso all''improvviso; come un laccio infatti esso si abbatterà sopra tutti coloro che abitano sulla faccia di tutta la terra. Vegliate in ogni momento pregando, perché abbiate la forza di sfuggire a tutto ciò che sta per accadere e di comparire davanti al Figlio dell''uomo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 3,1-6', 'Luca', 'Nell''anno quindicesimo dell''impero di Tiberio Cesare, mentre Ponzio Pilato era governatore della Giudea, Erode tetrarca della Galilea, e Filippo, suo fratello, tetrarca dell''Iturea e della Traconìtide, e Lisània tetrarca dell''Abilene, sotto i sommi sacerdoti Anna e Caifa, la parola di Dio venne su Giovanni, figlio di Zaccaria, nel deserto. Egli percorse tutta la regione del Giordano, predicando un battesimo di conversione per il perdono dei peccati, com''è scritto nel libro degli oracoli del profeta Isaia: Voce di uno che grida nel deserto: Preparate la via del Signore, raddrizzate i suoi sentieri! Ogni burrone sarà riempito, ogni monte e ogni colle sarà abbassato; le vie tortuose diverranno diritte e quelle impervie, spianate. Ogni uomo vedrà la salvezza di Dio!');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 3,10-18', 'Luca', 'Le folle interrogavano Giovanni: «Che cosa dobbiamo fare?». Rispondeva loro: «Chi ha due tuniche ne dia a chi non ne ha, e chi ha da mangiare faccia altrettanto». Vennero anche dei pubblicani a farsi battezzare e gli chiesero: «Maestro, che cosa dobbiamo fare?». Ed egli disse loro: «Non esigete nulla di più di quanto vi è stato fissato». Lo interrogavano anche alcuni soldati: «E noi, che cosa dobbiamo fare?». Rispose loro: «Non maltrattate e non estorcete niente a nessuno; accontentatevi delle vostre paghe». Poiché il popolo era in attesa e tutti, riguardo a Giovanni, si domandavano in cuor loro se non fosse lui il Cristo, Giovanni rispose a tutti dicendo: «Io vi battezzo con acqua; ma viene colui che è più forte di me, a cui non sono degno di slegare i lacci dei sandali. Egli vi battezzerà in Spirito Santo e fuoco. Tiene in mano la pala per pulire la sua aia e per raccogliere il frumento nel suo granaio; ma brucerà la paglia con un fuoco inestinguibile». Con molte altre esortazioni Giovanni evangelizzava il popolo');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 7,24-30', 'Luca', 'Quando gli inviati di Giovanni furono partiti, Gesù si mise a parlare di Giovanni alle folle: «Che cosa siete andati a vedere nel deserto? Una canna sbattuta dal vento? Allora, che cosa siete andati a vedere? Un uomo vestito con abiti di lusso? Ecco, quelli che portano vesti sontuose e vivono nel lusso stanno nei palazzi dei re. Ebbene, che cosa siete andati a vedere? Un profeta? Sì, io vi dico, anzi, più che un profeta. Egli è colui del quale sta scritto: Ecco, dinanzi a te mando il mio messaggero, davanti a te egli preparerà la tua via. Io vi dico: fra i nati da donna non vi è alcuno più grande di Giovanni, ma il più piccolo nel regno di Dio è più grande di lui. Tutto il popolo che lo ascoltava, e anche i pubblicani, ricevendo il battesimo di Giovanni, hanno riconosciuto che Dio è giusto. Ma i farisei e i dottori della Legge, non facendosi battezzare da lui, hanno reso vano il disegno di Dio su di loro»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 3,15-16.21-22', 'Luca', 'Poiché il popolo era in attesa e tutti, riguardo a Giovanni, si domandavano in cuor loro se non fosse lui il Cristo, Giovanni rispose a tutti dicendo: «Io vi battezzo con acqua; ma viene colui che è più forte di me, a cui non sono degno di slegare i lacci dei sandali. Egli vi battezzerà in Spirito Santo e fuoco». Ed ecco, mentre tutto il popolo veniva battezzato e Gesù, ricevuto anche lui il battesimo, stava in preghiera, il cielo si aprì e discese sopra di lui lo Spirito Santo in forma corporea, come una colomba, e venne una voce dal cielo: «Tu sei il Figlio mio, l''amato: in te ho posto il mio compiacimento»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 2,1-11', 'Giovanni', 'Il terzo giorno vi fu una festa di nozze a Cana di Galilea e c''era la madre di Gesù. Fu invitato alle nozze anche Gesù con i suoi discepoli. Venuto a mancare il vino, la madre di Gesù gli disse: «Non hanno vino». E Gesù le rispose: «Donna, che vuoi da me? Non è ancora giunta la mia ora». Sua madre disse ai servitori: «Qualsiasi cosa vi dica, fatela». Vi erano là sei anfore di pietra per la purificazione rituale dei Giudei, contenenti ciascuna da ottanta a centoventi litri. E Gesù disse loro: «Riempite d''acqua le anfore»; e le riempirono fino all''orlo. Disse loro di nuovo: «Ora prendetene e portatene a colui che dirige il banchetto». Ed essi gliene portarono. Come ebbe assaggiato l''acqua diventata vino, colui che dirigeva il banchetto - il quale non sapeva da dove venisse, ma lo sapevano i servitori che avevano preso l''acqua - chiamò lo sposo e gli disse: «Tutti mettono in tavola il vino buono all''inizio e, quando si è già bevuto molto, quello meno buono. Tu invece hai tenuto da parte il vino buono finora». Questo, a Cana di Galilea, fu l''inizio dei segni compiuti da Gesù; egli manifestò la sua gloria e i suoi discepoli credettero in lui. Dopo questo fatto scese a Cafàrnao, insieme a sua madre, ai suoi fratelli e ai suoi discepoli. Là rimasero pochi giorni');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,1-4;4,14-21', 'Luca', 'Poiché molti hanno cercato di raccontare con ordine gli avvenimenti che si sono compiuti in mezzo a noi, come ce li hanno trasmessi coloro che ne furono testimoni oculari fin da principio e divennero ministri della Parola, così anch''io ho deciso di fare ricerche accurate su ogni circostanza, fin dagli inizi, e di scriverne un resoconto ordinato per te, illustre Teòfilo, in modo che tu possa renderti conto della solidità degli insegnamenti che hai ricevuto. In quel tempo, Gesù ritornò in Galilea con la potenza dello Spirito e la sua fama si diffuse in tutta la regione. Insegnava nelle loro sinagoghe e gli rendevano lode. Venne a Nàzaret, dove era cresciuto, e secondo il suo solito, di sabato, entrò nella sinagoga e si alzò a leggere. Gli fu dato il rotolo del profeta Isaia; aprì il rotolo e trovò il passo dove era scritto: Lo Spirito del Signore è sopra di me; per questo mi ha consacrato con l''unzione e mi ha mandato a portare ai poveri il lieto annuncio, a proclamare ai prigionieri la liberazione e ai ciechi la vista; a rimettere in libertà gli oppressi, a proclamare l''anno di grazia del Signore. Riavvolse il rotolo, lo riconsegnò all''inserviente e sedette. Nella sinagoga, gli occhi di tutti erano fissi su di lui. Allora cominciò a dire loro: «Oggi si è compiuta questa Scrittura che voi avete ascoltato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 9,2,13', 'Marco', 'Sei giorni dopo, Gesù prese con sé Pietro, Giacomo e Giovanni e li condusse su un alto monte, in disparte, loro soli. Fu trasfigurato davanti a loro e le sue vesti divennero splendenti, bianchissime: nessun lavandaio sulla terra potrebbe renderle così bianche. E apparve loro Elia con Mosè e conversavano con Gesù. Prendendo la parola, Pietro disse a Gesù: «Rabbì, è bello per noi essere qui; facciamo tre capanne, una per te, una per Mosè e una per Elia». Non sapeva infatti che cosa dire, perché erano spaventati. Venne una nube che li coprì con la sua ombra e dalla nube uscì una voce: «Questi è il Figlio mio, l''amato: ascoltatelo!». E improvvisamente, guardandosi attorno, non videro più nessuno, se non Gesù solo, con loro. Mentre scendevano dal monte, ordinò loro di non raccontare ad alcuno ciò che avevano visto, se non dopo che il Figlio dell''uomo fosse risorto dai morti. Ed essi tennero fra loro la cosa, chiedendosi che cosa volesse dire risorgere dai morti. E lo interrogavano: «Perché gli scribi dicono che prima deve venire Elia?». Egli rispose loro: «Sì, prima viene Elia e ristabilisce ogni cosa; ma, come sta scritto del Figlio dell''uomo? Che deve soffrire molto ed essere disprezzato. Io però vi dico che Elia è già venuto e gli hanno fatto quello che hanno voluto, come sta scritto di lui»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,28b-36', 'Luca', 'Mentre pregava, il suo volto [di Gesù], cambiò d''aspetto e la sua veste divenne candida e sfolgorante. Ed ecco, due uomini conversavano con lui: erano Mosè ed Elia, apparsi nella gloria, e parlavano del suo esodo, che stava per compiersi a Gerusalemme. Pietro e i suoi compagni erano oppressi dal sonno; ma, quando si svegliarono, videro la sua gloria e i due uomini che stavano con lui. Mentre questi si separavano da lui, Pietro disse a Gesù: «Maestro, è bello per noi essere qui. Facciamo tre capanne, una per te, una per Mosè e una per Elia». Egli non sapeva quello che diceva. Mentre parlava così, venne una nube e li coprì con la sua ombra. All''entrare nella nube, ebbero paura. E dalla nube uscì una voce, che diceva: «Questi è il Figlio mio, l''eletto; ascoltatelo!». Appena la voce cessò, restò Gesù solo. Essi tacquero e in quei giorni non riferirono a nessuno ciò che avevano visto');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 5,31-37', 'Giovanni', '[In quel tempo Gesù diceva ai Giudei]: «Se fossi io a testimoniare di me stesso, la mia testimonianza non sarebbe vera. C''è un altro che dà testimonianza di me, e so che la testimonianza che egli dà di me è vera. Voi avete inviato dei messaggeri a Giovanni ed egli ha dato testimonianza alla verità. Io non ricevo testimonianza da un uomo; ma vi dico queste cose perché siate salvati. Egli era la lampada che arde e risplende, e voi solo per un momento avete voluto rallegrarvi alla sua luce. Io però ho una testimonianza superiore a quella di Giovanni: le opere che il Padre mi ha dato da compiere, quelle stesse opere che io sto facendo, testimoniano di me che il Padre mi ha mandato. E anche il Padre, che mi ha mandato, ha dato testimonianza di me. Ma voi non avete mai ascoltato la sua voce né avete mai visto il suo volto»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 22,14-23,56', 'Luca', 'Quando venne l''ora [Gesù], prese posto a tavola e gli apostoli con lui, e disse loro: «Ho tanto desiderato mangiare questa Pasqua con voi, prima della mia passione, perché io vi dico: non la mangerò più, finché essa non si compia nel regno di Dio». E, ricevuto un calice, rese grazie e disse: «Prendetelo e fatelo passare tra voi, perché io vi dico: da questo momento non berrò più del frutto della vite, finché non verrà il regno di Dio». Poi prese il pane, rese grazie, lo spezzò e lo diede loro dicendo: «Questo è il mio corpo, che è dato per voi; fate questo in memoria di me». E, dopo aver cenato, fece lo stesso con il calice dicendo: «Questo calice è la nuova alleanza nel mio sangue, che è versato per voi. Ma ecco, la mano di colui che mi tradisce è con me, sulla tavola. Il Figlio dell''uomo se ne va, secondo quanto è stabilito, ma guai a quell''uomo dal quale egli viene tradito!». Allora essi cominciarono a domandarsi l''un l''altro chi di loro avrebbe fatto questo. E nacque tra loro anche una discussione: chi di loro fosse da considerare più grande. Egli disse: «I re delle nazioni le governano, e coloro che hanno potere su di esse sono chiamati benefattori. Voi però non fate così; ma chi tra voi è più grande diventi come il più giovane, e chi governa come colui che serve. Infatti chi è più grande, chi sta a tavola o chi serve? Non è forse colui che sta a tavola? Eppure io sto in mezzo a voi come colui che serve. Voi siete quelli che avete perseverato con me nelle mie prove e io preparo per voi un regno, come il Padre mio l''ha preparato per me, perché mangiate e beviate alla mia mensa nel mio regno. E siederete in trono a giudicare le dodici tribù d''Israele. Simone, Simone, ecco: Satana vi ha cercati per vagliarvi come il grano; ma io ho pregato per te, perché la tua fede non venga meno. E tu, una volta convertito, conferma i tuoi fratelli». E Pietro gli disse: «Signore, con te sono pronto ad andare anche in prigione e alla morte». Gli rispose: «Pietro, io ti dico: oggi il gallo non canterà prima che tu, per tre volte, abbia negato di conoscermi». Poi disse loro: «Quando vi ho mandato senza borsa, né sacca, né sandali, vi è forse mancato qualcosa?». Risposero: «Nulla». Ed egli soggiunse: «Ma ora, chi ha una borsa la prenda, e così chi ha una sacca; chi non ha spada, venda il mantello e ne compri una. Perché io vi dico: deve compiersi in me questa parola della Scrittura: E fu annoverato tra gli empi. Infatti tutto quello che mi riguarda volge al suo compimento». Ed essi dissero: «Signore, ecco qui due spade». Ma egli disse: «Basta!». Uscì e andò, come al solito, al monte degli Ulivi; anche i discepoli lo seguirono. Giunto sul luogo, disse loro: «Pregate, per non entrare in tentazione». Poi si allontanò da loro circa un tiro di sasso, cadde in ginocchio e pregava dicendo: «Padre, se vuoi, allontana da me questo calice! Tuttavia non sia fatta la mia, ma la tua volontà». Gli apparve allora un angelo dal cielo per confortarlo. Entrato nella lotta, pregava più intensamente, e il suo sudore diventò come gocce di sangue che cadono a terra. Poi, rialzatosi dalla preghiera, andò dai discepoli e li trovò che dormivano per la tristezza. E disse loro: «Perché dormite? Alzatevi e pregate, per non entrare in tentazione». Mentre ancora egli parlava, ecco giungere una folla; colui che si chiamava Giuda, uno dei Dodici, li precedeva e si avvicinò a Gesù per baciarlo. Gesù gli disse: «Giuda, con un bacio tu tradisci il Figlio dell''uomo?». Allora quelli che erano con lui, vedendo ciò che stava per accadere, dissero: «Signore, dobbiamo colpire con la spada?». E uno di loro colpì il servo del sommo sacerdote e gli staccò l''orecchio destro. Ma Gesù intervenne dicendo: «Lasciate! Basta così!». E, toccandogli l''orecchio, lo guarì. Poi Gesù disse a coloro che erano venuti contro di lui, capi dei sacerdoti, capi delle guardie del tempio e anziani: «Come se fossi un ladro siete venuti con spade e bastoni. Ogni giorno ero con voi nel tempio e non avete mai messo le mani su di me; ma questa è l''ora vostra e il potere delle tenebre». Dopo averlo catturato, lo condussero via e lo fecero entrare nella casa del sommo sacerdote. Pietro lo seguiva da lontano. Avevano acceso un fuoco in mezzo al cortile e si erano seduti attorno; anche Pietro sedette in mezzo a loro. Una giovane serva lo vide seduto vicino al fuoco e, guardandolo attentamente, disse: «Anche questi era con lui». Ma egli negò dicendo: «O donna, non lo conosco!». Poco dopo un altro lo vide e disse: «Anche tu sei uno di loro!». Ma Pietro rispose: «O uomo, non lo sono!». Passata circa un''ora, un altro insisteva: «In verità, anche questi era con lui; infatti è Galileo». Ma Pietro disse: «O uomo, non so quello che dici». E in quell''istante, mentre ancora parlava, un gallo cantò. Allora il Signore si voltò e fissò lo sguardo su Pietro, e Pietro si ricordò della parola che il Signore gli aveva detto: «Prima che il gallo canti, oggi mi rinnegherai tre volte». E, uscito fuori, pianse amaramente. E intanto gli uomini che avevano in custodia Gesù lo deridevano e lo picchiavano, gli bendavano gli occhi e gli dicevano: «Fa'' il profeta! Chi è che ti ha colpito?». E molte altre cose dicevano contro di lui, insultandolo. Appena fu giorno, si riunì il consiglio degli anziani del popolo, con i capi dei sacerdoti e gli scribi; lo condussero davanti al loro sinedrio e gli dissero: «Se tu sei il Cristo, dillo a noi». Rispose loro: «Anche se ve lo dico, non mi crederete; se vi interrogo, non mi risponderete. Ma d''ora in poi il Figlio dell''uomo siederà alla destra della potenza di Dio». Allora tutti dissero: «Tu dunque sei il Figlio di Dio?». Ed egli rispose loro: «Voi stessi dite che io lo sono». E quelli dissero: «Che bisogno abbiamo ancora di testimonianza? L''abbiamo udito noi stessi dalla sua bocca». Tutta l''assemblea si alzò; lo condussero da Pilato e cominciarono ad accusarlo: «Abbiamo trovato costui che metteva in agitazione il nostro popolo, impediva di pagare tributi a Cesare e affermava di essere Cristo re». Pilato allora lo interrogò: «Sei tu il re dei Giudei?». Ed egli rispose: «Tu lo dici». Pilato disse ai capi dei sacerdoti e alla folla: «Non trovo in quest''uomo alcun motivo di condanna». Ma essi insistevano dicendo: «Costui solleva il popolo, insegnando per tutta la Giudea, dopo aver cominciato dalla Galilea, fino a qui». Udito ciò, Pilato domandò se quell''uomo era Galileo e, saputo che stava sotto l''autorità di Erode, lo rinviò a Erode, che in quei giorni si trovava anch''egli a Gerusalemme. Vedendo Gesù, Erode si rallegrò molto. Da molto tempo infatti desiderava vederlo, per averne sentito parlare, e sperava di vedere qualche miracolo fatto da lui. Lo interrogò, facendogli molte domande, ma egli non gli rispose nulla. Erano presenti anche i capi dei sacerdoti e gli scribi, e insistevano nell''accusarlo. Allora anche Erode, con i suoi soldati, lo insultò, si fece beffe di lui, gli mise addosso una splendida veste e lo rimandò a Pilato. In quel giorno Erode e Pilato diventarono amici tra loro; prima infatti tra loro vi era stata inimicizia. Pilato, riuniti i capi dei sacerdoti, le autorità e il popolo, disse loro: «Mi avete portato quest''uomo come agitatore del popolo. Ecco, io l''ho esaminato davanti a voi, ma non ho trovato in quest''uomo nessuna delle colpe di cui lo accusate; e neanche Erode: infatti ce l''ha rimandato. Ecco, egli non ha fatto nulla che meriti la morte. Perciò, dopo averlo punito, lo rimetterò in libertà». Ma essi si misero a gridare tutti insieme: «Togli di mezzo costui! Rimettici in libertà Barabba!». Questi era stato messo in prigione per una rivolta, scoppiata in città, e per omicidio. Pilato parlò loro di nuovo, perché voleva rimettere in libertà Gesù. Ma essi urlavano: «Crocifiggilo! Crocifiggilo!». Ed egli, per la terza volta, disse loro: «Ma che male ha fatto costui? Non ho trovato in lui nulla che meriti la morte. Dunque, lo punirò e lo rimetterò in libertà». Essi però insistevano a gran voce, chiedendo che venisse crocifisso, e le loro grida crescevano. Pilato allora decise che la loro richiesta venisse eseguita. Rimise in libertà colui che era stato messo in prigione per rivolta e omicidio, e che essi richiedevano, e consegnò Gesù al loro volere. Mentre lo conducevano via, fermarono un certo Simone di Cirene, che tornava dai campi, e gli misero addosso la croce, da portare dietro a Gesù. Lo seguiva una grande moltitudine di popolo e di donne, che si battevano il petto e facevano lamenti su di lui. Ma Gesù, voltandosi verso di loro, disse: «Figlie di Gerusalemme, non piangete su di me, ma piangete su voi stesse e sui vostri figli. Ecco, verranno giorni nei quali si dirà: "Beate le sterili, i grembi che non hanno generato e i seni che non hanno allattato". Allora cominceranno a dire ai monti: "Cadete su di noi!", e alle colline: "Copriteci!". Perché, se si tratta così il legno verde, che avverrà del legno secco?». Insieme con lui venivano condotti a morte anche altri due, che erano malfattori. Quando giunsero sul luogo chiamato Cranio, vi crocifissero lui e i malfattori, uno a destra e l''altro a sinistra. Gesù diceva: «Padre, perdona loro perché non sanno quello che fanno». Poi dividendo le sue vesti, le tirarono a sorte. Il popolo stava a vedere; i capi invece lo deridevano dicendo: «Ha salvato altri! Salvi se stesso, se è lui il Cristo di Dio, l''eletto». Anche i soldati lo deridevano, gli si accostavano per porgergli dell''aceto e dicevano: «Se tu sei il re dei Giudei, salva te stesso». Sopra di lui c''era anche una scritta: «Costui è il re dei Giudei». Uno dei malfattori appesi alla croce lo insultava: «Non sei tu il Cristo? Salva te stesso e noi!». L''altro invece lo rimproverava dicendo: «Non hai alcun timore di Dio, tu che sei condannato alla stessa pena? Noi, giustamente, perché riceviamo quello che abbiamo meritato per le nostre azioni; egli invece non ha fatto nulla di male». E disse: «Gesù, ricòrdati di me quando entrerai nel tuo regno». Gli rispose: «In verità io ti dico: oggi con me sarai nel paradiso». Era già verso mezzogiorno e si fece buio su tutta la terra fino alle tre del pomeriggio, perché il sole si era eclissato. Il velo del tempio si squarciò a metà. Gesù, gridando a gran voce, disse: «Padre, nelle tue mani consegno il mio spirito». Detto questo, spirò.
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 19,38-42', 'Giovanni', 'Dopo questi fatti, Giuseppe d''Arimatèa, che era discepolo di Gesù, ma di nascosto per timore dei Giudei, chiese a Pilato di prendere il corpo di Gesù. Pilato lo concesse. Allora egli andò e prese il corpo di Gesù. Vi andò anche Nicodèmo, quello che in precedenza era andato da lui di notte, e portò una mistura di mirra e di aloe di circa cento libbre. Essi presero allora il corpo di Gesù, e lo avvolsero in bende insieme con oli aromatici, com''è usanza seppellire per i Giudei. Ora, nel luogo dove era stato crocifisso, vi era un giardino e nel giardino un sepolcro nuovo, nel quale nessuno era stato ancora deposto. Là dunque deposero Gesù, a motivo della Preparazione dei Giudei, poiché quel sepolcro era vicino');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,11b-17', 'Luca', 'In quei giorni Egli [Gesù] le accolse [le folle], e prese a parlare loro del regno di Dio e a guarire quanti avevano bisogno di cure. Il giorno cominciava a declinare e i Dodici gli si avvicinarono dicendo: «Congeda la folla perché vada nei villaggi e nelle campagne dei dintorni, per alloggiare e trovare cibo: qui siamo in una zona deserta». Gesù disse loro: «Voi stessi date loro da mangiare». Ma essi risposero: «Non abbiamo che cinque pani e due pesci, a meno che non andiamo noi a comprare viveri per tutta questa gente». C''erano infatti circa cinquemila uomini. Egli disse ai suoi discepoli: «Fateli sedere a gruppi di cinquanta circa». Fecero così e li fecero sedere tutti quanti. Egli prese i cinque pani e i due pesci, alzò gli occhi al cielo, recitò su di essi la benedizione, li spezzò e li dava ai discepoli perché li distribuissero alla folla. Tutti mangiarono a sazietà e furono portati via i pezzi loro avanzati: dodici ceste');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 13,10-17', 'Matteo', 'Gli si avvicinarono allora, a Gesù, i discepoli e gli dissero: «Perché a loro parli con parabole?». Egli rispose loro: «Perché a voi è dato conoscere i misteri del regno dei cieli, ma a loro non è dato. Infatti a colui che ha, verrà dato e sarà nell''abbondanza; ma a colui che non ha, sarà tolto anche quello che ha. Per questo a loro parlo con parabole: perché guardando non vedono, udendo non ascoltano e non comprendono. Così si compie per loro la profezia di Isaia che dice: Udrete, sì, ma non comprenderete, guarderete, sì, ma non vedrete. Perché il cuore di questo popolo è diventato insensibile, sono diventati duri di orecchi e hanno chiuso gli occhi, perché non vedano con gli occhi, non ascoltino con gli orecchi e non comprendano con il cuore e non si convertano e io li guarisca! Beati invece i vostri occhi perché vedono e i vostri orecchi perché ascoltano. In verità io vi dico: molti profeti e molti giusti hanno desiderato vedere ciò che voi guardate, ma non lo videro, e ascoltare ciò che voi ascoltate, ma non lo ascoltarono»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 17,21-27', 'Matteo', 'Mentre si trovavano insieme in Galilea, Gesù disse loro: «Il Figlio dell''uomo sta per essere consegnato nelle mani degli uomini e lo uccideranno, ma il terzo giorno risorgerà». Ed essi furono molto rattristati. Quando furono giunti a Cafàrnao, quelli che riscuotevano la tassa per il tempio si avvicinarono a Pietro e gli dissero: «Il vostro maestro non paga la tassa?». Rispose: «Sì». Mentre entrava in casa, Gesù lo prevenne dicendo: «Che cosa ti pare, Simone? I re della terra da chi riscuotono le tasse e i tributi? Dai propri figli o dagli estranei?». Rispose: «Dagli estranei». E Gesù replicò: «Quindi i figli sono liberi. Ma, per evitare di scandalizzarli, va'' al mare, getta l''amo e prendi il primo pesce che viene su, aprigli la bocca e vi troverai una moneta d''argento. Prendila e consegnala loro per me e per te»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 12,49-57', 'Luca', '[In quel tempo Gesù disse ai suoi discepoli]: « Sono venuto a gettare fuoco sulla terra, e quanto vorrei che fosse già acceso! Ho un battesimo nel quale sarò battezzato, e come sono angosciato finché non sia compiuto! Pensate che io sia venuto a portare pace sulla terra? No, io vi dico, ma divisione. D''ora innanzi, se in una famiglia vi sono cinque persone, saranno divisi tre contro due e due contro tre; si divideranno padre contro figlio e figlio contro padre, madre contro figlia e figlia contro madre, suocera contro nuora e nuora contro suocera». Diceva ancora alle folle: «Quando vedete una nuvola salire da ponente, subito dite: "Arriva la pioggia", e così accade. E quando soffia lo scirocco, dite: "Farà caldo", e così accade. Ipocriti! Sapete valutare l''aspetto della terra e del cielo; come mai questo tempo non sapete valutarlo? E perché non giudicate voi stessi ciò che è giusto?»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 21,14-30', 'Matteo', '[In quel tempo Gesù disse ai discepoli]: « Avverrà infatti come a un uomo che, partendo per un viaggio, chiamò i suoi servi e consegnò loro i suoi beni. A uno diede cinque talenti, a un altro due, a un altro uno, secondo le capacità di ciascuno; poi partì. Subito colui che aveva ricevuto cinque talenti andò a impiegarli, e ne guadagnò altri cinque. Così anche quello che ne aveva ricevuti due, ne guadagnò altri due. Colui invece che aveva ricevuto un solo talento, andò a fare una buca nel terreno e vi nascose il denaro del suo padrone. Dopo molto tempo il padrone di quei servi tornò e volle regolare i conti con loro. Si presentò colui che aveva ricevuto cinque talenti e ne portò altri cinque, dicendo: "Signore, mi hai consegnato cinque talenti; ecco, ne ho guadagnati altri cinque". "Bene, servo buono e fedele - gli disse il suo padrone -, sei stato fedele nel poco, ti darò potere su molto; prendi parte alla gioia del tuo padrone". Si presentò poi colui che aveva ricevuto due talenti e disse: "Signore, mi hai consegnato due talenti; ecco, ne ho guadagnati altri due". "Bene, servo buono e fedele - gli disse il suo padrone -, sei stato fedele nel poco, ti darò potere su molto; prendi parte alla gioia del tuo padrone". Si presentò infine anche colui che aveva ricevuto un solo talento e disse: "Signore, so che sei un uomo duro, che mieti dove non hai seminato e raccogli dove non hai sparso. Ho avuto paura e sono andato a nascondere il tuo talento sotto terra: ecco ciò che è tuo". Il padrone gli rispose: "Servo malvagio e pigro, tu sapevi che mieto dove non ho seminato e raccolgo dove non ho sparso; avresti dovuto affidare il mio denaro ai banchieri e così, ritornando, avrei ritirato il mio con l''interesse. Toglietegli dunque il talento, e datelo a chi ha i dieci talenti. Perché a chiunque ha, verrà dato e sarà nell''abbondanza; ma a chi non ha, verrà tolto anche quello che ha. E il servo inutile gettatelo fuori nelle tenebre; là sarà pianto e stridore di denti»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,57-62', 'Luca', 'Mentre camminavano per la strada, un tale gli disse: «Ti se-guirò dovunque tu vada». E Gesù gli rispose: «Le volpi hanno le loro tane e gli uccelli del cielo i loro nidi, ma il Figlio dell''uomo non ha dove posare il capo». A un altro disse: «Se-guimi». E costui rispose: «Signore, permettimi di andare pri-ma a seppellire mio padre». Gli replicò: «Lascia che i morti seppelliscano i loro morti; tu invece va'' e annuncia il regno di Dio». Un altro disse: «Ti seguirò, Signore; prima però lascia che io mi congedi da quelli di casa mia». Ma Gesù gli rispose: «Nessuno che mette mano all''aratro e poi si volge indietro è adatto per il regno di Dio»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,26-38', 'Matteo', 'Al sesto mese, l''angelo Gabriele fu mandato da Dio in una città della Galilea, chiamata Nàzaret, a una vergine, promessa sposa di un uomo della casa di Davide, di nome Giuseppe. La vergine si chiamava Maria. Entrando da lei, disse: «Rallégrati, piena di grazia: il Signore è con te». A queste parole ella fu molto turbata e si domandava che senso avesse un saluto come questo. 30L''angelo le disse: «Non temere, Maria, perché hai trovato grazia presso Dio. Ed ecco, concepirai un figlio, lo darai alla luce e lo chiamerai Gesù. Sarà grande e verrà chiamato Figlio dell''Altissimo; il Signore Dio gli darà il trono di Davide suo padre e regnerà per sempre sulla casa di Giacobbe e il suo regno non avrà fine». Allora Maria disse all''angelo: «Come avverrà questo, poiché non conosco uomo?». Le rispose l''angelo: «Lo Spirito Santo scenderà su di te e la potenza dell''Altissimo ti coprirà con la sua ombra. Perciò colui che nascerà sarà santo e sarà chiamato Figlio di Dio. Ed ecco, Elisabetta, tua parente, nella sua vecchiaia ha concepito anch''essa un figlio e questo è il sesto mese per lei, che era detta sterile: nulla è impossibile a Dio». Allora Maria disse: «Ecco la serva del Signore: avvenga per me secondo la tua parola». E l''angelo si allontanò da lei');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 5,33-36', 'Giovanni', 'In quel tempo, Gesù disse ai Giudei: «Voi avete inviato dei messaggeri a Giovanni ed egli ha dato testimonianza alla verità. Io non ricevo testimonianza da un uomo; ma vi dico queste cose perché siate salvati. Egli era la lampada che arde e risplende, e voi solo per un momento avete voluto rallegrarvi alla sua luce. Io però ho una testimonianza superiore a quella di Giovanni: le opere che il Padre mi ha dato da compiere, quelle stesse opere che io sto facendo, testimoniano di me che il Padre mi ha mandato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 3,20-21', 'Matteo', 'In quel tempo Gesù entrò in una casa e di nuovo si radunò una folla, tanto che non potevano neppure mangiare. Allora i suoi, sentito questo, uscirono per andare a prenderlo; dicevano infatti: «È fuori di sé»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 5,43-48', 'Luca', 'Gesù diceva: «Avete inteso che fu detto: Amerai il tuo prossimo e odierai il tuo nemico. Ma io vi dico: amate i vostri nemici e pregate per quelli che vi perseguitano, affinché siate figli del Padre vostro che è nei cieli; egli fa sorgere il suo sole sui cattivi e sui buoni, e fa piovere sui giusti e sugli ingiusti. Infatti, se amate quelli che vi amano, quale ricompensa ne avete? Non fanno così anche i pubblicani? E se date il saluto soltanto ai vostri fratelli, che cosa fate di straordinario? Non fanno così anche i pagani? Voi, dunque, siate perfetti come è perfetto il Padre vostro celeste»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 19,38-40', 'Giovanni', 'Dopo questi fatti Giuseppe di Arimatea, che era discepolo di Gesù, ma di nascosto, per timore dei Giudei, chiese a Pilato di prendere il corpo di Gesù. Pilato lo concesse. Allora egli andò e prese il corpo di Gesù. Vi andò anche Nicodèmo - quello che in precedenza era andato da lui di notte - e portò circa trenta chili di una mistura di mirra e di àloe. Essi presero allora il corpo di Gesù e lo avvolsero con teli, insieme ad aromi, come usano fare i Giudei per preparare la sepoltura');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 12,1-12', 'Marco', 'In quel tempo, Gesù si mise a parlare con parabole [ai capi dei sacerdoti, agli scribi e agli anziani]: «Un uomo piantò una vigna, la circondò con una siepe, scavò una buca per il torchio e costruì una torre. La diede in affitto a dei contadini e se ne andò lontano. Al momento opportuno mandò un servo dai contadini a ritirare da loro la sua parte del raccolto della vigna. Ma essi lo presero, lo bastonarono e lo mandarono via a mani vuote. Mandò loro di nuovo un altro servo: anche quello lo picchiarono sulla testa e lo insultarono. Ne mandò un altro, e questo lo uccisero; poi molti altri: alcuni li bastonarono, altri li uccisero. Ne aveva ancora uno, un figlio amato; lo inviò loro per ultimo, dicendo: “Avranno rispetto per mio figlio!”. Ma quei contadini dissero tra loro: “Costui è l’erede. Su, uccidiamolo e l’eredità sarà nostra”. Lo presero, lo uccisero e lo gettarono fuori della vigna. Che cosa farà dunque il padrone della vigna? Verrà e farà morire i contadini e darà la vigna ad altri. Non avete letto questa Scrittura: “La pietra che i costruttori hanno scartato è diventata la pietra d’angolo; questo è stato fatto dal Signore ed è una meraviglia ai nostri occhi”?». E cercavano di catturarlo, ma ebbero paura della folla; avevano capito infatti che aveva detto quella parabola contro di loro. Lo lasciarono e se ne andarono');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,36-10,8', 'Matteo', 'In quel tempo, Gesù, vedendo le folle, ne sentì compassione, perché erano stanche e sfinite come pecore che non hanno pastore. Allora disse ai suoi discepoli: «La messe è abbondante, ma sono pochi gli operai! Pregate dunque il signore della messe perché mandi operai nella sua messe!». Chiamati a sé i suoi dodici discepoli, diede loro potere sugli spiriti impuri per scacciarli e guarire ogni malattia e ogni infermità. I nomi dei dodici apostoli sono: primo, Simone, chiamato Pietro, e Andrea suo fratello; Giacomo, figlio di Zebedèo, e Giovanni suo fratello; Filippo e Bartolomeo; Tommaso e Matteo il pubblicano; Giacomo, figlio di Alfeo, e Taddeo; Simone il Cananeo e Giuda l''Iscariota, colui che poi lo tradì. Questi sono i Dodici che Gesù inviò, ordinando loro: «Non andate fra i pagani e non entrate nelle città dei Samaritani; rivolgetevi piuttosto alle pecore perdute della casa d''Israele. Strada facendo, predicate, dicendo che il regno dei cieli è vicino. Guarite gli infermi, risuscitate i morti, purificate i lebbrosi, scacciate i demòni. Gratuitamente avete ricevuto, gratuitamente date»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc ?', 'Luca', 'In quel tempo, Gesù disse ai suoi discepoli: «Siate pronti, con le vesti strette ai fianchi e le lampade accese; siate simili a quelli che aspettano il loro padrone quando torna dalle noz-ze, in modo che, quando arriva e bussa, gli aprano subito. Beati quei servi che il padrone al suo ritorno troverà ancora svegli; in verità io vi dico, si stringerà le vesti ai fianchi, li farà mettere a tavola e passerà a servirli. E se, giungendo nel mez-zo della notte o prima dell’alba, li troverà così, beati loro!» (Lc 12,35-38).');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 13,18-12', 'Luca', 'In quel tempo, diceva Gesù: «A che cosa è simile il regno di Dio, e a che cosa lo posso paragonare? È simile a un granello di senape, che un uomo prese e gettò nel suo giardino; crebbe, divenne un albero e gli uccelli del cielo vennero a fare il nido fra i suoi rami». E disse ancora: «A che cosa posso paragonare il regno di Dio? È simile al lievito, che una donna prese e mescolò in tre misure di farina, finché non fu tutta lievitata»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,26-39', 'Luca', 'Al sesto mese, l''angelo Gabriele fu mandato da Dio in una città della Galilea, chiamata Nàzaret, a una vergine, promessa sposa di un uomo della casa di Davide, di nome Giuseppe. La vergine si chiamava Maria. Entrando da lei, disse: «Rallégrati, piena di grazia: il Signore è con te». A queste parole ella fu molto turbata e si domandava che senso avesse un saluto come questo. L''angelo le disse: «Non temere, Maria, perché hai trovato grazia presso Dio. Ed ecco, concepirai un figlio, lo darai alla luce e lo chiamerai Gesù. Sarà grande e verrà chiamato Figlio dell''Altissimo; il Signore Dio gli darà il trono di Davide suo padre e regnerà per sempre sulla casa di Giacobbe e il suo regno non avrà fine». Allora Maria disse all''angelo: «Come avverrà questo, poiché non conosco uomo?». Le rispose l''angelo: «Lo Spirito Santo scenderà su di te e la potenza dell''Altissimo ti coprirà con la sua ombra. Perciò colui che nascerà sarà santo e sarà chiamato Figlio di Dio. Ed ecco, Elisabetta, tua parente, nella sua vecchiaia ha concepito anch''essa un figlio e questo è il sesto mese per lei, che era detta sterile: nulla è impossibile a Dio». Allora Maria disse: «Ecco la serva del Signore: avvenga per me secondo la tua parola». E l''angelo si allontanò da lei');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 10,1-9', 'Marco', 'In quel tempo, il Signore designò altri settantadue e li inviò a due a due davanti a sé in ogni città e luogo dove stava per recarsi. Diceva loro: «La messe è abbondante, ma sono pochi gli operai! Pregate dunque il signore della messe, perché mandi operai nella sua messe! Andate: ecco, vi mando come agnelli in mezzo a lupi; non portate borsa, né sacca, né sandali e non fermatevi a salutare nessuno lungo la strada. In qualunque casa entriate, prima dite: “Pace a questa casa!”. Se vi sarà un figlio della pace, la vostra pace scenderà su di lui, altrimenti ritornerà su di voi. Restate in quella casa, mangiando e bevendo di quello che hanno, perché chi lavora ha diritto alla sua ricompensa. Non passate da una casa all’altra. Quando entrerete in una città e vi accoglieranno, mangiate quello che vi sarà offerto, guarite i malati che vi si trovano, e dite loro: “È vicino a voi il regno di Dio”»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc ?', 'Marco', 'In quel tempo, Gesù chiamò a sé i Dodici e prese a mandarli a due a due e dava loro potere sugli spiriti impuri. E ordinò loro di non prendere per il viaggio nient''altro che un bastone: né pane, né sacca, né denaro nella cintura; ma di calzare sandali e di non portare due tuniche. E diceva loro: «Dovunque entriate in una casa, rimanetevi finché non sarete partiti di lì. Se in qualche luogo non vi accogliessero e non vi ascoltassero, andatevene e scuotete la polvere sotto i vostri piedi come testimonianza per loro». Ed essi, partiti, proclamarono che la gente si convertisse, scacciavano molti demòni, ungevano con olio molti infermi e li guarivano (Mc 6,7-13).');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 5,17-30', 'Matteo', 'In quel tempo, Gesù disse ai Giudei: «Il Padre mio agisce an-che ora e anch''io agisco». Per questo i Giudei cercavano an-cor più di ucciderlo, perché non soltanto violava il sabato, ma chiamava Dio suo Padre, facendosi uguale a Dio. Gesù riprese a parlare e disse loro: «In verità, in verità io vi dico: il Figlio da se stesso non può fare nulla, se non ciò che vede fare dal Padre; quello che egli fa, anche il Figlio lo fa allo stesso mo-do. Il Padre infatti ama il Figlio, gli manifesta tutto quello che fa e gli manifesterà opere ancora più grandi di queste, perché voi ne siate meravigliati. Come il Padre risuscita i morti e dà la vita, così anche il Figlio dà la vita a chi egli vuole. Il Padre infatti non giudica nessuno, ma ha dato ogni giudizio al Fi-glio, perché tutti onorino il Figlio come onorano il Padre. Chi non onora il Figlio, non onora il Padre che lo ha mandato. In verità, in verità io vi dico: chi ascolta la mia parola e crede a colui che mi ha mandato, ha la vita eterna e non va incontro al giudizio, ma è passato dalla morte alla vita. In verità, in ve-rità io vi dico: viene l''ora - ed è questa - in cui i morti udran-no la voce del Figlio di Dio e quelli che l''avranno ascoltata, vivranno. Come infatti il Padre ha la vita in se stesso, così ha concesso anche al Figlio di avere la vita in se stesso, e gli ha dato il potere di giudicare, perché è Figlio dell''uomo. Non meravigliatevi di questo: viene l''ora in cui tutti coloro che sono nei sepolcri udranno la sua voce e usciranno, quanti fe-cero il bene per una risurrezione di vita e quanti fecero il ma-le per una risurrezione di condanna. Da me, io non posso fare nulla. Giudico secondo quello che ascolto e il mio giudizio è giusto, perché non cerco la mia volontà, ma la volontà di co-lui che mi ha mandato');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 14,1-15,47', 'Marco', 'Mancavano due giorni alla Pasqua e agli Àzzimi, e i capi dei sacerdoti e gli scribi cercavano il modo di catturare Gesù con un inganno per farlo morire. Dicevano infatti: «Non durante la festa, perché non vi sia una rivolta del popolo». Gesù si trovava a Betània, nella casa di Simone il lebbroso. Mentre era a tavola, giunse una donna che aveva un vaso di alabastro, pieno di profumo di puro nardo, di grande valore. Ella ruppe il vaso di alabastro e versò il profumo sul suo capo. Ci furono alcuni, fra loro, che si indignarono: «Perché questo spreco di profumo? Si poteva venderlo per più di trecento denari e darli ai poveri!». Ed erano infuriati contro di lei. Allora Gesù disse: «Lasciatela stare; perché la infastidite? Ha compiuto un''azione buona verso di me. I poveri infatti li avete sempre con voi e potete far loro del bene quando volete, ma non sempre avete me. Ella ha fatto ciò che era in suo potere, ha unto in anticipo il mio corpo per la sepoltura. In verità io vi dico: dovunque sarà proclamato il Vangelo, per il mondo intero, in ricordo di lei si dirà anche quello che ha fatto». Allora Giuda Iscariota, uno dei Dodici, si recò dai capi dei sacerdoti per consegnare loro Gesù. Quelli, all''udirlo, si rallegrarono e promisero di dargli del denaro. Ed egli cercava come consegnarlo al momento opportuno. Il primo giorno degli Àzzimi, quando si immolava la Pasqua, i suoi discepoli gli dissero: «Dove vuoi che andiamo a preparare, perché tu possa mangiare la Pasqua?». Allora mandò due dei suoi discepoli, dicendo loro: «Andate in città e vi verrà incontro un uomo con una brocca d''acqua; seguitelo. Là dove entrerà, dite al padrone di casa: "Il Maestro dice: Dov''è la mia stanza, in cui io possa mangiare la Pasqua con i miei discepoli?". Egli vi mostrerà al piano superiore una grande sala, arredata e già pronta; lì preparate la cena per noi». I discepoli andarono e, entrati in città, trovarono come aveva detto loro e prepararono la Pasqua. Venuta la sera, egli arrivò con i Dodici. Ora, mentre erano a tavola e mangiavano, Gesù disse: «In verità io vi dico: uno di voi, colui che mangia con me, mi tradirà». Cominciarono a rattristarsi e a dirgli, uno dopo l''altro: «Sono forse io?». Egli disse loro: «Uno dei Dodici, colui che mette con me la mano nel piatto. Il Figlio dell''uomo se ne va, come sta scritto di lui; ma guai a quell''uomo, dal quale il Figlio dell''uomo viene tradito! Meglio per quell''uomo se non fosse mai nato!». E, mentre mangiavano, prese il pane e recitò la benedizione, lo spezzò e lo diede loro, dicendo: «Prendete, questo è il mio corpo». Poi prese un calice e rese grazie, lo diede loro e ne bevvero tutti. E disse loro: «Questo è il mio sangue dell''alleanza, che è versato per molti. In verità io vi dico che non berrò mai più del frutto della vite fino al giorno in cui lo berrò nuovo, nel regno di Dio». Dopo aver cantato l''inno, uscirono verso il monte degli Ulivi. Gesù disse loro: «Tutti rimarrete scandalizzati, perché sta scritto: "Percuoterò il pastore e le pecore saranno disperse". Ma, dopo che sarò risorto, vi precederò in Galilea». Pietro gli disse: «Anche se tutti si scandalizzeranno, io no!». Gesù gli disse: «In verità io ti dico: proprio tu, oggi, questa notte, prima che due volte il gallo canti, tre volte mi rinnegherai». Ma egli, con grande insistenza, diceva: «Anche se dovessi morire con te, io non ti rinnegherò». Lo stesso dicevano pure tutti gli altri. Giunsero a un podere chiamato Getsèmani, ed egli disse ai suoi discepoli: «Sedetevi qui, mentre io prego». Prese con sé Pietro, Giacomo e Giovanni e cominciò a sentire paura e angoscia. Disse loro: «La mia anima è triste fino alla morte. Restate qui e vegliate». Poi, andato un po'' innanzi, cadde a terra e pregava che, se fosse possibile, passasse via da lui quell''ora. E diceva: «Abbà! Padre! Tutto è possibile a te: allontana da me questo calice! Però non ciò che voglio io, ma ciò che vuoi tu». Poi venne, li trovò addormentati e disse a Pietro: «Simone, dormi? Non sei riuscito a vegliare una sola ora? Vegliate e pregate per non entrare in tentazione. Lo spirito è pronto, ma la carne è debole». Si allontanò di nuovo e pregò dicendo le stesse parole. Poi venne di nuovo e li trovò addormentati, perché i loro occhi si erano fatti pesanti, e non sapevano che cosa rispondergli. Venne per la terza volta e disse loro: «Dormite pure e riposatevi! Basta! È venuta l''ora: ecco, il Figlio dell''uomo viene consegnato nelle mani dei peccatori. Alzatevi, andiamo! Ecco, colui che mi tradisce è vicino». E subito, mentre ancora egli parlava, arrivò Giuda, uno dei Dodici, e con lui una folla con spade e bastoni, mandata dai capi dei sacerdoti, dagli scribi e dagli anziani. Il traditore aveva dato loro un segno convenuto, dicendo: «Quello che bacerò, è lui; arrestatelo e conducetelo via sotto buona scorta». Appena giunto, gli si avvicinò e disse: «Rabbì» e lo baciò. Quelli gli misero le mani addosso e lo arrestarono. Uno dei presenti estrasse la spada, percosse il servo del sommo sacerdote e gli staccò l''orecchio. Allora Gesù disse loro: «Come se fossi un brigante siete venuti a prendermi con spade e bastoni. Ogni giorno ero in mezzo a voi nel tempio a insegnare, e non mi avete arrestato. Si compiano dunque le Scritture!». Allora tutti lo abbandonarono e fuggirono. Lo seguiva però un ragazzo, che aveva addosso soltanto un lenzuolo, e lo afferrarono. Ma egli, lasciato cadere il lenzuolo, fuggì via nudo. Condussero Gesù dal sommo sacerdote, e là si riunirono tutti i capi dei sacerdoti, gli anziani e gli scribi. Pietro lo aveva seguito da lontano, fin dentro il cortile del palazzo del sommo sacerdote, e se ne stava seduto tra i servi, scaldandosi al fuoco. I capi dei sacerdoti e tutto il sinedrio cercavano una testimonianza contro Gesù per metterlo a morte, ma non la trovavano. Molti infatti testimoniavano il falso contro di lui e le loro testimonianze non erano concordi. Alcuni si alzarono a testimoniare il falso contro di lui, dicendo: «Lo abbiamo udito mentre diceva: "Io distruggerò questo tempio, fatto da mani d''uomo, e in tre giorni ne costruirò un altro, non fatto da mani d''uomo"». Ma nemmeno così la loro testimonianza era concorde. Il sommo sacerdote, alzatosi in mezzo all''assemblea, interrogò Gesù dicendo: «Non rispondi nulla? Che cosa testimoniano costoro contro di te?». Ma egli taceva e non rispondeva nulla. Di nuovo il sommo sacerdote lo interrogò dicendogli: «Sei tu il Cristo, il Figlio del Benedetto?». Gesù rispose: «Io lo sono! E vedrete il Figlio dell''uomo seduto alla destra della Potenza e venire con le nubi del cielo». Allora il sommo sacerdote, stracciandosi le vesti, disse: «Che bisogno abbiamo ancora di testimoni? Avete udito la bestemmia; che ve ne pare?». Tutti sentenziarono che era reo di morte. Alcuni si misero a sputargli addosso, a bendargli il volto, a percuoterlo e a dirgli: «Fa'' il profeta!». E i servi lo schiaffeggiavano. Mentre Pietro era giù nel cortile, venne una delle giovani serve del sommo sacerdote e, vedendo Pietro che stava a scaldarsi, lo guardò in faccia e gli disse: «Anche tu eri con il Nazareno, con Gesù». Ma egli negò, dicendo: «Non so e non capisco che cosa dici». Poi uscì fuori verso l''ingresso e un gallo cantò. E la serva, vedendolo, ricominciò a dire ai presenti: «Costui è uno di loro». Ma egli di nuovo negava. Poco dopo i presenti dicevano di nuovo a Pietro: «È vero, tu certo sei uno di loro; infatti sei Galileo». Ma egli cominciò a imprecare e a giurare: «Non conosco quest''uomo di cui parlate». E subito, per la seconda volta, un gallo cantò. E Pietro si ricordò della parola che Gesù gli aveva detto: «Prima che due volte il gallo canti, tre volte mi rinnegherai». E scoppiò in pianto. E subito, al mattino, i capi dei sacerdoti, con gli anziani, gli scribi e tutto il sinedrio, dopo aver tenuto consiglio, misero in catene Gesù, lo portarono via e lo consegnarono a Pilato. Pilato gli domandò: «Tu sei il re dei Giudei?». Ed egli rispose: «Tu lo dici». I capi dei sacerdoti lo accusavano di molte cose. Pilato lo interrogò di nuovo dicendo: «Non rispondi nulla? Vedi di quante cose ti accusano!». Ma Gesù non rispose più nulla, tanto che Pilato rimase stupito. A ogni festa, egli era solito rimettere in libertà per loro un carcerato, a loro richiesta. Un tale, chiamato Barabba, si trovava in carcere insieme ai ribelli che nella rivolta avevano commesso un omicidio. La folla, che si era radunata, cominciò a chiedere ciò che egli era solito concedere. Pilato rispose loro: «Volete che io rimetta in libertà per voi il re dei Giudei?». Sapeva infatti che i capi dei sacerdoti glielo avevano consegnato per invidia. Ma i capi dei sacerdoti incitarono la folla perché, piuttosto, egli rimettesse in libertà per loro Barabba. Pilato disse loro di nuovo: «Che cosa volete dunque che io faccia di quello che voi chiamate il re dei Giudei?». Ed essi di nuovo gridarono: «Crocifiggilo!». Pilato diceva loro: «Che male ha fatto?». Ma essi gridarono più forte: «Crocifiggilo!». Pilato, volendo dare soddisfazione alla folla, rimise in libertà per loro Barabba e, dopo aver fatto flagellare Gesù, lo consegnò perché fosse crocifisso. Allora i soldati lo condussero dentro il cortile, cioè nel pretorio, e convocarono tutta la truppa. Lo vestirono di porpora, intrecciarono una corona di spine e gliela misero attorno al capo. Poi presero a salutarlo: «Salve, re dei Giudei!». E gli percuotevano il capo con una canna, gli sputavano addosso e, piegando le ginocchia, si prostravano davanti a lui. Dopo essersi fatti beffe di lui, lo spogliarono della porpora e gli fecero indossare le sue vesti, poi lo condussero fuori per crocifiggerlo. Costrinsero a portare la sua croce un tale che passava, un certo Simone di Cirene, che veniva dalla campagna, padre di Alessandro e di Rufo. Condussero Gesù al luogo del Gòlgota, che significa «Luogo del cranio», e gli davano vino mescolato con mirra, ma egli non ne prese. Poi lo crocifissero e si divisero le sue vesti, tirando a sorte su di esse ciò che ognuno avrebbe preso. Erano le nove del mattino quando lo crocifissero. La scritta con il motivo della sua condanna diceva: «Il re dei Giudei». Con lui crocifissero anche due ladroni, uno a destra e uno alla sua sinistra. Quelli che passavano di là lo insultavano, scuotendo il capo e dicendo: «Ehi, tu che distruggi il tempio e lo ricostruisci in tre giorni, salva te stesso scendendo dalla croce!». Così anche i capi dei sacerdoti, con gli scribi, fra loro si facevano beffe di lui e dicevano: «Ha salvato altri e non può salvare se stesso! Il Cristo, il re d''Israele, scenda ora dalla croce, perché vediamo e crediamo!». E anche quelli che erano stati crocifissi con lui lo insultavano. Quando fu mezzogiorno, si fece buio su tutta la terra fino alle tre del pomeriggio. Alle tre, Gesù gridò a gran voce: «Eloì, Eloì, lemà sabactàni?», che significa: «Dio mio, Dio mio, perché mi hai abbandonato?». Udendo questo, alcuni dei presenti dicevano: «Ecco, chiama Elia!». Uno corse a inzuppare di aceto una spugna, la fissò su una canna e gli dava da bere, dicendo: «Aspettate, vediamo se viene Elia a farlo scendere». Ma Gesù, dando un forte grido, spirò. Il velo del tempio si squarciò in due, da cima a fondo. Il centurione, che si trovava di fronte a lui, avendolo visto spirare in quel modo, disse: «Davvero quest''uomo era Figlio di Dio!». Vi erano anche alcune donne, che osservavano da lontano, tra le quali Maria di Màgdala, Maria madre di Giacomo il minore e di Ioses, e Salome, le quali, quando era in Galilea, lo seguivano e lo servivano, e molte altre che erano salite con lui a Gerusalemme. Venuta ormai la sera, poiché era la Parascève, cioè la vigilia del sabato, Giuseppe d''Arimatèa, membro autorevole del sinedrio, che aspettava anch''egli il regno di Dio, con coraggio andò da Pilato e chiese il corpo di Gesù. Pilato si meravigliò che fosse già morto e, chiamato il centurione, gli domandò se era morto da tempo. Informato dal centurione, concesse la salma a Giuseppe. Egli allora, comprato un lenzuolo, lo depose dalla croce, lo avvolse con il lenzuolo e lo mise in un sepolcro scavato nella roccia. Poi fece rotolare una pietra all''entrata del sepolcro. Maria di Màgdala e Maria madre di Ioses stavano a osservare dove veniva posto');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 16,20-23', 'Giovanni', 'In quel tempo, disse Gesù ai suoi discepoli: «In verità, in verità io vi dico: voi piangerete e gemerete, ma il mondo si rallegrerà. Voi sarete nella tristezza, ma la vostra tristezza si cambierà in gioia. La donna, quando partorisce, è nel dolore, perché è venuta la sua ora; ma, quando ha dato alla luce il bambino, non si ricorda più della sofferenza, per la gioia che è venuto al mondo un uomo. Così anche voi, ora, siete nel dolore; ma vi vedrò di nuovo e il vostro cuore si rallegrerà e nessuno potrà togliervi la vostra gioia. Quel giorno non mi domanderete più nulla»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Gv 16,23-28', 'Giovanni', 'In quel tempo, disse Gesù ai suoi discepoli: «In verità, in verità io vi dico: se chiederete qualche cosa al Padre nel mio nome, egli ve la darà. Finora non avete chiesto nulla nel mio nome. Chiedete e otterrete, perché la vostra gioia sia piena. Queste cose ve le ho dette in modo velato, ma viene l''ora in cui non vi parlerò più in modo velato e apertamente vi parlerò del Padre. In quel giorno chiederete nel mio nome e non vi dico che pregherò il Padre per voi: il Padre stesso infatti vi ama, perché voi avete amato me e avete creduto che io sono uscito da Dio. Sono uscito dal Padre e sono venuto nel mondo; ora lascio di nuovo il mondo e vado al Padre»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 3,20-35', 'Marco', 'In quel tempo, Gesù entrò in una casa e di nuovo si radunò una folla, tanto che non potevano neppure mangiare. Allora i suoi, sentito questo, uscirono per andare a prenderlo; dicevano infatti: «È fuori di sé». Gli scribi, che erano scesi da Gerusalemme, dicevano: «Costui è posseduto da Beelzebùl e scaccia i demòni per mezzo del capo dei demòni». Ma egli li chiamò e con parabole diceva loro: «Come può Satana scacciare Satana? Se un regno è diviso in se stesso, quel regno non potrà restare in piedi; se una casa è divisa in se stessa, quella casa non potrà restare in piedi. Anche Satana, se si ribella contro se stesso ed è diviso, non può restare in piedi, ma è finito. Nessuno può entrare nella casa di un uomo forte e rapire i suoi beni, se prima non lo lega. Soltanto allora potrà saccheggiargli la casa. In verità io vi dico: tutto sarà perdonato ai figli degli uomini, i peccati e anche tutte le bestemmie che diranno; ma chi avrà bestemmiato contro lo Spirito Santo non sarà perdonato in eterno: è reo di colpa eterna». Poiché dicevano: «È posseduto da uno spirito impuro». Giunsero sua madre e i suoi fratelli e, stando fuori, mandarono a chiamarlo. Attorno a lui era seduta una folla, e gli dissero: «Ecco, tua madre, i tuoi fratelli e le tue sorelle stanno fuori e ti cercano». Ma egli rispose loro: «Chi è mia madre e chi sono i miei fratelli?». Girando lo sguardo su quelli che erano seduti attorno a lui, disse: «Ecco mia madre e i miei fratelli! Perché chi fa la volontà di Dio, costui per me è fratello, sorella e madre»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt ?', 'Matteo', 'In quel tempo, si avvicinarono a Gesù i discepoli di Giovanni e gli dissero: «Perché noi e i farisei digiuniamo molte volte, mentre i tuoi discepoli non digiunano?». E Gesù disse loro: «Possono forse gli invitati a nozze essere in lutto finché lo sposo è con loro? Ma verranno giorni quando lo sposo sarà loro tolto, e allora digiuneranno. Nessuno mette un pezzo di stoffa grezza su un vestito vecchio, perché il rattoppo porta via qualcosa dal vestito e lo strappo diventa peggiore. Né si versa vino nuovo in otri vecchi, altrimenti si spaccano gli otri e il vino si spande e gli otri vanno perduti. Ma si versa vino nuovo in otri nuovi, e così l''uno e gli altri si conservano» (Mt 9,14-17).');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 7,1-8.14-15.21-23', 'Matteo', 'In quel tempo, si riunirono attorno a Gesù i farisei e alcuni degli scribi, venuti da Gerusalemme. Avendo visto che alcuni dei suoi discepoli prendevano cibo con mani impure, cioè non lavate - i farisei infatti e tutti i Giudei non mangiano se non si sono lavati accuratamente le mani, attenendosi alla tradizione degli antichi e, tornando dal mercato, non mangiano senza aver fatto le abluzioni, e osservano molte altre cose per tradizione, come lavature di bicchieri, di stoviglie, di oggetti di rame e di letti –, quei farisei e scribi lo interrogarono: «Perché i tuoi discepoli non si comportano secondo la tradizione degli antichi, ma prendono cibo con mani impure?». Ed egli rispose loro: «Bene ha profetato Isaìa di voi, ipocriti, come sta scritto: "Questo popolo mi onora con le labbra, ma il suo cuore è lontano da me. Invano mi rendono culto, insegnando dottrine che sono precetti di uomini". Trascurando il comandamento di Dio, voi osservate la tradizione degli uomini». Chiamata di nuovo la folla, diceva loro: «Ascoltatemi tutti e comprendete bene! Non c''è nulla fuori dell''uomo che, entrando in lui, possa renderlo impuro. Ma sono le cose che escono dall''uomo a renderlo impuro». E diceva [ai suoi discepoli]: «Dal di dentro infatti, cioè dal cuore degli uomini, escono i propositi di male: impurità, furti, omicidi, adultèri, avidità, malvagità, inganno, dissolutezza, invidia, calunnia, superbia, stoltezza. Tutte queste cose cattive vengono fuori dall''interno e rendono impuro l''uomo»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 9,9-13', 'Luca', 'In quel tempo, mentre andava via, Gesù, vide un uomo, chiamato Matteo, seduto al banco delle imposte, e gli disse: «Seguimi». Ed egli si alzò e lo seguì. Mentre sedeva a tavola nella casa, sopraggiunsero molti pubblicani e peccatori e se ne stavano a tavola con Gesù e con i suoi discepoli. Vedendo ciò, i farisei dicevano ai suoi discepoli: «Come mai il vostro maestro mangia insieme ai pubblicani e ai peccatori?». Udito questo, disse: «Non sono i sani che hanno bisogno del medico, ma i malati. Andate a imparare che cosa vuol dire: "Misericordia io voglio e non sacrifici". Io non sono venuto infatti a chiamare i giusti, ma i peccatori»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 9,51-56', 'Luca', 'Mentre stavano compiendosi i giorni in cui sarebbe stato elevato in alto, Gesù prese la ferma decisione di mettersi in cammino verso Gerusalemme e mandò messaggeri davanti a sé. Questi si incamminarono ed entrarono in un villaggio di Samaritani per preparargli l''ingresso. Ma essi non vollero riceverlo, perché era chiaramente in cammino verso Gerusalemme. Quando videro ciò, i discepoli Giacomo e Giovanni dissero: «Signore, vuoi che diciamo che scenda un fuoco dal cielo e li consumi?». Si voltò e li rimproverò. E si misero in cammino verso un altro villaggio');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 11,42-46', 'Luca', 'In quel tempo, il Signore disse: «Guai a voi, farisei, che pagate la decima sulla menta, sulla ruta e su tutte le erbe, e lasciate da parte la giustizia e l''amore di Dio. Queste invece erano le cose da fare, senza trascurare quelle. Guai a voi, farisei, che amate i primi posti nelle sinagoghe e i saluti sulle piazze. Guai a voi, perché siete come quei sepolcri che non si vedono e la gente vi passa sopra senza saperlo». Intervenne uno dei dottori della Legge e gli disse: «Maestro, dicendo questo, tu offendi anche noi». Egli rispose: «Guai anche a voi, dottori della Legge, che caricate gli uomini di pesi insopportabili, e quei pesi voi non li toccate nemmeno con un dito!»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 4,14-22a', 'Luca', 'Gesù ritornò in Galilea con la potenza dello Spirito e la sua fama si diffuse in tutta la regione. Insegnava nelle loro sinagoghe e gli rendevano lode. Venne a Nàzaret, dove era cresciuto, e secondo il suo solito, di sabato, entrò nella sinagoga e si alzò a leggere. Gli fu dato il rotolo del profeta Isaia; aprì il rotolo e trovò il passo dove era scritto: Lo Spirito del Signore è sopra di me; per questo mi ha consacrato con l''unzione e mi ha mandato a portare ai poveri il lieto annuncio, a proclamare ai prigionieri la liberazione e ai ciechi la vista; a rimettere in libertà gli oppressi, a proclamare l''anno di grazia del Signore. Riavvolse il rotolo, lo riconsegnò all''inserviente e sedette. Nella sinagoga, gli occhi di tutti erano fissi su di lui. Allora cominciò a dire loro: «Oggi si è compiuta questa Scrittura che voi avete ascoltato». Tutti gli davano testimonianza ed erano meravigliati delle parole di grazia che uscivano dalla sua bocca');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 1,14;4,14-21', 'Luca', 'Poiché molti hanno cercato di raccontare con ordine gli avvenimenti che si sono compiuti in mezzo a noi, come ce li hanno trasmessi coloro che ne furono testimoni oculari fin da principio e divennero ministri della Parola, così anch''io ho deciso di fare ricerche accurate su ogni circostanza, fin dagli inizi, e di scriverne un resoconto ordinato per te, illustre Teòfilo, in modo che tu possa renderti conto della solidità degli insegnamenti che hai ricevuto. In quel tempo, Gesù ritornò in Galilea con la potenza dello Spirito e la sua fama si diffuse in tutta la regione. Insegnava nelle loro sinagoghe e gli rendevano lode. Venne a Nàzaret, dove era cresciuto, e secondo il suo solito, di sabato, entrò nella sinagoga e si alzò a leggere. Gli fu dato il rotolo del profeta Isaìa; aprì il rotolo e trovò il passo dove era scritto: "Lo Spirito del Signore è sopra di me; per questo mi ha consacrato con l''unzione e mi ha mandato a portare ai poveri il lieto annuncio, a proclamare ai prigionieri la liberazione e ai ciechi la vista; a rimettere in libertà gli oppressi e proclamare l''anno di grazia del Signore". Riavvolse il rotolo, lo riconsegnò all''inserviente e sedette. Nella sinagoga, gli occhi di tutti erano fissi su di lui. Allora cominciò a dire loro: «Oggi si è compiuta questa Scrittura che voi avete ascoltato»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mc 4,3541', 'Marco', 'In quel medesimo giorno, venuta la sera, Gesù disse ai suoi discepoli: «Passiamo all''altra riva». E, congedata la folla, lo presero con sé, così com''era, nella barca. C''erano anche altre barche con lui. Ci fu una grande tempesta di vento e le onde si rovesciavano nella barca, tanto che ormai era piena. Egli se ne stava a poppa, sul cuscino, e dormiva. Allora lo svegliarono e gli dissero: «Maestro, non t''importa che siamo perduti?». Si destò, minacciò il vento e disse al mare: «Taci, càlmati!». Il vento cessò e ci fu grande bonaccia. Poi disse loro: «Perché avete paura? Non avete ancora fede?». E furono presi da grande timore e si dicevano l''un l''altro: «Chi è dunque costui, che anche il vento e il mare gli obbediscono?»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 1,16.18-21.24a', 'Matteo', 'Giacobbe generò Giuseppe, lo sposo di Maria, dalla quale è nato Gesù, chiamato Cristo. Così fu generato Gesù Cristo: sua madre Maria, essendo promessa sposa di Giuseppe, prima che andassero a vivere insieme si trovò incinta per opera dello Spirito Santo. Giuseppe suo sposo, poiché era uomo giusto e non voleva accusarla pubblicamente, pensò di ripudiarla in segreto. Mentre però stava considerando queste cose, ecco, gli apparve in sogno un angelo del Signore e gli disse: «Giuseppe, figlio di Davide, non temere di prendere con te Maria, tua sposa. Infatti il bambino che è generato in lei viene dallo Spirito Santo; ella darà alla luce un figlio e tu lo chiamerai Gesù: egli infatti salverà il suo popolo dai suoi peccati». Quando si destò dal sonno, Giuseppe fece come gli aveva ordinato l''angelo del Signore');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 15,13.11-32', 'Luca', 'In quel tempo, si avvicinavano a lui tutti i pubblicani e i peccatori per ascoltarlo. I farisei e gli scribi mormoravano dicendo: «Costui accoglie i peccatori e mangia con loro». Ed egli disse loro questa parabola: «Un uomo aveva due figli. Il più giovane dei due disse al padre: "Padre, dammi la parte di patrimonio che mi spetta". Ed egli divise tra loro le sue sostanze. Pochi giorni dopo, il figlio più giovane, raccolte tutte le sue cose, partì per un paese lontano e là sperperò il suo patrimonio vivendo in modo dissoluto. Quando ebbe speso tutto, sopraggiunse in quel paese una grande carestia ed egli cominciò a trovarsi nel bisogno. Allora andò a mettersi al servizio di uno degli abitanti di quella regione, che lo mandò nei suoi campi a pascolare i porci. Avrebbe voluto saziarsi con le carrube di cui si nutrivano i porci; ma nessuno gli dava nulla. Allora ritornò in sé e disse: "Quanti salariati di mio padre hanno pane in abbondanza e io qui muoio di fame! Mi alzerò, andrò da mio padre e gli dirò: Padre, ho peccato verso il Cielo e davanti a te; non sono più degno di essere chiamato tuo figlio. Trattami come uno dei tuoi salariati". Si alzò e tornò da suo padre. Quando era ancora lontano, suo padre lo vide, ebbe compassione, gli corse incontro, gli si gettò al collo e lo baciò. Il figlio gli disse: "Padre, ho peccato verso il Cielo e davanti a te; non sono più degno di essere chiamato tuo figlio". Ma il padre disse ai servi: "Presto, portate qui il vestito più bello e fateglielo indossare, mettetegli l''anello al dito e i sandali ai piedi. Prendete il vitello grasso, ammazzatelo, mangiamo e facciamo festa, perché questo mio figlio era morto ed è tornato in vita, era perduto ed è stato ritrovato". E cominciarono a far festa. Il figlio maggiore si trovava nei campi. Al ritorno, quando fu vicino a casa, udì la musica e le danze; chiamò uno dei servi e gli domandò che cosa fosse tutto questo. Quello gli rispose: "Tuo fratello è qui e tuo padre ha fatto ammazzare il vitello grasso, perché lo ha riavuto sano e salvo". Egli si indignò, e non voleva entrare. Suo padre allora uscì a supplicarlo. Ma egli rispose a suo padre: "Ecco, io ti servo da tanti anni e non ho mai disobbedito a un tuo comando, e tu non mi hai mai dato un capretto per far festa con i miei amici. Ma ora che è tornato questo tuo figlio, il quale ha divorato le tue sostanze con le prostitute, per lui hai ammazzato il vitello grasso". Gli rispose il padre: "Figlio, tu sei sempre con me e tutto ciò che è mio è tuo; ma bisognava far festa e rallegrarsi, perché questo tuo fratello era morto ed è tornato in vita, era perduto ed è stato ritrovato"»');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Mt 1,117', 'Matteo', 'Genealogia di Gesù Cristo figlio di Davide, figlio di Abramo. Abramo generò Isacco, Isacco generò Giacobbe, Giacobbe generò Giuda e i suoi fratelli, Giuda generò Fares e Zara da Tamar, Fares generò Esrom, Esrom generò Aram, Aram generò Aminadàb, Aminadàb generò Naassòn, Naassòn generò Salmon, Salmon generò Booz da Racab, Booz generò Obed da Rut, Obed generò Iesse, Iesse generò il re Davide. Davide generò Salomone da quella che era stata la moglie di Urìa, Salomone generò Roboamo, Roboamo generò Abìa, Abìa generò Asaf, Asaf generò Giòsafat, Giòsafat generò Ioram, Ioram generò Ozìa, Ozìa generò Ioatàm, Ioatàm generò Àcaz, Àcaz generò Ezechìa, Ezechìa generò Manasse, Manasse generò Amos, Amos generò Giosìa, Giosìa generò Ieconìa e i suoi fratelli, al tempo della deportazione in Babilonia. Dopo la deportazione in Babilonia, Ieconìa generò Salatièl, Salatièl generò Zorobabele, Zorobabele generò Abiùd, Abiùd generò Eliachìm, Eliachìm generò Azor, Azor generò Sadoc, Sadoc generò Achim, Achim generò Eliùd, Eliùd generò Eleàzar, Eleàzar generò Mattan, Mattan generò Giacobbe, Giacobbe generò Giuseppe, lo sposo di Maria, dalla quale è nato Gesù, chiamato Cristo. In tal modo, tutte le generazioni da Abramo a Davide sono quattordici, da Davide fino alla deportazione in Babilonia quattordici, dalla deportazione in Babilonia a Cristo quattordici');
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 2,114', 'Luca', 'Messa della notte - Dal Vangelo secondo Luca
INSERT INTO gospels (reference, evangelist, text) VALUES ('Lc 2,36-40', 'Matteo', 'C''era anche una profetessa, Anna, figlia di Fanuele, della tribù di Aser. Era molto avanzata in età, aveva vissuto con il marito sette anni dopo il suo matrimonio, era poi rimasta vedova e ora aveva ottantaquattro anni. Non si allontanava mai dal tempio, servendo Dio notte e giorno con digiuni e preghiere. Sopraggiunta in quel momento, si mise anche lei a lodare Dio e parlava del bambino a quanti aspettavano la redenzione di Gerusalemme. Quando ebbero adempiuto ogni cosa secondo la legge del Signore, fecero ritorno in Galilea, alla loro città di Nàzaret. Il bambino cresceva e si fortificava, pieno di sapienza, e la grazia di Dio era su di lui!');
